INSERT INTO `audits` (`id`, `audit_category`, `audit_entity`, `external_ref`, `title`, `authority`, `category`, `audit_type`, `status`, `start_date`, `end_date`, `closed_date`, `subject`, `created_by`, `created_at`, `updated_at`, `auditors`, `attendees`) VALUES
(X'F16EFB564C7D46589BADB7E7B1403F74', 'CAA', 'BCAA', 'BCAA.ATO.OUT.1 ', 'BCAA California Site Audit - 2025', 'INTERNAL', NULL, 'FCL/ATO/Outstation', 'IN_PROGRESS', '2025-11-04', '2025-11-05', NULL, 'The scope of this audit was to verify the correct implementation of the Aircrew Regulation 1178/2011, as amended by 2025/134, at the training site in the United States. EPC provides both theoretical and flight training for the PPL(A) licence at Thermal Airport in Coachella, USA. The audit resulted in nine findings and one observation.', X'415712F4C7D811F0AD9A84068FBD07E7', '2025-12-31 01:29:29', '2026-01-05 01:17:44', 'D\'Homme, Philippe (Lead Auditor)\nVan den Bergh, Kris (Expert)', 'Paz-Vereeken, Maria A. (Accountable Manager)\nMaes, Koen (Head Of Training, Chief Theoretical Knowledge Instructor)\nVereeken, Kay (CMM/SM Ad-Interim)');
INSERT INTO `compliance_domains` (`id`, `code`, `name`, `description`) VALUES
(1, 'GENERAL', 'General / Test Domain', 'Temporary test domain for findings');
INSERT INTO `finding_actions` (`id`, `finding_id`, `action_type`, `description`, `responsible_id`, `due_date`, `completed_at`, `effectiveness`, `created_at`) VALUES
(14, X'DCB15885FFFF4D81A2212B2847718850', 'CORRECTIVE', 'Include a visibility checklist as part of the OMM update for the Just Culture Policy that outlines required locations for displays and assign responsibility for monitoring compliance to designated personnel (CMM and his Assistant(s)).', NULL, '2026-03-31', NULL, 'NOT_EVALUATED', '2026-01-05 17:56:43'),
(15, X'DCB15885FFFF4D81A2212B2847718850', 'PREVENTIVE', 'In accordance with ORA.GEN.200 (Management System) and the principles of a proactive Safety Management System (SMS), EuroPilot Center (EPC) and SoCal Pilot Center (SPC) propose to implement and maintain a standardized \"Post-Flight Checklist\" as a mandatory element of the normal flight operation cycle.\n\nThis Post-Flight Checklist shall include a clearly defined and standardized Occurrence Reporting trigger, ensuring that the identification, consideration, and reporting of hazards, incidents, or irregularities are systematically embedded into routine post-flight activities at EPC and SPC.\n\nBy integrating Occurrence Reporting into the Post-Flight Checklist (identical to the mandatory completion of aircraft technical logbooks and flight records) EPC and SPC ensure that safety reporting is treated as a normal operational responsibility rather than an exceptional action. This approach supports a just culture, promotes timely and accurate reporting, and ensures that safety-relevant information is captured consistently and without undue delay.\n\nThis standardized process supports and improves continuous hazard identification, effective safety risk management, and meaningful safety data collection for monitoring, analysis, and continuous improvement, as required under the SMS framework defined in ORA.GEN.200 and associated AMC/GM material.\n\nProposed Checklist content:\n\nPOST-FLIGHT CHECKLIST\n1.	Post-Flight Walk-Around ☐ PERFORMED\n2.	Refueling Requirement ☐ CONSIDERED\n— After leaving the ramp —\n3.	Technical Squawks / Defects ☐ REPORTED\n4.	Occurrence Report ☐ FILED (IF APPLICABLE)\n5.	Post-Flight Debriefing ☐ COMPLETED / SIGNED\n6.	Aircraft & Flight Logbooks ☐ COMPLETED / SIGNED\n7.	Operational Sign-Out ☐ PERFORMED\n', NULL, '2026-01-31', NULL, 'NOT_EVALUATED', '2026-01-05 17:56:43'),
(16, X'E93535E8557341C7A9F6BD54B0AF689C', 'CORRECTIVE', 'Update Annex 16 of the OMM to include the flight instructors qualified for the Advanced UPRT course and US training by compiling information from relevant training records.', NULL, '2026-01-13', NULL, 'NOT_EVALUATED', '2026-01-06 02:15:59'),
(17, X'E93535E8557341C7A9F6BD54B0AF689C', 'PREVENTIVE', 'Create a simple checklist for instructors to submit their qualifications related to new courses quarterly to ensure any updates are captured timely.', NULL, '2026-02-05', NULL, 'NOT_EVALUATED', '2026-01-06 02:15:59'),
(18, X'26576E407BE04921BE69DDDBB8B5F20A', 'CORRECTIVE', 'Draft a written agreement between Euro Pilot Center and SoCal Pilot Center outlining the contracted activities and requirements based on existing regulations.', NULL, '2026-02-28', NULL, 'NOT_EVALUATED', '2026-01-06 02:24:59'),
(19, X'26576E407BE04921BE69DDDBB8B5F20A', 'PREVENTIVE', 'Conduct a brief internal review of current practices related to contracted activities to ensure compliance with documentation standards. Ensure Compliance Audits are conducted accordingly.', NULL, '2026-03-31', NULL, 'NOT_EVALUATED', '2026-01-06 02:24:59'),
(20, X'F301FCF46843437C9C6635135040ACFE', 'CORRECTIVE', 'Update the ATO procedures manuals (OM, TM GEN and other Manuals referring to Paper Files), to explicitly state the use of electronic student training files, removing all old references to paper-based training folders.', NULL, '2026-03-31', NULL, 'NOT_EVALUATED', '2026-01-06 02:35:55'),
(21, X'F301FCF46843437C9C6635135040ACFE', 'PREVENTIVE', 'Develop a standard operating procedure (SOP) for keeping electronic student training files in compliance with EASA: ORA.GEN \"record keeping\" only states: \"Records shall be stored in a manner that ensures protection from damage, alteration, and theft, and allows easy accessibility to the competent authority.\" In addition: The text: \"EuroPilot Center maintains student training records in an electronic format. Electronic student files are managed in accordance with ORA.GEN.220 and ORA.ATO.120, ensuring data integrity, traceability, protection against unauthorised modification, and availability to the competent authority upon request + explanation on how this is accomplished today.', NULL, '2026-03-31', NULL, 'NOT_EVALUATED', '2026-01-06 02:35:55'),
(22, X'D46FF0515C6D48F9B2A09E46F20130D2', 'CORRECTIVE', 'Revise the existing agreement titled \'Addendum – Economic Leverage & Limitations\' to include explicit statements of the Accountable Manager\'s responsibilities concerning safety accountability, authority for financing activities, and responsibility for the management system.', NULL, '2026-02-05', NULL, 'NOT_EVALUATED', '2026-01-06 02:47:47'),
(23, X'D46FF0515C6D48F9B2A09E46F20130D2', 'PREVENTIVE', 'Review of the revised agreement during the next internal Audit, to ensure alignment with EASA regulations and the latest BCAA guidance.', NULL, '2026-03-31', NULL, 'NOT_EVALUATED', '2026-01-06 02:47:47'),
(24, X'B785B728C2BF42DDA9BD48B97A02B37F', 'CORRECTIVE', 'Conduct a review of the current Private Pilot Theoretical knowledge curriculum against the BCAA published learning objectives to identify any missing content.', NULL, '2026-08-31', NULL, 'NOT_EVALUATED', '2026-01-06 02:52:07'),
(25, X'B785B728C2BF42DDA9BD48B97A02B37F', 'PREVENTIVE', 'ADDIE Framework emphasis update in the TM GEN. With the focus on closing the feedback loop.', NULL, '2026-03-31', NULL, 'NOT_EVALUATED', '2026-01-06 02:52:07'),
(26, X'ABD6FC66CA024679B1ABE3B16CBF570F', 'CORRECTIVE', 'Develop a more in depth procedure in the TM GEN, Chapter 2.1, outlining periodic reviews of training materials in alignment with the ADDIE framework, including timelines, responsibilities, and practical tools used to measure the results of a training curriculum.', NULL, '2026-03-31', NULL, 'NOT_EVALUATED', '2026-01-06 02:58:04'),
(27, X'ABD6FC66CA024679B1ABE3B16CBF570F', 'PREVENTIVE', 'Develop and include a software tool which automatically verifies compliance with updated rules/regulations affecting the training curriculums/training manuals. Focus also on the method on how to verify successful results from the existing training programs with the goal to continuously improve training curricula.', NULL, '2026-06-30', NULL, 'NOT_EVALUATED', '2026-01-06 02:58:04'),
(28, X'A429F0F3F89945CBA4759968D6C056BA', 'CORRECTIVE', 'Update the Training Manual General (TM GEN) and Operations Manual (OM) to include basic responsibilities for Post-holders regarding U.S. training activities.', NULL, '2026-03-31', NULL, 'NOT_EVALUATED', '2026-01-06 03:05:48'),
(29, X'A429F0F3F89945CBA4759968D6C056BA', 'PREVENTIVE', 'The CMM conducts an official Post-holder meeting to communicate the updated responsibilities related to U.S. training activities.', NULL, '2026-03-31', NULL, 'NOT_EVALUATED', '2026-01-06 03:05:48'),
(30, X'31AE9B3E9B4143648290D2561B0E1D12', 'CORRECTIVE', 'Update the Safety Management System Tool to ensure the Safety Manager will be triggered automatically, to enter final and intermediate feedback into ECCAIRS, ensuring all necessary details are captured.', NULL, '2026-03-31', NULL, 'NOT_EVALUATED', '2026-01-06 03:10:18'),
(31, X'31AE9B3E9B4143648290D2561B0E1D12', 'PREVENTIVE', 'Conduct a training session to inform staff about the importance of entering feedback into ECCAIRS and utilizing the new Safety Management System Tool.', NULL, '2026-03-31', NULL, 'NOT_EVALUATED', '2026-01-06 03:10:18'),
(32, X'C9D8DB298E3D43B9B948D7A1803F665E', 'CORRECTIVE', 'Appoint a permanent Deputy Head of Training and update all relevant documentation to reflect this change.', NULL, '2026-01-12', NULL, 'NOT_EVALUATED', '2026-01-06 03:22:22'),
(33, X'C9D8DB298E3D43B9B948D7A1803F665E', 'PREVENTIVE', 'Develop a procedure, described in the OMM, for reviewing and updating Postholder positions, to ensure timely succession planning (and provide backup).', NULL, '2026-03-31', NULL, 'NOT_EVALUATED', '2026-01-06 03:22:22'),
(34, X'C9D8DB298E3D43B9B948D7A1803F665E', 'PREVENTIVE', 'Implement a 6-month oversight review meeting to discuss roles and responsibilities, ensuring alignment with operational needs (including consideration of backup).', NULL, '2026-03-31', NULL, 'NOT_EVALUATED', '2026-01-06 03:22:22');
INSERT INTO `finding_rca` (`finding_id`, `steps_json`, `created_by`, `created_at`, `updated_at`, `root_cause_text`, `locked_at`, `locked_by`, `lock_reason`, `approved_by_name`, `approved_at`) VALUES
(X'26576E407BE04921BE69DDDBB8B5F20A', '[{\"whyNumber\":1,\"question\":\"Why are there no written agreements between Euro Pilot Center and SoCal Pilot Center defining the contracted activities and applicable requirements?\",\"answer\":\"SoCal Pilot Center was always considered a satellite organization of EuroPilot Center and not a subcontractor. \"},{\"whyNumber\":2,\"question\":\"Why was SoCal Pilot Center considered a satellite organization of Euro Pilot Center rather than a subcontractor?\",\"answer\":\"Because the AMC does not clearly differentiate between internal satellite operations and externally contracted activities, leading to assumptions that formal subcontracting agreements were unnecessary, which has been confirmed for many years by the BCAA.\"},{\"whyNumber\":3,\"question\":\"Why does the AMC not clearly differentiate between internal satellite operations and externally contracted activities?\",\"answer\":\"Because the AMC lacks detailed guidance and definitions regarding the classification and management of organizational arrangements, resulting in ambiguity in applying contract management requirements.\"},{\"whyNumber\":4,\"question\":\"Why does the AMC lack detailed guidance and definitions regarding the classification and management of organizational arrangements?\",\"answer\":\"Because the AMC was developed without comprehensive stakeholder consultation and risk assessment specific to multi-entity training organizations, leading to gaps in addressing complex contractual and operational relationships.\"},{\"whyNumber\":5,\"question\":\"Why was the AMC developed without comprehensive stakeholder consultation and risk assessment specific to multi-entity training organizations?\",\"answer\":\"Because the regulatory framework prioritized generic applicability and expedited publication over the inclusion of specialized input and tailored risk analyses, resulting in insufficient coverage of complex organizational structures.\"}]', X'415712F4C7D811F0AD9A84068FBD07E7', '2026-01-06 02:22:16', '2026-01-05 18:27:36', 'Because the regulatory framework prioritized generic applicability and expedited publication over the inclusion of specialized input and tailored risk analyses, resulting in insufficient coverage of complex organizational structures.', '2026-01-05 18:27:36', NULL, 'Final Proposal', 'Kay Vereeken', '2026-01-05 18:27:36'),
(X'31AE9B3E9B4143648290D2561B0E1D12', '[{\"whyNumber\":1,\"question\":\"Why are the conclusions and mitigating actions from occurrences not entered into ECCAIRS?\",\"answer\":\"Because the ATO has no defined process or clear instructions to ensure completion and upload of final and intermediate feedback into the ECCAIRS system.\"},{\"whyNumber\":2,\"question\":\"Why does the ATO lack a defined process or clear instructions for completing and uploading feedback into ECCAIRS?\",\"answer\":\"Because the ATO\'s safety management documentation and training programs do not include specific guidance on finalizing occurrence reports within the ECCAIRS platform.\"},{\"whyNumber\":3,\"question\":\"Why do the ATO\'s safety management documentation and training programs not include specific guidance on finalizing occurrence reports within the ECCAIRS platform?\",\"answer\":\"Because the ATO\'s oversight and internal review processes have not identified the gap in procedural documentation nor mandated updates to include ECCAIRS finalization requirements.\"},{\"whyNumber\":4,\"question\":\"Why have the ATO\'s oversight and internal review processes not identified the gap in procedural documentation nor mandated updates to include ECCAIRS finalization requirements?\",\"answer\":\"Because the oversight framework has no routine audit specifically targeting the completeness of safety management documentation and the integration of occurrence reporting processes within the ECCAIRS system.\"},{\"whyNumber\":5,\"question\":\"Why does the oversight framework have no routine audit specifically targeting the completeness of safety management documentation and the integration of occurrence reporting processes within the ECCAIRS system?\",\"answer\":\"Because the oversight framework has no established audit criteria focused on the implementation and effectiveness of occurrence reporting and feedback mechanisms within the ATO\'s safety management system.\"}]', X'415712F4C7D811F0AD9A84068FBD07E7', '2026-01-06 03:08:16', '2026-01-05 19:12:16', 'Because the oversight framework has no established audit criteria focused on the implementation and effectiveness of occurrence reporting and feedback mechanisms within the ATO\'s safety management system.', '2026-01-05 19:12:16', NULL, 'Final Proposal', 'Kay Vereeken', '2026-01-05 19:12:16'),
(X'A429F0F3F89945CBA4759968D6C056BA', '[{\"whyNumber\":1,\"question\":\"Why do the responsibilities assigned to Post-holders not explicitly reflect their responsibility for training activities conducted in the U.S.?\",\"answer\":\"Because the Training Manual and Operations Manual (ORA.ATO.130) do not explicitly include provisions or guidelines that address oversight and accountability for training activities conducted outside the home country.\"},{\"whyNumber\":2,\"question\":\"Why do the Training Manual and Operations Manual (ORA.ATO.130) not explicitly include provisions or guidelines for overseas training oversight?\",\"answer\":\"Because the manual development process might not have sufficiently considered the operational complexities and regulatory requirements associated with conducting training activities outside the home country.\"},{\"whyNumber\":3,\"question\":\"Why might the manual development process not have sufficiently considered the operational complexities and regulatory requirements associated with conducting training activities outside the home country?\",\"answer\":\"Because there was inadequate stakeholder engagement and risk assessment during the manual development process, leading to an incomplete understanding of cross-jurisdictional training challenges.\"},{\"whyNumber\":4,\"question\":\"Why was there inadequate stakeholder engagement and risk assessment during the manual development process?\",\"answer\":\"Because the process lacked a structured framework for comprehensive consultation and systematic risk analysis specific to international training operations.\"},{\"whyNumber\":5,\"question\":\"Why did the process lack a structured framework for comprehensive consultation and systematic risk analysis specific to international training operations?\",\"answer\":\"Because the organization’s Compliance and procedural review mechanisms did not prioritize or focus on the development of specialized frameworks addressing cross-border training complexities and related regulatory harmonization.\"}]', X'415712F4C7D811F0AD9A84068FBD07E7', '2026-01-06 03:03:47', '2026-01-05 19:07:53', 'Because the organization’s Compliance and procedural review mechanisms did not prioritize or focus on the development of specialized frameworks addressing cross-border training complexities and related regulatory harmonization.', '2026-01-05 19:07:53', NULL, 'Final Proposal', 'Kay Vereeken', '2026-01-05 19:07:53'),
(X'ABD6FC66CA024679B1ABE3B16CBF570F', '[{\"whyNumber\":1,\"question\":\"Why was the ATO unable to provide evidence of regular application of the ADDIE framework for course development and evaluation?\",\"answer\":\"Because the ATO has not implemented periodic\\/systematic review of Training Manual Content, withing the scope of its ADDIE framework.\"},{\"whyNumber\":2,\"question\":\"Why has the ATO not implemented a periodic\\/systematic review of Training Manual Content within the scope of its ADDIE framework?\",\"answer\":\"Because the ATO currently has no formalized procedures\\/oversight mechanisms to ensure scheduled reviews and updates of training materials are conducted in alignment with the ADDIE framework.\"},{\"whyNumber\":3,\"question\":\"Why does the ATO not have formalized procedures or oversight mechanisms to ensure scheduled reviews and updates of training materials within the ADDIE framework?\",\"answer\":\"Because the ATO lacks a documented internal governance structure that defines roles, responsibilities, and workflows for maintaining and monitoring the systematic review of training content (ADDIE).\"},{\"whyNumber\":4,\"question\":\"Why does the ATO lack a documented internal governance structure defining roles, responsibilities, and workflows for maintaining systematic review of training content?\",\"answer\":\"Because there has been insufficient management focus (and possible resource allocation) towards developing and formalizing internal compliance assurance processes, related to training curriculum management.\"},{\"whyNumber\":5,\"question\":\"Why has there been insufficient management focus and resource allocation towards developing and formalizing internal compliance assurance processes related to training curriculum management?\",\"answer\":\"Because the ATO\'s strategic planning and risk management frameworks did not prioritize compliance assurance in training curriculum management as a critical area requiring dedicated resources and oversight.\"}]', X'415712F4C7D811F0AD9A84068FBD07E7', '2026-01-06 02:55:07', '2026-01-05 19:03:14', 'Because the ATO\'s strategic planning and risk management frameworks did not prioritize compliance assurance in training curriculum management as a critical area requiring dedicated resources and oversight.', '2026-01-05 19:03:14', NULL, 'Final Proposal', 'Kay Vereeken', '2026-01-05 19:03:14'),
(X'B785B728C2BF42DDA9BD48B97A02B37F', '[{\"whyNumber\":1,\"question\":\"Why was the ATO unable to provide evidence that its training program fully incorporates all of the published learning objectives?\",\"answer\":\"Because the ATO lacks a formalized process to regularly review and align its training program with the latest published learning objectives.\"},{\"whyNumber\":2,\"question\":\"Why does the ATO lack a formalized process to regularly review and align its training program with the latest published learning objectives?\",\"answer\":\"Because the ATO\'s management system does not include a documented procedure for periodic curriculum evaluation and updates in accordance with regulatory changes. (which could be part of the ADDIE framework)\"},{\"whyNumber\":3,\"question\":\"Why does the ATO\'s management system not include a documented procedure for periodic curriculum evaluation and updates in accordance with regulatory changes?\",\"answer\":\"Because the ADDIE framework (feedback loop has not been closed).\"},{\"whyNumber\":4,\"question\":\"Why has the ADDIE framework feedback loop not been closed?\",\"answer\":\"Because there has been no formal system to ensure continuous monitoring and implementation of training curriculum updates (Ref to ADDIE).\"},{\"whyNumber\":5,\"question\":\"Why has there been no formal system to ensure continuous monitoring and implementation of training curriculum updates?\",\"answer\":\"Because the ATO has not allocated dedicated resources or assigned specific responsibilities for ongoing training curriculum maintenance.\"}]', X'415712F4C7D811F0AD9A84068FBD07E7', '2026-01-06 02:49:45', '2026-01-05 18:53:44', 'Because the ATO has not allocated dedicated resources or assigned specific responsibilities for ongoing training curriculum maintenance.', '2026-01-05 18:53:44', NULL, 'Final Proposal', 'Kay Vereeken', '2026-01-05 18:53:44'),
(X'C9D8DB298E3D43B9B948D7A1803F665E', '[{\"whyNumber\":1,\"question\":\"Why was no replacement designated for the Deputy Head of Training position after the previous incumbent departed?\",\"answer\":\"Because the function of \\\"Deputy Head of Training\\\" is not an official function under Part-ORA. Historically, the BCAA, during an audit conducted 3 years ago, had questions about how the Head of Training in Belgium was capable to maintain oversight over the training activities in the US. It was mentioned that the Online System provides \\\"at glance\\\" data on student progress. In addition, reference was made to our internal staff meetings. The BCAA wanted to see more oversight, so we created the Deputy Head of Training position to satisfy the requirement (although no operational need was deemed required). This under the management system flexibility of Part-ORA.\"},{\"whyNumber\":2,\"question\":\"Why was the Deputy Head of Training position created without a formalized requirement or operational need?\",\"answer\":\"Because the Part ORA management system flexibility allowed the organization to implement roles to address specific audit concerns without integrating them into formal regulatory requirements or operational processes.\"},{\"whyNumber\":3,\"question\":\"Why was the Deputy Head of Training position not integrated into formal operational processes despite being created to address audit concerns?\",\"answer\":\"Because the management system allowed for reactive, ad hoc role creation to satisfy audit findings. The operational need was never deemed required.\"},{\"whyNumber\":4,\"question\":\"Why did the management system allow the Deputy Head of Training position to remain unintegrated without triggering a formal replacement process?\",\"answer\":\"Because the management system lacked specific procedures or controls mandating the review and continuity of non-regulatory required, ad hoc roles created solely for audit satisfaction.\"},{\"whyNumber\":5,\"question\":\"Why did the management system lack specific procedures or controls mandating the review and continuity of non-regulatory required, ad hoc roles?\",\"answer\":\"Because the organization’s oversight and Compliance Processes did not incorporate comprehensive governance for roles established outside formal regulatory frameworks, leading to gaps in role sustainability and succession planning.\"}]', X'415712F4C7D811F0AD9A84068FBD07E7', '2026-01-06 03:17:25', '2026-01-05 19:26:04', 'Because the organization’s oversight and Compliance Processes did not incorporate comprehensive governance for roles established outside formal regulatory frameworks, leading to gaps in role sustainability and succession planning.', '2026-01-05 19:26:04', NULL, 'Final Proposal', 'Kay Vereeken', '2026-01-05 19:26:04'),
(X'D46FF0515C6D48F9B2A09E46F20130D2', '[{\"whyNumber\":1,\"question\":\"Why does the agreement titled \'Addendum – Economic Leverage & Limitations\' not adequately reflect the responsibilities required of the Accountable Manager under EASA regulations?\",\"answer\":\"Because the addendum was developed at the time based upon full guidance obtained from our regulatory body, being the BCAA, after discussing the role and responsibility of the proposed AM.\"},{\"whyNumber\":2,\"question\":\"Why was the addendum developed based on guidance that did not include full EASA AM responsibilities?\",\"answer\":\"Because the regulatory guidance from the BCAA at the time lacked comprehensive detail on AM duties under EASA regulations, resulting in incomplete incorporation of required responsibilities into the agreement. Hence the document in its current format was accepted by the BCAA.\"},{\"whyNumber\":3,\"question\":\"Why did the regulatory guidance from the BCAA at the time lack comprehensive detail on AM duties under EASA regulations?\",\"answer\":\"Because the BCAA might not have fully updated or aligned its internal regulatory framework and associated guidance documents to reflect all specific requirements introduced by EASA regulations regarding the AM role, leading to gaps in communicated expectations.\"},{\"whyNumber\":4,\"question\":\"Why might the BCAA not have fully updated or aligned its internal regulatory framework and associated guidance documents to reflect all specific requirements introduced by EASA regulations regarding the AM role?\",\"answer\":\"Because of limited resources and prioritization challenges within the BCAA regulatory oversight function, which may have delayed comprehensive review and update of guidance documents to ensure full alignment with evolving EASA standards.\"},{\"whyNumber\":5,\"question\":\"Why were there limited resources and prioritization challenges within the BCAA regulatory oversight function?\",\"answer\":\"Because the BCAA has faced constraints in budget, lots of staff changes, issues with allocation and staffing capacity, compounded by competing regulatory demands and evolving oversight responsibilities, which might have impacted its ability to dedicate sufficient focus to comprehensive regulatory framework updates. The information found in the Regulations was, in accordance with our internal Compliance Review, compliant with the existing regulations, hence comfirmed by BCAA oversight..\"}]', X'415712F4C7D811F0AD9A84068FBD07E7', '2026-01-06 02:44:06', '2026-01-05 18:48:57', 'Because the BCAA has faced constraints in budget, lots of staff changes, issues with allocation and staffing capacity, compounded by competing regulatory demands and evolving oversight responsibilities, which might have impacted its ability to dedicate sufficient focus to comprehensive regulatory framework updates. The information found in the Regulations was, in accordance with our internal Compliance Review, compliant with the existing regulations, hence comfirmed by BCAA oversight..', '2026-01-05 18:48:57', NULL, 'Final Proposal', 'Kay Vereeken', '2026-01-05 18:48:57'),
(X'DCB15885FFFF4D81A2212B2847718850', '[{\"whyNumber\":1,\"question\":\"Why is the just culture policy not sufficiently visible or endorsed in operational areas?\",\"answer\":\"Because the organization has not implemented a formal process to ensure the consistent dissemination and prominent display of the policy across all operational environments.\"},{\"whyNumber\":2,\"question\":\"Why has the organization not implemented a formal process to ensure the consistent dissemination and prominent display of the policy across all operational environments?\",\"answer\":\"Because there is a lack of clear procedures and assigned responsibilities within the management system for policy communication and visibility monitoring.\"},{\"whyNumber\":3,\"question\":\"Why is there a lack of clear procedures and assigned responsibilities within the management system for policy communication and visibility monitoring?\",\"answer\":\"Because management system documentation has not been updated to explicitly incorporate requirements for just culture policy communication, responsibility allocation, and verification mechanisms.\"},{\"whyNumber\":4,\"question\":\"Why has the management system documentation not been updated to explicitly incorporate requirements for just culture policy communication, responsibility allocation, and verification mechanisms?\",\"answer\":\"Because the organization’s document control and review processes do not currently mandate periodic evaluation and revision of safety policy-related procedures to reflect evolving regulatory expectations and operational needs.\"},{\"whyNumber\":5,\"question\":\"Why do the organization’s document control and review processes not currently mandate periodic evaluation and revision of safety policy-related procedures?\",\"answer\":\"Because the management oversight and internal audit mechanisms lack specific criteria and focus on assessing the adequacy and currency of safety policy documentation within the document control framework.\"}]', X'415712F4C7D811F0AD9A84068FBD07E7', '2026-01-05 17:55:31', '2026-01-05 18:09:52', 'Because the management oversight and internal audit mechanisms lack specific criteria and focus on assessing the adequacy and currency of safety policy documentation within the document control framework.', '2026-01-05 18:09:52', NULL, 'Final Proposal', 'Kay Vereeken', '2026-01-05 18:09:52'),
(X'E93535E8557341C7A9F6BD54B0AF689C', '[{\"whyNumber\":1,\"question\":\"Why does the Annex 16 of the OMM not include flight instructors qualified for the Advanced UPRT course or US training?\",\"answer\":\"Because the format of the Annex was produced before the A-UPRT course was approved and has not been updated ever since.\"},{\"whyNumber\":2,\"question\":\"Why has the Annex 16 format not been updated since before the A-UPRT course approval?\",\"answer\":\"Because there is no established process (or correlation) within the OMM documentation management system, to ensure timely updates reflecting new courses and instructor qualifications after a new course has been added.\"},{\"whyNumber\":3,\"question\":\"Why is there no established process to ensure timely updates to the OMM documentation?\",\"answer\":\"Because the organization\'s documentation management framework lacks defined responsibilities and procedural controls specifically addressing the integration of new training programs and associated instructor qualifications.\"},{\"whyNumber\":4,\"question\":\"Why does the documentation management framework lack defined responsibilities and procedural controls for integrating new training programs and instructor qualifications?\",\"answer\":\"Because the organization has not implemented a formal governance structure or change control mechanism that requires periodic review and continuous improvement of documentation processes for training program updates. This could be part of the ADDIE framework (last feedback loop).\"},{\"whyNumber\":5,\"question\":\"Why has the organization not implemented a formal governance structure or change control mechanism for periodic review and improvement of documentation related to training program updates?\",\"answer\":\"Because there is insufficient organizational emphasis and resource allocation for establishing structured governance and change management processes within the training program\\/documentation system, limiting the capacity to enforce continuous oversight and updates aligned with evolving training requirements.\"}]', X'415712F4C7D811F0AD9A84068FBD07E7', '2026-01-06 02:11:38', '2026-01-05 18:20:20', 'Because there is insufficient organizational emphasis and resource allocation for establishing structured governance and change management processes within the training program/documentation system, limiting the capacity to enforce continuous oversight and updates aligned with evolving training requirements.', '2026-01-05 18:20:20', NULL, 'Final Proposal', 'Kay Vereeken', '2026-01-05 18:20:20'),
(X'F301FCF46843437C9C6635135040ACFE', '[{\"whyNumber\":1,\"question\":\"Why do the ATO\'s manuals for the PPL training program still refer to a paper-based student training folder?\",\"answer\":\"Because the ATO has not updated its approved procedures to reflect the transition to electronic student training files in full.\"},{\"whyNumber\":2,\"question\":\"Why has the ATO not updated its approved procedures to reflect the transition to electronic student training files in full?\",\"answer\":\"Because the format in which the Electronic Student Training Folder was produced, was based on our existing E-gle system, allowing us to Print each debriefing sheet after each flight and logging it in a physical paper binder. So the need to update the manual was not deemed necessary.\"},{\"whyNumber\":3,\"question\":\"Why was the need to update the manual not deemed necessary despite the transition to exclusively electronic training files?\",\"answer\":\"Because of the way on how the formatting of the debriefing sheets was worked out (print-ready file in the exact same layout as the paper debriefing sheet).\"},{\"whyNumber\":4,\"question\":\"Why was the formatting of the debriefing sheets designed to mimic the paper debriefing sheets exactly?\",\"answer\":\"At the time of creating the E-gle System, no such systems were in place in the Industry and no regulatory guidance was available yet.\"},{\"whyNumber\":5,\"question\":\"Why were no regulatory guidelines or industry standards in place to support electronic documentation systems at the time of creating the E-gle System?\",\"answer\":\"Because regulatory frameworks and industry best practices for paperless operations were still evolving and had not yet established specific requirements or guidance for electronic training record management. Even today, GM1 ORA.GEN.220 still refers to generic guidance on this.\"}]', X'415712F4C7D811F0AD9A84068FBD07E7', '2026-01-06 02:28:20', '2026-01-05 18:42:16', 'Because regulatory frameworks and industry best practices for paperless operations were still evolving and had not yet established specific requirements or guidance for electronic training record management. Even today, GM1 ORA.GEN.220 still refers to generic guidance on this.', '2026-01-05 18:42:16', NULL, 'Final Proposal', 'Kay Vereeken', '2026-01-05 18:42:16');
INSERT INTO `findings` (`id`, `audit_id`, `reference`, `title`, `classification`, `status`, `severity`, `description`, `regulation_ref`, `requirement_key`, `raised_date`, `target_date`, `closed_date`, `domain_id`, `created_at`, `updated_at`, `cap_selected_option`, `cap_selected_effort`, `notes`) VALUES
(X'26576E407BE04921BE69DDDBB8B5F20A', X'F16EFB564C7D46589BADB7E7B1403F74', 'BCAA.ATO.NC.336', 'SoCal Pilot Center (Legal Entity) and Contracted Activities', 'LEVEL_2', 'OPEN', 'HIGH', 'The activities within the organisation\'s scope of approval involve three entities:\n1. E-Guided Learning Experience LLC (U.S. Company - Limited Liability Company)\n2. SoCal Pilot Center (U.S. Company - Corporation)\n3. Euro Pilot Center (EPC) (Belgian company - bv)\n\nE-Guided Learning Experience LLC is a board member of EPC. \nEPC has been approved by the Belgian CAA to provide the training listed in its certificate. Part of these training activities are subcontracted to SoCal Pilot Center.\n\nThe training activities conducted in the U.S. are organised by SoCal Pilot Center, which is not certified to carry out this activity.\nUnder ORA.GEN.205, these training activities must be considered contracted activities by the ATO Euro Pilot Center (Belgian\ncompany).\n\nHowever, there is no written agreement between Euro Pilot Center and SoCal Pilot Center clearly defining:\n\n- The contracted activities\n- The applicable requirements', 'ORA.GEN.205 - Contracted activities', NULL, '2026-01-05', '2026-02-20', NULL, 1, '2026-01-05 01:09:38', '2026-01-06 02:24:59', 'A', 'QUICK', 'The BCAA considers SPC as a Contracted Entity (due to its legal status). A contract should be produced outlining the responsibilities of both parties.'),
(X'31AE9B3E9B4143648290D2561B0E1D12', X'F16EFB564C7D46589BADB7E7B1403F74', 'BCAA.ATO.NC.338', 'ECCAIRS final and intermediate feedback loop missing', 'LEVEL_2', 'OPEN', 'LOW', 'The ATO registers occurrences in ECCAIRS and ensures proper follow-up within its internal safety management system.\nHowever, the conclusions and mitigating actions (final and intermediate reports) resulting from these occurrences are not\nentered into ECCAIRS.', 'ORA.GEN.160 - Occurrence Reporting', NULL, '2026-01-05', '2026-02-20', NULL, 1, '2026-01-05 01:14:22', '2026-02-12 03:08:15', 'A', 'QUICK', NULL),
(X'A429F0F3F89945CBA4759968D6C056BA', X'F16EFB564C7D46589BADB7E7B1403F74', 'BCAA.ATO.NC.337', 'Responsibilities of Post-holders (CMM, SM, HT) and related US activities', 'LEVEL_2', 'OPEN', 'MEDIUM', 'Certain phases of the PPL(A) flying and theoretical training programs, are conducted in the United States. \nHowever, the responsibilities assigned to the Post-holders (CMM, SM, HT, ...) do not explicitly reflect their responsibility for these training\nactivities taking place in the U.S.\n\nThe lack of clearly defined responsibilities for training activities conducted in the U.S. may lead to gaps in oversight and compliance with safety standards. This could result in inadequate monitoring of training quality, operational risks, and regulatory adherence, potentially compromising flight safety and trainee competence.', 'ORA.ATO.130 - Training Manual and Operations Manual', NULL, '2026-01-05', '2026-02-20', NULL, 1, '2026-01-05 01:12:29', '2026-01-06 03:05:48', 'A', 'QUICK', NULL),
(X'ABD6FC66CA024679B1ABE3B16CBF570F', X'F16EFB564C7D46589BADB7E7B1403F74', 'BCAA.ATO.NC.333', 'Application of ADDIE Framework', 'LEVEL_2', 'OPEN', 'MEDIUM', 'The General Training Manual describes in chapter 2.1 that the ATO uses the ADDIE framework (GM5 ORA.ATO.230(a) Training manual and operations manual) as a systematic and iterative process for course design. \nHowever, during the audit, the ATO was not able to provide evidence this process is used to develop and evaluate the course on a regularly base.\nWithout documented evidence of applying the ADDIE framework or similar process, there is a risk that courses may not be systematically designed or regularly evaluated. This could lead to outdated content, reduced training effectiveness, and non-compliance with internal quality standards or regulatory requirements.', 'ORA.ATO.230(a) - Training Manual and Operations Manual (ADDIE)', NULL, '2026-01-05', '2026-02-20', NULL, 1, '2026-01-05 01:01:19', '2026-01-06 02:58:04', 'B', 'RECOMMENDED', 'GM5 ORA.ATO.230(a)\nAbout design, implement, and continuously improve its training programs using the ADDIE instructional systems design framework.\nAnalysis → Design → Development → Implementation → Evaluation.\n\nPHASE 1 - Analysis\nPurpose: Define the training need.\n\nGM intent:\n- Identify training objectives\n- Identify target population (entry level, prerequisites)\n- Identify regulatory requirements (Part-FCL, ACS, syllabus)\n- Identify training environment (aircraft, FSTD, instructors)\n\nTypical evidence:\n- Training Needs Analysis (TNA)\n- Entry conditions\n- Regulatory mapping (ACS / syllabus cross-refs)\n\nPHASE 2 - Design\nPurpose: Plan how training will achieve the objectives.\n\nGM intent:\n- Define learning objectives (knowledge, skill, attitude)\n- Structure the training sequence\n- Define assessment methods\n- Allocate hours, media, and instructors\n\nTypical evidence:\n- Syllabus structure\n- Phase breakdown\n- Exercise objectives\n- Assessment strategy\n\nPHASE 3 - Development\nPurpose: Create the training content.\n\nGM intent:\n- Produce lesson plans\n- Develop training material\n- Develop exam questions / checks\n- Prepare instructor guidance\n\nTypical evidence:\n- Lesson plans\n- Briefing notes\n- CBT modules\n- Instructor guides\n\nPHASE 4 - Implementation\nPurpose: Deliver the training.\n\nGM intent:\n- Conduct training as designed\n- Ensure instructors are qualified and standardised\n- Apply record-keeping and progress tracking\n\nTypical evidence:\n- Student training records\n- Instructor sign-offs\n- Training schedules\n- Standardisation records\n\nPHASE 5 - Evaluation\nPurpose: Verify effectiveness and improve.\n\n(This is the most important part for EASA, the feedback loop is closed)\n\nUse:\n- Student performance data\n- Exam results\n- Instructor feedback\n- Safety / compliance findings\n\nFeed results back into:\n- Syllabus updates\n- Lesson plan improvements\n- Instructor standardisation\n\nTypical evidence:\n- Pass/fail trend analysis\n- Course reviews\n- Corrective actions\n- Revised training material\n\nNOTE: GM5 does NOT require:\n\n- A document titled “ADDIE Report”\n- Separate files for each ADDIE phase\n- Paper documentation\n- A specific format or template'),
(X'B785B728C2BF42DDA9BD48B97A02B37F', X'F16EFB564C7D46589BADB7E7B1403F74', 'BCAA.ATO.NC.339', 'EASA PPL Theoretical Knowledge Learning Objectives', 'OBSERVATION', 'OPEN', 'LOW', 'The BCAA has published the required learning objectives for the PPL(A) theoretical knowledge course on its website. \nHowever, the ATO was unable to provide evidence that its training program fully incorporates all of these published learning objectives.', 'ORA.ATO.230 - Training Manual and Operations Manual', NULL, '2026-01-05', '2026-02-20', NULL, 1, '2026-01-05 01:15:57', '2026-02-12 02:34:08', 'A', 'QUICK', 'The BCAA has published a detailed document with the PPL(A) learning objectives. This was the initiative of the Competent Authority (not EASA). However, in order to review the accuracy of our Training Materials it is advisable to check the content in depth and cross reference it.'),
(X'C9D8DB298E3D43B9B948D7A1803F665E', X'F16EFB564C7D46589BADB7E7B1403F74', 'BCAA.ATO.NC.331', 'Deputy Head of Training Position Not Assigned', 'LEVEL_2', 'OPEN', 'HIGH', 'The ATO EPC management system specifies a Deputy Head of Training position intended to support the Head of Training in all\nduties and to assume these responsibilities during the Head of Training’s absence, such as during training activities conducted\nin the United States. However, at the time of the audit, the individual assigned to this deputy role was no longer employed by\nthe organisation, and no replacement had been designated.', 'ORA.ATO.110 Personnel requirements', 'OMM4.0|P3|55|2', '2025-12-31', '2026-02-20', NULL, 1, '2025-12-31 01:33:48', '2026-01-06 03:22:22', 'B', 'RECOMMENDED', 'Note about what is happening.'),
(X'D46FF0515C6D48F9B2A09E46F20130D2', X'F16EFB564C7D46589BADB7E7B1403F74', 'BCAA.ATO.NC.330', 'AM Addendum - Economic Leverage & Limitations', 'LEVEL_2', 'OPEN', 'MEDIUM', 'The Accountable Manager (AM), Mrs. Maria Paz, has been designated by E-Guided Learning Experience through an agreement titled “Addendum – Economic Leverage & Limitations”. However, this agreement does not adequately reflect the responsibilities required of the AM under EASA regulations. Specifically, it does not include:\n\n1. Direct safety accountability as required by ORA.GEN.200(a)(1);\n2. Authority to ensure that all activities can be financed and carried out in accordance with applicable requirements (ORA.GEN.210 (a));\n3. Responsibility for establishing and maintaining an effective management system ORA.GEN.210 (a)).', 'ORA.GEN.210 Personnel requirements', NULL, '2025-12-31', '2026-02-20', NULL, 1, '2025-12-31 01:32:03', '2026-01-06 02:47:47', 'A', 'QUICK', NULL),
(X'DCB15885FFFF4D81A2212B2847718850', X'F16EFB564C7D46589BADB7E7B1403F74', 'BCAA.ATO.NC.334', 'Visibility of Just Culture Policy', 'LEVEL_2', 'OPEN', 'LOW', 'The ATO has developed a safety policy that incorporates just culture principles. \nHowever, the policy is not sufficiently visible or endorsed in operational areas as required by AMC1 ORA.GEN.200(a)(2) (a) (3). \nDuring the audit, it was observed that the policy is only displayed on the wall in one room and is not prominently visible when entering the hangar. Insufficient visibility and endorsement of the safety policy may lead to reduced awareness among personnel, weakening the organizations safety culture. \nThis could result in inconsistent application of just culture principles and increase the likelihood of safety-related incidents or non-compliance with regulatory expectations.', 'ORA.GEN.200 - Management System', NULL, '2026-01-05', '2026-02-20', NULL, 1, '2026-01-05 01:04:06', '2026-01-06 02:09:29', 'B', 'RECOMMENDED', 'Checklist in Garmin e-format.'),
(X'E93535E8557341C7A9F6BD54B0AF689C', X'F16EFB564C7D46589BADB7E7B1403F74', 'BCAA.ATO.NC.335', 'Listing of Flight Instructor Qualifications (UPRT and US Ops)', 'LEVEL_2', 'OPEN', 'LOW', 'Annex 16 (16/04/2025) of the EuroPilot Center Organization Management Manual (OMM) lists all flight instructors providing training within the ATO EPC, and specifies the courses they deliver. However, the list does not include:\n\n- Flight instructors qualified to provide flight training for the Advanced UPRT course.\n- Information on which instructors are trained to provide training in the United States.', 'ORA.GEN.130 - Changes to organisations', NULL, '2026-01-05', '2026-02-20', NULL, 1, '2026-01-05 01:06:45', '2026-01-06 02:19:51', 'A', 'QUICK', 'Kay has to ad this to the scheduling system so the Instructor Qualifications are periodically auto-verified. This will ensure compliance. It should be expanded to Medical and License updates as well, so we always have the latest version and do not have to manually ask for it. It can even be extended to students as well (including graduated students).'),
(X'F301FCF46843437C9C6635135040ACFE', X'F16EFB564C7D46589BADB7E7B1403F74', 'BCAA.ATO.NC.332', 'Paperless operations and documentation', 'LEVEL_2', 'OPEN', 'MEDIUM', 'The procedures described in the ATO’s manuals for the PPL training program still refer to the use of a paper-based student training folder. However, in practice, student training files are maintained exclusively in electronic format. Although the ATO was able to provide all required training records during the audit, the use of electronic student files is not reflected or described in the approved procedures.', 'ORA.GEN.130 - Changes to organisations', NULL, '2026-01-05', '2026-02-20', NULL, 1, '2026-01-05 00:58:43', '2026-01-06 02:35:55', 'A', 'QUICK', '1. AMC1 ORA.ATO.120 – Record-keeping\nThis AMC explicitly allows electronic systems, provided they ensure:\na) Traceability, b) Data integrity, c) Protection against unauthorized modifications, and d) Availability to the competent authority upon request.\nRecords may be kept in electronic format, provided that adequate backup, access control, and data protection measures are in place.\n\n2. AMC1 ORA.ATO.120(a) and (b)\nStudent progress records (progress cards, training files, etc.): May be maintained electronically, Instructor “signatures” may be: digital signatures, authenticated logins, traceable user actions. No requirement exists for handwritten signatures or physical binders.');
INSERT INTO `manual_excerpts` (`excerpt_id`, `manual_code`, `manual_rev`, `manual_part`, `section_ref`, `title`, `text`, `source_file`, `sha256`, `excerpt_id_norm`) VALUES
('OM6_P0_0.1', 'OM', '6.0', 0, '0.1', 'LIST OF EFFECTIVE PARTS', '0.1 LIST OF EFFECTIVE PARTS\n\nEuroPilot Center’s nominated persons certify that the content of this Operations Manual complies with all applicable EASA PART-FCL and PART-NCO requirements.\n\nOn behalf of EuroPilot Center:\n\nAccountable Manager: Maria A. Paz\nDate: 07-01-2023\n\nCompliance Monitoring Manager: Koen Maes\nDate: 09-01-2023\n\nEffective Parts:\n\nPart 0 – Pages 1–18 – Date: 09-01-2023 – Revision 6\nPart 1 – Pages 1–38 – Date: 09-01-2023 – Revision 6\nPart 2 – Pages 1–35 – Date: 09-01-2023 – Revision 6\nPart 3 – Pages 1–35 – Date: 09-01-2023 – Revision 6\nPart 4 – Pages 1–13 – Date: 09-01-2023 – Revision 6', 'OM_REV_6.0_CANONICAL_PART_0.txt', '8430e80b38e9731dae01b8a378e0b94bf063cdbdd38662aff0e2b4428692af44', 'OM6_P0_0_1'),
('OM6_P0_0.2', 'OM', '6.0', 0, '0.2', 'REVISION SYSTEM', '0.2 REVISION SYSTEM\n\nThe EuroPilot Center Operations Manual and its amendments are proposed, drafted, issued, and after a BCAA spot check, accepted and implemented by the Head of Training.\n\nThe Compliance Monitoring Manager ensures that the content of the Training Manual complies with all applicable regulations and requirements.\n\nAny amendment proposal by the Head of Training shall be executed by sending an email to the Compliance Monitoring Manager and the Accountable Manager. The email shall include the revised draft of the applicable manual, section or paragraph, and the reason(s) for the amendment.\n\nUpon verification by the Compliance Monitoring Manager, the amendment will be submitted to the BCAA.\n\nAll amendments shall be accompanied by an updated List of Effective Parts, identification of changes by a vertical bar placed in front of the amended text, and a Highlight of Changes paragraph published as part of this manual.\n\nDigital, password-protected PDF versions of the Operations Manual may be distributed and marked as “Uncontrolled Copy”. These files are protected against printing.\n\nNote: A Temporary Revision Procedure is not applicable within EuroPilot Center B/ATO-017.', 'OM_REV_6.0_CANONICAL_PART_0.txt', 'e779e32eda10ed4e538cce65c2d864bbee0a073c1f45709c0eb2f37ed2866617', 'OM6_P0_0_2'),
('OM6_P0_0.3', 'OM', '6.0', 0, '0.3', 'AMENDMENT LIST', '0.3 AMENDMENT LIST\n\nRETAIN SHEET UNTIL REPLACED WITH NEW ISSUE\n\nRevision: Original\nReason: First issue of OM\nRevision Date: 01-07-2013\nEffective Date: 01-09-2013\nDate Incorporated: 01-09-2013\nIncorporated By: KAY\n\nRevision: Rev 1\nReason: Amendment 1\nRevision Date: 30-06-2017\nEffective Date: 15-07-2017\nDate Incorporated: 30-06-2017\nIncorporated By: KAY\n\nRevision: Rev 2\nReason: Amendment 2\nRevision Date: 31-08-2019\nEffective Date: 09-09-2019\nDate Incorporated: 31-08-2019\nIncorporated By: KAY\n\nRevision: Rev 3\nReason: Amendment 3\nRevision Date: 18-04-2022\nEffective Date: 28-04-2022\nDate Incorporated: 28-04-2022\nIncorporated By: KOEN M\n\nRevision: Rev 4\nReason: Amendment 4\nRevision Date: 28-07-2022\nEffective Date: 08-08-2022\nDate Incorporated: 08-08-2022\nIncorporated By: KAY\n\nRevision: Rev 5\nReason: Amendment 5 / CAA Remarks\nRevision Date: 18-12-2022\nEffective Date: 19-12-2022\nDate Incorporated: 19-12-2022\nIncorporated By: KAY\n\nRevision: Rev 6\nReason: Amendment 6 / CAA Remarks\nRevision Date: 09-01-2023\nEffective Date: 19-01-2023\nDate Incorporated: 19-01-2023\nIncorporated By: STEF', 'OM_REV_6.0_CANONICAL_PART_0.txt', '6e0e14f2dc17d4349ee55ed4d24248dc8d34c8177d7e462e33d6948c8aa3b0d0', 'OM6_P0_0_3'),
('OM6_P0_0.4', 'OM', '6.0', 0, '0.4', 'DISTRIBUTION LIST', '0.4 DISTRIBUTION LIST\n\nCopy No. 0 – Master Copy\nCopy No. 1 – BCAA Training Department (Signed Digital PDF)\nCopy No. 2–9 – Not assigned\nCopy No. 10–30 – Not assigned', 'OM_REV_6.0_CANONICAL_PART_0.txt', 'a4afd56caed623dc0225b0e44bffb89bf30ff74722698a112fa4b567563c5340', 'OM6_P0_0_4'),
('OM6_P0_0.5', 'OM', '6.0', 0, '0.5', 'INDEX OF ABBREVIATIONS', '0.5 INDEX OF ABBREVIATIONS\n\nA/C – Aircraft\nAMC – Acceptable Means of Compliance\nATO – Approved Training Organisation\nBCAA – Belgian Civil Aviation Authority\nCFI – Chief Flight Instructor\nCTKI – Chief Theoretical Knowledge Instructor\nEASA – European Union Aviation Safety Agency\nFSTD – Flight Simulation Training Device\nPIC – Pilot-in-Command\nSPIC – Student Pilot-in-Command\nTM – Training Manual\nUTC – Universal Time Coordinated\nVFR – Visual Flight Rules\nIFR – Instrument Flight Rules', 'OM_REV_6.0_CANONICAL_PART_0.txt', '35afc0a8d93f41940395256add497a20bad801256edfbbf73598be71a7bc2b1c', 'OM6_P0_0_5'),
('OM6_P0_0.6', 'OM', '6.0', 0, '0.6', 'DEFINITIONS AND TERMS', '0.6 DEFINITIONS AND TERMS\n\nAerobatic flight: Intentional manoeuvres involving abrupt attitude changes not required for normal flight or instruction.\nAircraft: Any machine that can derive support in the atmosphere from the reactions of the air.\nFlight time: Total time from the moment an aircraft first moves for the purpose of taking off until the moment it finally comes to rest at the end of the flight.\nInstrument flight time: Time during which a pilot controls an aircraft solely by reference to instruments.\nPilot-in-Command (PIC): The pilot designated as responsible for the safe conduct of the flight.\nStudent Pilot-in-Command (SPIC): A student pilot acting as pilot-in-command under the supervision of a flight instructor.', 'OM_REV_6.0_CANONICAL_PART_0.txt', 'ba4a5c82fb1af915e1dcc6e57ac3db1f83215feb90d46376eb6e87c9a1c62e65', 'OM6_P0_0_6'),
('OM6_P0_0.7', 'OM', '6.0', 0, '0.7', 'HIGHLIGHT OF CHANGES', '0.7 HIGHLIGHT OF CHANGES\n\nRevision 6 – Key Changes:\n\nRemoval of R44 references\nUpdate of FAA Repair Station subcontractor\nUpdates to Part 2 (Technical) regarding MEL, defect reporting, and EFB usage\nUpdates to Part 3 (Route) for Weather, NOTAMs, and Mass and Balance via EFB\nUpdates to Part 4 (Personnel Training), including KSA.100 Training\nOM Annex 16 updated\n\nEND OF PART 0 – CANONICAL TEXT', 'OM_REV_6.0_CANONICAL_PART_0.txt', '05f605a8d6fb573647d5a611125ae2906277ddc30ac3e14a483d83c8565fad4b', 'OM6_P0_0_7'),
('OM6_P1_1.1', 'OM', '6.0', 1, '1.1', 'Preliminaria', '1.1 Preliminaria\n\nEuroPilot Center is an Approved Training Organization, staffed, equipped and operated in a suitable environment offering Flight Training, Synthetic Flight Training and Theoretical Knowledge Training for:\n	•	Modular IR(A), Single Engine, Multi-Engine\n	•	Theoretical Course ATPL(A)\n	•	Modular Multi-Engine Piston Class Rating Airplanes, MEP(L)\n	•	Flight Instructor Airplanes\n	•	Flight Instructor Upgrade to Instrument Rating Instructor, FI(A) with privileges to instruct IR(A)\n	•	Instrument Rating Instructor, IRI(A)\n	•	Class Rating Instructor, CRI(A)\n	•	Commercial Pilot License, CPL(A)\n	•	VFR Night Rating, NQ\n	•	Theoretical Knowledge Course, PPL(A)\n	•	Private Pilot License, PPL(A)\n	•	UPRT and UPRT Instructor\n	•	MCC, APS/MCC including MCCI', 'OM_REV_6.0_CANONICAL_PART_1.txt', 'f10c4717af3338979bab1a56ce5c13ec4fd87a1925f758f48aa02fa245cecd9f', 'OM6_P1_1_1'),
('OM6_P1_1.1.1', 'OM', '6.0', 1, '1.1.1', 'Principal Place of Business', '1.1.1 Principal Place of Business\n\nEuroPilot Center\nLuchthavenlei EPC Building Box 210\nB-2100 Antwerp – Belgium\nPhone: +32 (0)3 281 84 29', 'OM_REV_6.0_CANONICAL_PART_1.txt', '4520a4a1a899ebdafd134291fdccbfb809bb15abd380e33fab0602ee13fac8b4', 'OM6_P1_1_1_1'),
('OM6_P1_1.1.2', 'OM', '6.0', 1, '1.1.2', 'Training Locations', '1.1.2 Training Locations\n\nMain Training Location:\nAntwerp, Belgium (EBAW)\n\nEuroPilot Center\nLuchthavenlei EPC Building Box 210\nB-2100 Antwerp – Belgium\nPhone: +32 (0)3 281 84 29\n\nSatellite Training Location:\nThermal, California USA (KTRM)\n\nEuroPilot Center doing business as SoCal Pilot Center\n56-850 Higgins Drive\nHangars 026 and 027 along Avenger Blvd\nCA 92274 Thermal\nPhone: +1 (0)760 238 0209\nPhone: +1 (0)760 989 4525', 'OM_REV_6.0_CANONICAL_PART_1.txt', '89a458cd80d3f7b56429846615e845625d9d0aa2c3765bcc41b27b300d8106d5', 'OM6_P1_1_1_2'),
('OM6_P1_1.2', 'OM', '6.0', 1, '1.2', 'Content of the Operations Manual', '1.2 Content of the Operations Manual\n\nThe Operations Manual consists of the following parts:\n	•	Part 0 – Manual Administration\n	•	Part 1 – General\n	•	Part 2 – Technical\n	•	Part 3 – Route\n	•	Part 4 – Personnel Training\n\nA copy of the Operations Manual (and all its amendments and revisions) will be provided to the BCAA.', 'OM_REV_6.0_CANONICAL_PART_1.txt', '32a2ccee0ab8ca30b203f50124c1e9b0f2c5c00c904d9e4957c5cd34a38b573a', 'OM6_P1_1_2'),
('OM6_P1_1.3', 'OM', '6.0', 1, '1.3', 'Draft and Issue', '1.3 Draft and Issue\n\nThe EuroPilot Center Operations Manual is drafted and issued by the Head of Training.', 'OM_REV_6.0_CANONICAL_PART_1.txt', '7161093cfcec6b83e519270268ec895f742398d391b2bb5b64b8310e662dba0e', 'OM6_P1_1_3'),
('OM6_P1_1.4', 'OM', '6.0', 1, '1.4', 'Language', '1.4 Language\n\nThe EuroPilot Center Operations Manual has been drafted in the English language.\n\n\n\n2. ORGANIZATION AND RESPONSIBILITIES', 'OM_REV_6.0_CANONICAL_PART_1.txt', '5684032bb2c88033cc9d68e514c7ac0c552611a2f0cdfb6bf69ce4b563dd64bf', 'OM6_P1_1_4'),
('OM6_P1_2.1', 'OM', '6.0', 1, '2.1', 'Structure of the ATO', '2.1 Structure of the ATO', 'OM_REV_6.0_CANONICAL_PART_1.txt', 'dbb3a39477365a82bcf459601b2ae10e787433c7fb102524d1a65e1014cd1702', 'OM6_P1_2_1'),
('OM6_P1_2.1.1', 'OM', '6.0', 1, '2.1.1', 'Management and Staff', '2.1.1 Management and Staff\nEuroPilot Center employs sufficient in number, experienced and qualified managers in accordance with AMC1 ORA.ATO.210 – Personnel requirements.\n\nThe Management and Staff are:\n	•	Accountable Manager: Mrs. Maria Paz\n	•	Chief Operations Officer: Mr. Stef Van De Sompele\n	•	ATO Safety Manager: Mr. Jasper De Hertog\n	•	ATO Compliance Monitoring Manager: Mr. Stef Van De Sompele\n	•	ATO Compliance Monitoring Auditor: Mr. Glenn Crab\n	•	FSTD Compliance Monitoring Manager: Mr. Koen Maes\n	•	FSTD Compliance Monitoring Auditor: Mr. Glenn Crab / Mr. Stef Van De Sompele\n	•	FSTD Manager: Mr. Koen Maes\n	•	Head of Training (BE): Mr. Koen Maes\n	•	Deputy Head of Training (US): Mr. Jasper De Hertog\n	•	Chief Flight Instructor: Mr. Lieven Gijsels\n	•	Chief Theoretical Knowledge Instructor: Mr. Jasper De Hertog\n	•	Continuous Airworthiness Manager: Mr. Michael De Vestel\n	•	Accountant: Mr. Tom Debudt\n	•	Facility Manager: Mr. Stef Van De Sompele\n	•	IT Manager: Mr. Thierry Leysen', 'OM_REV_6.0_CANONICAL_PART_1.txt', '4198c92c5de97f53a6922a8b8d49f28ca50d6df278bf2b6eb4584e0df411b10e', 'OM6_P1_2_1_1'),
('OM6_P1_2.1.2', 'OM', '6.0', 1, '2.1.2', 'Organogram', '2.1.2 Organogram\nReference is made to OM Annex 35 – Organogram Revision 3.0.', 'OM_REV_6.0_CANONICAL_PART_1.txt', 'c27a957c7e1f1d170616f6bbbc5ba703c8a6a1b52e33f64201aaac5dd47729b6', 'OM6_P1_2_1_2'),
('OM6_P1_2.2', 'OM', '6.0', 1, '2.2', 'Responsibilities', '2.2 Responsibilities', 'OM_REV_6.0_CANONICAL_PART_1.txt', '3d2f2ae94519109f8207a91ca3438dcf1d05205668b94631f62864d37ffe388a', 'OM6_P1_2_2'),
('OM6_P1_2.2.1', 'OM', '6.0', 1, '2.2.1', 'Accountable Manager', '2.2.1 Accountable Manager\nThe Accountable Manager is the person acceptable to the BCAA. He or she has corporate authorities for ensuring that all training activities can be financed and carried out to the standards determined by the Authorities.\n\nHe or she defines the intent of the Compliance Monitoring System and has the overall responsibility for the efficient function of the system.\n\nNote 1: Physical presence of the Accountable Manager on a daily basis is not required when the Chief Operations Officer is present or when either one of the Operations Officers are present.\nNote 2: Reference is made to the addendum “Economic Leverage & Limitations between E-Guided Learning Experience and the Accountable Manager”, outlining financial power and restrictions.', 'OM_REV_6.0_CANONICAL_PART_1.txt', 'e7a8cf3a8e8711150f274346aaa6cd3b2ae6ca3dbad8a8d51580693e07dfa7cd', 'OM6_P1_2_2_1'),
('OM6_P1_2.2.10', 'OM', '6.0', 1, '2.2.10', 'FSTD Management', '2.2.10 FSTD Management\n\nFSTD Compliance Monitoring Manager\nThe duties and responsibilities of the FSTD Compliance Monitoring Manager are identical to those of the Compliance Monitoring Manager as described in the Organization Management Manual (OMM), Part 2, Chapter 3.2 – Duties and Responsibilities, but restricted to FSTD operations only.\n\nFSTD Manager\nThe FSTD Manager is the person appointed by the Accountable Manager. He/She is responsible for daily FSTD operations, including (non-limitative list):\n\nFSTD supervision.\nFSTD maintenance (including FSTD Maintenance Reports).\nFSTD calibrations.\nExecution of quarterly QTG tests.\nScheduling yearly internal subjective evaluation.\nCertification documents.\nTidiness.\nAvionics updates.\nKeeping checklists and software up-to-date.\nFollow-up on FSTD trouble report items.\nFSTD phone support.\nFSTD installation and relocation.', 'OM_REV_6.0_CANONICAL_PART_1.txt', 'ffd788ca48d297e406b52e618519a8faf60a31074f4b2eb56f2cfc45b23106ee', 'OM6_P1_2_2_10'),
('OM6_P1_2.2.11', 'OM', '6.0', 1, '2.2.11', 'Continuous Airworthiness Manager', '2.2.11 Continuous Airworthiness Manager\n\nThe duties and responsibilities of the Continuous Airworthiness Manager are to ensure that (non-limitative list):\n\nAll aircraft are maintained in an airworthy condition.\nAny operational and emergency equipment fitted is correctly installed and serviceable or clearly identified as unserviceable.\nThe airworthiness certificate remains valid.\nThe maintenance of the aircraft is performed in accordance with the approved maintenance program as specified in EASA Part-M, MA.302.', 'OM_REV_6.0_CANONICAL_PART_1.txt', 'c85151ad3e4b9e648982b43a0a88149ece45a5ebf6a1bc5af3a06eaf16621190', 'OM6_P1_2_2_11'),
('OM6_P1_2.2.12', 'OM', '6.0', 1, '2.2.12', 'Accountant', '2.2.12 Accountant\n\nThe duties and responsibilities of the accountant are (non-limitative list):\n\nPrepares asset, liability, and capital account entries by compiling and analyzing account information.\nDocuments financial transactions by entering account information.\nRecommends financial actions by analyzing accounting options.\nSummarizes current financial status by collecting information and preparing balance sheet, profit and loss statement, and other reports.\nSubstantiates financial transactions by auditing documents.\nMaintains accounting controls by preparing and recommending policies and procedures.\nGuides accounting clerical staff by coordinating activities and answering questions.\nReconciles financial discrepancies by collecting and analyzing account information.\nSecures financial information.\n\nThe accountant reports to the Accountable Manager on a weekly basis.', 'OM_REV_6.0_CANONICAL_PART_1.txt', '7730696aa5a8fdf332d2f764bc01d2e78e19c9d87885d948633f26ff4ddfcd22', 'OM6_P1_2_2_12'),
('OM6_P1_2.2.13', 'OM', '6.0', 1, '2.2.13', 'IT Manager', '2.2.13 IT Manager\n\nManaging information technology and computer systems and building maintenance items.\n\nThe duties and responsibilities of the IT Manager are (non-limitative list):\n\nThe general IT infrastructure including computers, iPads, printers and phone.\nBuilding access and building security.\nPassword management.\nFiles and folders.\nDropbox.\nRestarting and resetting services.\nNetwork connections, modem, internet services.\nBackup systems.\nE-mail communications and e-mail servers.\nWeb servers.\nRemote access.\nReplacing batteries of mouse, keyboard, remote control, smoke detectors and flashlights.\nAircraft cleaning.\nAvionics updates.\n\nThe IT Manager reports to the Operations Officer on a regular basis.', 'OM_REV_6.0_CANONICAL_PART_1.txt', '8e3a177cfa794d3282c88f7cd10fbd3b23af8baf61d7984f1e29bee664f51d7f', 'OM6_P1_2_2_13'),
('OM6_P1_2.2.14', 'OM', '6.0', 1, '2.2.14', 'Facility Manager', '2.2.14 Facility Manager\n\nThe Facility Manager is responsible for (non-limitative list):\n\nAccepting incoming deliveries and shipments.\nAssistance in basic administrative tasks.\nBuilding maintenance and cleanliness.\nAppliances.\nMailbox.\nBuilding consumables.\nCleaning.\nGarbage.\n\nThe Facility Manager reports to the Operations Officer on a regular basis.', 'OM_REV_6.0_CANONICAL_PART_1.txt', 'e802b6445a4bea038394ec5b1da2caaec023943263384880ac811e617641b464', 'OM6_P1_2_2_14'),
('OM6_P1_2.2.15', 'OM', '6.0', 1, '2.2.15', 'Subcontracted Training', '2.2.15 Subcontracted Training\n\nNot applicable.\n\n3. STUDENT DISCIPLINE', 'OM_REV_6.0_CANONICAL_PART_1.txt', '2f7ad81f33d48aac9fec998c3883d6250bfda47ef00855e46d81734b4f156afe', 'OM6_P1_2_2_15'),
('OM6_P1_2.2.2', 'OM', '6.0', 1, '2.2.2', 'Chief Operations Officer', '2.2.2 Chief Operations Officer\n\nThe Chief Operations Officer is accountable for the administration, ground and flight operations, and will oversee the work of the Operations Officer(s).\n\nThe Chief Operations Officer is responsible for (non-limitative list):\n\nInvoicing.\nFollow up of student financial balance sheets.\nExecution of all incoming and outgoing payments.\nBookkeeping.\nFollow up on insurances.\nUpdating website, online calendar etc.\nEvent planning and organization.\nActive prospection.\nPrice quotes.\nLong-term training schedule (Flight Training and Theoretical Knowledge Training).\nOrganizing of meetings, teleconferences.\nPilot shop, sales and stock follow up.\nPlacing of orders.\n\nThe Chief Operations Officer reports to the Accountable Manager on a weekly basis.\n\nNote: Physical presence of the Chief Operations Officer on a daily basis is not required when either one of the Operations Officers is present.', 'OM_REV_6.0_CANONICAL_PART_1.txt', 'baaf41d64ed59b9eb9eedd8ddd83ab0c5f971c9a85792654ef340d289e98cea6', 'OM6_P1_2_2_2'),
('OM6_P1_2.2.3', 'OM', '6.0', 1, '2.2.3', 'Operations Officer', '2.2.3 Operations Officer\n\nThe Operations Officer is responsible for the day-to-day operations of EuroPilot Center and reports on a daily basis to the Chief Operations Officer. His/her responsibilities are:\n\nDaily opening & closing of the school.\nTaking care of prospects (phone, visit, e-mail).\nSupporting students.\nSupporting of instructors and examiners.\nSupporting of the Management.\nHandling Sales.\nAccepting deliveries.\nE-mail management.\nStudent Admission.\nIndividual Student Training File follow-up.\nContract Management.\nPreparing Skill test forms/Application forms/BCAA forms for the Head of Training.\nFollow up on Insurances.\nCustomer service, satisfaction and follow-up.\nBasic Facility Management related tasks (Building access, basic building maintenance, appliance and mailbox, cleaning and garbage) in cooperation with the Facility Manager.\nBasic IT Management related tasks in cooperation with the IT manager.\nAdministering Internal Exams to students.\nAssisting the Chief Theoretical Knowledge Instructor on student follow up (Theoretical Knowledge Training).\nAssisting the Chief Flight Instructor on student follow up (Flight Training).\nPerforming Airline Candidate Screenings.\nPerforming Airline Assessments/Screening.\nMaths and Physics Prep courses.\nSimulator Subscriptions.\nBe The Pilot Sessions (Introduction Flights).\nMarketing related tasks (Updating website, social media, printed media, e-mail campaigns, market research, press-releases, events, prospecting, preparation of price quotes).\nShort-term Training Schedule (Flight Training and Theoretical Knowledge Training).\nOrganizing of meetings, teleconferences.\nPilot Shop, Sales and stock follow up.\nPreparing orders.\nAircraft and FSTD maintenance follow-up.\nProviding Simulator Support in cooperation with the FSTD manager.\nCleanliness of the Aircraft (scheduling).', 'OM_REV_6.0_CANONICAL_PART_1.txt', '7391a88b8454b4149135cf079f66483e0d7a00e616eb3719a4c51b0e0ec8a3d3', 'OM6_P1_2_2_3'),
('OM6_P1_2.2.4', 'OM', '6.0', 1, '2.2.4', 'Head of Training', '2.2.4 Head of Training\n\nThe Head of Training is the person acceptable to the BCAA. He/She is responsible for all aspects of the training organized by the ATO. He/She holds the required qualifications in accordance with AMC2 ORA.ATO.210 – Personnel requirements.\n\nThe Head of Training shall have extensive flight training experience and holds sound managerial capabilities as follows:\n\nAt least 1,500 hours of Flight Time as Pilot In Command; and\nAt least 2 years of experience on instructional duties (as TKI, FI(A) and/or CRI); and\nAt least 1 year of experience in a managerial role (Aviation or non-aviation related);\nAt least 500 hours on flying instructional duties (as FI(A) or CRI), of which 250 hours may be Instrument Ground Time.\n\nHis/Her responsibilities include:\n\nTheoretical knowledge training.\nFlight Training.\nSynthetic Flight Training.\nIndividual Student Training File (Assisted by Operations Officers).\nApplications for Skill tests, proficiency checks and Theoretical Knowledge Exams (Assisted by the Operations Officers).\nSupervision of students, progress and periodical evaluations (Assisted by Chief Flight Instructor, Chief Theoretical Knowledge Instructor and Operations Officer).\nPerforming Airline Assessments/Screening (Assisted by the Operations Officers).\nAircraft and FSTD maintenance follow-up (Assisted by the Operations Officers).\nApproval of individual training programs (Assisted by the Deputy Head of Training).\nMonitoring the Chief Theoretical Knowledge Instructor and Chief Flight Instructor.\n\nNote 1: In order to facilitate communication between the Head of Training and the nominated Deputy Head of Training at all other approved Training Locations, EuroPilot Center has implemented an electronic Progress Follow-up system, making live tracking of Student Progress possible, regardless of the training location. In addition, weekly video calls are performed to discuss student progress.\n\nNote 2: Physical presence of the Head of Training on a daily basis is not required when the Deputy Head of Training is present.', 'OM_REV_6.0_CANONICAL_PART_1.txt', '461a8f384653b2fdce6735443693db0371bd8a9c11b121a0316e2a09fc8c9c35', 'OM6_P1_2_2_4'),
('OM6_P1_2.2.4.1', 'OM', '6.0', 1, '2.2.4.1', 'Deputy Head of Training', '2.2.4.1 Deputy Head of Training\n\nThe Deputy Head of Training assists the Head of Training in all tasks and resumes his responsibilities when not physical present (e.g. at a different approved training location) with the purpose to guarantee compliance with the personnel requirements. He holds all required qualifications in accordance with AMC2 ORA.ATO.210 – Personnel requirements.\n\nThe Deputy Head of Training shall have extensive flight training experience and holds sound managerial capabilities as follows:\n\nAt least 1,000 hours of Flight Time as Pilot In Command; and\nAt least 1 years of experience on instructional duties (as TKI, FI(A) and/or CRI); and\nAt least 1 year of experience in a managerial role (Aviation or non-aviation related);\nAt least 300 hours on flying instructional duties (as FI(A) or CRI), of which 150 hours may be Instrument Ground Time.', 'OM_REV_6.0_CANONICAL_PART_1.txt', '74dbacc638639d2b2a9673ac7ba0917ecd07cb67b22748d8082e35043206a393', 'OM6_P1_2_2_4_1'),
('OM6_P1_2.2.5', 'OM', '6.0', 1, '2.2.5', 'Chief Flight Instructor', '2.2.5 Chief Flight Instructor\n\nThe Chief Flight Instructor is the person acceptable to the BCAA. He/She holds all required qualifications in accordance with AMC2 ORA.ATO.210 – Personnel requirements.\n\nHis/Her responsibilities include:\n\nFlight Training.\nSynthetic Flight Training.\nSupervision of students, progress and periodical evaluations (Assisted by the Operations Officer).\nPerforming Airline Assessments/Screening (Assisted by the Operations Officer).\nMonitoring Flight Instructors.\n\nNote: Physical presence of the Chief Flight Instructor on a daily basis is not required but he/she should be contactable within a reasonable timeframe.', 'OM_REV_6.0_CANONICAL_PART_1.txt', '6d95e979a0cb6a02cd0a5e63054fb268391b402c304f359a7c12b2254857f257', 'OM6_P1_2_2_5'),
('OM6_P1_2.2.6', 'OM', '6.0', 1, '2.2.6', 'Chief Theoretical Knowledge Instructor', '2.2.6 Chief Theoretical Knowledge Instructor\n\nThe Chief Theoretical Knowledge Instructor is the person acceptable to the BCAA. He/She holds all required qualifications in accordance with AMC2 ORA.ATO.210 – Personnel requirements.\n\nHis/Her responsibilities include:\n\nTheoretical knowledge training.\nSupervision of students, progress and periodical evaluations (Assisted by the Operations Officer).\nAdministering Internal Exams to students (Assisted by the Operations Officer).\nPerforming Airline Assessments/Screening (Assisted by the Operations Officer).\nMaths and Physics Prep courses (Assisted by the Operations Officer).\nMonitoring Theoretical Knowledge Instructors.\n\nNote: Physical presence of the Chief Theoretical Knowledge Instructor on a daily basis is not required but he/she should be contactable within a reasonable timeframe.', 'OM_REV_6.0_CANONICAL_PART_1.txt', '5399608dc937b84f0ebe7bd621fd8a0cb480518d1912e46e578f174fa82e0554', 'OM6_P1_2_2_6'),
('OM6_P1_2.2.7', 'OM', '6.0', 1, '2.2.7', 'Training Staff', '2.2.7 Training Staff\n\nFlight Instructors\nThe Flight Instructor is the person appointed by the Head of Training. He/She holds the licenses and level of experience according to FCL.900 – Instructor Certificates.\n\nBefore the Flight Instructor commences his performances for EuroPilot Center, he/she has successfully demonstrated his flying, instructional and pedagogical skills to the Head of Training or Chief Flight Instructor.\n\nHis/Her responsibilities include (non-limitative list):\n\nComplying with the applicable regulations.\nApplying the EuroPilot Center Operations Manual and Training Manual.\nEnsuring his instruction skills and knowledge remain up to date (by attending instructor seminars, refresher courses etc.).\nMaintaining the validity of his licenses, medical, type or class ratings.\nEnsuring the performance of sufficient briefing and debriefing.\nVerifying all required documents are on board and valid before departing on a flight.\nVerifying that the preflight preparations have been carried out correctly.\nVerifying that a correct and sufficient amount of fuel, oil (or other liquids) are on board.\nEnsuring the aircraft/synthetic journey log is correctly filled out immediately after each flight.\nEnsuring all obligations and requirements are met before approving solo flights.\nEnsuring the student’s training file is filled out after each flight.\nEnsuring the student’s logbook is filled out after each flight.\nRespecting the planning and timeframe.\nAlerting any technical deficiency of the aircraft or synthetic training device.\nReporting any occurrence, incident or accident immediately to the Chief Flight Instructor.\nEnsuring the aircraft / synthetic training device is kept clean.\nEnsuring the aircraft is parked safely at all times.\nEnsuring the premises are kept clean and are locked when departing.\n\nTheoretical Knowledge Instructors\nThe Theoretical Knowledge Instructor is the person appointed by the Head of Training. Before the Theoretical Knowledge Instructor commences his/her performances for EuroPilot Center, he/she has successfully demonstrated his/her instructional and pedagogical skills to the Head of Training or Chief Theoretical Knowledge Instructor by means of a formal interview and a test lecture based on the material developed for the respective subject(s).\n\nHis/Her responsibilities include (non-limitative list):\n\nComplying with the applicable regulations.\nApplying the EuroPilot Center Operations Manual and Training Manual.\nEnsuring his instruction skills and knowledge remain up to date (by attending instructor seminars, refresher courses etc.).\nEnsuring the student’s training file is filled out after each theory session.\nEnsuring the appropriate attendance sheets are filled out and signed after each theory session.\nRespecting the planning and timeframe.\nReporting any occurrence immediately to the Chief Theoretical Knowledge Instructor.\nEnsuring the premises are kept clean and are locked when departing.\nReporting any deficiency relating to CBT or classroom equipment.', 'OM_REV_6.0_CANONICAL_PART_1.txt', 'dadf540c940539382e4fc01bbc33ef795e8d978ffecb290049e6882f4560b595', 'OM6_P1_2_2_7'),
('OM6_P1_2.2.8', 'OM', '6.0', 1, '2.2.8', 'Compliance Monitoring', '2.2.8 Compliance Monitoring\n\nCompliance Monitoring Manager\nThe duties and responsibilities of the Compliance Monitoring Manager are described in the Organization Management Manual (OMM), Part 2, Chapter 4.2 – Duties and Responsibilities.\n\nAll audits mentioned under OMM Annex 01 – Audit Plan, with the exception of:\n\nAudit 3 – Training Records, Logs, Duty and Rest Times; and\nAudit 8 – Training Procedures (Theory, Synthetic and Flying)\n\nmay be conducted by the Compliance Monitoring Manager.\n\nCompliance Monitoring Auditor\nThe duties and responsibilities of the Compliance Monitoring Auditor are described in the Organization Management Manual (OMM), Part 2, Chapter 3.2 – Duties and Responsibilities.\n\nAssistant Compliance Monitoring Manager / Auditor\nThe duties and responsibilities of the Assistant Compliance Monitoring Manager / Auditor are described in the Organization Management Manual (OMM), Part 2, Chapter 3.2 – Duties and Responsibilities.', 'OM_REV_6.0_CANONICAL_PART_1.txt', '26122c8600218a65396ef896e5c5ee834ded7876ba7f7f860bb4b29e2ceeced2', 'OM6_P1_2_2_8'),
('OM6_P1_2.2.9', 'OM', '6.0', 1, '2.2.9', 'Safety Manager', '2.2.9 Safety Manager\n\nThe duties and responsibilities of the Safety Manager are described in the Organization Management Manual (OMM), Part 3, Chapter 3.3 – Safety Manager.', 'OM_REV_6.0_CANONICAL_PART_1.txt', '7a4dcfe06e1ef7d34d5da9624a63468ec192ed307ced4d5d3fb6227681964524', 'OM6_P1_2_2_9'),
('OM6_P1_3.1', 'OM', '6.0', 1, '3.1', 'General', '3.1 General\n\nThe student has to follow the instructions and guidelines of the instructors.\n\nThe student is responsible at all times for maintaining the validity of his license and medical, and providing a copy of these certificates to the EuroPilot Center Administration.', 'OM_REV_6.0_CANONICAL_PART_1.txt', '80196609cc1823662187fb8d56a7ef7b1e8e2f4d8276d7a3911a0403d3c7f5a4', 'OM6_P1_3_1'),
('OM6_P1_3.1.1', 'OM', '6.0', 1, '3.1.1', 'Consumption of alcohol', '3.1.1 Consumption of alcohol\n\nUnder no circumstances may alcohol be consumed in any form by the student within 8 hours before (synthetic) Flight Training.', 'OM_REV_6.0_CANONICAL_PART_1.txt', 'e9fc9a8ef272ec40827cde2465971db20ce8f285b34dc34d4bab57611f59ea86', 'OM6_P1_3_1_1'),
('OM6_P1_3.1.2', 'OM', '6.0', 1, '3.1.2', 'Narcotics', '3.1.2 Narcotics\n\nThe use of narcotics in any form is strictly prohibited.\n\nThe use of drugs by the student, in connection with (synthetic) Flight Training is prohibited, except drugs that have been prescribed by a doctor with knowledge of performance requirements in flying environment.\n\nThis exception needs to be approved by the Head of Training prior to the start of the (synthetic) Flight Training.', 'OM_REV_6.0_CANONICAL_PART_1.txt', 'bc14ed4b8da77876b8a9898bd4cc443a9f034f5b78824f741857e3f719177129', 'OM6_P1_3_1_2'),
('OM6_P1_3.1.3', 'OM', '6.0', 1, '3.1.3', 'Physical fitness, sleep and rest', '3.1.3 Physical fitness, sleep and rest\n\nFlight safety requires the student to receive regular and sufficient opportunities for rest and sleep.\n\nThe student must ensure that proper advantage is taken of the provided rest period to relax and regain his fitness.', 'OM_REV_6.0_CANONICAL_PART_1.txt', 'f945af83315c8e1f146f9828e3992e5a371f182bb6509b5db46e9e564c1a170c', 'OM6_P1_3_1_3'),
('OM6_P1_3.1.4', 'OM', '6.0', 1, '3.1.4', 'Surgical operation and medical fitness', '3.1.4 Surgical operation and medical fitness\n\nIn the event of a decrease in the medical fitness, physically or psychologically, which might render the student unable to safely carry out training, the student must seek advice of an authorized medical examiner prior to returning to training.\n\nProof hereof must be delivered to the Head of Training by the respective medical examiner’s written attestation.\n\nThe following rules are applicable at all times:\n\nAero-medical advice must be sought prior to returning to training following any surgical operation.\nAny general anesthesia renders the student unfit for training for at least 48 hours.\nAny local anesthesia renders the student unfit for training for at least 12 hours.\nAny blood donation renders the student unfit for training for at least 12 hours.\nAny diving activity renders the student unfit for training for at least 12 hours.\nThe student must not perform training if he is suffering from fatigue or feels unfit for training.', 'OM_REV_6.0_CANONICAL_PART_1.txt', '5b0e978f135baac26e472a843bcae728eb6b31cebc176cb661c44bb04cdfc863', 'OM6_P1_3_1_4'),
('OM6_P1_3.1.5', 'OM', '6.0', 1, '3.1.5', 'Corrective Actions', '3.1.5 Corrective Actions\n\nIn case a student breaks (or intends to break) any rules relating to the consumption of alcohol, use of narcotics or drugs, or physical fitness, as described above or imposed by the BCAA, it is the duty of each individual who may become aware of this, to report the same to the Chief Flight Instructor, Chief Theoretical Knowledge Instructor and/or Head of Training.\n\nIn extreme cases, the Head of Training may decide to terminate the training in consultation with the Chief Flight Instructor and/or Chief Theoretical Knowledge Instructor.', 'OM_REV_6.0_CANONICAL_PART_1.txt', '24ec077ffcd15d64a87907e034f2c799d63bb6cdfb152864c04304d04bc266eb', 'OM6_P1_3_1_5'),
('OM6_P1_3.2', 'OM', '6.0', 1, '3.2', 'Student Training Environment', '3.2 Student Training Environment', 'OM_REV_6.0_CANONICAL_PART_1.txt', '7ff2bc87ee7aace5d67a2628ef982df4ffcac09a97b91033cdb330e34ead7ae9', 'OM6_P1_3_2'),
('OM6_P1_3.2.1', 'OM', '6.0', 1, '3.2.1', 'Student – Instructor ratio', '3.2.1 Student – Instructor ratio\n\nIn accordance with AMC1 ORA.ATO.210 – Personnel requirements, the following rules are applicable at all times:\n\nThe normal student-instructor ratio corresponds to a maximum of six students for one instructor (Head of Training excluded).\nDuring a student’s training, a maximum of six different instructors should be used.\nClass numbers in ground subjects involving a high degree of supervision or practical work should not exceed 28 students.', 'OM_REV_6.0_CANONICAL_PART_1.txt', 'f040186c76979f9e4f0dcf59dfa0bfc79ba4acad1077be8003a8520d924e6b4a', 'OM6_P1_3_2_1'),
('OM6_P1_3.2.2', 'OM', '6.0', 1, '3.2.2', 'Rules governing a student choosing another Approved Training Organization', '3.2.2 Rules governing a student choosing another Approved Training Organization\n\nFormal approval is required from the BCAA in case a student decides to change Approved Training Organization at any time during his training.\n\nHe shall formally inform the Head of Training hereof in writing.\n\nThe student’s new Approved Training Organization shall file a “change of ATO” application with the BCAA and request a copy of the complete training record from the Head of Training at EuroPilot Center.\n\n\n\n4. APPROVAL AND AUTHORIZATION OF FLIGHTS', 'OM_REV_6.0_CANONICAL_PART_1.txt', '3ffcc0d041aaa28c6fa0874712388d30b9f6ac899b422ba1212f105293350091', 'OM6_P1_3_2_2'),
('OM6_P1_4.1', 'OM', '6.0', 1, '4.1', 'Flight Training Authorization', '4.1 Flight Training Authorization\n\nAll student flights must be approved by the assigned flight instructor and only flights:\n\nResorting under the Training Program; or\nIntroductory flights (as described under Annex VII of Regulation (EU) No 965/2012, NCO.GEN.103)\n\nmay be performed.\n\nAny other flight must be authorized by the Head of Training or his deputy.\n\nFor each solo (navigation) flight, the required solo authorization form must be used as described in the EuroPilot Center Training Manual – General, Chapter 1.3.5.', 'OM_REV_6.0_CANONICAL_PART_1.txt', 'e637aedc375d9cadd5295f13e4cbe4f222a80c892e9af472af834b147d714c71', 'OM6_P1_4_1'),
('OM6_P1_4.2', 'OM', '6.0', 1, '4.2', 'Aircraft availability and organization of flights', '4.2 Aircraft availability and organization of flights', 'OM_REV_6.0_CANONICAL_PART_1.txt', '319ff2671e72db9d84b93f5407fa708abcc9c516e938e104fd120bdd4d033e14', 'OM6_P1_4_2'),
('OM6_P1_4.2.1', 'OM', '6.0', 1, '4.2.1', 'Monthly Flight Training Schedule', '4.2.1 Monthly Flight Training Schedule\nThe flight training schedule covers the planning of the students, instructors and the training fleet.\n\nThe flight training schedule is established on a monthly basis, offering both students and instructors more security and a better way to combine flying activities with a private and professional life.\n\nThe following scheduling procedure is applied:\n\nStep 1: before the 20th of each month, all instructional staff provides their availabilities for the coming month through the online planning system.\nStep 2: around the 20th of each month, an e-mail is sent out by the Chief Operations Officer to all students with the available dates for training for the upcoming month.\nStep 3: each individual student feedback is processed, and temporary training slots are allocated in the online planning system. A draft schedule is produced, and completed or modified depending on the feedback from all students.\nStep 4: on the 23rd a reminder is sent out to the students who haven’t replied yet.\nStep 5: when the schedule is almost complete (usually around the 24th), an e-mail is sent out to each student individually, including a personal training schedule.\nStep 6: upon receipt of final confirmation by the student, the training slots are saved into the online planning system. An aircraft, training device and instructor are allocated to the training slot.\nStep 7: for each flight training session, a training device (FSTD) is allocated as far as practicable (color green), offering a backup in case of adverse weather conditions.\n\nChanges to the schedule throughout the month can only be performed by the Chief Operations Officer or Operations Officer.\n\nNote 1: In no event should any Flight or Theoretical Knowledge Instructor alter the monthly schedule as this will lead to loss of overview and efficiency.\n\nNote 2: Students are never allowed to reserve training slots with instructor directly via the online planning system, with the exception of self-practice FSTD sessions, which the student may reserve directly (color code blue) via the online planning system. A restriction of maximum 2 hours per student is applicable in order to guarantee every student sufficient self-practice time on the FSTD’s.\n\nNote 3: Flight training sessions on the FSTD (with instructors) always have priority over self-practice FSTD sessions.', 'OM_REV_6.0_CANONICAL_PART_1.txt', 'a5360a87dfc91bd466821be79d7324ced900ab9d2309d4870e8caa62f6283e16', 'OM6_P1_4_2_1'),
('OM6_P1_4.2.2', 'OM', '6.0', 1, '4.2.2', 'Online Planning System', '4.2.2 Online Planning System\n\nAll training sessions will be planned via an online planning system:\n\nhttp://www.flightcircle.com\n\nBoth students and instructors can, upon obtaining a personal login and password, consult the online planning at all times.', 'OM_REV_6.0_CANONICAL_PART_1.txt', 'f6fe7292ada0815a97841a9693d9842ed0d5150d6a568b5b09fc5d4722a9d448', 'OM6_P1_4_2_2'),
('OM6_P1_4.2.3', 'OM', '6.0', 1, '4.2.3', 'Cancellations / no-shows', '4.2.3 Cancellations / no-shows\n\nAlthough EuroPilot Center strives to minimize the number of changes to the schedule as much as possible, certain last minute changes are inevitable.\n\nOnly in the following circumstances is a cancellation acceptable:\n\nStudent and/or instructor are unfit to fly.\nIllness of the student and/or instructor.\nExceptional personal circumstances.\nStudent not or insufficiently prepared for the flight or synthetic training session.\nPoor weather conditions.\nAircraft defects.\nFSTD defects.\nMaintenance.\nPriority granted examination flights.\n(Local) Airport restrictions.\nTemporary flying restrictions.\n\nA reliable and efficient communication procedure is in place to cope with last minute changes.\n\nWe refer to Annex 36 – Cancellation Flowchart.\n\nNote: In case of cancellations, the Operations Officer will make a note in the online planning system, using the following codes:\n\nC1: Weather cancel\nC2: Cancellation due to the student\nC3: Cancellation due to maintenance\nC4: Cancellation due to the Instructor', 'OM_REV_6.0_CANONICAL_PART_1.txt', 'bf7c1ca75bbd12d3350a0b5b6c1f18e007ab70558f51ed15c7083d0b1d0261d8', 'OM6_P1_4_2_3'),
('OM6_P1_4.2.4', 'OM', '6.0', 1, '4.2.4', 'Preparation', '4.2.4 Preparation\n\nStudents are required to be present at EuroPilot Center, minimum 30 minutes before the scheduled time in the online planning system.\n\nA student should have prepared his flight as described in the Operations Manual Part 3, Chapter 2.1.\n\nThe instructor will integrate a check of the student’s preparation during the preflight briefing.', 'OM_REV_6.0_CANONICAL_PART_1.txt', 'a7fbb478020ac13753b9c66ad63f6202638091a58e5bb4797632dd73637c94aa', 'OM6_P1_4_2_4'),
('OM6_P1_4.2.5', 'OM', '6.0', 1, '4.2.5', 'Restrictions', '4.2.5 Restrictions\n\nThe number of aircraft that can be supervised by an instructor at the same time in case of poor weather is limited to one aircraft.\n\n\n\n5. FLIGHT CREW QUALIFICATION RECORDS', 'OM_REV_6.0_CANONICAL_PART_1.txt', 'b9b3d7d7d6df68b82e8368bdd246428e15e23607db452fb4052a2fd580d4de91', 'OM6_P1_4_2_5'),
('OM6_P1_5.1', 'OM', '6.0', 1, '5.1', 'Personnel', '5.1 Personnel\n\nThe Flight Instructor file is available in a digital format via the E-gle Online system and contains the following data:\n\nPersonal Data\nLicense / Medical\nCourse Enrollment (Standardization Course & Proficiency Checks)\nContract, CV, BCAA Application Form', 'OM_REV_6.0_CANONICAL_PART_1.txt', '719b926f55a28ad141e4287c57b4597265ef11ab191e978ff5463cc710305305', 'OM6_P1_5_1'),
('OM6_P1_5.1.1', 'OM', '6.0', 1, '5.1.1', 'Recent Experience', '5.1.1 Recent Experience\n\nFlight Instructors should only be allowed to provide training if:\n\nThey comply with the requirements under FCL.060 – Recent experience; and\nThey have performed at least 1 hour of flight instruction within the previous 12 months within EuroPilot Center.\n\nNote: If no instructional duties were performed by the Flight Instructor within EuroPilot Center for a period exceeding 12 months, a refresher course as described under OM Part 4, Chapter 3 needs to be performed.\n\nThere are no recent experience requirements for Theoretical Knowledge Instructors.', 'OM_REV_6.0_CANONICAL_PART_1.txt', '9efd3ef61b8427fb2cf2a0b17bac17259949b8d5b5907b2d1e76bce432d698d7', 'OM6_P1_5_1_1'),
('OM6_P1_5.1.2', 'OM', '6.0', 1, '5.1.2', 'Follow-up', '5.1.2 Follow-up\n\nIt is the responsibility of Flight Instructors to provide the EuroPilot Center Administration immediately with a copy of the License or Medical preferably via e-mail (PDF scancopy) in order to follow-up due dates of licenses, ratings, authorizations, initials, refreshers and medicals.\n\nIt is the responsibility of the Head of Training to follow-up the due dates of licenses, ratings, authorizations, initials, refreshers and medicals into the E-gle Online System which timely alerts the following persons via e-mail:\n\nHead of Training\nChief Operations Officer\nOperations Officers\nRespective instructor', 'OM_REV_6.0_CANONICAL_PART_1.txt', '5e096a4b0ea2df328221fd17c3b7b7b7615f0522c6730b7276820a487556240d', 'OM6_P1_5_1_2'),
('OM6_P1_5.2', 'OM', '6.0', 1, '5.2', 'Students', '5.2 Students\n\nA copy of the valid license and valid medical certificate of all students shall be filed in the E-gle Online system.', 'OM_REV_6.0_CANONICAL_PART_1.txt', 'a99fbf64fe5b6049e02e054fcd19e8b504d583aa2c486a4262ddfcf1c2639686', 'OM6_P1_5_2'),
('OM6_P1_5.2.1', 'OM', '6.0', 1, '5.2.1', 'Follow-up', '5.2.1 Follow-up\n\nIt is the responsibility of the student to provide the EuroPilot Center Administration immediately with a copy of the License or Medical preferably via e-mail (PDF scancopy) in order to follow-up due dates of licenses, ratings, authorizations, initials, refreshers and medicals.\n\nIt is the responsibility of the Head of Training to follow-up the due dates of licenses, ratings, authorizations, initials, refreshers and medicals into the E-gle Online System which timely alerts the following persons via e-mail:\n\nHead of Training\nChief Operations Officer\nOperations Officers\nRespective student', 'OM_REV_6.0_CANONICAL_PART_1.txt', '8038ff56cab9856e8d022f1e0cfe63f6e70e64fc631a79900cacebea375910cc', 'OM6_P1_5_2_1'),
('OM6_P1_5.3', 'OM', '6.0', 1, '5.3', 'Pilot Logbook', '5.3 Pilot Logbook\n\nIn accordance with FCL.050, holders of a pilot license shall record details of all flights flown, in a format acceptable to the BCAA responsible for license or rating issue.\n\nThis logbook enables pilot license holders to record flying experience in a manner which will facilitate this process while providing a permanent record of the license holders flying.\n\nPilots who fly regularly airplanes and helicopters, or different aircraft types are recommended to hold separate logbooks for each type of flying.\n\nThe logbook entries should be made as soon as practicable after any flight undertaken. All entries in the logbook shall be made in ink or indelible pencil.\n\nThe specifics of every flight in the course of which the holder of a pilot license acts as a (student) pilot of an aircraft are to be recorded in the appropriate columns using one line for each flight, provided that if an aircraft carries out a number of flights upon the same day returning on each occasion to the same place of departure and the interval between successive flights does not exceed thirty minutes, such series of flights may be recorded as a single entry.\n\nFlight time for airplanes, touring motor gliders and powered-lift means the total time from the moment an aircraft first moves for the purpose of taking off until the moment it finally comes to rest at the end of the flight; for helicopters, it means the total time from the moment a helicopter’s rotor blades start turning until the moment the helicopter finally comes to rest at the end of the flight, and the rotor blades are stopped.\n\nAll flying carried out as Pilot-in-Command shall be entered in the logbook as Pilot-in-Command.\n\n6. COMMAND OF THE AIRCRAFT', 'OM_REV_6.0_CANONICAL_PART_1.txt', '434c7fd7d0d5c5efc22b2e767ab293fdc5b45cf6f7483cdd9fa5aff42fb44f56', 'OM6_P1_5_3'),
('OM6_P1_6.1', 'OM', '6.0', 1, '6.1', 'General', '6.1 General\n\nTraining flights can be performed either dual or solo.\n\nThe crew shall consist of either an instructor and a student (dual) or either the student only (solo).\n\nIn all EuroPilot Center aircraft, one seat is considered as the “Pilot Seat”. In aircraft, this is the left seat.\n\nThe other seat in front is referred to as the “Instructor Seat”.\n\nDuring all flights, except training flights for Flight Instructor ratings, the student shall occupy the Pilot Seat.\n\nFlying in the Instructor Seat is allowed only for qualified EuroPilot Center Flight Instructors or Flight Instructor Students.\n\nTherefore:\n\nDuring all dual training flights, the instructor is the Pilot In Command.\nDuring all solo flights, the student is the Pilot In Command.\n\nNote: During skill tests, the candidate is considered as Pilot In Command.\n\n\n\n7. FLYING DUTY PERIODS, LIMITATIONS AND REST PERIODS', 'OM_REV_6.0_CANONICAL_PART_1.txt', '2dba01a3cb96139bc34add07556fc222dbfcf68d887159c2a75b820ee818c543', 'OM6_P1_6_1'),
('OM6_P1_7.1', 'OM', '6.0', 1, '7.1', 'General', '7.1 General\n\nA Duty is any task that a student or instructor is required to carry out associated with the business of an AOC holder or an ATO.\n\nA Duty Period is a period which starts when a student or instructor is required by an operator or an ATO to commence a duty and ends when they are free from all duties.\n\nA Flight Duty Period is any time during which a student or instructor operates in an aircraft as a member of its crew.\n\nThe Flight Duty Period starts when the student or instructor is required by an Operator or an ATO to report for a flight or a series of flights; it finishes at the end of the last flight on which he or she is an operating crew member.\n\nA Rest Period is an uninterrupted and defined period of time during which a student or instructor is free from all duties.\n\nThe Home Base is the location nominated by EuroPilot Center to the student or instructor from where they normally start and end a Flight Duty Period and where EuroPilot Center is not responsible for their accommodation.\n\nAntwerp Airport (EBAW) is considered as the Home Base for EuroPilot Center.\n\nInstructors or students performing Flight Duties for other Operators or ATO’s are at all times responsible to inform EuroPilot Center about these Flight Duties.\n\nThey must ensure that they do not operate an EuroPilot Center aircraft if they know that they have not had sufficient rest or they are suffering from or are likely to suffer from fatigue or feel unfit, to the extent that the flight may be endangered.\n\nEuroPilot Center will keep track of the Flight Duty Periods performed within EuroPilot Center for students and instructors by means of the Blue Cat system.', 'OM_REV_6.0_CANONICAL_PART_1.txt', '6a0f1b523de001d173e55ec6c6a406173be7a661fa84b04109ec875a0c0f74c3', 'OM6_P1_7_1'),
('OM6_P1_7.2', 'OM', '6.0', 1, '7.2', 'Instructors', '7.2 Instructors\n\nThe maximum basic daily Flight Duty Period for instructors (both part time and full time) shall normally not exceed 13 hours.\n\nIn the event of unforeseen circumstances, the Head of Training may allow an extension of the Flight Duty Period by maximum 1 hour.\n\nThe minimum rest which must be provided before undertaking a Flight Duty Period starting at home base shall be at least as long as the preceding duty period or 12 hours whichever is the greater.\n\nIn case of a duty and rest violation, a duty and rest violation report form shall be filed by the instructor.\n\nWe refer to OM Annex 39 – Duty and Rest Violation Report Form.', 'OM_REV_6.0_CANONICAL_PART_1.txt', '8d39508cd828d854c09ff7c9629ec45282bc95eeeefa1068cfed4b943e92a8fd', 'OM6_P1_7_2'),
('OM6_P1_7.3', 'OM', '6.0', 1, '7.3', 'Students', '7.3 Students\n\nThe maximum basic daily Flight Duty Period for students shall normally not exceed 13 hours.\n\nIn the event of unforeseen circumstances, the Head of Training may allow an extension of the Flight Duty Period by maximum 1 hour.\n\nThe minimum rest which must be provided before undertaking a Flight Duty Period starting at home base shall be at least as long as the preceding duty period or 12 hours whichever is the greater.\n\nIn case of a duty and rest violation, a duty and rest violation report form shall be filed by the student.\n\nWe refer to OM Annex 39 – Duty and Rest Violation Report Form.\n\n\n8. FLIGHT PLANNING AND OPERATING PROCEDURES', 'OM_REV_6.0_CANONICAL_PART_1.txt', '84b7c04aac71a3e24e941f1bd080c04e955f9ec7c81eb66a698d637147a61726', 'OM6_P1_7_3'),
('OM6_P1_8.1', 'OM', '6.0', 1, '8.1', 'Responsibility of the Pilot in Command', '8.1 Responsibility of the Pilot in Command\n\nThe Pilot in Command of a training flight must be qualified on the respective aircraft either:\n\nas a licensed flight instructor, class rating instructor or instrument rating instructor; or\nas a student pilot with a solo authorization from a flight instructor.', 'OM_REV_6.0_CANONICAL_PART_1.txt', '317b289671dcbc22f7b106b81e47601d7a15dc843034e0978ffa93a60c6e1839', 'OM6_P1_8_1'),
('OM6_P1_8.1.1', 'OM', '6.0', 1, '8.1.1', 'Pilot-in-command responsibilities and authority (Ref. NCO.GEN.105)', '8.1.1 Pilot-in-command responsibilities and authority (Ref. NCO.GEN.105)\n\nthe pilot-in-command shall be responsible for:\n\nThe safety of all passengers and cargo on board, as soon as he arrives on board, until he leaves the aircraft at he end of the flight;\nThe operation and safety of the aircraft: for airplanes, from the moment it is first ready to move for the purpose of flight until the moment it comes to rest at the end of the flight and the engine(s) used as primary propulsion unit(s) is/are shut down;\nThe initiation, continuation, termination or diversion of a flight in the interest of safety;\nEnsuring that all operational procedures and checklists are complied with. The pilot-in-command should use the latest checklists provided by the manufacturer. If checks conducted prior to take-off are suspended at any point, the pilot-in-command should re-start them from a safe point prior to the interruption;\n\nOnly commencing a flight if he/she is satisfied that the following operational limitations are complied with:\n\nthe aircraft is airworthy;\nthe aircraft is duly registered;\ninstruments and equipment required for the execution of that flight are installed in the aircraft and are operative, unless operation with inoperative equipment is permitted by the minimum equipment list (MEL) or equivalent document, if applicable, as provided for in NCO.IDE.A.105, NCO.IDE.H.105.\nthe mass of the aircraft and the centre of gravity location are such that the flight can be conducted within limits prescribed in the airworthiness documentation;\nall equipment, baggage and cargo are properly loaded and secured and an emergency evacuation remains possible;\nthe aircraft operating limitations as specified in the aircraft flight manual (AFM) will not be exceeded at any time during the flight;\nany navigational database required for PBN is suitable and current.\n\nNot commencing a flight if he is incapacitated from performing duties by any cause such as injury, sickness, fatigue or the effects of any psychoactive substance;\n\nNot continuing a flight beyond the nearest weather-permissible aerodrome or operating site when his/her capacity to perform duties is significantly reduced from causes such as fatigue, sickness or lack of oxygen;\n\nDeciding on acceptance of the aircraft with unserviceable equipment in accordance with the configuration deviation list (CDL) or minimum equipment list (MEL), as applicable; and\n\nRecording utilization data and all known or suspected defects in the aircraft at the termination of the flight, or series of flights, in the aircraft Trouble Report.\n\nThe pilot-in-command shall ensure that during critical phases of flight or whenever deemed necessary in the interest of safety, all crew members are seated at their assigned stations and do not perform any activities other than those required for the safe operation of the aircraft.\n\nThe pilot-in-command shall have the authority to refuse carriage of or disembark any person (student), baggage or cargo that may represent a potential hazard to the safety of the aircraft or its occupants.\n\nThe pilot-in-command shall, as soon as possible, report to the appropriate air traffic services (ATS) unit any hazardous weather or flight conditions encountered that are likely to affect the safety of other aircraft.\n\nThese reports should include any detail which may be pertinent to the safety of other aircraft.\n\nSuch reports should be made whenever any of the following conditions are encountered or observed:\n\nsevere turbulence;\nsevere icing;\nsevere mountain wave;\nthunderstorms, with or without hail, that are obscured, embedded, widespread or in squall lines;\nheavy dust storm or heavy sandstorm;\nvolcanic ash cloud; and\nunusual and/or increasing volcanic activity or a volcanic eruption.\n\nWhen other meteorological conditions not listed above, e.g. wind shear, are encountered that, in the opinion of the pilot-in-command, may affect the safety or the efficiency of other aircraft operations, the pilot-in-command should advise the appropriate air traffic services (ATS) unit as soon as practicable.\n\nThe pilot-in-command shall, in an emergency situation that requires immediate decision and action, take any action he considers necessary under the circumstances in accordance with 7.d of Annex IV to Regulation (EC) No 216/2008. In such cases he may deviate from rules, operational procedures and methods in the interest of safety. If required by the State in which the incident occurs, the pilot-in-command should submit a report on any such violation to the appropriate authority of such State; in that event, the pilot-in-command should also submit a copy of it to the competent authority. Such reports should be submitted as soon as possible and normally within 10 days.\n\nDuring flight, the pilot-in-command shall:\n\nKeep his safety belt fastened while at his/her station; and\nRemain at the controls of the aircraft at all times except if another pilot is taking the controls.\n\nThe pilot-in-command shall submit a report of an act of unlawful interference without delay to the competent authority and shall inform the designated local authority.\n\nThe pilot-in-command shall notify the nearest appropriate authority by the quickest available means of any accident involving the aircraft that results in serious injury or death of any person or substantial damage to the aircraft or property.', 'OM_REV_6.0_CANONICAL_PART_1.txt', 'b11bb442a3a8b32b803d7a1e4ebd2b165455ef4024082cb394798b31b006340e', 'OM6_P1_8_1_1'),
('OM6_P1_8.1.2', 'OM', '6.0', 1, '8.1.2', 'Compliance with laws, regulations and procedures (Ref. NCO.GEN.110)', '8.1.2 Compliance with laws, regulations and procedures (Ref. NCO.GEN.110)\n\nThe pilot-in-command shall comply with the laws, regulations and procedures of those States where operations are conducted.\n\nThe pilot-in-command shall be familiar with the laws, regulations and procedures, pertinent to the performance of his duties, prescribed for the areas to be traversed, the aerodromes or operating sites to be used and the related air navigation facilities as referred to in 1.a of Annex IV to Regulation (EC) No 216/2008.', 'OM_REV_6.0_CANONICAL_PART_1.txt', '848140e18c9c2e777a2110b9cdd9722c49e3dee33651e1660c8c9d0f6bb4a853', 'OM6_P1_8_1_2'),
('OM6_P1_8.2', 'OM', '6.0', 1, '8.2', 'Taxiing of Airplanes', '8.2 Taxiing of Airplanes\n\nIn accordance with NCO.GEN.115, EuroPilot Center Airplanes shall only be taxied on the movement area of an aerodrome if the person at the controls:\n\nis an appropriately qualified pilot; or\nhas been designated by the operator and:\n\nis trained to taxi the airplane;\nis trained to use the radio telephone, if radio communications are required;\nhas received instruction in respect of aerodrome layout, routes, signs, marking, lights, air traffic control (ATC) signals and instructions, phraseology and procedures; and\nis able to conform to the operational standards required for safe airplane movement at the aerodrome.\n\nNote 1: Taxiing should be treated as a safety-critical activity due to the risks related to the movement of the airplane and the potential for a catastrophic event on the ground.\n\nNote 2: Taxiing is a high-workload phase of flight that requires the full attention of the pilot-in-command.\n\nNote 3: The person designated by the operator to taxi an airplane should possess the following skills and knowledge:\n\npositioning of the airplane to ensure safety when starting engine;\ngetting ATIS reports and taxi clearance, where applicable;\ninterpretation of airfield markings/lights/signals/indicators;\ninterpretation of airplane signals, where applicable;\nidentification of suitable parking area;\nmaintaining lookout and right-of-way rules and complying with ATC or marshaling instructions when applicable;\navoidance of adverse effect of propeller slipstream or jet wash on other airplane, aerodrome facilities and personnel;\ninspection of taxi path when surface conditions are obscured;\ncommunication with others when controlling an airplane on the ground;\ninterpretation of operational instructions;\nreporting of any problem that may occur while taxiing an airplane; and\nadapting the taxi speed in accordance with prevailing aerodrome, traffic, surface and weather conditions.', 'OM_REV_6.0_CANONICAL_PART_1.txt', '2dd07d929df3ac6588c9a9123ba0f43b2f0f3b5a747a735c49c2ccc7257a02f9', 'OM6_P1_8_2'),
('OM6_P1_8.3', 'OM', '6.0', 1, '8.3', 'Use of Portable Electronic Devices', '8.3 Use of Portable Electronic Devices', 'OM_REV_6.0_CANONICAL_PART_1.txt', 'a903e1f38a206dc504a1b6c1cc5ba0e5d9ee8a095bfbda2870eb68b370772715', 'OM6_P1_8_3'),
('OM6_P1_8.3.1', 'OM', '6.0', 1, '8.3.1', 'Definition of a Portable Electronic Device', '8.3.1 Definition of a Portable Electronic Device\n\nA Portable Electronic Device (PED) is defined as:\n\nAny kind of electronic device, typically but not limited to consumer electronics, brought on board the aircraft by crew members, passengers, or as part of the cargo and that are not included in the approved aircraft configuration.\n\nAll equipment that is able to consume electrical energy falls under this definition.', 'OM_REV_6.0_CANONICAL_PART_1.txt', '96fe3f5675aefc60f70c0729054e7f7fe0ebb86d953a3e8eff780a875734af48', 'OM6_P1_8_3_1'),
('OM6_P1_8.3.2', 'OM', '6.0', 1, '8.3.2', 'Restriction on use of Portable Electronic Devices during training operations', '8.3.2 Restriction on use of Portable Electronic Devices during training operations\n\nIn accordance with NCO.GEN.125, the pilot-in-command shall not permit any person to use a portable electronic device (PED) on board an aircraft that could adversely affect the performance of the aircraft’s systems and equipment.\n\nPrecautions should also be taken to eliminate any fire hazard.', 'OM_REV_6.0_CANONICAL_PART_1.txt', 'cb7f2cb5e60d871d1dc2c571057c2e03f2f0521b45cbad0ff6d56f128bae8cc8', 'OM6_P1_8_3_2'),
('OM6_P1_8.3.3', 'OM', '6.0', 1, '8.3.3', 'Fire hazard of Portable Electronic Devices', '8.3.3 Fire hazard of Portable Electronic Devices\n\nPED’s with lithium batteries are capable of ignition and subsequent explosion due to overheating. Overheating may be caused by shorting, rapid discharge or overcharging.\n\nOverheating results in thermal runaway, which is a chemical reaction within the battery causing the internal temperature and pressure to rise.\n\nThis produces a fire that repeatedly flares up as each battery cell in turn ruptures and releases its contents.\n\nFighting a fire that contains either disposable or rechargeable lithium battery cells requires:\n\nExtinguishment of the fire; and\nCooling of the remaining cells to stop the thermal runaway.\n\nWater is the most effective coolant.\n\nHalon, Halon replacement and/or water fire extinguishers should be used for initial knockdown of these fires, followed by immediate dousing with water from any available source.\n\nNote: Do not use fire resistant burn bags to isolate burning lithium-type batteries. Transferring a burning appliance into a burn bag may be extremely hazardous.\n\nDo not move the device until you are certain the fire is extinguished and the device is cool.\n\nApply the appropriate Cabin Fire Emergency procedures and land as soon as possible.', 'OM_REV_6.0_CANONICAL_PART_1.txt', '0ded5da4b08bbe5d6b10175659fc877af2b2c37a412984e7ef156015e58c63d4', 'OM6_P1_8_3_3'),
('OM6_P1_8.3.4', 'OM', '6.0', 1, '8.3.4', 'Electronic Flight Bags – Hardware', '8.3.4 Electronic Flight Bags – Hardware', 'OM_REV_6.0_CANONICAL_PART_1.txt', '7a42290cbbfe71f078f870ab205dbd1086f1120d9dd49af53d329565d10bd5ed', 'OM6_P1_8_3_4'),
('OM6_P1_8.3.4.1', 'OM', '6.0', 1, '8.3.4.1', 'EFB viewable stowage', '8.3.4.1 EFB viewable stowage\nWhen a viewable stowage device is used, the pilot-in-command should ensure that, if the EFB moves or is separated from its stowage, or if the viewable stowage is unsecured from the aircraft (as a result of turbulence, maneuvering, or other action), it will not jam flight controls, damage flight deck equipment, or injure any person on board.\n\nThe viewable stowage device should not be positioned in such a way that it obstructs visual or physical access to aircraft controls and/or displays, flight crew ingress or egress, or external vision.\n\nThe design of the viewable stowage device should allow the user easy access to any item of the EFB system, and notably to the EFB controls and a clear view of the EFB display while in use.', 'OM_REV_6.0_CANONICAL_PART_1.txt', '2bc972f2e6ba87df6dcc6c1e54ce8dc283b482457d99cc5f970288339e5af6ad', 'OM6_P1_8_3_4_1'),
('OM6_P1_8.3.4.2', 'OM', '6.0', 1, '8.3.4.2', 'Cables', '8.3.4.2 Cables\nIf cables are used to connect an EFB to an aircraft system, power source, or any other equipment:\n\nthe cables should not hang loosely in a way that compromises task performance and safety;\nflight crew should be able to easily secure the cables out of the way during operations (e.g. by using cable tether straps); and\nthe cables should be of sufficient length so that they do not obstruct the use of any movable device on the flight deck.', 'OM_REV_6.0_CANONICAL_PART_1.txt', '0908677232327fd9a67c9d312a08da774bc204d3342c00f8846eb175abd3f76a', 'OM6_P1_8_3_4_2'),
('OM6_P1_8.3.5', 'OM', '6.0', 1, '8.3.5', 'Electronic Flight Bags – Functions', '8.3.5 Electronic Flight Bags – Functions', 'OM_REV_6.0_CANONICAL_PART_1.txt', 'f2db4a3aabd52c53951ea0a5d12d4093e0a1887c0264d6198aeb5990ad71a8aa', 'OM6_P1_8_3_5'),
('OM6_P1_8.3.5.1', 'OM', '6.0', 1, '8.3.5.1', 'Familiarisation', '8.3.5.1 Familiarisation\nThe pilot-in-command should familiarize himself or herself with the use of the EFB hardware and its applications on the ground before using them in flight for the first time.\n\nThis can be performed by using the FSTD, in conjunction with an emulated GPS signal from the FSTD.\n\nA user guide is be available for the pilot-in-command which can be found on the Software Developer’s website:\n\nhttps://support.garmin.com/support/manuals', 'OM_REV_6.0_CANONICAL_PART_1.txt', '1f71e62c5de234a796aa7f6d4fcecd1e8d4273875758ac88668bfe51aaee2d93', 'OM6_P1_8_3_5_1'),
('OM6_P1_8.3.5.2', 'OM', '6.0', 1, '8.3.5.2', 'Preflight Check', '8.3.5.2 Preflight Check\nBefore each flight, the pilot-in-command should perform the following checks to ensure the continued safe operation of the EFB during the flight:\n\nGeneral check of the EFB operation by switching it ON and checking that the applications they intend to use in flight are adequately operative;\nCheck of the remaining available battery power, if applicable, to ensure the availability of the EFB during the planned flight;\nCheck of the version effectivity of the EFB databases, if applicable (e.g. for charts, performance calculation and weight and balance applications); and\nCheck that an appropriate backup is available when a chart application or an application displaying aircraft checklists is used.', 'OM_REV_6.0_CANONICAL_PART_1.txt', 'e3c90db3ce1e6a066dbbafab47d41a861988319af0d05b7bf8c4f598db329e31', 'OM6_P1_8_3_5_2'),
('OM6_P1_8.3.5.3', 'OM', '6.0', 1, '8.3.5.3', 'Chart applications', '8.3.5.3 Chart applications\nThe navigation charts that are depicted should contain the necessary information in an appropriate format, to perform the operation safely.\n\nConsideration should be given to the size of the display to ensure legibility.', 'OM_REV_6.0_CANONICAL_PART_1.txt', '571b840e8f8aa132b542b780a2ee334e3b6268b94bb5c6ab53e1739cf18854c9', 'OM6_P1_8_3_5_3'),
('OM6_P1_8.3.5.4', 'OM', '6.0', 1, '8.3.5.4', 'Performance calculation and weight and balance functions or applications', '8.3.5.4 Performance calculation and weight and balance functions or applications\nPrior to the first use of a performance calculation or weight and balance function or application, and following any update of the database supporting the function or the application, a check should be performed on the ground to verify that the output of the application corresponds with the data derived from the AFM (or other appropriate sources).\n\nNote: Compliance with this rule is accomplished by using the latest Garmin Pilot Aircraft Data File and E-Checklist File, which can be downloaded from the www.flightcircle.com website or other future source.\n\nThis file has been verified for use by the EuroPilot Center Administration. For this reason, no editing of these files is allowed by the user.', 'OM_REV_6.0_CANONICAL_PART_1.txt', 'cf823b7e12a61882d98f0ec4d0f8e337621e46702ca4645e7ad701b5c7a16463', 'OM6_P1_8_3_5_4'),
('OM6_P1_8.3.5.5', 'OM', '6.0', 1, '8.3.5.5', 'Airport moving map display (AMMD) application', '8.3.5.5 Airport moving map display (AMMD) application\nAn AMMD application should not be used as a primary means of navigation for taxiing, but as a confirmation of outside visual references.', 'OM_REV_6.0_CANONICAL_PART_1.txt', '3053d16ad7c04646b7b157b443399f4738ed20c0c5f2160dbfdf08837826ffc0', 'OM6_P1_8_3_5_5'),
('OM6_P1_8.3.5.6', 'OM', '6.0', 1, '8.3.5.6', 'Other functions', '8.3.5.6 Other functions\nIf advanced functions on non-certified devices that display information related to the aircraft position in flight, navigation, surroundings in terms of e.g. terrain or traffic, or attitude are used, the pilot-in-command should be aware of the potential misleading or erroneous information displayed and should only use these functions as an advisory or supplementary means.\n\nNote: The approved avionics in the airplane are to be use for primary navigation. The EFB shall in no situation be used as a primary navigation aid but as an advisory or supplementary means only.', 'OM_REV_6.0_CANONICAL_PART_1.txt', 'a1706763f348a49a6d633d1ef2accdd271fbc3e02ea27bcda77a6daeb6dd10cf', 'OM6_P1_8_3_5_6'),
('OM6_P1_8.4', 'OM', '6.0', 1, '8.4', 'ATS Flight Plan', '8.4 ATS Flight Plan\n\nThe pilot-in-command must ensure that an ATS Flight Plan is produced and filed when required under SERA.4001.\n\nReference is made to the Aeronautical Information Publication (AIP), Part 2, Enroute, Chapter 1.1, requirements to submit a flight plan.', 'OM_REV_6.0_CANONICAL_PART_1.txt', '75dba24cb4b330455ea052775e9429f42b1d7787d3ddb810d74d6581c21afead', 'OM6_P1_8_4'),
('OM6_P1_8.5', 'OM', '6.0', 1, '8.5', 'Operational Flight Plan (OFP)', '8.5 Operational Flight Plan (OFP)\n\nThe pilot-in-command must ensure that an Operational Flight Plan is produced for each VFR or IFR cross-country training flight.\n\nA cross-country flight is defined as a flight between a point of departure and a point of arrival following a pre-planned route, using standard navigation procedures (dead-reckoning, pilotage and/or radio navigation).\n\nNote:\nAn Operational Flight Plan is not required for VFR or IFR training flights taking off and landing at the same aerodrome or operating site.\n\nThe Operational Flight Plan contains at least the following:\n\nAircraft registration\nType and variant\nDate of flight\nFlight identification (Mission code assignment, e.g. 1-1-1)\nNames and duty assignments of students and/or instructor\nPlace of departure\nTime of departure (actual off-block time, take-off time)\nPlace of arrival (planned and actual)\nTime of arrival (actual landing and on-block time)\nType of operation (e.g. training flight)\nRoute and route segment with check-points/waypoints, distances, time and tracks\nPlanned cruising speed and flying times between check-points/waypoints, estimated and actual times overhead\nSafe altitudes and minimum levels\nPlanned altitudes and flight levels\nFuel calculations (records of in-flight fuel checks)\nFuel on board when starting the engine\nAlternates for destination, take-off and en-route, if applicable\nInitial ATS flight plan clearance and subsequent re-clearance\nIn-flight re-planning calculations\nRelevant meteorological information\n\nReference is made to OM Annex 01 – EuroPilot Center Operational Flight Plan.', 'OM_REV_6.0_CANONICAL_PART_1.txt', '8d7e513c74aaf6fd09faa0eda790ba181888e55af7d1632aea52b11549e1c368', 'OM6_P1_8_5'),
('OM6_P1_8.6', 'OM', '6.0', 1, '8.6', 'Carriage of passengers', '8.6 Carriage of passengers', 'OM_REV_6.0_CANONICAL_PART_1.txt', '2c774fe173248955d197fdac868e0c7c87e8441d75d61d2e289aac8639a19d4d', 'OM6_P1_8_6'),
('OM6_P1_8.6.1', 'OM', '6.0', 1, '8.6.1', 'General', '8.6.1 General\n\nCarriage of passengers is normally not allowed during training flights.\n\nHowever, to this rule the following exceptions apply:\n\nOther students may occupy a rear seat when an instructor occupies the Instructor Seat.\nAn instructor may occupy a rear seat when supervising another instructor.\nA representative of the BCAA may occupy a rear seat for inspection purposes.\nA representative of an air carrier may occupy a rear seat for the purpose of evaluating the training.\nA representative of ATC may occupy a rear seat for the purpose of co-ordinating flight operations.\n\nCarriage of passengers during training flights other than mentioned above may be authorized by the Head of Training by means of a written approval.', 'OM_REV_6.0_CANONICAL_PART_1.txt', '6834214aedcee49e3b5bb33463cf5ee991b7f8fa7085f911f8d86f6c764a6c9b', 'OM6_P1_8_6_1'),
('OM6_P1_8.6.2', 'OM', '6.0', 1, '8.6.2', 'Seats and seatbelts (Ref. NCO.OP.150)', '8.6.2 Seats and seatbelts (Ref. NCO.OP.150)\n\nIn the event passengers are carried on board during a training flight, the pilot-in-command shall ensure that, prior to and during taxiing, take-off and landing, and whenever deemed necessary in the interest of safety, each passenger on board occupies a seat or berth and has his/her safety belt or restraint device properly secured.', 'OM_REV_6.0_CANONICAL_PART_1.txt', '1178862be08694965a68c6420d83c91814f401410d4cf3a2579cdf58ab4faf1e', 'OM6_P1_8_6_2'),
('OM6_P1_8.7', 'OM', '6.0', 1, '8.7', 'Information on emergency and survival equipment carried', '8.7 Information on emergency and survival equipment carried\n\nIn accordance with NCO.GEN.130, except for aircraft taking-off and landing at the same aerodrome or operating site, EuroPilot Center shall at all times have available, for immediate communication to rescue coordination centers (RCCs), lists containing information on the emergency and survival equipment carried on board.\n\nReference is made to Annex 37 – Emergency Equipment List.', 'OM_REV_6.0_CANONICAL_PART_1.txt', 'd54d112dcd57e8ef41bba26c9ab3c3c2f4fe170ecf068a981eaa63cb1a3f7e74', 'OM6_P1_8_7'),
('OM6_P1_8.8', 'OM', '6.0', 1, '8.8', 'Aircraft documentation and retention of documents', '8.8 Aircraft documentation and retention of documents', 'OM_REV_6.0_CANONICAL_PART_1.txt', '1409f0683e24cd0ca9b744d4b67a921bea4c64148dda6ddea753ddc44d156369', 'OM6_P1_8_8'),
('OM6_P1_8.8.1', 'OM', '6.0', 1, '8.8.1', 'Documents required on board of the aircraft', '8.8.1 Documents required on board of the aircraft\n\nIn accordance with NCO.GEN.135, the following documents, manuals and information are required on each flight and the pilot-in-command shall make available within a reasonable time of being requested to do so by the competent authority, the documentation required to be carried on board.\n\nDOCUMENTS REQUIRED BY – NCO.GEN.135\n	1.	The Aircraft Flight Manual (AFM), or equivalent document(s)\n	2.	The original certificate of registration *\n	3.	The original certificate of airworthiness (CofA) *\n	4.	The noise certificate, if applicable *\n	5.	The list of specific approvals, if applicable *\n	6.	The aircraft radio licence, if applicable *\n	7.	The third-party liability insurance certificate(s) *\n	8.	The journey log, or equivalent, for the aircraft *\n	9.	Details of the filed ATS flight plan, if applicable\n	10.	Current and suitable aeronautical charts for the route of the proposed flight and all routes along which it is reasonable to expect that the flight may be diverted\n	11.	Procedures and visual signals information for use by intercepting and intercepted aircraft\n	12.	The MEL or CDL, if applicable\n	13.	Any other documentation that may be pertinent to the flight or is required by the States concerned with the flight\n\nReference is made to OM Annex 38 – Safety & Emergency Signals.\n\nNote 1:\nOn flights intending to take off and land at the same aerodrome or operating site, or remaining within a distance or area determined by the BCAA, the documents marked with an * may be retained at the aerodrome or operating site.\n\nNote 2:\nIn case of loss or theft of any of the above documents, the training operation may continue until the flight reaches the base or a place where a replacement document can be provided.\n\nNote 3:\nThe above documents, including aeronautical charts, may be available in a form other than on printed paper. An electronic storage medium is acceptable if accessibility, usability and reliability can be assured.\n\nThe Garmin G1000 system fulfills the requirement AMC1 NCO.GEN.135(a)(10) when the aeronautical navigation database is up to date. The topographical system data should be reasonably recent, having regard to the nature of the planned operation. Access to another electronic or paper chart is highly recommended but not required.', 'OM_REV_6.0_CANONICAL_PART_1.txt', '81d7b418ed2efe6ba19420fabb3b250124f1706455b11f9307bf64242565504c', 'OM6_P1_8_8_1'),
('OM6_P1_8.8.2', 'OM', '6.0', 1, '8.8.2', 'Training documents and storage period', '8.8.2 Training documents and storage period\n\nAll theoretical knowledge, flight and synthetic flight training conducted within EuroPilot Center shall be documented by means of the standard Evaluation Forms and Attendance Sheets, filled out and digitally signed by both the respective instructor and the student.\n\nAll forms shall be filed in the Individual Student Training File on the E-gle Platform.\n\nAll Individual Student Training Files will be stored on the E-gle Platform for a period of at least five (5) years.', 'OM_REV_6.0_CANONICAL_PART_1.txt', 'e74ebcb64c8672c658ccc9f058fc060f612a395e9b9920450e2fdf640320f01e', 'OM6_P1_8_8_2'),
('OM6_P1_8.9', 'OM', '6.0', 1, '8.9', 'Transport of dangerous goods', '8.9 Transport of dangerous goods\n\nIn accordance with NCO.GEN.140 regarding the transport of dangerous goods, the following paragraphs apply.', 'OM_REV_6.0_CANONICAL_PART_1.txt', '7a4f8d2e77256cebaeeb16126bcb73782a0409ca2b232e0aaafd23304b4b2208', 'OM6_P1_8_9'),
('OM6_P1_8.9.1', 'OM', '6.0', 1, '8.9.1', 'Definition', '8.9.1 Definition\n\nThe ICAO defines dangerous goods as articles or substances which are capable of posing a risk to health, safety, property or the environment, and which are shown in the list of dangerous goods in the technical instructions or which are classified according to those instructions.\n\nDangerous goods are classified into nine hazard classes:\n\nClass 1 – Explosives\nClass 2 – Gases\nClass 3 – Flammable liquids\nClass 4 – Flammable solids\nClass 5 – Oxidizing agents and organic peroxides\nClass 6 – Toxic and infectious substances\nClass 7 – Radioactive materials\nClass 8 – Corrosives\nClass 9 – Miscellaneous hazardous substances', 'OM_REV_6.0_CANONICAL_PART_1.txt', '0f6173d7549042398f4c898a5c1e3fa8d095d00617d5496e6a338cd5eccfadcb', 'OM6_P1_8_9_1'),
('OM6_P1_8.9.2', 'OM', '6.0', 1, '8.9.2', 'EuroPilot Center Dangerous Goods Policy', '8.9.2 EuroPilot Center Dangerous Goods Policy\n\nWhile EuroPilot Center has no approval nor any intention to transport dangerous goods on purpose, students, flight instructors and passengers may not always be aware that certain items carried on board could be classified as dangerous goods.\n\nIn order to create awareness and mitigate the risk of hidden dangerous goods on board training flights, instructors are encouraged to use the published IATA safety leaflets and brief students about forbidden items on board an aircraft.\n\nThe pilot-in-command shall ensure that everyone on board has been provided with information about dangerous goods in accordance with the Technical Instructions.', 'OM_REV_6.0_CANONICAL_PART_1.txt', 'bc326c2d0780d8afab5fe3e5f0ce97eb6246851c0b84c84d1be735d5702bbc60', 'OM6_P1_8_9_2'),
('OM6_P1_8.9.3', 'OM', '6.0', 1, '8.9.3', 'Dangerous goods accidents/incidents and reporting', '8.9.3 Dangerous goods accidents/incidents and reporting\n\nAny type of dangerous goods incident or accident, or the finding of forbidden dangerous goods in passenger or crew baggage, or on the person of a passenger or crew member, must be reported.\n\nThe pilot-in-command shall:\n\nFile an occurrence report (electronic filing through the EPC SMS System); and\nEnsure that the EuroPilot Center Safety Manager reports without delay and within 72 hours of the event to the BCAA and the appropriate authority of the State of occurrence, in the event of any dangerous goods accident or incident.\n\n9. SAFETY AND SECURITY', 'OM_REV_6.0_CANONICAL_PART_1.txt', 'bd5a12a631dfd58a53ac18187afa2748246a0793cb34232f258a9f400beeebdd', 'OM6_P1_8_9_3'),
('OM6_P1_9.1', 'OM', '6.0', 1, '9.1', 'Safety Measures and Procedures', '9.1 Safety Measures and Procedures', 'OM_REV_6.0_CANONICAL_PART_1.txt', 'b265aebb2ee17f8cc5ef8b125134d51524e261446e297b837c0a7ce757e0dc48', 'OM6_P1_9_1'),
('OM6_P1_9.1.1', 'OM', '6.0', 1, '9.1.1', 'Visual look-out', '9.1.1 Visual look-out\nThe general rule to maintain a visual look-out to avoid collision with other flying objects or obstacles shall be enforced during VFR flights, VFR portions enroute and visual circuits.\n\nSpecial attention must be paid to the traffic situation at or in the vicinity of a VFR aerodrome or an aerodrome with mixed VFR and IFR traffic.', 'OM_REV_6.0_CANONICAL_PART_1.txt', '9557e592530aabcfbca82ab25bb05e5d14d7a6dafef2251a48bbb9388c37aa1c', 'OM6_P1_9_1_1'),
('OM6_P1_9.1.10', 'OM', '6.0', 1, '9.1.10', 'Ground Proximity Detection (Ref. NCO.OP.195)', '9.1.10 Ground Proximity Detection (Ref. NCO.OP.195)\nWhen undue proximity to the ground is detected by the pilot-in-command or by a ground proximity warning system, the pilot-in-command shall take corrective action immediately in order to establish safe flight conditions.', 'OM_REV_6.0_CANONICAL_PART_1.txt', '951b4e215ecab6886d1306a723b627e0bfbc07178180901f70d4c90dc5bfabec', 'OM6_P1_9_1_10'),
('OM6_P1_9.1.11', 'OM', '6.0', 1, '9.1.11', 'Airborne Collision Avoidance System – ACAS II (Ref. NCO.OP.200)', '9.1.11 Airborne Collision Avoidance System – ACAS II (Ref. NCO.OP.200)\nWhen ACAS II is used, operational procedures and training shall be in accordance with Regulation (EU) No 1332/2011.\n\nNote: Currently no aircraft are equipped with ACAS II.', 'OM_REV_6.0_CANONICAL_PART_1.txt', 'b7c820b1502d7ac7b42bb1fcba1ed677294f0821410da33ab91ffc1ac0236123', 'OM6_P1_9_1_11'),
('OM6_P1_9.1.12', 'OM', '6.0', 1, '9.1.12', 'Ice and other contaminants', '9.1.12 Ice and other contaminants\nGround procedures (Ref. NCO.OP.165)\nThe pilot-in-command shall only commence take-off if the aircraft is clear of any deposit that might adversely affect the performance or controllability of the aircraft, except as permitted in the AFM.\n\nNote:\nIf there is any snow, ice or frost on the aircraft during pre-flight, the aircraft shall be made snow, ice and frost free before departing. In such event, the instructor must be informed immediately.\n\nFlight procedures (Ref. NCO.OP.170)\nThe pilot-in-command shall only commence a flight or intentionally fly into expected or actual icing conditions if the aircraft is certified and equipped to cope with such conditions.\n\nIf icing exceeds the intensity for which the aircraft is certified, or if an aircraft not certified for flight in known icing conditions encounters icing, the pilot-in-command shall exit the icing conditions without delay by a change of level and/or route and, if necessary, by declaring an emergency to ATC.', 'OM_REV_6.0_CANONICAL_PART_1.txt', 'a9ff4dcde2c2a4708ec4dc11461cc700c0768e5de12b1acdb8f9ba16915f4f11', 'OM6_P1_9_1_12'),
('OM6_P1_9.1.13', 'OM', '6.0', 1, '9.1.13', 'Simulated situations in flight (Ref. NCO.OP.180)', '9.1.13 Simulated situations in flight (Ref. NCO.OP.180)\nThe pilot-in-command shall, when carrying passengers or cargo, not simulate:\n\nSituations that require the application of abnormal or emergency procedures; or\nFlight in instrument meteorological conditions (IMC).\n\nNote 1:\nThe above does not apply to training flights with student pilots on board.\n\nNote 2:\nIntentional spin manoeuvres are only performed if the aircraft is spin approved and at all times with a supervising instructor on board.\n\nNote 3:\nNo engine shall be shut down in a single-engine aircraft for simulated emergency exercises.', 'OM_REV_6.0_CANONICAL_PART_1.txt', 'e8d043d55b493b08c348637f36e29e0c4fe4e9c6d3c99218e7515d5fb4542702', 'OM6_P1_9_1_13'),
('OM6_P1_9.1.2', 'OM', '6.0', 1, '9.1.2', 'Use of safety belts', '9.1.2 Use of safety belts\nThe safety belt must be worn at all times by the student and/or instructor.', 'OM_REV_6.0_CANONICAL_PART_1.txt', '05242ecf6a39528b11cab6e3a71c624948b5fedbd0388e465a330431920b8659', 'OM6_P1_9_1_2'),
('OM6_P1_9.1.3', 'OM', '6.0', 1, '9.1.3', 'Instructor Take Over', '9.1.3 Instructor Take Over\nIn case of an Instructor Take Over, the following applies:\n\nInstructor:\n“MY CONTROLS”\n(Instructor takes over the controls)\n\nStudent:\n“YOUR CONTROLS”\n(Student releases the controls)\n\nInstructor:\n“MY CONTROLS”\n(Instructor confirms he has the controls)\n\nIn case the student wants to transfer the controls, the following applies:\n\nStudent:\n“YOUR CONTROLS”\n(Student releases the controls)\n\nInstructor:\n“MY CONTROLS”\n(Instructor takes over the controls)\n\nStudent:\n“YOUR CONTROLS”\n(Student confirms he has transferred the controls)', 'OM_REV_6.0_CANONICAL_PART_1.txt', '47ef88047eb3d9af0721fb465e8da2af1887e22f4326b625f308eecb33e01528', 'OM6_P1_9_1_3'),
('OM6_P1_9.1.4', 'OM', '6.0', 1, '9.1.4', 'Securing of aircraft', '9.1.4 Securing of aircraft\nCaution is required when taxiing into confined spaces close to hangars or other aircraft.\n\nTaxi lines should be followed and aircraft should be parked safely in order not to cause any hazards or obstruction to other aircraft or emergency vehicles on the manoeuvring area.\n\nParked aircraft must be properly secured using chocks, tie-downs, control locks and pitot covers.\n\nSpecial attention must be paid during windy weather conditions.\n\nTow bars shall never be left connected to the nose wheel unattended due to the risk of propeller strike.', 'OM_REV_6.0_CANONICAL_PART_1.txt', 'f24971ee3c507de5677e7218542def03d98f85e2a9c69b27c3b3d1b47e95ea27', 'OM6_P1_9_1_4'),
('OM6_P1_9.1.5', 'OM', '6.0', 1, '9.1.5', 'Fuel reserve', '9.1.5 Fuel reserve\nNo flights shall be conducted under any circumstances using any class or type of aircraft for EuroPilot Center flight operations unless a landing can be made at the intended airport of landing with a minimum of the reserve fuel stated in the Operations Manual, Part 3, Chapter 2.3.', 'OM_REV_6.0_CANONICAL_PART_1.txt', 'f3ea56d32ac6342d1d1f09d6f31a1fd27d9fb2f773b265e45ee192c18dbdefae', 'OM6_P1_9_1_5'),
('OM6_P1_9.1.6', 'OM', '6.0', 1, '9.1.6', 'Collision avoidance', '9.1.6 Collision avoidance\nThe student and/or instructor must ensure:\n\nAll windshields and side windows are clean and clear of obstructions.\nSelecting the correct flight altitudes.\nApplying the proper pattern entry procedure and subsequently flying the proper pattern.\nRemaining alert at all times in the air and on the ground and using the proper traffic scanning method.', 'OM_REV_6.0_CANONICAL_PART_1.txt', '825ac5f7856df041c1633029ffb29b95b64113a22050d17d9e68399f58d2245c', 'OM6_P1_9_1_6'),
('OM6_P1_9.1.7', 'OM', '6.0', 1, '9.1.7', 'Other general flight safety rules', '9.1.7 Other general flight safety rules\nThe student and/or instructor must ensure:\n\nA proper pre-flight inspection has been carried out before each flight.\nAll applicable checklists are used.\nAccurate knowledge of the aircraft fuel system, capacity and fuel consumption.', 'OM_REV_6.0_CANONICAL_PART_1.txt', 'b1c06e57834a604c3ddbded5d83763ad4fff96c66a882dc07530da07626556fb', 'OM6_P1_9_1_7'),
('OM6_P1_9.1.8', 'OM', '6.0', 1, '9.1.8', 'Smoking on board (Ref. NCO.OP.155)', '9.1.8 Smoking on board (Ref. NCO.OP.155)\nSmoking is prohibited on board of any aircraft operated by EuroPilot Center.', 'OM_REV_6.0_CANONICAL_PART_1.txt', 'd869d3baeffb76a7907d264b4a2a70a6e644c6e37a7670c4b791849ee585c820', 'OM6_P1_9_1_8'),
('OM6_P1_9.1.9', 'OM', '6.0', 1, '9.1.9', 'Refuelling (Ref. NCO.OP.145)', '9.1.9 Refuelling (Ref. NCO.OP.145)\nThe aircraft shall not be refuelled with aviation gasoline (AVGAS), wide-cut type fuel, or a mixture of these types of fuel with people on board.', 'OM_REV_6.0_CANONICAL_PART_1.txt', '5454fe5f21ece6af207fdf925ad4c8fd4c11e5eb77920e92b619b1207f7c7e16', 'OM6_P1_9_1_9'),
('OM6_P1_9.2', 'OM', '6.0', 1, '9.2', 'FNPT II Simulator', '9.2 FNPT II Simulator\n\nBefore starting an FNPT II training session, the Flight Instructor or Synthetic Training Instructor in charge must ascertain that each person present in the Synthetic Training Device has been properly briefed regarding the position of the emergency stop switches, if present, and any means of evacuation available in case of emergency.\n\nAll persons present in the Synthetic Training Device shall be properly secured by all safety belts and/or harnesses provided from the moment the motion starts until the simulator has come to a full stop.\n\nThe total number of persons present in the simulator shall never exceed the number of seats available with safety belts.\n\nSmoking, consumption of food and/or drinks and the use of cell phones are not allowed in the simulator.\n\nReference is made to OM Annex 02 – Synthetic Training Device Safety Briefing.', 'OM_REV_6.0_CANONICAL_PART_1.txt', '71bb757953bb8fc2b1315f43e13a77c707860e96a963412ebd635299dad18aef', 'OM6_P1_9_2'),
('OM6_P1_9.3', 'OM', '6.0', 1, '9.3', 'Premises and Airport Apron', '9.3 Premises and Airport Apron', 'OM_REV_6.0_CANONICAL_PART_1.txt', 'a3a3c9275d676a6087e7398290100ee40654bd70c7d551a21d0132ff0c89ea4e', 'OM6_P1_9_3'),
('OM6_P1_9.3.1', 'OM', '6.0', 1, '9.3.1', 'Main Training Location – Antwerp, Belgium (EBAW)', '9.3.1 Main Training Location – Antwerp, Belgium (EBAW)\nThe EuroPilot Center premises comply with all applicable safety requirements and the following equipment is available:\n\nEmergency fluorescent lighting.\nEmergency exit signage.\nEmergency exits in accordance with the standard commercial building code.\nEmergency escape ladder on the first floor.\nSmoke detectors in all required areas.\nTwo standard fire extinguishers.\nOne CO2 fire extinguisher for FSTD use.\nFirst aid kits.', 'OM_REV_6.0_CANONICAL_PART_1.txt', '4a40f0698c52bb8c25968064b1965548028bfe1e2e74a6251d7a0e2063743989', 'OM6_P1_9_3_1'),
('OM6_P1_9.3.2', 'OM', '6.0', 1, '9.3.2', 'Satellite Training Location – Thermal, California USA (KTRM)', '9.3.2 Satellite Training Location – Thermal, California USA (KTRM)\nThe EuroPilot Center premises comply with all applicable safety requirements and the following equipment is available:\n\nEmergency fluorescent lighting.\nEmergency exit signage.\nEmergency exits in accordance with the standard commercial building code.\nSmoke detectors in all required areas.\nFive fire extinguishers plus four fire extinguishers inside the hangars.\nOne CO2 fire extinguisher for FSTD use.\nFirst aid kits.', 'OM_REV_6.0_CANONICAL_PART_1.txt', '40d657e9c18aff30f7e57272917e924002ff3c57840a317c3b05e085b6147ebf', 'OM6_P1_9_3_2'),
('OM6_P1_9.4', 'OM', '6.0', 1, '9.4', 'Reporting of occurrences, incidents and accidents', '9.4 Reporting of occurrences, incidents and accidents', 'OM_REV_6.0_CANONICAL_PART_1.txt', '70ecc14104a05e2f2dcb4e56c8dbdfec36f01ce62dbe558379f77e4acc4e15d7', 'OM6_P1_9_4'),
('OM6_P1_9.4.1', 'OM', '6.0', 1, '9.4.1', 'Occurrence report system – general', '9.4.1 Occurrence report system – general\nThe occurrence report system is part of the Safety Management System used to report occurrences relating to flight safety.\n\nReference is made to the Organization Management Manual, Part 3, Chapter 5.6.4.', 'OM_REV_6.0_CANONICAL_PART_1.txt', 'b7f27d709a00954bdc7674bd61bfd2a08bd586e1dd2e490a3776aa118c1c5c03', 'OM6_P1_9_4_1'),
('OM6_P1_9.5', 'OM', '6.0', 1, '9.5', 'Procedure to be followed in case of incidents or accidents', '9.5 Procedure to be followed in case of incidents or accidents\n\nThe procedure as described in the Organization Management Manual, Part 3, Chapter 5.8, shall be followed in case of accident or incident.', 'OM_REV_6.0_CANONICAL_PART_1.txt', 'cd6358e6190fab276bd031aaa7839ea44225c2d3d9550b2ea6b102cefd2e3fc9', 'OM6_P1_9_5'),
('OM6_P1_9.6', 'OM', '6.0', 1, '9.6', 'Radio listening watch', '9.6 Radio listening watch\n\nIt is EuroPilot Center procedure to tune the COM 2 audio box of the aircraft on the International Emergency Frequency (121.500).\n\nBoth instructor and student should maintain a listening watch at all times, if not disturbing for the training activity.', 'OM_REV_6.0_CANONICAL_PART_1.txt', '77f0d513ec1b43073575485ace54dea9675098046ced50f0490bb1fcbe3b7b9a', 'OM6_P1_9_6'),
('OM6_P1_9.7', 'OM', '6.0', 1, '9.7', 'Safety pilots', '9.7 Safety pilots\n\nNot applicable for training within EuroPilot Center.', 'OM_REV_6.0_CANONICAL_PART_1.txt', '7427866fe3c1cc282583d69ccb1f2a7fda97a198d57416ecea96d7ce81c4f1d9', 'OM6_P1_9_7'),
('OM6_P2_1.1', 'OM', '6.0', 2, '1.1', 'Cessna C172SP – G1000', '1.1 Cessna C172SP – G1000\n\nThe aircraft used for Flight Training within EuroPilot Center include the Cessna C172SP – G1000.\n\nThe C172SP (Skyhawk) is an all-metal, four-place, high-wing, single-engine aircraft equipped with tricycle landing gear and designed for general utility and training purposes.\n\nEngine\nNumber of engines: 1\nEngine manufacturer: Textron Lycoming\nEngine model number: IO-360-L2A\nEngine type: Normally aspirated, direct drive, air-cooled, horizontally opposed, fuel injected, four-cylinder engine with 360.0 cu.in. displacement\nHorsepower rating and engine speed: 180 BHP at 2700 RPM\n\nPropeller\nPropeller manufacturer: McCauley Propeller Systems\nPropeller model number: 1A170E/JHA7660\nNumber of blades: 2\nPropeller diameter: 76 inches\nPropeller type: Fixed pitch\n\nFuel\nApproved fuels: AVGAS 100LL or AVGAS 100\nTotal capacity: 56.0 US gallons\nTotal usable: 53.0 US gallons\nTotal capacity each tank: 28.0 US gallons\nTotal usable each tank: 26.5 US gallons\n\nOil\nApproved oil (all temperatures): W100 or equivalent (refer to maintenance)\nOil sump capacity: 8.0 US quarts\nTotal oil capacity: 9.0 US quarts\n\nDimensions\nWingspan: 11 m\nWing area: 16.16 square meters\nLength: 8.3 m\nTail height: 2.5 m\nPropeller ground clearance: 28.6 cm\nMinimum turn radius: 8.4 m\n\nMasses\nStandard empty mass: 755 kg\nMaximum useful load (traffic load + usable fuel): 405 kg\nMaximum ramp mass (normal category): 1,160 kg\nMaximum ramp mass (utility category): 1,000 kg\nMaximum take-off mass (normal category): 1,156 kg\nMaximum take-off mass (utility category): 998 kg\nMaximum landing mass (normal category): 1,156 kg\nMaximum landing mass (utility category): 998 kg', 'OM_REV_6.0_CANONICAL_PART_2.txt', 'd5f6d794eb5e40b33a121f35534bb1fab84512d91b1a6461959b937568bfa77a', 'OM6_P2_1_1'),
('OM6_P2_1.2', 'OM', '6.0', 2, '1.2', 'Diamond DA42', '1.2 Diamond DA42\n\nThe Diamond DA42 is a composite, four-place, low-wing, multi-engine aircraft equipped with tricycle landing gear and designed for general utility and training purposes.\n\nEngine\nNumber of engines: 2\nEngine manufacturer: Continental\nEngine model number: CD-135\nEngine type: Liquid-cooled, four-cylinder, four-stroke diesel-cycle engine with wet sump lubrication, inline construction, common-rail direct injection, reduction gear (1:1.69)\nHorsepower rating and engine speed: 135 HP at 2,300 RPM per engine\n\nPropellers\nPropeller manufacturer: MT-Propeller\nNumber of blades: 3\nPropeller type: Constant speed, feathering\nPropeller diameter: 187 cm\nPropeller pitch angle:', 'OM_REV_6.0_CANONICAL_PART_2.txt', '91030cf61606ca7ec6f116c243e29eb972b24b21d4df3b5ecd4e0be8f01f8144', 'OM6_P2_1_2'),
('OM6_P2_12', 'OM', '6.0', 2, '12', 'degrees (low pitch)', '12 degrees (low pitch)', 'OM_REV_6.0_CANONICAL_PART_2.txt', '0c9f20202c5d08282f8a6b4ccc6adc7bb7eac9d3ed4f77034512be02521935c0', 'OM6_P2_12'),
('OM6_P2_15', 'OM', '6.0', 2, '15', 'degrees (start lock)', '15 degrees (start lock)', 'OM_REV_6.0_CANONICAL_PART_2.txt', '2a3e6b162f818975832532139655d12dab97d859825045424bafa6bc0ce270e2', 'OM6_P2_15'),
('OM6_P2_2.1', 'OM', '6.0', 2, '2.1', 'Checklists', '2.1 Checklists', 'OM_REV_6.0_CANONICAL_PART_2.txt', '3bb8febce0d3798805219ecb0acbc9e3e5bd0dca048a89a23c45186b3f9631be', 'OM6_P2_2_1'),
('OM6_P2_2.1.1', 'OM', '6.0', 2, '2.1.1', 'Use of Checklists', '2.1.1 Use of Checklists\nThe standard way of operating the aircraft in single-pilot operations is by means of checklists. There are three types of checklists:\n\nScan flows\nRead and do\nRecall\n\nScan flows are performed from top to bottom and from left to right. Every instrument and switch in the cockpit is checked in a logical order and the required actions are performed for the relevant phase of flight. Scan flows can be performed both on the ground and in flight.\n\nRead-and-do checklists are performed only on the ground, with the exception of specific emergency checklists. An item is read out and thereafter the required action is performed.\n\nRecall checklists are performed by heart. All in-flight checklists are recall checklists and must be known by heart at all times.\n\nAll checklists must be carried out loud and clear and announced, for example “Before Start Checklist”, and finished with “Before Start Checklist Completed”.', 'OM_REV_6.0_CANONICAL_PART_2.txt', '8309103e751626a5b89ade6a47ed420174dc7e52a5ee8f1e90c801698e27e342', 'OM6_P2_2_1_1'),
('OM6_P2_2.1.2', 'OM', '6.0', 2, '2.1.2', 'Checklist Overview', '2.1.2 Checklist Overview\nThe following checklists will be performed for the applicable aircraft types:\n\nExternal inspection (walk-around)\nBefore starting engine\nStarting engine\nAfter start\nTaxi\nBefore take-off\nLine-up\nTake-off\nAfter take-off / climb\nCruise\nDescent / approach\nLanding\nGo-around\nAfter landing\nSecuring the aircraft\n\nReference is made to:\n\nOM Annex 03 – Checklist Cessna 172SP\nOM Annex 04 – Cross Reference List C172SP Checklist\nOM Annex 25 – Checklist Diamond DA42', 'OM_REV_6.0_CANONICAL_PART_2.txt', 'a1aaf1c28c88fc4578a073fded7a79e4d1a6abf1fa3926c6180057141b24c6ef', 'OM6_P2_2_1_2'),
('OM6_P2_2.2', 'OM', '6.0', 2, '2.2', 'Standard Operating Procedures', '2.2 Standard Operating Procedures', 'OM_REV_6.0_CANONICAL_PART_2.txt', 'c3dd1005e21ace26666029ff6e72b685d8d73bf449f4d295b745b3afcfc745c4', 'OM6_P2_2_2'),
('OM6_P2_2.2.1', 'OM', '6.0', 2, '2.2.1', 'Cessna C172SP – G1000', '2.2.1 Cessna C172SP – G1000\nReference is made to OM Annex 07 – Standard Operating Procedures Cessna C172SP.', 'OM_REV_6.0_CANONICAL_PART_2.txt', 'dbf79ca87edf4fbcc60ed8e95300e99e41968c8839d5b8b6372edfb945be0036', 'OM6_P2_2_2_1'),
('OM6_P2_2.2.2', 'OM', '6.0', 2, '2.2.2', 'Diamond DA42', '2.2.2 Diamond DA42\nReference is made to the Pilot Operating Handbook (POH), Section 4A – Normal Operating Procedures.', 'OM_REV_6.0_CANONICAL_PART_2.txt', '837a5ff7db2124ff9f087349b401477b68b189134babbfdaa2dba06eb43c121c', 'OM6_P2_2_2_2'),
('OM6_P2_2.3', 'OM', '6.0', 2, '2.3', 'Limitations', '2.3 Limitations\n\nAll aircraft shall be operated in accordance with the applicable operating limitations as described in the Pilot Operating Handbook (POH).\n\nFor the Cessna C172SP – G1000, reference is made to POH Part 2 – Operating Limitations, Chapters 2-4 through 2-23.\n\nFor the Diamond DA42, reference is made to POH Section 1 – Limitations, Pages 2-4 through 2-36.', 'OM_REV_6.0_CANONICAL_PART_2.txt', '916e8c41250865f95cfdc156cded1485d0d2935c30742d8d7057bf936ab64520', 'OM6_P2_2_3'),
('OM6_P2_2.4', 'OM', '6.0', 2, '2.4', 'Maintenance', '2.4 Maintenance', 'OM_REV_6.0_CANONICAL_PART_2.txt', '2a8bf33321cd8558ed0795e781cf3d6463a38cbf7b7819d7126895d8f3eef31d', 'OM6_P2_2_4'),
('OM6_P2_2.4.1', 'OM', '6.0', 2, '2.4.1', 'Maintenance Organisation Subcontractor', '2.4.1 Maintenance Organisation Subcontractor\nAircraft maintenance is provided in accordance with applicable EASA regulations via the following subcontractors:\n\nSTYL AVIATION – EASA Part-M Subpart F\nASP AVIONICS – EASA Part-145\nLAMBERT AIRCRAFT ENGINEERING\nLA QUINTA AIR SERVICES (USA – FAA Repair Station)', 'OM_REV_6.0_CANONICAL_PART_2.txt', 'd2bc44b97b1e8f3f5cea7c08f6db4e559b2bc428cfdb0c9a4d9efcf20c447d69', 'OM6_P2_2_4_1'),
('OM6_P2_2.4.2', 'OM', '6.0', 2, '2.4.2', 'CAMO Subcontractor', '2.4.2 CAMO Subcontractor\nContinuing Airworthiness Management is provided by STYL AVIATION in accordance with EASA Part-M.', 'OM_REV_6.0_CANONICAL_PART_2.txt', '3cf31bb62d76ba9ffcc365df20e2b03ad939390e17b6f7646868879eead0a26b', 'OM6_P2_2_4_2'),
('OM6_P2_2.4.3', 'OM', '6.0', 2, '2.4.3', 'Release to Service after Maintenance', '2.4.3 Release to Service after Maintenance\nNo aircraft may be released to service unless a Certificate of Release to Service has been issued in accordance with EASA Part-M.', 'OM_REV_6.0_CANONICAL_PART_2.txt', '3ae7176821228bf9ecb79dccea80f88f6a60ab6bc2efa43d6f1fe18ca0008ca9', 'OM6_P2_2_4_3'),
('OM6_P2_2.5', 'OM', '6.0', 2, '2.5', 'Aircraft Journey Logs', '2.5 Aircraft Journey Logs\n\nIn accordance with NCO.GEN.150, each journey shall be retained for each flight, or series of flights, in the form of a journey log or equivalent.\n\nThe aircraft journey log should include the following items where applicable:\n\nAircraft nationality and registration\nDate\nName of crew member(s)\nDuty assignments of crew members, if applicable\nPlace of departure\nPlace of arrival\nTime of departure\nTime of arrival\nHours of flight\nNature of flight\nIncidents and observations, if any\nSignature of the pilot-in-command\n\nThe aircraft journey logs provided by the country of registration of the relevant aircraft, fulfilling the requirements above, shall be used within EuroPilot Center.\n\nThe aircraft journey log must be filled out by the flight instructor or by the student in case of solo flights.\n\n\n\nElectronic Dispatch / Check-In System\nThe online scheduling system provides an electronic backup for the paper logbooks and is used to record, distribute and communicate important flight data to the EuroPilot Center administration, including:\n\nFlight and instruction times\nMaintenance follow-up\nTrouble report items\nFuel consumption\nInstructor and student duty times\nSpecial remarks\n\nBefore each training session, the instructor is responsible for dispatching the flight by verifying the Hobbs and/or Tacho times entered by the previous pilot and the expected fuel and oil on board.\n\nImmediately after each training session, the instructor is responsible for checking the flight in and entering the Hobbs and/or Tacho times, remaining fuel and oil, flight and ground instruction times and trouble report items.\n\nThis task may be delegated to an Operations Officer, but the final responsibility remains with the instructor.', 'OM_REV_6.0_CANONICAL_PART_2.txt', '1457cda1c60d03c2bf57aefc68b26a9eab64b9d26e5ec7327cefe78a38306309', 'OM6_P2_2_5'),
('OM6_P2_2.6', 'OM', '6.0', 2, '2.6', 'Technical Logs', '2.6 Technical Logs', 'OM_REV_6.0_CANONICAL_PART_2.txt', '39dbe76437b2c997e521c34bdb3812030e92a792e03bb0925a4bad99a1f9f059', 'OM6_P2_2_6'),
('OM6_P2_2.6.1', 'OM', '6.0', 2, '2.6.1', 'Aircraft Defect Reporting', '2.6.1 Aircraft Defect Reporting\nAll aircraft defects must be reported immediately before, during or after the flight by the Pilot-in-Command in the applicable paper Aircraft Trouble Report and via the electronic check-in process.\n\nAny deferred aircraft defect shall be reported by the responsible maintenance engineer in the applicable paper and electronic Aircraft Trouble Report.\n\nWhen an item has been repaired, it must be signed off by the maintenance engineer, including a description of the action taken.\n\nIt remains the responsibility of the Pilot-in-Command to check the paper and electronic Trouble Report before each flight in order to assess the airworthiness requirements for the intended operation.\n\nReference is made to:\n\nOM Annex 10 – Trouble Report C172SP G1000\nOM Annex 11 – Trouble Report Robinson R44\nOM Annex 30 – Trouble Report Diamond DA42', 'OM_REV_6.0_CANONICAL_PART_2.txt', 'de6e3d9a8a2681d4856eba9dacdef74b48ff278d36d4f43f36146c25e18bb5af', 'OM6_P2_2_6_1'),
('OM6_P2_2.6.2', 'OM', '6.0', 2, '2.6.2', 'Procedure in Case of Aircraft Defects', '2.6.2 Procedure in Case of Aircraft Defects', 'OM_REV_6.0_CANONICAL_PART_2.txt', 'e3e113f8a8dffc5d73fc6acf86ee16155dcd045797610a3bc0429414c22bacd1', 'OM6_P2_2_6_2'),
('OM6_P2_2.6.2.1', 'OM', '6.0', 2, '2.6.2.1', 'Defect Discovered by the Pilot-in-Command', '2.6.2.1 Defect Discovered by the Pilot-in-Command\nThe Pilot-in-Command shall contact the applicable maintenance subcontractor. The authorized maintenance engineer shall decide whether the defect seriously affects flight safety or whether it can be deferred.\n\nIf deferred, the defect shall be entered in the Aircraft Trouble Report, placarded as required, and signed by the authorized maintenance engineer.', 'OM_REV_6.0_CANONICAL_PART_2.txt', '090045c22e2a1c8b75714b5bc67ec03214d36a3cf9ed6e14aaa0c9e770e76dca', 'OM6_P2_2_6_2_1'),
('OM6_P2_2.6.2.2', 'OM', '6.0', 2, '2.6.2.2', 'Defect Discovered by Maintenance Personnel', '2.6.2.2 Defect Discovered by Maintenance Personnel\nWhen a defect is discovered by authorized maintenance personnel and does not seriously affect flight safety, it may be deferred and recorded accordingly.', 'OM_REV_6.0_CANONICAL_PART_2.txt', 'f22bebbf46f364c6fdcd7842fd343091ba1887577098991adfb1c6617ba66ee7', 'OM6_P2_2_6_2_2'),
('OM6_P2_2.6.2.3', 'OM', '6.0', 2, '2.6.2.3', 'Dispatch of an Aircraft with Deferred Items', '2.6.2.3 Dispatch of an Aircraft with Deferred Items\nThe aircraft shall only be dispatched when all required Trouble Report entries have been made, deferred items placarded, equipment requirements met, and the Pilot-in-Command can ensure the safety of the flight.', 'OM_REV_6.0_CANONICAL_PART_2.txt', 'e319a4c7f6f2bb75979b2f319b383f1ed694060e70cf0ed2030bef29d96d14f5', 'OM6_P2_2_6_2_3'),
('OM6_P2_2.7', 'OM', '6.0', 2, '2.7', 'Aircraft Weighing Procedures', '2.7 Aircraft Weighing Procedures\n\nIn accordance with NCO.POL.105, the mass and centre of gravity of the aircraft have been established by actual weighing prior to initial entry into service.\n\nThis information can be found in the Weight Report or Fleet Masses Document.\n\nThe accumulated effects of modifications and repairs on mass and balance shall be accounted for and documented.\n\nReference is made to OM Annex 40 – Fleet Masses.\n\n\n3. EMERGENCY PROCEDURES', 'OM_REV_6.0_CANONICAL_PART_2.txt', '29bb081c667dd107e67aabd7f8ec4367ffef0779d75e350e6510b28b108258aa', 'OM6_P2_2_7'),
('OM6_P2_3.1', 'OM', '6.0', 2, '3.1', 'Emergency Procedures – Cessna C172SP – G1000', '3.1 Emergency Procedures – Cessna C172SP – G1000\n\nA detailed description of the emergency procedures applicable to the Cessna C172SP – G1000 can be found in the following tables.\n\nThe emergency procedures are grouped under the following categories:\n\nENGINE RELATED FAILURES\nFIRE AND SMOKE\nICING\nLANDING GEAR\nELECTRICAL EQUIPMENT\nFLIGHT INSTRUMENTS\nLIGHTING\nFLIGHT CONTROLS\nFUEL SYSTEM\nCOMMUNICATION\nMISCELLANEOUS\n\nThe emergency procedures described in the tables are derived from the applicable Pilot Operating Handbook (POH) and shall be applied as required.', 'OM_REV_6.0_CANONICAL_PART_2.txt', '563fe7e92aa8a1e94a3cafa56389d5b34169e1783a3fb16c5f2de43c0f597fbe', 'OM6_P2_3_1'),
('OM6_P2_3.2', 'OM', '6.0', 2, '3.2', 'Emergency Procedures – Diamond DA42', '3.2 Emergency Procedures – Diamond DA42\n\nA detailed description of the emergency procedures applicable to the Diamond DA42 can be found in the following tables.\n\nThe emergency procedures are grouped under the following categories:\n\nENGINE RELATED FAILURES\nFIRE AND SMOKE\nICING\nLANDING GEAR\nELECTRICAL EQUIPMENT\nFLIGHT INSTRUMENTS\nLIGHTING\nFLIGHT CONTROLS\nFUEL SYSTEM\nCOMMUNICATION\nMISCELLANEOUS\n\nThe emergency procedures described in the tables are derived from the applicable Pilot Operating Handbook (POH) and shall be applied as required.\n\n4. RADIO AND NAVIGATION AIDS', 'OM_REV_6.0_CANONICAL_PART_2.txt', '2a61f08f9f1a3879b5a5a2ce7bd818b8235fa5af1729c807b93bc9a81b681171', 'OM6_P2_3_2'),
('OM6_P2_4.1', 'OM', '6.0', 2, '4.1', 'Cessna C172SP – G1000', '4.1 Cessna C172SP – G1000', 'OM_REV_6.0_CANONICAL_PART_2.txt', 'ba410690d0ab53007cda590460f1858fc3abb2d78e709d1e3e3b8d5a4483db4d', 'OM6_P2_4_1'),
('OM6_P2_4.1.1', 'OM', '6.0', 2, '4.1.1', 'Cockpit layout', '4.1.1 Cockpit layout\n	1.	MASTER Switch (ALT and BAT)\n	2.	STBY BATT Switch\n	3.	STBY BATT Test Annunciator\n	4.	AVIONICS Switch (BUS 1 and BUS 2)\n	5.	Primary Flight Display\n	6.	Standby Airspeed Indicator\n	7.	Audio Control Panel\n	8.	Standby Attitude Indicator\n	9.	Standby Altimeter\n	10.	Multifunction Display\n	11.	ELT Remote Switch / Annunciator\n	12.	Flight Hour Recorder\n	13.	Bendix / King KR87 ADF (not installed)\n	14.	Microphone Button\n	15.	Glove Box\n	16.	Cabin Heat Control\n	17.	Cabin Air Control\n	18.	Wing Flap Control and Position Indicator\n	19.	Mixture Control Knob\n	20.	Handheld Microphone\n	21.	Fuel Shutoff Valve\n	22.	Fuel Selector Valve\n	23.	12V / 10A Power Outlet\n	24.	AUX Audio Input Jack\n	25.	Elevator Trim Control Wheel and Position Indicator\n	26.	Throttle Control Knob (with friction lock)\n	27.	Go-Around Button\n	28.	ALT Static Air Valve Control\n	29.	Yoke Mounted Map Light\n	30.	Parking Brake Handle\n	31.	Circuit Breaker Panel\n	32.	Electrical Switch Panel\n	33.	MAGNETOS / START Switch\n	34.	Dimming Panel', 'OM_REV_6.0_CANONICAL_PART_2.txt', 'ca95b7b1329b4dc14aeb88f63bde870af3057376924523f4d93f667fa69e928b', 'OM6_P2_4_1_1'),
('OM6_P2_4.1.2', 'OM', '6.0', 2, '4.1.2', 'G1000 Equipment', '4.1.2 G1000 Equipment\nThe Cessna C172SP is equipped with a Garmin G1000 Integrated Avionics System.\n\nThe Garmin G1000 Avionics System is an integrated flight control and navigation system. The system combines primary flight instruments, communications, aircraft system information and navigational information, all displayed on two colour displays.\n\nThe G1000 system consists of the following equipment:\n\nTwo Garmin Display Units (GDU)\nOne Audio Panel (GMA)\nTwo Integrated Avionics Units (GIA), including GPS / VHF NAV and COM, ADF and DME\nOne Attitude and Heading Reference System (AHRS)\nOne Magnetometer – Flux Valve (GRS)\nOne Air Data Computer (GDC)\nOne Engine Monitor, Engine and Airframe Unit (GEA)\nOne Mode-S Transponder (GTX)\nOne Automatic Flight Control System (GFC)\n\nProper training is provided to all flight instructors and students with respect to the G1000 system.\n\nA computer-based self-study course (CBT) is provided, including a familiarisation session on the G1000 trainer.', 'OM_REV_6.0_CANONICAL_PART_2.txt', 'fea35caff13958f40333302c03e0b2fbc3fe53ce8e656cafeb6e9e0380cd2c1a', 'OM6_P2_4_1_2'),
('OM6_P2_4.2', 'OM', '6.0', 2, '4.2', 'Diamond DA42', '4.2 Diamond DA42\n\n5. MINIMUM EQUIPMENT LIST (MEL)\n\n6. INSTRUMENTS, DATA AND EQUIPMENT', 'OM_REV_6.0_CANONICAL_PART_2.txt', '7cf3c816ddf2d02d9568b1319b289489a533d47b32d74dcae3ccbe0b960aebd1', 'OM6_P2_4_2'),
('OM6_P2_4.2.1', 'OM', '6.0', 2, '4.2.1', 'Cockpit layout', '4.2.1 Cockpit layout\n	1.	Electric Master Switch\n	2.	Avionics Master Switch\n	3.	Engine Master Switches\n	4.	Start Switch\n	5.	Pitot / Stall Warning Heat Switch\n	6.	Alternator Switches\n	7.	ECU Test Buttons\n	8.	ECU Swap Switches\n	9.	Rotary buttons for instrument lighting and flood light\n	10.	Light Switches\n	11.	Emergency Switch\n	12.	Flap Selector Switch\n	13.	Landing Gear Switch\n	14.	Alternate Static Valve\n	15.	Microphone Socket\n	16.	Ventilation Nozzles\n	17.	Circuit Breakers\n	18.	Backup Airspeed Indicator\n	19.	Backup Artificial Horizon\n	20.	Backup Altimeter\n	21.	Emergency Compass\n	22.	ELT Control Unit\n	23.	Primary Flight Display (PFD)\n	24.	Audio Amplifier / Intercom / Marker Beacon Receiver\n	25.	Multi-Function Display (MFD)\n	26.	De-ice Control Panel\n	27.	Autopilot Control Unit\n	28.	Alternate Air Lever\n	29.	Landing Gear Emergency Extension Lever\n	30.	Oxygen Pressure Knob\n	31.	Oxygen Control Knob\n\n\n5. MINIMUM EQUIPMENT LIST (MEL)\n\nEuroPilot Center does not apply operational procedures in accordance with NCO.IDE.A.105 to dispatch an aircraft with inoperative equipment through a Minimum Equipment List (MEL).\n\nAlternatively, in accordance with Commission Regulation (EC) No. 2042/2003, M.A.403, any defect that hazards seriously the flight safety shall be rectified before further flight.\n\nOnly authorized certifying staff (maintenance engineers) may decide whether an aircraft defect hazards seriously the flight safety and therefore decide when and which rectification action shall be taken before further flight and which defect rectification can be deferred.\n\nAny aircraft defect that would not hazard seriously the flight safety shall be rectified as soon as practicable after the date the defect was first identified and within any limits specified in the maintenance data.\n\nAny defect not rectified before flight shall be recorded in the aircraft maintenance record system and all deferred defects shall be made known to the pilot / flight crew via the paper and electronic Trouble Report.\n\nDeferred defects shall be transferred by maintenance onto worksheets at the next appropriate maintenance check.\n\nAny deferred defect which is not rectified during the maintenance check shall be re-entered onto a new deferred defect record sheet.\n\nThe original date of the defect shall be retained.\n\nThe necessary components or parts needed for rectification shall be made available or ordered on a priority basis and fitted at the earliest opportunity.\n\nNote:\nAs EuroPilot Center has no MEL procedure in place, the decision to defer an aircraft defect cannot be taken by the Pilot-in-Command but must be taken by an authorized maintenance engineer.\nThe decision to dispatch the aircraft after an item has been deferred lies with the Pilot-in-Command.\n\n\n\n6. INSTRUMENTS, DATA AND EQUIPMENT', 'OM_REV_6.0_CANONICAL_PART_2.txt', '5ca997bc17ebd85c23f4dd4b5114adb424c5c493ccb86c6863cb86f02891187d', 'OM6_P2_4_2_1'),
('OM6_P2_6.1', 'OM', '6.0', 2, '6.1', 'Airplanes', '6.1 Airplanes\n\nIn accordance with NCO.IDE.A.100, the following instruments and equipment, when required for the intended flight operations, shall be approved in accordance with the applicable airworthiness requirements if they are:\n\nUsed by the flight crew to control the flight path;\nUsed to comply with NCO.IDE.A.190 (radio communication equipment requirements);\nUsed to comply with NCO.IDE.A.195 (navigation equipment requirements);\nInstalled in the airplane.\n\nThe following items, when required for the intended flight operations, do not need equipment approval:\n\nSpare fuses;\nIndependent portable lights;\nAn accurate timepiece;\nFirst-aid kit;\nSurvival and signaling equipment;\nSea anchor and equipment for mooring;\nChild restraint device.\n\nInstruments and equipment not required for the intended flight operations, as well as any other equipment not required by other applicable Annexes but carried on a flight, shall comply with the following:\n\nThe information provided shall not be used by the flight crew to comply with operational communication or navigation requirements;\nThe equipment shall not affect the airworthiness of the airplane, even in case of failure or malfunction.\n\nInstruments and equipment shall be readily operable or accessible from the flight crew station.\n\nAll required emergency equipment shall be easily accessible for immediate use.', 'OM_REV_6.0_CANONICAL_PART_2.txt', '6917fccd0fa5007b272e07b858a80de83c334d8c28f7a566d289d081589dcb74', 'OM6_P2_6_1'),
('OM6_P2_6.1.1', 'OM', '6.0', 2, '6.1.1', 'Spare Electrical Fuses', '6.1.1 Spare Electrical Fuses\n\nIn accordance with NCO.IDE.A.110, a spare electrical fuse means a replaceable fuse in the flight crew compartment, not an automatic circuit breaker or circuit breakers in the electric compartments.\n\nWhen replaceable fuses are used in the aircraft, airplanes shall be equipped with spare electrical fuses, of the ratings required for complete circuit protection, for replacement of those fuses that are allowed to be replaced in flight.', 'OM_REV_6.0_CANONICAL_PART_2.txt', '56dd2f558a79cc2daef8491f2dea2f0808a40b4fbb42db891791f05203750128', 'OM6_P2_6_1_1'),
('OM6_P2_6.1.10', 'OM', '6.0', 2, '6.1.10', 'Supplemental Oxygen', '6.1.10 Supplemental Oxygen\n\nIn accordance with NCO.OP.190, the pilot-in-command shall ensure that all flight crew members engaged in performing duties essential to the safe operation of an aircraft in flight use supplemental oxygen continuously whenever he/she determines that at the altitude of the intended flight the lack of oxygen might result in impairment of the faculties of crew members, and shall ensure that supplemental oxygen is available to passengers when lack of oxygen might harmfully affect passengers.\n\nIn any other case when the pilot-in-command cannot determine how the lack of oxygen might affect all occupants on board, he/she shall ensure that:\n\nAll crew members engaged in performing duties essential to the safe operation of an aircraft in flight use supplemental oxygen for any period in excess of 30 minutes when the pressure altitude in the passenger compartment will be between 10,000 ft and 13,000 ft; and\nAll occupants use supplemental oxygen for any period that the pressure altitude in the passenger compartment will be above 13,000 ft.', 'OM_REV_6.0_CANONICAL_PART_2.txt', 'a070539895ee5100fb2f5697243484d243e5fed9ea8bd2d525b29f3560af80a0', 'OM6_P2_6_1_10'),
('OM6_P2_6.1.10.1', 'OM', '6.0', 2, '6.1.10.1', 'Pressurized airplanes', '6.1.10.1 Pressurized airplanes\nNo pressurized airplanes are operated at EuroPilot Center, consequently NCO.IDE.A.150 is not applicable.', 'OM_REV_6.0_CANONICAL_PART_2.txt', '692a173229626333df65ff85feffcf10a77deb545d658f0f7b0024db115c7f64', 'OM6_P2_6_1_10_1'),
('OM6_P2_6.1.10.2', 'OM', '6.0', 2, '6.1.10.2', 'Non-pressurized airplanes', '6.1.10.2 Non-pressurized airplanes\nIn accordance with NCO.IDE.A.155, non-pressurized airplanes operated when an oxygen supply is required shall be equipped with oxygen storage and dispensing apparatus capable of storing and dispensing the required oxygen supplies.', 'OM_REV_6.0_CANONICAL_PART_2.txt', '74c529877849b3160142025ed63389d3e853e6441eca2f2b55e4511d229c952b', 'OM6_P2_6_1_10_2'),
('OM6_P2_6.1.11', 'OM', '6.0', 2, '6.1.11', 'Hand Fire Extinguishers', '6.1.11 Hand Fire Extinguishers\n\nAirplanes shall be equipped with at least one hand fire extinguisher:\n\nIn the flight crew compartment; and\nIn each passenger compartment that is separate from the flight crew compartment, except if the compartment is readily accessible to the flight crew.\n\nThe type and quantity of extinguishing agent for the required fire extinguishers shall be suitable for the type of fire likely to occur in the compartment where the extinguisher is intended to be used and to minimise the hazard of toxic gas concentration in compartments occupied by persons.', 'OM_REV_6.0_CANONICAL_PART_2.txt', '3fce42530a06d5a4a42605f9bdaf039664beabc722ae3e9306bc30b87c84637e', 'OM6_P2_6_1_11'),
('OM6_P2_6.1.12', 'OM', '6.0', 2, '6.1.12', 'Marking of Break-In Points', '6.1.12 Marking of Break-In Points\n\nIn accordance with NCO.IDE.A.165, marking of break-in points is not applicable for any airplane at EuroPilot Center.', 'OM_REV_6.0_CANONICAL_PART_2.txt', '451e8a403ad2dec79338b97c16eaed86e35b14b9b0a35fe9da227f795059b9c2', 'OM6_P2_6_1_12'),
('OM6_P2_6.1.13', 'OM', '6.0', 2, '6.1.13', 'Emergency Locator Transmitters (ELT)', '6.1.13 Emergency Locator Transmitters (ELT)\n\nIn accordance with NCO.IDE.A.170, airplanes shall be equipped with:\n\nAn ELT of any type, when first issued with an individual Certificate of Airworthiness on or before 1 July 2008;\nAn automatic ELT, when first issued with an individual Certificate of Airworthiness after 1 July 2008; or\nA survival ELT (ELT(S)) or a personal locator beacon (PLB), carried by a crew member or a passenger, when certified for a maximum passenger seating configuration of six or less.\n\nNote:\nELTs of any type and PLBs shall be capable of transmitting simultaneously on 121.5 MHz and 406 MHz.\n\nNote:\nAll batteries used in ELTs or PLBs should be replaced (or recharged, if the battery is rechargeable) when the equipment has been in use for more than one cumulative hour or in the following cases:\n\nWith EASA Form 1, replaced or recharged before the end of their useful life in accordance with the maintenance instructions;\nWith no EASA Form 1, replaced or recharged when 50 percent of their useful life (or for rechargeable batteries, 50 percent of their useful life of charge) has expired;\nIn PLBs, replaced or recharged when 50 percent of their useful life (or for rechargeable batteries, 50 percent of their useful life of charge) has expired;\nNot applicable to batteries unaffected during probable storage intervals.\n\nNote:\nThe new expiry date for a replaced or recharged battery should be legibly marked on the outside of the equipment.', 'OM_REV_6.0_CANONICAL_PART_2.txt', 'e401178593b051ab7d6673101f6615466810ea63cf2578dc4ee54d9f6633b128', 'OM6_P2_6_1_13'),
('OM6_P2_6.1.14', 'OM', '6.0', 2, '6.1.14', 'Flight over Water', '6.1.14 Flight over Water\n\nIn accordance with NCO.IDE.A.175, the airplane shall be equipped with a life-jacket for each person on board (or equivalent individual flotation device) for each person on board younger than 24 months, that shall be worn or stowed in a position that is readily accessible from the seat or berth of the person for whose use it is provided:\n\nWhen operating the Cessna C172SP over water beyond gliding distance from land; or taking off or landing at an aerodrome or operating site where, in the opinion of the pilot-in-command, the take-off or approach path is so disposed over water that there would be a likelihood of a ditching;\nWhen operating the Cessna C172SP or Diamond DA42 at a distance away from land where an emergency landing is possible greater than that corresponding to 30 minutes at normal cruising speed or 50 NM, whichever is less.\n\nThe pilot-in-command of an airplane operated at a distance away from land where an emergency landing is possible greater than that corresponding to 30 minutes at normal cruising speed or 50 NM, whichever is the lesser, shall determine the risks to survival of the occupants of the airplane in the event of a ditching, based on which he/she shall determine the carriage of:\n\nEquipment for making the distress signals;\nLife-rafts in sufficient numbers to carry all persons on board, stowed so as to facilitate their ready use in emergency; and\nLife-saving equipment, to provide the means of sustaining life, as appropriate to the flight to be undertaken.', 'OM_REV_6.0_CANONICAL_PART_2.txt', 'bb57d5f8aaa287cc3437b94f7c9eff2e252ad5336e7c7d7b4fca9bd86a2baeaf', 'OM6_P2_6_1_14'),
('OM6_P2_6.1.15', 'OM', '6.0', 2, '6.1.15', 'Survival Equipment', '6.1.15 Survival Equipment\n\nIn accordance with NCO.IDE.A.180, when operating an airplane over areas in which search and rescue would be especially difficult, the airplane shall be equipped with such signaling devices and life-saving equipment, including means of sustaining life, as may be appropriate to the area overflown.', 'OM_REV_6.0_CANONICAL_PART_2.txt', '205d762d0181178a7faf4fad76eba0db67dbefb2a51a88834c1deefe60fc08f2', 'OM6_P2_6_1_15'),
('OM6_P2_6.1.16', 'OM', '6.0', 2, '6.1.16', 'Radio Communication Equipment', '6.1.16 Radio Communication Equipment\n\nIn accordance with NCO.IDE.A.190, airplanes shall be equipped with radio communication equipment capable of conducting two-way communication with those aeronautical stations and on those frequencies to meet airspace requirements.\n\nRadio communication equipment shall provide for communication on the aeronautical emergency frequency 121.5 MHz.\n\nWhen more than one communication equipment unit is required, each shall be independent of the other or others to the extent that a failure in any one will not result in failure of any other.', 'OM_REV_6.0_CANONICAL_PART_2.txt', '1920c05d32b02e5e03840156e1ef6daee41584532e0c1f395be2cfface7f7c43', 'OM6_P2_6_1_16'),
('OM6_P2_6.1.17', 'OM', '6.0', 2, '6.1.17', 'Navigation Equipment', '6.1.17 Navigation Equipment\n\nIn accordance with NCO.IDE.A.195, when the airplane is intended to be operated over routes that cannot be navigated by reference to visual landmarks, it shall be equipped with any navigation equipment necessary to enable it to proceed in accordance with:\n\nThe ATS flight plan, if applicable; and\nThe applicable airspace requirements.\n\nThe airplane shall have sufficient navigation equipment to ensure that, in the event of the failure of one item of equipment at any stage of the flight, the remaining equipment shall allow safe navigation, or an appropriate contingency action, to be completed safely.\n\nWhen the airplane is intended to land in IMC, it shall be equipped with suitable equipment capable of providing guidance to a point from which a visual landing can be performed.\n\nFor Performance Based Navigation (PBN) operations, the airplane shall meet the airworthiness certification requirements for the appropriate navigation specification.', 'OM_REV_6.0_CANONICAL_PART_2.txt', '3184ae4f05e79e3a046dd10de8d1f5ab7709e496da5d9d0cb90846018d81717a', 'OM6_P2_6_1_17'),
('OM6_P2_6.1.18', 'OM', '6.0', 2, '6.1.18', 'Transponder', '6.1.18 Transponder\n\nIn accordance with NCO.IDE.A.200, the airplane shall be equipped with a secondary surveillance radar (SSR) transponder with all the required capabilities, where required by the airspace being flown.', 'OM_REV_6.0_CANONICAL_PART_2.txt', 'c31f3461b07cfed5954493b6a2c23e0a7d082542a71533a38ea24ed3a4711101', 'OM6_P2_6_1_18'),
('OM6_P2_6.1.2', 'OM', '6.0', 2, '6.1.2', 'Operating Lights', '6.1.2 Operating Lights\n\nIn accordance with NCO.IDE.A.115, airplanes operated at night shall be equipped with:\n\nAn anti-collision light system;\nNavigation / position lights;\nA landing light;\nLighting supplied from the airplane’s electrical system to provide adequate illumination for all instruments and equipment essential to the safe operation of the airplane;\nLighting supplied from the airplane’s electrical system to provide illumination in all passenger compartments;\nAn independent portable light for each crew member station.', 'OM_REV_6.0_CANONICAL_PART_2.txt', '6cd341f4be563e3b43e10c0335309397d32c7ba3572cd250130d7a2c57997f21', 'OM6_P2_6_1_2'),
('OM6_P2_6.1.3', 'OM', '6.0', 2, '6.1.3', 'Equipment for Operations under VFR / DAY', '6.1.3 Equipment for Operations under VFR / DAY\n\nIn accordance with NCO.IDE.A.120, airplanes operated under VFR by day shall be equipped with:\n\nMagnetic heading;\nTime, in hours, minutes and seconds;\nPressure altitude;\nIndicated airspeed.', 'OM_REV_6.0_CANONICAL_PART_2.txt', '9f7b5d2b43e290cad635301943953f368ff12a9f86a6e91387ac8d47e5910c9f', 'OM6_P2_6_1_3'),
('OM6_P2_6.1.4', 'OM', '6.0', 2, '6.1.4', 'Equipment for Operations under VFR / NIGHT', '6.1.4 Equipment for Operations under VFR / NIGHT\n\nIn accordance with NCO.IDE.A.120, airplanes operated under VFR by night, shall in addition be equipped with a means of measuring and displaying:\n\nTurn and slip;\nAttitude;\nVertical speed;\nStabilized heading;\nAnd a means of indicating when the supply of power to the gyroscopic instruments is not adequate.\n\nNote:\nEuroPilot Center does not allow any training operation in IMC without being under IFR (therefore the requirement of having an operative pitot heater is not applicable for VFR DAY & NIGHT).\n\nNote:\nFor VFR night flights that do not exceed 60 minutes duration, that take off and land at the same aerodrome, and that remain within 50 NM of that aerodrome, an equivalent means of complying with having a Turn and Slip and an Attitude Indicator are either:\n\nA turn and slip indicator only; or\nA turn coordinator only; or\nBoth an Attitude Indicator and a Slip Indicator.', 'OM_REV_6.0_CANONICAL_PART_2.txt', '1532f459a11300d31cef972358f83f78f46cc1f228d40c3d62d943f32987ce75', 'OM6_P2_6_1_4'),
('OM6_P2_6.1.5', 'OM', '6.0', 2, '6.1.5', 'Equipment for Operations under IFR', '6.1.5 Equipment for Operations under IFR\n\nIn accordance with NCO.IDE.A.125, airplanes operated under IFR shall be equipped with a means of measuring and displaying the following:\n\nMagnetic heading;\nTime in hours, minutes and seconds;\nPressure altitude;\nIndicated airspeed;\nVertical speed;\nTurn and slip;\nAttitude;\nStabilized heading;\nOutside air temperature;\nA means of indicating when the supply of power to the gyroscopic instruments is not adequate; and\nA means of preventing malfunction of the airspeed indicating system due to condensation or icing.\n\nNote:\nA means of measuring and displaying the time in hours, minutes and seconds may be a wrist watch capable of the same functions.\n\nNote:\nIndividual equipment requirements may be met by combinations of instruments, by integrated flight systems or by a combination of parameters on electronic displays. The information so available to each required pilot should not be less than that required in the applicable operational requirements, and the equivalent safety of the installation should be approved during type certification of the airplane for the intended type of operation.\n\nNote:\nThe means of measuring and indicating turn and slip, airplane attitude and stabilized airplane heading may be met by combinations of instruments or by integrated flight director systems, provided that the safeguards against total failure, inherent in the three separate instruments, are retained.', 'OM_REV_6.0_CANONICAL_PART_2.txt', 'b222bab202867bf9c702b46ac7c371531aeb3ed43f67a9788af7354e67167faa', 'OM6_P2_6_1_5'),
('OM6_P2_6.1.6', 'OM', '6.0', 2, '6.1.6', 'Terrain Awareness System (TAWS)', '6.1.6 Terrain Awareness System (TAWS)\n\nIn accordance with NCO.IDE.A.130, a Terrain Awareness System is not applicable for training operations within EuroPilot Center.', 'OM_REV_6.0_CANONICAL_PART_2.txt', '22cfe7138bfc75ee0d2a03e649dc50f46a8631ea161f49837b41b6404e004352', 'OM6_P2_6_1_6'),
('OM6_P2_6.1.7', 'OM', '6.0', 2, '6.1.7', 'Flight Crew Interphone (Intercom) System', '6.1.7 Flight Crew Interphone (Intercom) System\n\nIn accordance with NCO.IDE.A.135, during flight training operations with students, two flight crew members are required; consequently a flight crew interphone (Intercom) system, including headsets and microphones for use by all flight crew members shall be installed and must be operational.\n\nNote 1:\nThe flight crew interphone system should not be of a handheld type.\n\nNote 2:\nHeadset boom microphones should be of the noise cancelling type.\n\nNote 3:\nIf the intention is to utilize noise cancelling earphones, the pilot-in-command should ensure that the earphones do not attenuate any aural warnings or sounds necessary for alerting the flight crew on matters related to the safe operation of the airplane.', 'OM_REV_6.0_CANONICAL_PART_2.txt', '7a8ed0b8f6364365e0ec853df02ee298ee5d4c4b099258889196bad80f70913f', 'OM6_P2_6_1_7'),
('OM6_P2_6.1.8', 'OM', '6.0', 2, '6.1.8', 'Seats, Seat Safety Belts, Restraint Systems and Child Restraint Devices', '6.1.8 Seats, Seat Safety Belts, Restraint Systems and Child Restraint Devices\n\nIn accordance with NCO.IDE.A.140, airplanes shall be equipped with:\n\nA seat or berth for each person on board who is aged 24 months or more;\nA seat belt on each passenger seat and restraining belts for each berth;\nA child restraint device (CRD) for each person on board younger than 24 months; and\nA seat belt with upper torso restraint system on each flight crew seat, having a single point release for airplanes having a Certificate of Airworthiness first issued on or after 25 August 2016.\n\nNote:\nIt is EuroPilot Center’s policy not to take any passengers at an age younger than 24 months unless with special authorization from the Head of Training.', 'OM_REV_6.0_CANONICAL_PART_2.txt', 'be7b4551a6c67df709006d6d892d7883ed55da101418750e3e6d44500e45369b', 'OM6_P2_6_1_8'),
('OM6_P2_6.1.9', 'OM', '6.0', 2, '6.1.9', 'First-Aid Kit', '6.1.9 First-Aid Kit\n\nIn accordance with NCO.IDE.A.145, all airplanes shall be equipped with a first-aid kit:\n\nReadily accessible for use;\nKept up-to-date;\nLocated inside the airplane cabin and indicated by a recognizable sign.\n\nThe location shall be briefed to all occupants of the airplane before the flight.\n\nThe contents of the First Aid Kits will be supplemented, based on the Internal Risk Assessment covering the entire scope of EuroPilot Center’s Training Operation, as follows:\n\nAppropriate medication, limited to: Anti-diarrhea, Anti-nausea, an Antihistamine (Diphenhydramine), Hydrocortisone cream, Pain Relievers (Paracetamol / Ibuprofen);\nBandages (assorted sizes, including a triangular bandage);\nBurns dressings (large and small);\nWound dressings (large and small);\nAdhesive dressings (assorted sizes);\nAntiseptic wound cleaner;\nSafety scissors;\nDisposable gloves;\nDisposable resuscitation aid;\nSurgical masks.\n\nTo be kept up-to-date, the first-aid kit should be:\n\nInspected periodically to confirm that contents are maintained in proper condition;\nReplenished at regular intervals, in accordance with instructions contained on their labels, or as circumstances warrant;\nReplenished after use in-flight at the first opportunity where replacement items are available.\n\nIMPORTANT:\nNothing of the medication listed above shall be advised nor administered by any staff member of EuroPilot Center. It is the responsibility of EuroPilot Center staff members to inform occupants of the airplane about the availability of these medications. The responsibility and decision whether or not to take any of these medications rests solely with the occupant, preferably advised by a Licensed Medical Practitioner.', 'OM_REV_6.0_CANONICAL_PART_2.txt', '36da950e90ca564d71942ebe6708c751e9dd40e5b9c9ebf6cf1242a4a337d58e', 'OM6_P2_6_1_9'),
('OM6_P2_81', 'OM', '6.0', 2, '81', 'degrees (feathered)', '81 degrees (feathered)\n\nFuel\nApproved fuels:\nJet A-1 (ASTM D1655)\nJet A (ASTM D1655)\nJet Fuel No. 3 (GB6537-94)\nDiesel (EN 590) and blends\n\nTotal capacity without auxiliary tanks: 52.0 US gallons\nTotal usable without auxiliary tanks: 50.0 US gallons\nTotal capacity with auxiliary tanks: 79.4 US gallons\nTotal usable with auxiliary tanks: 76.4 US gallons\nTotal capacity each main tank: 26.0 US gallons\nTotal usable each main tank: 25.0 US gallons\nTotal capacity each auxiliary tank: 13.7 US gallons\nTotal usable each auxiliary tank: 13.2 US gallons\n\nOil and Coolants\nApproved engine oil:\nShell Helix Ultra 5W-30\nShell Helix Ultra 5W-40\nAeroshell Oil Diesel 10W-40\nor equivalent (refer to maintenance)\n\nApproved gearbox oil:\nShell EP 75W90 API GL-4\nShell Spirax GSX 75W-80\n\nApproved coolant:\nWater / BASF Glysantin Protect Plus / G48\n\nDimensions\nWingspan: 13.42 m\nWing area: 16.29 square meters\nLength: 8.56 m\nTail height: 2.49 m\n\nMasses\nMinimum flight mass: 1,250 kg\nMaximum take-off mass:\n1,700 kg (without MAM 42-088)\n1,785 kg (with MAM 42-088)\n\nMaximum zero fuel mass:\n1,674 kg (with OAM 42-188 and OAM 42-195)\n\nMaximum landing mass:\n1,700 kg (without MAM 42-088)\n1,785 kg (with MAM 42-195)\n\nMaximum load in nose baggage compartment: 30 kg\nMaximum load in cabin baggage extension: 18 kg\nMaximum load cabin baggage compartment and extension combined: 45 kg\n\n2. AIRCRAFT HANDLING', 'OM_REV_6.0_CANONICAL_PART_2.txt', '8dd09818192b83fda294c9084b9a366865472c54f192dd32d23eb82824ba0b58', 'OM6_P2_81'),
('OM6_P3_1.000', 'OM', '6.0', 3, '1.000', 'Kg', '1.000 Kg\nChapter 5, Page 17 - Fig 5-5 (Sheet 3)', 'OM_REV_6.0_CANONICAL_PART_3.txt', '7cd081e719f62c71dca77591982ca732b5f426a39351be386cde8c42983dda6b', 'OM6_P3_1_000'),
('OM6_P3_1.089', 'OM', '6.0', 3, '1.089', 'Kg', '1.089 Kg\nChapter 5, Page 16 - Fig 5-5 (Sheet 2)\nTOM', 'OM_REV_6.0_CANONICAL_PART_3.txt', '32940cb967fbf99c5e3f7083abab5572613b11715e9ef41299b90cf25eb377a6', 'OM6_P3_1_089'),
('OM6_P3_1.1', 'OM', '6.0', 3, '1.1', 'Take Off', '1.1 Take Off', 'OM_REV_6.0_CANONICAL_PART_3.txt', '1dbe45d69c391b8cbcd9812b3a53c5e1acdecab76849256c5d7fb0d1b1f5098c', 'OM6_P3_1_1'),
('OM6_P3_1.1.1', 'OM', '6.0', 3, '1.1.1', 'Take Off performance C172SP', '1.1.1 Take Off performance C172SP\nSince the only Take Off requirement for a Single Engine Airplane is the Field Length, the Pilot In Command must ensure that:\nWhen no stopway or clearway is available, the calculated Take Off distance when multiplied by', 'OM_REV_6.0_CANONICAL_PART_3.txt', 'cfe4b309638bd7f8210122bfd40578789cf348ec13baa57cebcf02b6200a1c9a', 'OM6_P3_1_1_1'),
('OM6_P3_1.1.2', 'OM', '6.0', 3, '1.1.2', 'Take Off performance DA42', '1.1.2 Take Off performance DA42\nWhen no stopway or clearway is available, the calculated Take Off distance when multiplied by', 'OM_REV_6.0_CANONICAL_PART_3.txt', 'b8fb4d5342b29f498c3870e6c0ecf70ad70b3e016ab1e094cdcc885cd55fcbe3', 'OM6_P3_1_1_2'),
('OM6_P3_1.156', 'OM', '6.0', 3, '1.156', 'Kg', '1.156 Kg\nChapter 5, Page 15 - Fig 5-5 (Sheet 1)\nTOM', 'OM_REV_6.0_CANONICAL_PART_3.txt', '4489107732381ef8f709caf7058e56fac60312c2c433f6ff7dd89de26ed8bf9e', 'OM6_P3_1_156'),
('OM6_P3_1.2', 'OM', '6.0', 3, '1.2', 'Enroute / Cruise', '1.2 Enroute / Cruise', 'OM_REV_6.0_CANONICAL_PART_3.txt', '01121812db64da7a3f6e566de506bdf067527ae6432d25403e6167b395f576ce', 'OM6_P3_1_2'),
('OM6_P3_1.2.1', 'OM', '6.0', 3, '1.2.1', 'Cruise performance C172SP', '1.2.1 Cruise performance C172SP\nThe aircraft may not be assumed to be flying above the altitude at which a rate of climb of 300 ft/min is attained.\nThe net gradient of descent, in the event of engine failure, shall be the gross gradient of descent increased by a gradient of 0.5%\nThe maximum altitude at which a rate of climb of 300 ft/min is attained (Service Ceiling) is: 14.000 ft.\nNet gradient of descent can be determined under:\nChapter 3, Page 26 - Fig 3-1 (Corresponds to: 10,97% or 6,26 degrees in zero wind conditions).\nCruise Performance Tables can be found under:\nChapter 5, Page 20 - Fig 5-8 (Sheet 1)\nChapter 5, Page 21 - Fig 5-8 (Sheet 2) Cruise Range Profiles can be found under:\nChapter 5, Page 22 - Fig 5-9\nCruise Endurance Profiles can be found under:\nChapter 5, Page 23 - Fig 5-10', 'OM_REV_6.0_CANONICAL_PART_3.txt', 'af2d0b5abc4efe941b39cc1794447bc3bc031770ce3fe95ec1e8ca5643616443', 'OM6_P3_1_2_1'),
('OM6_P3_1.2.2', 'OM', '6.0', 3, '1.2.2', 'Cruise performance DA42', '1.2.2 Cruise performance DA42\nThe aircraft may not be assumed to be flying above the altitude at which a rate of climb of 300 ft/min is attained.\nThe assumed en-route gradient with one engine inoperative shall be the gross gradient of descent or climb, as appropriate, respectively increased by a gradient of 0,5%, or decreased by a gradient of 0,5%.\nWe refer to the DA42 POH, Section 5 - Performance.', 'OM_REV_6.0_CANONICAL_PART_3.txt', '230c50b12e226d321e865fcba2fd261f5357bb67c1de72abf9992a2efeffeca2', 'OM6_P3_1_2_2'),
('OM6_P3_1.25', 'OM', '6.0', 3, '1.25', 'must not exceed the Take Off Run Available (TORA) or;', '1.25 must not exceed the Take Off Run Available (TORA) or;\nWhen a stopway and/or clearway is available, the calculated Take Off distance must:\nnot exceed Take Off Run Available (TORA)\nwhen multiplied by 1,3 not exceed Accelerate Stop Distance Available (ASDA)\nwhen multiplied by 1.15, not exceed Take Off Distance Available (TODA)\nNote: It is EuroPilot Center policy not to take off with tailwind.\nThe Take Off distance for the DA42 can be determined via the tables in the POH. Conservative distances can be established by reading the chart at the next higher value of weight, altitude and temperature. The above mentioned safety margins need to be added.\nWe refer to the DA42 POH, Section 5 - Performance.\n\nIn addition to the field length requirements, a Multi Engine Airplane should also consider the obstacle clearance requirements:\n\nThe pilot in command must ensure that take-off flight path should clear all obstacles by a vertical margin of at least 50 ft, or by a horizontal distance of at least 90 m plus 0,125 x D, where D is the horizontal distance travelled by the Airplane from the end of the take-off distance available or the end of the take-off distance if a turn is scheduled before the end of the take-off distance available except as provided in (b) and (c) below.\nFor Airplanes with a wingspan of less than 60 m such as rhe DA42, a horizontal obstacle clearance of half the Airplane wingspan (6,71 meter) plus 60 m, plus 0,125 x D may be used.\nWhen showing compliance with this subparagraph it must be assumed that:\nThe take-off flight path begins at a height of 50 ft above the surface at the end of the take-off distance required and ends at a height of 1 500 ft above the surface;\nThe Airplane is not banked before the Airplane has reached a height of 50 ft above the surface, and that thereafter the angle of bank does not exceed 15°;\nFailure of the critical engine occurs at the point on the all engine take-off flight path where visual reference for the purpose of avoiding obstacles is expected to be lost;\nThe gradient of the take-off flight path from 50 ft to the assumed engine failure height is equal to the average all- engine gradient during climb and transition to the en-route configuration, multiplied by a factor of 0,77; and\nThe gradient of the take-off flight path from the height reached in accordance with subparagraph 4 above to the end of the take-off flight path is equal to the one engine inoperative en-route climb gradient shown in the Airplane Flight Manual.\nWhen showing compliance with subparagraph (a) above for those cases where the intended flight path does not require track changes of more than 15°, the Pilot in command need not consider those obstacles which have a lateral distance greater than:', 'OM_REV_6.0_CANONICAL_PART_3.txt', 'fba35d31a7d08c79b07ff0bca8dc979e7e6e62aac3ef0f548e2e8b8fce250c3b', 'OM6_P3_1_25'),
('OM6_P3_1.3', 'OM', '6.0', 3, '1.3', 'Landing', '1.3 Landing\n\n2. FLIGHT PLANNING', 'OM_REV_6.0_CANONICAL_PART_3.txt', '68ba02070089adb99d5d7f1c82bce82ebb3bd07ba3bafea3e8fddb39166efc06', 'OM6_P3_1_3'),
('OM6_P3_1.3.1', 'OM', '6.0', 3, '1.3.1', 'Landing performance C172SP', '1.3.1 Landing performance C172SP\nSince the only Landing requirement for a Single Engine aircraft is the Field Length, the Pilot In Command must ensure that:\n\nThe landing distance, from a screen height of 50 ft, must not exceed 70 % of the Landing Distance Available (LDA), i.e. a factor of 1,43.\nIf the landing surface is grass up to 20 cm long on firm soil, the landing distance should be multiplied by a factor of 1,15.\nIf the METAR or TAF or combination of both indicate that the runway may be wet at the estimated time of arrival, the landing distance should be multiplied by a factor of 1,15.\nThe landing distance should be increased by 5% for each 1% downslope. No allowance is permitted for upslope.\n\nThe Landing Distance for the C172SP can be determined via the tables in the POH, keeping in mind that distances shown are based on the short field landing technique. The above mentioned safety margins need to be added.\n\nLM 1.156 Kg Chapter 5, Page 24 - Fig 5-11\n\nNote: It is EuroPilot Center policy not to land with tailwind.', 'OM_REV_6.0_CANONICAL_PART_3.txt', '3192e6e4233016e25e1344b29dd11e89e1e839f8ef309f3f6251a83a920fbe98', 'OM6_P3_1_3_1'),
('OM6_P3_1.3.2', 'OM', '6.0', 3, '1.3.2', 'Landing performance DA42', '1.3.2 Landing performance DA42\nThe landing distance, from a screen height of 50 ft, must not exceed 70 % of the Landing Distance Available (LDA), i.e. a factor of 1,43.\nIf the landing surface is grass up to 20 cm long on firm soil, the landing distance should be multiplied by a factor of 1,15.\nIf the METAR or TAF or combination of both indicate that the runway may be wet at the estimated time of arrival, the landing distance should be multiplied by a factor of 1,15.\nThe landing distance should be increased by 5% for each 1% downslope. No allowance is permitted for upslope.\n\nThe Landing Distance for the DA42 can be determined via the tables in the POH. The above mentioned safety margins need to be added.\nWe refer to the DA42 POH, Section 5 - Performance.\n\nNote: It is EuroPilot Center policy not to land with tailwind.', 'OM_REV_6.0_CANONICAL_PART_3.txt', 'b30a0109a79bb91ee5fc8e08d885a3db4c1e0e4e5870f8a3794ea8b8a64c57cb', 'OM6_P3_1_3_2'),
('OM6_P3_1.3.3', 'OM', '6.0', 3, '1.3.3', 'Take-off and landing climb requirements (Multi Engine Airplanes)', '1.3.3 Take-off and landing climb requirements (Multi Engine Airplanes)\nIn addition to the field length requirements, a Multi Engine Airplane should also consider take off and landing climb requirements:\n\nTake-off climb\n\nAll engines operating:\nThe steady gradient of climb after take-off must be at least 4% with:\n• Take-off power on each engine;\n• The landing gear extended except that if the landing gear can be retracted in not more than 7 seconds, it may be assumed to be retracted;\n• The wing flaps in the take-off position(s); and\n• A climb speed not less than the greater of 1,1 VMC and 1,2 VS1.\n\nOne engine inoperative:\nThe steady gradient of climb at an altitude of 400 ft above the take-off surface must be measurably positive with:\n• The critical engine inoperative and its propeller in the minimum drag position;\n• The remaining engine at take-off power;\n• The landing gear retracted;\n• The wing flaps in the take-off position(s); and\n• A climb speed equal to that achieved at 50 ft.\n\nThe steady gradient of climb must be not less than 0,75 % at an altitude of 1 500 ft above the take-off surface with:\n• The critical engine inoperative and its propeller in the minimum drag position;\n• The remaining engine at not more than maximum continuous power;\n• The landing gear retracted;\n• The wing flaps retracted; and\n• A climb speed not less than 1,2 VS1.\n\nWe refer to the DA42 POH, Section 5 - Performance, chapter 5.3.7.\n\nLanding climb\n\nAll engines operating:\nThe steady gradient of climb must be at least 2,5 % with:\n• Not more than the power or thrust that is available eight seconds after initiation of movement of the power controls from the minimum flight idle position;\n• The landing gear extended;\n• The wing flaps in the landing position; and\n• A climb speed equal to VREF.\n\nOne engine inoperative:\nThe steady gradient of climb must be not less than 0,75 % at an altitude of 1 500 ft above the landing surface with:\n• The critical engine inoperative and its propeller in the minimum drag position;\n• The remaining engine at not more than maximum continuous power;\n• The landing gear retracted;\n• The wing flaps retracted; and\n• A climb speed not less than 1,2 VS1.\n\nWe refer to the DA42 POH, Section 5 - Performance, chapter 5.3.12.\n\n2. FLIGHT PLANNING', 'OM_REV_6.0_CANONICAL_PART_3.txt', '43adec7593fa4fb530c88245ca3d4ce27d3ae5f5efcc111fb0f275703186b7e3', 'OM6_P3_1_3_3'),
('OM6_P3_101', 'OM', '6.0', 3, '101', 'ft – 150 ft | 400 m', '101 ft – 150 ft | 400 m', 'OM_REV_6.0_CANONICAL_PART_3.txt', '0ce144262411f8353ed54e35cd92cfc67d2e01b0ba167f87a27761ee00c830fa', 'OM6_P3_101'),
('OM6_P3_151', 'OM', '6.0', 3, '151', 'ft – 200 ft | 500 m', '151 ft – 200 ft | 500 m', 'OM_REV_6.0_CANONICAL_PART_3.txt', '8feae64406c148c9ceb0312de597bafdce4c0804b5811224bf92871b67859f6d', 'OM6_P3_151'),
('OM6_P3_2.1', 'OM', '6.0', 3, '2.1', 'General', '2.1 General\n\nIn accordance with NCO.OP.135 (a), before commencing a flight, the PIC shall ascertain by every reasonable means available that the space-based facilities (GNSS), ground and/or water facilities, including communication facilities and navigation aids available and directly required on such flight, for the safe operation of the aircraft, are adequate for the type of operation under which the flight is to be conducted.\n\nIn accordance with NCO.OP.135 (b), before commencing a flight, the PIC shall be familiar with all available meteorological information appropriate to the intended flight.\n\nPreparation for a flight away from the vicinity of the place of departure, and for every flight under IFR, shall include at least:\n• A study of available current weather reports and forecasts; and\n• The planning of an alternative course of action to provide for the eventuality that the flight cannot be completed as planned, because of weather conditions.\n\nFurther, in accordance with NCO.OP.175, before commencing take-off, the PIC shall be satisfied that:\n• According to the information available, the weather at the aerodrome or operating site and the condition of the runway or final approach and take-off areas (FATO’s) intended to be used would not prevent a safe take-off and departure; and\n• Applicable aerodrome operating minima will be complied with.\n\nIn accordance with NCO.OP.205, before commencing an approach to land, the pilot-in-command shall be satisfied that:\n• According to the information available, the weather at the aerodrome or the operating site and the condition of the runway or final approach and take-off areas (FATO’s) intended to be used would not prevent a safe approach, landing or missed approach.\n\nAs a reference, the below Preflight Preparation Checklist and paragraphs describe how to prepare a training flight.\n\nStudents are required to be at the airport at least 30 minutes before the scheduled Off Block Time to prepare the flight. During the first two training sessions, the instructor will brief the student about the Preflight Preparation. From the third training mission on, the student is required to perform this tasks individually.\n\nNote: The student must be made aware of the fact that failure, late or inaccurate Preflight Preparation, may lead to the cancellation of the training flight.', 'OM_REV_6.0_CANONICAL_PART_3.txt', 'bf002c4da0d5d74461398fb4d054aa4bf513c7b0f48920c9252d0ef3e9c8a99e', 'OM6_P3_2_1'),
('OM6_P3_2.2', 'OM', '6.0', 3, '2.2', 'The Preflight Preparation Checklist', '2.2 The Preflight Preparation Checklist\n\nNote: The checklist below has been included in the GarminPilot EFB Checklist.', 'OM_REV_6.0_CANONICAL_PART_3.txt', 'c7fe61540cc28d056ceb4e7c29ca32295ffa9a2c884f53265b61f8b2b70d0640', 'OM6_P3_2_2'),
('OM6_P3_2.3', 'OM', '6.0', 3, '2.3', 'Planning Minima for VFR Training Flights', '2.3 Planning Minima for VFR Training Flights\n\nIn accordance with NCO.OP.160 (a) the PIC shall only commence or continue a VFR training flight if the latest available meteorological information indicates that the weather conditions:\nAlong the route; and\nAt the intended destination at the estimated time of use; will be at or above the applicable VFR operating minima.\nNote: The standard VMC minima under 4.1.1 will apply for all dual VFR training flights.', 'OM_REV_6.0_CANONICAL_PART_3.txt', '2aa9b379c56ccd4850ebfe6c06b6b19e14869da5601ec568fbf0c52a4efa8eeb', 'OM6_P3_2_3'),
('OM6_P3_2.4', 'OM', '6.0', 3, '2.4', 'Planning Minima for IFR Training Flights', '2.4 Planning Minima for IFR Training Flights', 'OM_REV_6.0_CANONICAL_PART_3.txt', 'b2a257f0af378dc1b636b7af7f0bf39a077e4a310fcbd6c8ad4ffbf149612936', 'OM6_P3_2_4'),
('OM6_P3_2.4.1', 'OM', '6.0', 3, '2.4.1', 'Meteorological Conditions', '2.4.1 Meteorological Conditions\nIn accordance with NCO.OP.160 (b) the PIC shall only commence or continue an IFR training flight towards the planned destination aerodrome if the latest available meteorological information indicates that at the estimated time of arrival, the weather conditions:\nAt the destination are at or above the applicable aerodrome operating minima as described under 4.2; or\nAt least one destination alternate aerodrome is at or above the applicable aerodrome operating minima described under 4.2.\n\nNote: If a flight contains VFR and IFR segments, the meteorological information referred to in 2.3 and 2.4 above and shall be applicable as far as relevant.', 'OM_REV_6.0_CANONICAL_PART_3.txt', 'bf3c5ad726b11bf3e1b8035c95511213822ccba5f52654e55086212fa2043210', 'OM6_P3_2_4_1'),
('OM6_P3_2.4.2', 'OM', '6.0', 3, '2.4.2', 'Instrument Approach Operations', '2.4.2 Instrument Approach Operations\nIn accordance with NCO.OP.142, the PIC shall ensure that sufficient means are available to navigate and land at the destination aerodrome or at any destination alternate aerodrome in the case of loss of capability for the intended approach and landing operation.', 'OM_REV_6.0_CANONICAL_PART_3.txt', 'b4ae0de160b3b62b0539ad3aabbd08acd8c8f6b5ac1bf406ba4c49ebe003122c', 'OM6_P3_2_4_2'),
('OM6_P3_2.4.3', 'OM', '6.0', 3, '2.4.3', 'Specification of Isolated Aerodromes', '2.4.3 Specification of Isolated Aerodromes\nIn accordance with NCO.OP.105 for the selection of alternate aerodromes and the fuel policy, the PIC shall consider an aerodrome as an isolated aerodrome if the flying time to the nearest adequate destination alternate aerodrome is more than 60 minutes for airplanes with reciprocating engines.', 'OM_REV_6.0_CANONICAL_PART_3.txt', '697076694b46179241b88af071f9a203b095c19b1981c91c3297c963dbf8b90e', 'OM6_P3_2_4_3'),
('OM6_P3_2.4.4', 'OM', '6.0', 3, '2.4.4', 'Take Off Alternate', '2.4.4 Take Off Alternate\nThe PIC shall only commence an IFR training flight if the latest available meteorological information indicates that at the estimated time of arrival, the weather conditions at the departure aerodrome are at or above the applicable aerodrome operating minima as described under 4.2.\nNote: An immediate return to the departure aerodrome should always be possible.', 'OM_REV_6.0_CANONICAL_PART_3.txt', 'be5ff6f1fa4887a3f15baed16d64b3b9e71d4a00b3895a2490a620d9aa661034', 'OM6_P3_2_4_4'),
('OM6_P3_2.4.5', 'OM', '6.0', 3, '2.4.5', 'Destination Alternate', '2.4.5 Destination Alternate\nIn accordance with NCO.OP.140 the PIC shall specify at least one weather-permissible destination alternate aerodrome for an IFR flight in the flight plan, unless:\nThe available current meteorological information indicates that, for the period from 1 hour before until 1 hour after the estimated time of arrival, or from the actual time of departure to 1 hour after the estimated time of arrival, whichever is the shorter period, the approach and landing may be made under visual meteorological conditions (VMC); or\nThe place of intended landing is isolated and an IAP is prescribed for the aerodrome of intended landing; and available current meteorological information indicates that the following meteorological conditions will exist from 2 hours before to 2 hours after the estimated time of arrival:\nA cloud base of at least 1.000 ft above the minimum associated with the IAP; and\nVisibility of at least 5,5 km or of 4 km more than the minimum associated with the procedure.', 'OM_REV_6.0_CANONICAL_PART_3.txt', '61ca658cf9be221550e2cbd307359e0e78ab724462340a3f3b98b4abc570d79b', 'OM6_P3_2_4_5'),
('OM6_P3_2.5', 'OM', '6.0', 3, '2.5', 'Weather and NOTAMS', '2.5 Weather and NOTAMS\n\nOnly approved sources for Preflight Preparation, such as the METEO office at the airport and/or official websites (Skeyes) and our GarminPilot EFB app may be used. Carrying a hardcopy of current Weather and NOTAMS is no longer required.\n\nIMPORTANT! Prior to each flight, the student is required to send a copy of the Weather and NOTAMS as a PDF file via e-mail to:\nHim/herself; and\nHis/her Flight Instructor; and\nFlightdocs@europilotcenter.be\n\nThe use of the above electronic sources is mandatory. However, in case the data is not available in an electronic format, a paper-copy of the Weather and NOTAMS must be carried on board.', 'OM_REV_6.0_CANONICAL_PART_3.txt', 'ad32f6a5e0ba5ffc000f5773a4255faec2064093c463505aedd8cab3e366b490', 'OM6_P3_2_5'),
('OM6_P3_2.5.1', 'OM', '6.0', 3, '2.5.1', 'Preflight Information Briefings', '2.5.1 Preflight Information Briefings\nA Preflight Briefing must be derived, containing at least:\n\nWeather data (METAR/TAF/SIGMET) for the:\nDeparture Aerodrome\nDeparture Alternate (if required)\nEn-route Alternates\nDestination\nDestination Alternate(s)\n\nWeather Charts:\n(Low Level) Significant Weather Chart\nUpper Wind and Temperature Chart for the applicable Flight Levels\n\nNOTAMS for the:\nApplicable Area(s)\nDeparture Aerodrome\nDeparture Alternate (if required)\nEn-route Alternates\nDestination\nDestination Alternate(s)\n\nNote: Special attention is required to the availability of Navigation Aids and Approach aids.\nNote: Daily Warnings for flights within the FIR EBBU must be verified before each flight.\nNote: Temporary Flight Restrictions (TFR’s) for flights within the USA must be verified before each flight.', 'OM_REV_6.0_CANONICAL_PART_3.txt', 'cf39db581009095edbda3ca14fe4ece79fd82e52f9ab72bb0e030ab46458e500', 'OM6_P3_2_5_1'),
('OM6_P3_2.6', 'OM', '6.0', 3, '2.6', 'Passenger Briefing', '2.6 Passenger Briefing\n\nIn accordance with NCO.OP.130, the PIC shall ensure that before or, where appropriate, during the flight, passengers are given a briefing on emergency equipment and procedures.\n\nThe applicable Aircraft Safety Briefing Card should be used (if available).', 'OM_REV_6.0_CANONICAL_PART_3.txt', '3944f760128c34c9203571f5c13a888546759816dc14d6dacb874f46ce0bc519', 'OM6_P3_2_6'),
('OM6_P3_2.7', 'OM', '6.0', 3, '2.7', 'Fuel Calculations', '2.7 Fuel Calculations', 'OM_REV_6.0_CANONICAL_PART_3.txt', '3d7d604406dd2bb3a74b542afdb3a10798aa6b78e3674ac6d7a9ba93cb7309d5', 'OM6_P3_2_7'),
('OM6_P3_2.7.1', 'OM', '6.0', 3, '2.7.1', 'Airplanes', '2.7.1 Airplanes\nIn accordance with NCO.OP.125, the PIC shall only commence a flight if the airplane carries sufficient fuel and oil for the following:\n\nVFR Flights (NCO.OP.125 (a)(1))\n\nBy day, taking-off and landing at the same aerodrome/landing site and always remaining in sight of that aerodrome/landing site:\nto fly the intended route and thereafter for at least 10 minutes at normal cruising altitude;\n\nBy day:\nto fly to the aerodrome of intended landing and thereafter to fly for at least 30 minutes at normal cruising altitude; or\n\nBy night:\nto fly to the aerodrome of intended landing and thereafter to fly for at least 45 minutes at normal cruising altitude;\n\nNote: It is EuroPilot Center’s Policy for all VFR flights to have at least 45 minutes final reserve on board.\n\n\n\nIFR Flights (NCO.OP.125 (a)(2))\n\nWhen no destination alternate is required:\nto fly to the aerodrome of intended landing and thereafter to fly for at least 45 minutes at normal cruising altitude; or\n\nWhen a destination alternate is required:\nto fly to the aerodrome of intended landing, to an alternate aerodrome and thereafter to fly for at least 45 minutes at normal cruising altitude.\n\n\n\nSample Fuel Calculation C172SP & Minimum Oil Requirements\nFUEL\n\nAMT USG | POH REFERENCE\nSTART-UP/TAXI: | 1.4 USG | POH Chapter 5 - Page 19\nFuel for Climb from SL to 2.000 ft - ISA | 0,8 USG | POH Chapter 5 - Page 19\nFuel For 1 hour cruise @ 2.000 ft - ISA - 57% PWR | 8,1 USG | POH Chapter 5 - Page 20 - 21\n\nTRIP FUEL: | 8.9 USG\n\nAlternate Fuel (IFR Destination Alternate): | 6,0 USG\n\nFinal Reserve (45’): | 6,1 USG\n\nContingency (5%/TRIP): | 0,5 USG\n\nMIN REQUIRED: | 22,9 USG\n\nActual Fuel On Board: | 30,0 USG\n\nEXTRA FUEL: | 7,1 USG\n\nTAKE OFF IS NOT ALLOWED WHEN A LOW FUEL L/R WARNING IS PRESENT.\n(meaning less than 5 USG in any tank detected)\n\nNote: Training Flights in VMC are not allowed with less than 15 USG on board.\nNote: Training Flights in IMC are not allowed with less than 25 USG on board.\nNote: Fuel consumption values in the POH performance tables assume Recommended Lean Mixture.\n\nMIN OIL REQUIREMENTS C172SP\nThe engine should not be operated on less than five quarts of oil. For extended flight, fill to eight quarts (dipstick indication only).\n\n\n\nSample Fuel Calculation DA42 & Minimum Oil Requirements\nFUEL\n\nAMT USG | POH REFERENCE\nSTART-UP/TAXI: | 2,0 USG | N/A\nFuel for Climb from SL to 2.000 ft - ISA | 1,2 USG | N/A\nFuel For 1 hour cruise @ 2.000 ft - ISA - 60% PWR | 8,8 USG | POH Chapter 5 - Ch 5.3.2\n\nTRIP FUEL: | 10 USG\n\nAlternate Fuel (IFR Destination Alternate): | 8,8 USG | POH Chapter 5 - Ch 5.3.2\n\nFinal Reserve (45’): | 6,6 USG\n\nContingency (5%/TRIP): | 0,4 USG\n\nMIN REQUIRED: | 27,8 USG\n\nActual Fuel On Board: | 30,0 USG\n\nEXTRA FUEL: | 2,2 USG\n\nTAKE OFF IS NOT ALLOWED WHEN A LOW FUEL L/R WARNING IS PRESENT.\n(meaning less than 4 +/- 1 USG in any tank detected)\n\nNote: Training Flights in VMC are not allowed with less than 20 USG on board.\nNote: Training Flights in IMC are not allowed with less than 30 USG on board.\n\nMINIMUM OIL REQUIREMENTS DA42\nThe engines should not be operated on less than 4.8 quarts of oil.\nAlso the gearbox oil level should be checked prior to each flight as well as the Coolant liquid level.', 'OM_REV_6.0_CANONICAL_PART_3.txt', 'c86ba8c5ea0566f87f45b946d200c08db29e650c09aef82296ed9c4d1ec3bd60', 'OM6_P3_2_7_1'),
('OM6_P3_2.7.2', 'OM', '6.0', 3, '2.7.2', 'Helicopters', '2.7.2 Helicopters\nIntentionally left blank.', 'OM_REV_6.0_CANONICAL_PART_3.txt', 'ea6b63d6475513d80feb1588e098b8f90c3dff0618fe563c3c5d3ee70519b5b4', 'OM6_P3_2_7_2'),
('OM6_P3_2.7.3', 'OM', '6.0', 3, '2.7.3', 'Calculations (NCO.OP.125 (b) and (c))', '2.7.3 Calculations (NCO.OP.125 (b) and (c))\nThe minimum fuel required must be computed before each flight, based on:\nForecast meteorological conditions;\nAnticipated ATC routings and traffic delays;\nAny other condition that may delay the landing of the airplane or increase fuel and/or oil consumption.\n\nThe performance data and guidelines in the POH of the applicable aircraft shall be used.\n\nIn addition, the PIC must ensure that the actual amount of fuel on board is equal to or more than the determined minimum fuel required for the intended flight by means of a visual check (dripstick).\n\nNote: In no case shall an aircraft depart when a LOW FUEL WARNING annunciator is present.\nNote: In no case (except in case of emergency) shall an aircraft land with less than the final reserve fuel on board. If this situation occurs, the PIC shall declare a fuel emergency and land as soon as possible. An occurrence report must be filed and the Head of Training must be informed without delay.\n\nIt is EuroPilot Center policy always to take the maximum amount of fuel possible before each flight considering the Mass and Balance limitations.\n\nNothing shall preclude amendment of a flight plan in-flight, in order to re-plan the flight to another destination, provided that all requirements can be complied with from the point where the flight is re-planned.', 'OM_REV_6.0_CANONICAL_PART_3.txt', '4e7443a10b0a5201432cd4e4e5fa0b462a631c38d9bdfb3e4a84ac834b45b887', 'OM6_P3_2_7_3'),
('OM6_P3_2.7.4', 'OM', '6.0', 3, '2.7.4', 'In-Flight Fuel Management (NCO.OP.185)', '2.7.4 In-Flight Fuel Management (NCO.OP.185)\nThe PIC shall check at regular intervals that the amount of usable fuel remaining in flight is not less than the fuel required to proceed to a weather-permissible aerodrome and the planned reserve fuel as required as mentioned above.\n\nNote: An in-flight fuel check, at least once every hour, shall be performed by comparing the actual fuel on board with the calculated fuel on the Operational Flight Plan.', 'OM_REV_6.0_CANONICAL_PART_3.txt', 'cd024ece9787bd647afc4db794c49fae720b7d089d39cf901b5fdfb4a7ec4987', 'OM6_P3_2_7_4'),
('OM6_P3_2.8', 'OM', '6.0', 3, '2.8', 'Minimum Safe Altitudes', '2.8 Minimum Safe Altitudes\n\nThe PIC must ensure the aircraft is operated at all times at a safe altitude in accordance with the subparagraphs below:', 'OM_REV_6.0_CANONICAL_PART_3.txt', '919832e26f95f4f2de706404288a31a574e493fb2e71db3910d438b1958b2119', 'OM6_P3_2_8'),
('OM6_P3_2.8.1', 'OM', '6.0', 3, '2.8.1', 'VFR Flights', '2.8.1 VFR Flights\nIn accordance with SERA.5005f, except when necessary for take-off or landing, or except by permission from the CAA, a VFR flight shall not be flown:\n\nOver the congested areas of cities, towns or settlements, or over an open-air assembly of persons at a height less than 1.000 FT above the highest obstacle within a radius of 600 M from the aircraft;\nElsewhere, at a height less than 500 FT AGL, or 500 FT above the highest obstacle within a radius of 150 M from the aircraft.\n\nIn any case, the PIC shall fly at an Altitude or Flight Level which allows him to make a safe forced landing at any time.', 'OM_REV_6.0_CANONICAL_PART_3.txt', 'bbeeaed19939e683f33e60e7906f1f1c487cc83efffa093c4ae8c7d767a2290a', 'OM6_P3_2_8_1'),
('OM6_P3_2.8.2', 'OM', '6.0', 3, '2.8.2', 'Aerobatic Flights', '2.8.2 Aerobatic Flights\nIn accordance with SERA.3130:\n\nNo aircraft shall be flown acrobatically except under VMC and at a minimum height of 2.000 ft AGL. When acrobatic flights are conducted at or below 3.000 ft, the flight visibility shall be 5 km at the least.\n\nNo aircraft shall be flown acrobatically over the congested areas of cities, towns or settlements, industrial buildings, the LNG Terminal of Zeebrugge, nuclear plants or over an open-air assembly of persons, in controlled airspace or in restricted areas.\n\nAcrobatic flights are prohibited in danger areas except when these areas are reserved solely for these acrobatic flights.', 'OM_REV_6.0_CANONICAL_PART_3.txt', 'e5138de02682f462c31b2dc131751256d392e3801d73ceb906ccda1b941542a7', 'OM6_P3_2_8_2'),
('OM6_P3_2.8.3', 'OM', '6.0', 3, '2.8.3', 'IFR Flights', '2.8.3 IFR Flights\nIn accordance with SERA.5015, except when necessary for take-off or landing, or except when authorized by the CAA, an IFR flight shall be flown:\n\nAt a level that is at least 1.000 FT above the highest obstacle located within 8 KM of the estimated position of the aircraft.\n\n3. LOADING', 'OM_REV_6.0_CANONICAL_PART_3.txt', '51846eb678abe0c13df58f09dfb7441b9936b31fce4b0fc0a7d67c96c3acf341', 'OM6_P3_2_8_3'),
('OM6_P3_201', 'OM', '6.0', 3, '201', 'ft – 300 ft | 1.000 m', '201 ft – 300 ft | 1.000 m\nMore than 300 ft | 1.500 m\n\nNote: 1.500 m is also applicable if no positive take-off flight path can be constructed.\n\nAs the C172SP is a single engine airplane, no positive take off path can be constructed after an engine failure, consequently the minimum take off RVR/VIS for all IFR training operations within EuroPilot Center will be 1.500 m.\n\nFor the DA42, the assumed Engine Failure Height is considered more than 300 ft, consequently the minimum take off RVR/VIS for all IFR training operations will be 1.500 m.\n\nNote: The reported RVR/VIS value representative of the initial part of the take-off run can be replaced by pilot assessment.', 'OM_REV_6.0_CANONICAL_PART_3.txt', '7597814425a22f82cac7979cb318202ce9256c93fdad02b4761f3e37bae24428', 'OM6_P3_201'),
('OM6_P3_3.1', 'OM', '6.0', 3, '3.1', 'Mass and Balance', '3.1 Mass and Balance\nIn accordance with NCO.POL.100, during any phase of operation, the loading, the mass and the centre of gravity (CG) position of the aircraft shall comply with any limitation specified in the AFM, or equivalent document.\nPlacards, listings, instrument markings, or combinations thereof, containing those operating limitations prescribed by the AFM for visual presentation, shall be displayed in the aircraft.\nA precise Mass and Balance calculation must be performed before each flight.\nNote: A hardcopy of the Mass and Balance Calculation on board is no longer required. A soft copy (e.g. PDF sent via e-mail or obtained via an app is acceptable).\nNote: Always use actual masses. For this purpose, a pare of scales is provided in the EuroPilot Center Briefing Room. If you are unable to determine the actual mass, use the standard masses as provided below:\n• MALE 104 Kg\n• FEMALE 86 Kg\n• CHILD 35 Kg', 'OM_REV_6.0_CANONICAL_PART_3.txt', 'b802f9fb13df4d0dcb16ed6b3e23479983baa2c4585d9f7509dbb481e11d105b', 'OM6_P3_3_1'),
('OM6_P3_3.1.1', 'OM', '6.0', 3, '3.1.1', 'Mass and Balance - C172SP', '3.1.1 Mass and Balance - C172SP\nDetails about the Mass and Balance for the C172SP can be found in the POH, Chapter 6, Page 1 till 18.', 'OM_REV_6.0_CANONICAL_PART_3.txt', '9c15550eb3c3dcf8b7fb4026683603100c673c8f0d82e77740f62833a4d7f16a', 'OM6_P3_3_1_1'),
('OM6_P3_3.1.2', 'OM', '6.0', 3, '3.1.2', 'Mass and Balance - DA42', '3.1.2 Mass and Balance - DA42\nDetails about the Mass and Balance for the DA42 can be found in the POH, Chapter 6, Page 6-2 till 6-16.', 'OM_REV_6.0_CANONICAL_PART_3.txt', 'e56f291a4cc23e08950d6eba2f9b4f7eac214dd3e4f42a16a5c74a71ee67ae10', 'OM6_P3_3_1_2'),
('OM6_P3_3.2', 'OM', '6.0', 3, '3.2', 'Electronic Mass & Balance', '3.2 Electronic Mass & Balance\nFor the purpose of calculating the Mass & Balance for the Cessna C172SP and DA42, an electronic Mass & Balance system is included in the Garmin Pilot EFB app:\nThe following data should be entered into the system:\n• Registration: Enter the aircraft registration\n• Crew 1: Enter the actual mass of the student (Kg)\n• Crew 2: Enter the actual mass of the instructor (Kg)\n• Front Pax 1: Enter the actual mass of the front passenger (in case of one crew member) (Kg)\n• Rear Pax 2: Enter the actual mass of the left rear passenger (Kg)\n• Rear Pax 3: Enter the actual mass of the right rear passenger (Kg) - If applicable.\n• Luggage in Compartments: Enter the actual mass of the luggage (Kg)\n• Block Fuel: Verify (Automatic).\n• Trip Fuel: Verify (Automatic).\nThe system will calculate a detailed Mass & Balance which can be exported to a PDF file.\nIMPORTANT! Prior to each flight, the student is required to send a copy of the Mass & Balance PDF file via e-mail to:\n• Him/herself; and\n• His/her Flight Instructor; and\n• Flightdocs@europilotcenter.be\nThe use of the above system is mandatory, however the Pilot In Command always remains responsible for crosschecking the calculated data.\nWhenever the above system is not available, the Pilot In Command must calculate the Mass & Balance manually by means of the Sample Loading Problem in the POH of the applicable aircraft.\n\n\n\n4. WEATHER MINIMA\n\nThe following paragraphs are applicable for all training operations in Europe.\nFor training operations at the US Training Satellite, we refer to OM Annex 41 – FAA Weather Minima.', 'OM_REV_6.0_CANONICAL_PART_3.txt', '39d04ad337808947c1af8385ca1367b88a9462da1ad8a8ed029615567fe7f77d', 'OM6_P3_3_2'),
('OM6_P3_300', 'OM', '6.0', 3, '300', 'm, if the flight is conducted under conditions allowing visual course guidance navigation, or if navigational aids are available enabling the pilot to maintain the intended flight path with the same accuracy; or', '300 m, if the flight is conducted under conditions allowing visual course guidance navigation, or if navigational aids are available enabling the pilot to maintain the intended flight path with the same accuracy; or', 'OM_REV_6.0_CANONICAL_PART_3.txt', 'd303ddefa29b2aac4b3e60bf3fc0e2bcb48a0d5a452d20849cb441c3c5128d53', 'OM6_P3_300'),
('OM6_P3_4.1', 'OM', '6.0', 3, '4.1', 'VFR Training Flights (Dual)', '4.1 VFR Training Flights (Dual)', 'OM_REV_6.0_CANONICAL_PART_3.txt', '926ac69ab11e559907b1eebaf630c0093eba9b9384bf8cde8e1a6fb13080a19a', 'OM6_P3_4_1'),
('OM6_P3_4.1.1', 'OM', '6.0', 3, '4.1.1', 'Standard VMC Minima', '4.1.1 Standard VMC Minima\nIn accordance with SERA.5001 and SERA.5005a, except when operating as a special VFR flight, VFR flights shall be conducted so that the aircraft is flown in conditions of visibility and distance from clouds equal to or greater than those specified in the following table:\n(*) The VMC minima in Class A airspace are included for guidance to pilots and do not imply acceptance of VFR flights in Class A airspace.\n(**) Flight visibilities reduced to not less than 1.500m are permitted for flights operating:\n• At speeds of 140 KIAS or less to give adequate opportunity to observe other traffic or any obstacles in time to avoid collision; or\n• In circumstances in which the probability of encounters with other traffic would normally be low, e.g. in areas of low volume traffic and for aerial work at low levels.\n\nAIRSPACE CLASS A* B C D E F and G\nAbove 900 m (3.000 ft ) AMSL or above 300 m (1.000 ft ) above terrain, whichever is the higher\nAt and below 900 m (3.000 ft ) AMSL or 300 m (1.000 ft ) above terrain, whichever is higher\nDISTANCE FROM CLOUDS 1.500 m horizontally 300 m (1 000 ft ) vertically\nClear of clouds and in sight of the surface\nFLIGHT VISIBILITY 8 km at and above FL 100 5 km below FL 100 5 km**', 'OM_REV_6.0_CANONICAL_PART_3.txt', '2f1d7ae22a5f6af172533e1ae3cd1eecdba57ae82fbc78fb3ea0a94a5b726795', 'OM6_P3_4_1_1'),
('OM6_P3_4.1.2', 'OM', '6.0', 3, '4.1.2', 'VFR Flights at Aerodromes', '4.1.2 VFR Flights at Aerodromes\nIn accordance with SERA.5005b, except when a special VFR clearance is obtained from an ATC unit, VFR flights shall not take off or land at an aerodrome within a CTR, or enter the ATZ or aerodrome traffic circuit when the reported meteorological conditions at that aerodrome are below the following minima:\n• the ceiling is less than 1.500ft; or\n• the ground visibility is less than 5km.', 'OM_REV_6.0_CANONICAL_PART_3.txt', 'cbff06ba95550c34baf9e75a38f9a1aea2dfc30970b1b2065abbdc6a400b8397', 'OM6_P3_4_1_2'),
('OM6_P3_4.1.3', 'OM', '6.0', 3, '4.1.3', 'Special VFR Flights', '4.1.3 Special VFR Flights\nIn accordance with SERA.5010, Special VFR flights may be authorized to operate within a CTR, subject to an ATC clearance.\nExcept when permitted by the CAA for helicopters in special cases such as, but not limited to, police, medical flights, search and rescue operations and fire-fighting flights, the following additional conditions shall be applied:\n• Such special VFR flights may be conducted during day only, unless otherwise permitted by the CAA;\n• By the pilot:\n✓ Clear of clouds and with the surface in sight;\n✓ The flight visibility is not less than 1.500m (or for helicopters, not less than 800m;)\n✓ Fly at speed of 140 KIAS or less to give adequate opportunity to observe other traffic and any obstacles in time to avoid a collision; and\n• An ATC unit will not issue a special VFR clearance to aircraft to take off or land at and aerodrome within a CTR, or enter the ATZ zone or aerodrome traffic circuit, when the reported meteorological conditions at the aerodrome are below the following minima:\n✓ The ground visibility is less than 1.500m or, for helicopters, less than 800m\n✓ The ceiling is less than 600ft.', 'OM_REV_6.0_CANONICAL_PART_3.txt', '2243150c6ed60c18e1afb46b8565259d8f676fc5ae801770c4139d1569274511', 'OM6_P3_4_1_3'),
('OM6_P3_4.1.4', 'OM', '6.0', 3, '4.1.4', 'VFR at night', '4.1.4 VFR at night\nIn accordance with SERA.5005c, VFR flights at night may be authorized under the following conditions:\n• If leaving the vicinity of an aerodrome, a flight plan shall be submitted;\n• Flights shall establish and maintain two way radio communication on the appropriate ATS communication channel, when available;\n• The VMC visibility and distance from cloud minima as specified in 4.1.1 above shall apply, except that:\n✓ The ceiling shall not be less than 1.500ft;\n✓ The reduced flight visibility provisions specified in remark (**) of 4.1.1 shall not apply;\n✓ In airspace classes B, C, D, E, F and G at and below 3.000 ft AMSL or 1.000ft AGL, whichever is the higher, the pilot shall maintain continuous sight of the surface;\n• Except when necessary for take-off or landing, or except when specifically authorized by the CAA, a VFR flight at night shall be flown at a level that is at least 1.000ft above the highest obstacle located within 8km of the estimated position of the aircraft.\nNote 1: In Belgium, VFR flights at night are authorized, except for gliders, DPM, ULM and RPA.\nNote 2: In Luxembourg, VFR flights at night may be operated in Luxembourg CTR, Luxembourg TMA (up to FL 95) or class G airspace (up to 2.000 ft AMSL) after approval of the CAA.', 'OM_REV_6.0_CANONICAL_PART_3.txt', '5ee94a00bb5cb1c91f1bfe79b993608c30fadf78a0b1b15e92c4364d3119629f', 'OM6_P3_4_1_4'),
('OM6_P3_4.2', 'OM', '6.0', 3, '4.2', 'IFR Training Flights (Dual)', '4.2 IFR Training Flights (Dual)', 'OM_REV_6.0_CANONICAL_PART_3.txt', 'b2ad78573e95bb219a6b391ec85d3da72016a4c6ddb2e63ca201b55abd4651fb', 'OM6_P3_4_2'),
('OM6_P3_4.2.1', 'OM', '6.0', 3, '4.2.1', 'Aerodrome Operating Minima (NCO.OP.110)', '4.2.1 Aerodrome Operating Minima (NCO.OP.110)\nThe PIC shall select and use Aerodrome Operating Minima for each:\n• Departure Aerodrome;\n• Destination Aerodrome;\n• Alternate Aerodrome;\n\nWith the exception of the Take Off Minima, EuroPilot Center has implemented the calculated Aerodrome Operating Minima published by Jeppesen.\n\nNote: On Jeppesen Approach and Aerodrome charts an inverse printed “Standard” label in the upper left corner of the minimums band indicate they are derived according to the requirements described in EASA Air Operations documents. These minima exceed the state minima.\n\nThe PIC shall however always take the following into account:\n• The type, performance and handling characteristics of the aircraft;\n• His/her competence and experience;\n• The dimensions and characteristics of the runways and final approach and take-off areas (FATO’s) that may be selected for use;\n• The adequacy and performance of the available visual and non-visual ground aids;\n• The equipment available on the aircraft for the purpose of navigation and/or control of the flight path, during the take-off, the approach, the flare, the landing, the rollout and the missed approach;\n• The obstacles in the approach, the missed approach and the climb-out areas necessary for the execution of contingency procedures;\n• The obstacle clearance altitude/height for the instrument approach procedures;\n• The means to determine and report meteorological conditions; and\n• The flight technique to be used during the final approach.\n\nThe minima for a specific type of approach and landing procedure shall be used if:\n• The ground equipment required for the intended procedure is operative;\n• The aircraft systems required for the type of approach are operative;\n• The required aircraft performance criteria are met; and\n• The pilot is qualified appropriately.\n\n\n\nEUROPILOT CENTER – IFR TRAINING MINIMA\nTYPE | MINIMA | Ref.\nTAKE OFF RVR/VIS | 1.500 m | 4.2.4\nAPPROACH RVR/VIS | JEPPESEN | Approach Plate\nVISUAL APPROACH | 800 m | 4.2.5.3', 'OM_REV_6.0_CANONICAL_PART_3.txt', '7461f49d5619b49a8659e05dda4cfdde97a4883d36acb8cfcc1c9d340d91f143', 'OM6_P3_4_2_1'),
('OM6_P3_4.2.2', 'OM', '6.0', 3, '4.2.2', 'Departure and Approach Procedures (NCO.OP.115)', '4.2.2 Departure and Approach Procedures (NCO.OP.115)\nThe PIC shall use the departure and approach procedures established by the State of the aerodrome, if such procedures have been published for the runway or final approach and take-off areas (FATO’s) to be used.\n\nThe pilot-in-command may deviate from a published departure route, arrival route or approach procedure:\n• Provided obstacle clearance criteria can be observed, full account is taken of the operating conditions and any ATC clearance is adhered to; or\n• When being radar-vectored by an ATC unit.', 'OM_REV_6.0_CANONICAL_PART_3.txt', '4e871149cab36efd74dcae5a7e839e78501d2b2d178eaf09b6149e42e3bddf20', 'OM6_P3_4_2_2'),
('OM6_P3_4.2.3', 'OM', '6.0', 3, '4.2.3', 'Low Visibility Procedures', '4.2.3 Low Visibility Procedures\nEuroPilot Center has no BCAA approval to conduct training operations when Low Visibility Operations are in force in accordance with Annex V (Part-SPA), Subpart E to Regulation (EU) No 965/2012.', 'OM_REV_6.0_CANONICAL_PART_3.txt', 'dcd85ab25e97409522077184d04c594e459864e28cc511425880133179e58a44', 'OM6_P3_4_2_3'),
('OM6_P3_4.2.4', 'OM', '6.0', 3, '4.2.4', 'Take Off Minima', '4.2.4 Take Off Minima\nEuroPilot Center applies the Take Off Minima procedures based on AMC1 NCO.OP.110.', 'OM_REV_6.0_CANONICAL_PART_3.txt', '529c8e98e2ed28a5ab153b2be484c3cc20add7c6860d05d26116ff9fd9420e6e', 'OM6_P3_4_2_4'),
('OM6_P3_4.2.4.1', 'OM', '6.0', 3, '4.2.4.1', 'General', '4.2.4.1 General\nTake off minima must be expressed as visibility or RVR limits, taking into account all relevant factors for each aerodrome planned to be used and the Aircraft characteristics. Where there is a specific need to see and avoid obstacles on departure and/or for a forced landing, additional conditions (e.g. ceiling) must be specified.\n\nThe PIC shall not commence take off unless the weather conditions at the aerodrome of departure are equal to or better than applicable minima for landing at that aerodrome, unless a suitable take off alternate aerodrome is available.\n\nWhen the reported meteorological visibility is below the required take off minima and RVR is not reported, a take off may only be commenced if the PIC can determine that the RVR/visibility along the take off runway is equal to or better than the required minimum.\n\nWhen no reported meteorological visibility or RVR are available, a take off may only be commenced if the PIC can determine that the RVR/visibility along the take off runway is equal to or better than the required minimum.', 'OM_REV_6.0_CANONICAL_PART_3.txt', '2c2eea867a3607b2c1ab541fe4268a87423d2840e1ae9c0fc379ab1d9e38d218', 'OM6_P3_4_2_4_1'),
('OM6_P3_4.2.4.2', 'OM', '6.0', 3, '4.2.4.2', 'Visual reference', '4.2.4.2 Visual reference\nThe take off minima must be selected to ensure sufficient guidance to control the Aircraft in the event of a discontinued take off in adverse circumstances and a continued take-off after failure of the critical engine.\n\nFor night operations, ground lights should be available to illuminate the runway/final approach and take-off area (FATO) and any obstacles.', 'OM_REV_6.0_CANONICAL_PART_3.txt', '8eeacb52821177d9a29f61ce7ce6872a83bdc57d4867967ecf70c2ed6930c2a0', 'OM6_P3_4_2_4_2'),
('OM6_P3_4.2.4.3', 'OM', '6.0', 3, '4.2.4.3', 'Required RVR/visibility', '4.2.4.3 Required RVR/visibility\nFor multi-engined airplanes, with performance such that in the event of a critical engine failure at any point during take-off the airplane can either stop or continue that take-off to a height of 1.500 ft above the aerodrome while clearing obstacles by the required margins, the take-off minimums specified by the operator should be expressed as RVR/VIS values not lower than those specified in Table 3, Take Off RVR/VIS.\n\nFor multi-engined airplanes without the performance to comply with the conditions mentioned above in the event of a critical engine failure, there may be a need to re-land immediately and to see and avoid obstacles in the take-off area. Such airplanes may be operated to the following take-off minimums provided they are able to comply with the applicable obstacle clearance criteria, assuming engine failure at the height specified.\n\nThe take-off minimums specified by the operator should be based upon the height from which the one-engine-inoperative (OEI) net take-off flight path can be constructed.\n\nThe RVR minimums used should not be lower than either of the values specified in Table 3, Take Off RVR/VIS or Table 4, Assumed Engine Failure Height above the Runway versus RVR/VIS.\n\n\n\nTABLE 3. TAKE OFF RVR/VIS\nFACILITIES | RVR/VIS\nDAY ONLY – NIL | 500 m\nDAY – At least runway edge lights or centerline marking | 400 m\nNIGHT – at least runway edge lights and runway end lights or runway centerline lights and runway end lights | —\n\n\n\nTABLE 4. TAKE OFF – ASSUMED ENG. FAIL HEIGHT ABOVE THE RWY VS. RVR/VIS\nASSUMED ENG. FAIL HEIGHT | RVR/VIS\n≤ 50 ft | 400 m (200 m with LVTO approval)', 'OM_REV_6.0_CANONICAL_PART_3.txt', 'b9ca59b50622e4ec625bed6bcdf407c3ee5b7f96b199eeb7734f22471803b3fa', 'OM6_P3_4_2_4_3'),
('OM6_P3_4.2.5', 'OM', '6.0', 3, '4.2.5', 'Approach Minima', '4.2.5 Approach Minima', 'OM_REV_6.0_CANONICAL_PART_3.txt', 'cb1cb960c3cb2da22cf61bafb945c44b0c367843fc5c3494efaa6de12e04a115', 'OM6_P3_4_2_5'),
('OM6_P3_4.2.5.1', 'OM', '6.0', 3, '4.2.5.1', 'Aerodrome operating minima for NPA, APC, CAT I Operations (NCO.OP.111)', '4.2.5.1 Aerodrome operating minima for NPA, APC, CAT I Operations (NCO.OP.111)\nThe decision height (DH) to be used for a non-precision approach (NPA) flown with the continuous descent final approach (CDFA) technique, approach procedure with vertical guidance (APV) or category I (CAT I) operation shall not be lower than the highest of:\n• The minimum height to which the approach aid can be used without the required visual reference;\n• The obstacle clearance height (OCH) for the category of aircraft;\n• The published approach procedure DH where applicable;\n• The system minimum specified in Table 1 (System Minima NCO.OP.111); or\n• The minimum DH specified in the AFM or equivalent document, if stated.\n\nThe minimum descent height (MDH) for an NPA operation flown without the CDFA technique shall not be lower than the highest of:\n• The OCH for the category of aircraft;\n• The system minimum specified in Table 1 (System Minima NCO.OP.111) below; or\n• The minimum MDH specified in the AFM, if stated.\n\n\n\nTABLE 1. SYSTEM MINIMA NCO.OP.111\nFACILITY | LOWEST DH/MDH (ft)\nInstrument landing system (ILS) | 200 ft\nGNSS / SBAS (LPV) | 200 ft\nGNSS (LNAV) | 250 ft\nGNSS / VNAV (LNAV/VNAV) | 250 ft\nLocaliser (LOC) with or without DME | 250 ft\nSurveillance radar approach (SRA) (terminating at ½ NM) | 250 ft\nSRA (terminating at 1 NM) | 300 ft\nSRA (terminating at 2 NM or more) | 350 ft\nVOR | 300 ft\n\n\n\nTABLE 1. SYSTEM MINIMA NCO.OP.111 (continued)\nFACILITY | LOWEST DH/MDH (ft)\nVOR/DME | 250 ft\nNon-directional beacon (NDB) | 350 ft\nNDB/DME | 300 ft\nVHF direction finder (VDF) | 350 ft\n\nNote: The published Jeppesen Approach Minima will be used for all EuroPilot Center IFR Training Operations.', 'OM_REV_6.0_CANONICAL_PART_3.txt', '027aa679f69d810b5d5729c2a74d03d80dc65afb3fc82e5c8d2bc303217d863d', 'OM6_P3_4_2_5_1'),
('OM6_P3_4.2.5.2', 'OM', '6.0', 3, '4.2.5.2', 'Continuous Descent Final Approach Procedure (CDFA)', '4.2.5.2 Continuous Descent Final Approach Procedure (CDFA)\nThe CDFA technique should ensure that an approach can be flown on the desired vertical path and track in a stabilized manner, without significant vertical path changes during the final approach segment descent to the runway.\n\nThis technique applies to an approach with no vertical guidance and controls the descent path until the DA/H.\n\nThis descent path can be either a:\n• Recommended descent rate, based on estimated ground speed;\n• Descent path depicted on the approach chart; or\n• Descent path coded in the flight management system in accordance with the approach chart descent path.\n\nNote: The published Jeppesen Charts used by EuroPilot Center will satisfy the requirement whereby the appropriate cross check altitudes/heights with the corresponding appropriate range information are shown. The Missed Approach Point (MAPt) is published on these chart.\n\nNote: The required descent path should be flown to the DA/H, observing any step-down crossing altitudes if applicable.\n\nNote: As this is a DA/H no add-on to the published Jeppesen Approach minimums is required.\n\nNote: Standard Minima Callouts should be performed when approaching the DA/H.\n\nNote: The missed approach should be initiated no later than reaching the MAPt or at the DA/H, whichever comes first. The lateral part of the missed approach should be flown via the MAPt unless otherwise stated on the approach chart.', 'OM_REV_6.0_CANONICAL_PART_3.txt', '4d86c667e2c4f53b044b423d8296f9cb92ae534981c53d592b771ef3a45ebf4c', 'OM6_P3_4_2_5_2'),
('OM6_P3_4.2.5.3', 'OM', '6.0', 3, '4.2.5.3', 'Visual Approach', '4.2.5.3 Visual Approach\nEuroPilot Center applies the Visual Approach Procedures based on AMC2 NCO.OP.110. The PIC shall not use an RVR of less than 800 m for a visual approach.', 'OM_REV_6.0_CANONICAL_PART_3.txt', '5e780410df60744f1521e59c70b98ba1d2eaeaf5cc62c09656b3743bd2d2dc11', 'OM6_P3_4_2_5_3'),
('OM6_P3_4.2.5.4', 'OM', '6.0', 3, '4.2.5.4', 'Conversion reported visibility to RVR', '4.2.5.4 Conversion reported visibility to RVR\nEuroPilot Center applies the Conversion of reported Visibility to RVR Procedure based on GM5 NCO.OP.110.\n\nA conversion from meteorological visibility to RVR/CMV should not be used:\n• When reported RVR is available;\n• For calculating take-off minimums; and\n• For any RVR minimums less than 800 m.\n\nIf the RVR is reported as being above the maximum value assessed by the aerodrome operator, e.g. “RVR more than 1.500 m”, it should not be considered as a reported value for as “When reported visibility is available”.\n\nWhen converting meteorological visibility to RVR in circumstances other than those above, the conversion factors specified in the following table should be used:\n\nLighting elements in operation | RVR = Reported Met. Visibility ×\nDAY | NIGHT\nHi approach and RWY lights | 1.5 | 2\nAny type of lights other than above | 1 | 1.5\nNo lighting | 1 | Not Applicable', 'OM_REV_6.0_CANONICAL_PART_3.txt', '6ddf25098cfa94c9a4d3e71045d9c85d6a7964801c21d16b1b48ceee9d126588', 'OM6_P3_4_2_5_4'),
('OM6_P3_4.2.6', 'OM', '6.0', 3, '4.2.6', 'Noise Abatement Procedures (NCO.OP.120)', '4.2.6 Noise Abatement Procedures (NCO.OP.120)\nThe PIC shall take into account published noise abatement procedures to minimize the effect of aircraft noise while ensuring that safety has priority over noise abatement.', 'OM_REV_6.0_CANONICAL_PART_3.txt', '989f4e27e122f1619d8d20c2418fc2720603ee8d52699071fd76acf58a799297', 'OM6_P3_4_2_6'),
('OM6_P3_4.2.7', 'OM', '6.0', 3, '4.2.7', 'Commencement and continuation of approach – Approach Ban (NCO.OP.210)', '4.2.7 Commencement and continuation of approach – Approach Ban (NCO.OP.210)\nThe PIC may commence an instrument approach regardless of the reported runway visual range/visibility (RVR/VIS).\n\nIf the reported RVR/VIS is less than the applicable minimum, the approach shall not be continued:\n• Below 1.000 ft above the aerodrome; or\n• Into the final approach segment in the case where the decision altitude/height (DA/H) or minimum descent altitude/height (MDA/H) is more than 1.000 ft above the aerodrome.\n\nWhere the RVR is not available, RVR values may be derived by converting the reported visibility as described under 4.2.5.4.\n\nIf, after passing 1.000 ft above the aerodrome, the reported RVR/VIS falls below the applicable minimum, the approach may be continued to DA/H or MDA/H.\n\nThe approach may be continued below DA/H or MDA/H and the landing may be completed provided that the visual reference adequate for the type of approach operation and for the intended runway is established at the DA/H or MDA/H and is maintained.\n\nThe touchdown zone RVR shall always be controlling.', 'OM_REV_6.0_CANONICAL_PART_3.txt', 'd30ac953a8e1c1f467dc6704b86071a09c754dc1c166cbf6d8037f879ff8d67e', 'OM6_P3_4_2_7'),
('OM6_P3_4.3', 'OM', '6.0', 3, '4.3', 'VFR Training Flights (Solo)', '4.3 VFR Training Flights (Solo)\n\nThe standard VMC minima apply for all VFR solo flights with the exception that the visibility must be at least 8 km.', 'OM_REV_6.0_CANONICAL_PART_3.txt', '8ff7f0efaf766cf4c69b968f12be96a32b176f136a7503a3d765c4e75070e43b', 'OM6_P3_4_3'),
('OM6_P3_4.4', 'OM', '6.0', 3, '4.4', 'Wind Limitations', '4.4 Wind Limitations\n\nMaximum Crosswind Component Cessna C172SP\nThe maximum crosswind component shall not exceed the maximum demonstrated crosswind component (Gusts excluded) of the applicable aircraft.\nThis is 15 Kts (Gust excluded) for the C172SP.\n\nFor VFR solo flights, the maximum crosswind component (Gust included) shall not exceed 10 kts.\n\nMaximum Overall Wind Component Cessna C172SP\nThe maximum overall wind shall not exceed 29 Kts (Gusts included).\n\nFor VFR solo flights, the maximum overall wind (Gust included) shall not exceed 15 kts.\n\nMaximum Wind Diamond DA42\nThe maximum crosswind component shall not exceed the maximum demonstrated crosswind component (Gusts excluded) of the applicable aircraft.\nThis is 20 Kts (Gust excluded) for the DA42.\n\nMaximum Overall Wind Component Diamond DA42\nThe maximum overall wind shall not exceed 29 Kts (Gusts included).\n\n\n\n5. TRAINING AREA\n\nThe following locations will be used for Flight Training within EuroPilot Center.\nStandard noise abatement procedures apply at all times.\nWe refer to the AIP Belgium/Luxembourg for airport-specific procedures.', 'OM_REV_6.0_CANONICAL_PART_3.txt', '2886350d21b416658faf98fe01218e950af311c3870d88def985f4ff39673293', 'OM6_P3_4_4'),
('OM6_P3_5.1', 'OM', '6.0', 3, '5.1', 'Training Aerodromes (including hazards)', '5.1 Training Aerodromes (including hazards)\n\nIn accordance with NCO.OP.100, the pilot-in-command shall only use aerodromes and operating sites that are adequate for the type of aircraft and operation concerned.\n\nThe applicable noise abatement procedures can be found in the relevant AIP document for training flights in Europe or the FAA Chart Supplement for training flights in the USA.\n\nTouch and Go / Circuit Training\nEBAW – Antwerpen (Stop and Go due to noise restrictions)\nHazards:\n• Bird hazard (wood pigeons and herons)\n• Close presence of city\n• Take-off RWY 29 (limited space available to perform a forced landing)\n• Approach RWY 11 (mechanical turbulence during windy conditions)\n• Approach RWY 29 (windshear short final – fort)\n\nEBST – Sint-Truiden (Touch and Go)\nHazards:\n• Bird hazard (buzzards)\n• Drones\n\nEBKH – Keiheuvel (Grass runway)\nHazards:\n• Glider flying / winch up to 2.000 ft AAL\n\nEBHN – Hoevenen (Grass runway)\nHazards:\n• High tension lines in the close vicinity\n• Paradrop activity\n\nKTRM – Thermal (Touch and Go)\nHazards:\n• High volume of business jet traffic during wintertime\n• High ambient temperature during summertime\n\nKPSP – Palm Springs (Touch and Go)\nHazards:\n• Terrain\n• High volume of business jet traffic during wintertime\n• High ambient temperature during summertime\n• Mechanical turbulence during high wind conditions\n\nKUDD – Bermuda Dunes (Touch and Go)\nHazards:\n• High volume of business jet traffic during wintertime\n• High ambient temperature during summertime\n• Mechanical turbulence during high wind conditions\n\nL08 – Borrego Valley (Touch and Go)\nHazards:\n• Terrain\n• High ambient temperature during summertime\n• Mechanical turbulence during high wind conditions\n\nKBWC – Brawley (Touch and Go)\nHazards:\n• High ambient temperature during summertime\n• High volume of crop-dusting activity\n• Bird hazard (Canadian geese)\n\n\n\nNight Touch and Go / Circuit Training\nEBAW – Antwerpen (Stop and Go due to noise restrictions)\n\nEBOS – Oostende (Touch and Go)\nHazards:\n• Frequent windy conditions (verify limitations)\n• Risk of sudden advection fog\n\nEBLG – Luik (Touch and Go)\nHazards:\n• Nil\n\nKTRM – Thermal (Touch and Go)\n\nKPSP – Palm Springs (Touch and Go)\n\nKUDD – Bermuda Dunes (Touch and Go)\n\nL08 – Borrego Valley (Touch and Go)\n\nKBWC – Brawley (Touch and Go)\n\n\n\nSID / STAR / Precision / Non-Precision / Circling\nEBAW – Antwerpen\nEBOS – Oostende\nEBLG – Luik\nEBCI – Charleroi\nHazards:\n• Airspace congestion\n• Close presence of city\n\nEBKT – Kortrijk\nHazards:\n• Taxiway and apron condition (prop-strike risk)\n• No ATC (AFIS only)\n\nKTRM – Thermal\nKPSP – Palm Springs\nKUDD – Bermuda Dunes\nL08 – Borrego Valley\nKBWC – Brawley\n\nKTNP – Twentynine Palms\nHazards:\n• Military helicopter activity\n• High ambient temperature during summertime\n• Frequent windy conditions (verify limitations)\n\nKBLH – Blythe\nHazards:\n• Paradrop\n• High ambient temperature during summertime\n\nKHII – Lake Havasu\nHazards:\n• Terrain\n• High ambient temperature during summertime\n• Frequent windy conditions (verify limitations)\n\nKEED – Needles\nHazards:\n• Terrain\n• High ambient temperature during summertime\n• Frequent windy conditions (verify limitations)\n\nKIFP – Laughlin Bullhead\nHazards:\n• Terrain\n• High ambient temperature during summertime\n• Frequent windy conditions (verify limitations)\n\nKHND – Las Vegas Henderson\nHazards:\n• High volume of commercial traffic\n• High ambient temperature during summertime\n• Frequent windy conditions (verify limitations)\n• Terrain\n\nKNYL – Yuma\n\nKSDM – Brown\nHazards:\n• Terrain\n• Paradrop\n\nKMYF – Montgomery Field\nHazards:\n• Terrain\n• Risk of fog during May and June\n• Frequent windy conditions (verify limitations)\n• High volume of traffic\n\nKSEE – El Cajon\nHazards:\n• Terrain\n• Risk of fog during May and June\n• Frequent windy conditions (verify limitations)\n• High volume of traffic\n\nKNKX – Ramona\nHazards:\n• Terrain\n• Risk of fog during May and June\n• Frequent windy conditions (verify limitations)\n\nKCRQ – Carlsbad\nHazards:\n• Terrain\n• Risk of fog during May and June\n• Frequent windy conditions (verify limitations)\n\nKOKB – Oceanside\nHazards:\n• Paradrop\n• Terrain\n• Short runway\n• Risk of fog during May and June\n• Frequent windy conditions (verify limitations)\n\nKSNA – John Wayne\nHazards:\n• Terrain\n• High volume of commercial traffic\n• Wake turbulence\n• Risk of fog during May and June\n• Frequent windy conditions (verify limitations)\n\nKLGB – Long Beach\nHazards:\n• High volume of commercial traffic\n• Wake turbulence\n• Risk of fog during May and June\n• Frequent windy conditions (verify limitations)\n\nKTOA – Torrance\nHazards:\n• High volume of helicopter traffic\n• Risk of fog during May and June\n• Frequent windy conditions (verify limitations)\n\nKVNY – Van Nuys\nHazards:\n• High volume of business jet traffic\n• Risk of fog during May and June\n• Frequent windy conditions (verify limitations)\n\nKBUR – Burbank\nHazards:\n• High volume of commercial traffic\n• Wake turbulence\n• Rising terrain\n\nKONT – Ontario\nHazards:\n• High volume of commercial traffic\n• Wake turbulence\n\nKCNO – Chino\nKRAL – Riverside\n\nKAJO – Corona\nHazards:\n• Terrain\n• Mechanical turbulence during high wind conditions\n\nKSBD – San Bernardino\nHazards:\n• Terrain\n\nKAPV – Apple Valley\nHazards:\n• High density altitude\n• Terrain\n• Drones\n• Mechanical turbulence during high wind conditions\n\nKVCV – Victorville\nHazards:\n• High density altitude\n• Terrain\n• Drones\n• Mechanical turbulence during high wind conditions', 'OM_REV_6.0_CANONICAL_PART_3.txt', '856e57396eda260daeae7c2740ae11655eb7aee80e6619a328cc980ac52cab55', 'OM6_P3_5_1'),
('OM6_P3_5.3', 'OM', '6.0', 3, '5.3', 'Training Area', '5.3 Training Area\n\nBasic Airwork (including Basic Instrument Flying)\nWest of Antwerp and North-West of Brussels:\nArea A: 500 ft MSL till 1.500 ft MSL\nArea B: 500 ft MSL till 2.500 ft MSL\nArea C: 500 ft MSL till 3.500 ft MSL\nArea D: 500 ft MSL till 4.500 ft MSL\n\n\n\nInterceptions, Holdings, DME Arcs\nANT – Antwerp VOR\nNIK – Nicky VOR\nMAK – Mackel NDB\nONW – Antwerpen NDB\n\n\n\nBasic Airwork (including Basic Instrument Flying) USA\nAround the TRM VOR:\nArea A: 500 ft AGL till 18.000 ft MSL\n\nEast of the Thermal Airport, over the Salton Sea and High Desert:\nArea B: 500 ft AGL till 18.000 ft MSL\n\nNote: Check activity of Kane West Military Operating Area with LA Center and SoCal Approach.\n\n\n\nInterceptions, Holdings, DME Arcs USA\nTRM – Thermal VOR\nPSP – Palm Springs VOR\nTNP – Twentynine Palms VOR\nBLH – Blythe VOR\nPKE – Parker VOR\nPDZ – Paradise VOR\nSB – Petis NDB', 'OM_REV_6.0_CANONICAL_PART_3.txt', '38d87674c0e2bac8733c906df740e36d1d2170768f6819226558365a70988e28', 'OM6_P3_5_3'),
('OM6_P3_51', 'OM', '6.0', 3, '51', 'ft – 100 ft | 400 m (300 m with LVTO approval)', '51 ft – 100 ft | 400 m (300 m with LVTO approval)', 'OM_REV_6.0_CANONICAL_PART_3.txt', 'b19bd824e317837bdbee3446567c298225c44771e3fa5aa39916bdde7b86d7c4', 'OM6_P3_51'),
('OM6_P3_600', 'OM', '6.0', 3, '600', 'm, for flights under all other conditions.', '600 m, for flights under all other conditions.\n\nWhen showing compliance with subparagraph (a) above for those cases where the intended flight path requires track changes of more than 15°, the pilot in command need not consider those obstacles which have a lateral distance greater than:', 'OM_REV_6.0_CANONICAL_PART_3.txt', '3a50b5a958fddf0e949b4f8da8e2ae726b7de1cf2702cd0bade1e5e9506dc40c', 'OM6_P3_600'),
('OM6_P3_900', 'OM', '6.0', 3, '900', 'm for flights under all other conditions.', '900 m for flights under all other conditions.\nWhen showing compliance with subparagraphs (a), (b) and (c) above, the pilot in command must take account of the following:\nThe mass of the Airplane at the commencement of the take-off run;\nThe pressure altitude at the aerodrome;\nThe ambient temperature at the aerodrome; and\nNot more than 50 % of the reported head-wind component or not less than 150 % of the reported tail-wind component.', 'OM_REV_6.0_CANONICAL_PART_3.txt', 'c5cbb5f519c01a8ac9a06098a568abda738cebfcf9f3e3493f642fea10b3a19a', 'OM6_P3_900'),
('OM6_P4_1', 'OM', '6.0', 4, '1', 'Hour: Briefing and training on the FSTD', '1 Hour: Briefing and training on the FSTD\n\nCourse Method:\nInteractive Video Lessons\nDirected Study\nSimulator Assisted Briefing on the FSTD\n\nStudy Materials:\nIPCA, KSA.100 IVL Video Course\nIPCA, KSA.100 iBook for iPad\nThe EPC TM Gen\nThe EPC TM for the ATPL(A) – If applicable\nThe EPC TM for the APS/MCC – If applicable\n\nKnowledge Test:\nThe Initial and refresher test will contain 20 multiple choice questions.\nA passmark of 75% is applicable and the questions missed should be discussed during a debriefing.\n\nWe refer to OM Annex 16 – KSA.100 Training Course', 'OM_REV_6.0_CANONICAL_PART_4.txt', '5ef7f79cc1c33658640afd3c81478f7f9cdb7978389ba6f71408e1ebcd2a2606', 'OM6_P4_1'),
('OM6_P4_1.1', 'OM', '6.0', 4, '1.1', 'Accountable Manager', '1.1 Accountable Manager\n\nAccountable Manager\nIt is the responsibility of the Accountable Manager to:\nEnsure that sufficient financial means are (made) available for accepting new staff members within the organization.\nDecide upon the actual selection criteria for Nominated Person positions in accordance with the Operations Manual, Part 1, Chapter 2:\nHead of Training and his/her deputy\nChief Flight Instructor\nChief Theoretical Knowledge Instructor\nCompliance Monitoring Manager\nSafety Manager\nChief Operations Officer\nDecide upon the actual selection criteria for training staff in accordance with the Operations Manual, Part 1, Chapter 2:\nTheoretical Knowledge Instructors\nFlight Instructors\nSynthetic Training Instructors\nDecide upon the selection criteria for other personnel.\nTake the final decision in accepting Nominated Persons, training staff and other personnel within EuroPilot Center.', 'OM_REV_6.0_CANONICAL_PART_4.txt', '6e039c28b00e76204cf6b3d4e1df24d3465e7d029e3fc63abb6cf23cabd52018', 'OM6_P4_1_1'),
('OM6_P4_1.2', 'OM', '6.0', 4, '1.2', 'Head of Training and his/her deputy', '1.2 Head of Training and his/her deputy\n\nHead of Training and his/her deputy\nIt is the responsibility of the Head of Training and his/her deputy to:\nEnsure sufficient training staff is available at any time to conduct the Theoretical and Flight Training in accordance with the requirements of the Operations Manual.\nAssist upon the determination of the actual selection criteria in accordance with the Operations Manual, Part 1, Chapter 2:\nChief Flight Instructor\nChief Theoretical Knowledge Instructor\nAssists upon the determination of the actual selection criteria for training staff in accordance with the Operations Manual, Part 1, Chapter 2:\nTheoretical Knowledge Instructors\nFlight Instructors\nSynthetic Training Instructors\nEnsure standardization in the teaching methods of all training staff.\nOrganize regular Standardization Meetings with the Chief Flight Instructor and Chief Theoretical Knowledge Instructor.\nMonitor and evaluate the Chief Flight Instructor on his:\nTeaching and Learning Skills;\nCurrency of License, Ratings and Medicals;\nApplication and knowledge of the Rules and Regulations;\nApplication and knowledge of the Standard Operating Procedures;\nmonitor and evaluate the Chief Theoretical Knowledge Instructor on his:\nTeaching and Learning Skills;\nApplication and knowledge of the Rules and Regulations;\nApplication and knowledge of the Standard Operating Procedures;\nAdvise the Accountable Manager on accepting training staff.', 'OM_REV_6.0_CANONICAL_PART_4.txt', '509f648abf09e29ba2278f217f832ddefdc2378d3292418df49b2584f41cb6ea', 'OM6_P4_1_2'),
('OM6_P4_1.3', 'OM', '6.0', 4, '1.3', 'Chief Flight Instructor', '1.3 Chief Flight Instructor\n\nChief Flight Instructor\nIt is the responsibility of the Chief Flight Instructor to:\nOrganize Standardization Meetings with all Flight Instructors (at least once/year);\nEnsure all Flight Instructors and Synthetic Training Instructors receive proper Initial Standardization Training;\nEnsure all Flight Instructors and Synthetic Training Instructors receive proper Recurrent Standardization Training;\nEnsure all Flight Instructors and Synthetic Training Instructors are evaluated yearly on their:\nTeaching and Learning Skills;\nCurrency of License, Ratings and Medicals;\nApplication and knowledge of the Rules and Regulations;\nApplication and knowledge of the Standard Operating Procedures;\nAdvise the Head of Training on accepting training staff.', 'OM_REV_6.0_CANONICAL_PART_4.txt', '34d8348b64dabbe3d33f2afae8a6363af29a9d1b4379ad86b97d7dc818b2e40d', 'OM6_P4_1_3'),
('OM6_P4_1.4', 'OM', '6.0', 4, '1.4', 'Chief Theoretical Knowledge Instructor', '1.4 Chief Theoretical Knowledge Instructor\n\nChief Theoretical Knowledge Instructor\nIt is the responsibility of the Chief Theoretical Knowledge Instructor to:\nOrganise Standardization Meetings with all Theoretical Knowledge Instructors (at least once/year);\nEnsure all Theoretical Knowledge Instructors receive proper Initial Standardization Training;\nensure all Theoretical Knowledge Instructors receive proper Recurrent Standardization Training;\nensure all Theoretical Knowledge Instructors are evaluated yearly on their:\nTeaching and Learning Skills;\nApplication of the Rules and Regulations;\nApplication of the Standard Operating Procedures;\nAdvise the Head of Training on accepting training staff.', 'OM_REV_6.0_CANONICAL_PART_4.txt', '72a01e39c16bdb4746de178327c0f99e19b7ad1bbb2b7504c425e64d381fd5c3', 'OM6_P4_1_4'),
('OM6_P4_1.5', 'OM', '6.0', 4, '1.5', 'Chief Operations Officer', '1.5 Chief Operations Officer\n\nChief Operations Officer\nIt is the responsibility of the Chief Operations Officer to:\nUpon request of the Accountable Manager, publish any vacant Nominated Person, training staff, Operations Officer or any other position within EuroPilot Center;\nInvite and organize the intake conversation with candidate Nominated Persons, Operations Officer, training staff etc;\nAdvise the Accountable Manager on accepting a candidate;\nSchedule, upon request of the Head of Training, Chief Flight Instructor or Chief Theoretical Knowledge Instructor, Initial or Recurrent Training for all training staff.\n\n2. INITIAL TRAINING', 'OM_REV_6.0_CANONICAL_PART_4.txt', '36192ca2a6c873732a64a45096f6b71a1a8f6bd65ec48d5649bbedffdcad0add', 'OM6_P4_1_5'),
('OM6_P4_2', 'OM', '6.0', 4, '2', 'Hours: Interactive Video Lesson (review)', '2 Hours: Interactive Video Lesson (review)', 'OM_REV_6.0_CANONICAL_PART_4.txt', 'fe335566da4ef8c0ac613e572ef2780ce77a4afcfeb56ab88a5a61dd38b78801', 'OM6_P4_2'),
('OM6_P4_2.1', 'OM', '6.0', 4, '2.1', 'Initial Training Plan', '2.1 Initial Training Plan\n\n3. REFRESHER TRAINING', 'OM_REV_6.0_CANONICAL_PART_4.txt', '01968f1d4b466fd751140658feab5217c6d884238a6bb950a533f75e4c9b7d36', 'OM6_P4_2_1'),
('OM6_P4_2.1.1', 'OM', '6.0', 4, '2.1.1', 'Aim of the course', '2.1.1 Aim of the course\nThis course is intended for Flight Instructors not having performed an initial Flight Instructor, Instrument Rating Instructor or Class Rating Instructor Course with EuroPilot Center and Theoretical Knowledge Instructor. The course will consist of:\nThe Company Standardization Courses (as required, described under Chapter 4);\n\nAn Initial Training Course Certificate signed by the new Flight/Theoretical Knowledge Instructor and countersigned by the Head of Training or his/her Deputy, will be issued at the end of this course.\n\nThe Initial Training Course Certificate must be sent to the BCAA, together with:\nThe BCAA Instructor Application form; and\nThe Instructor CV.\n\nThese documents will be saved in the Online E-Gle system for future reference.\n\nNote: Flight Instructors having received the initial Flight Instructor, Instrument Rating Instructor or Class Rating Instructor Training with EuroPilot Center, are exempted from the Initial Training Course above. They will automatically receive an Initial Training Course Certificate after having successfully completed the Flight Instructor, Instrument Rating Instructor or Class Rating Instructor Training.\n\nWe refer to OM Annex 15: Initial Training Course Certificate', 'OM_REV_6.0_CANONICAL_PART_4.txt', '78420f925d97ef969dfa4d22ef98ee95f0dc5df1e6bd9d47fbeea79e8102b648', 'OM6_P4_2_1_1'),
('OM6_P4_2.1.2', 'OM', '6.0', 4, '2.1.2', 'Training Plan', '2.1.2 Training Plan\nWe refer to the Standardization Courses described under Chapter 4.\n\n3. REFRESHER TRAINING', 'OM_REV_6.0_CANONICAL_PART_4.txt', '367f8ae2836fe83623f15eed5ee1f72d84a73bd79952afe36d50bed893457766', 'OM6_P4_2_1_2'),
('OM6_P4_3.1', 'OM', '6.0', 4, '3.1', 'Refresher Courses', '3.1 Refresher Courses\n\n4. STANDARDIZATION TRAINING', 'OM_REV_6.0_CANONICAL_PART_4.txt', '2c9148990102812f65ef38e4a270c6ed49328091a8774515b0cfe8cc723284dd', 'OM6_P4_3_1'),
('OM6_P4_3.1.1', 'OM', '6.0', 4, '3.1.1', 'Aim of the course', '3.1.1 Aim of the course\nA refresher course will be organized each year during the months of January & February for every Flight- and Theoretical Knowledge Instructor individually; or at any time:\nAfter the absence of an Instructor for 12 months or more;\nA major update of any Training Manual;\nA major update of Standard Operating Procedures;\nIntroduction of new/updated regulations;\nIntroduction of a new type of aircraft.\n\nWe refer to the Proficiency Forms on the E-Gle Online System.', 'OM_REV_6.0_CANONICAL_PART_4.txt', 'b520382694071a19cdb212cbd92d52f4c38f6156efb9f424d24b5016a7b19e32', 'OM6_P4_3_1_1'),
('OM6_P4_3.1.2', 'OM', '6.0', 4, '3.1.2', 'Training Plan', '3.1.2 Training Plan\nWe refer to the Standardization Courses described under Chapter 4.', 'OM_REV_6.0_CANONICAL_PART_4.txt', '6f45afab46e90442390159b331f77512769589034c13d7475933a195e97c35d3', 'OM6_P4_3_1_2'),
('OM6_P4_3.1.3', 'OM', '6.0', 4, '3.1.3', 'Instructor Bulletins', '3.1.3 Instructor Bulletins\nInstructor Bulletins are drafted by the Head of Training and/or his Deputy, may be urgent in nature and do not require the need to organize a refresher course.\n\nThe Instructor Bulletins are distributed via e-mail to all Flight and Theoretical Knowledge Instructors.\n\nNote: Our CRM system is able to track if the Instructor has opened the document and adds a time-stamp in the system.\n\n4. STANDARDIZATION TRAINING', 'OM_REV_6.0_CANONICAL_PART_4.txt', 'ae134f47202a24dde77e5c9510183bfa4ae50c643442c72d49e8e323baaa6597', 'OM6_P4_3_1_3'),
('OM6_P4_4', 'OM', '6.0', 4, '4', 'Hours: Interactive Video Lesson', '4 Hours: Interactive Video Lesson', 'OM_REV_6.0_CANONICAL_PART_4.txt', '1f86f763d07fceaf937d7210b47c0a0b950fb7a1194e45eb7721da60db17d559', 'OM6_P4_4'),
('OM6_P4_4.1', 'OM', '6.0', 4, '4.1', 'Courses', '4.1 Courses\n\nThe EuroPilot Center Standardization Training consists of a series of individual courses described in this chapter. They can be either part of the:\nInitial Standardization; (as described under Chapter 2) or\nA Refresher Standardization (as described under Chapter 3).\n\nThe following table indicates which individual courses a Flight or Theoretical Knowledge Instructor should take, depending on his/her Instructional activities within the ATO.\n\nINITIAL / REFRESHER STANDARDIZATION TRAINING\n\nREFER TO THE Initial_Refresher_Standardization_Matrix.csv\n\nWe refer to the Electronic Forms available on the E-Gle Online System.', 'OM_REV_6.0_CANONICAL_PART_4.txt', 'ec1ab818c09f2c700be32dc0c8b43287f0d146362f7fa0c36116a6ce7dcc4f0f', 'OM6_P4_4_1'),
('OM6_P4_4.1.1', 'OM', '6.0', 4, '4.1.1', 'Company Course', '4.1.1 Company Course\nThe aim of the Company Standardization course is to familiarize the Instructor with the operational procedures described in the following Manuals:\nOperations Manual Part 1, 2, 3 and 4;\nOMM Part 2 – Compliance Monitoring Management; and\nOMM Part 3 – Safety Management.\n\nDuration: N.A.\nCourse Method: Self-Study\n\nStudy Materials:\nPDF copy of the relevant manuals (OM, OMM)\n\nKnowledge Test:\nThe initial and refresher test will contain a questionnaire of 30 multiple choice questions.\nA passmark of 75% is applicable and the questions missed should be discussed during a debriefing.', 'OM_REV_6.0_CANONICAL_PART_4.txt', 'f7d5549cb6013d9aa064870fe77472a7416c0994e8114eaee4bf5d702a73dc53', 'OM6_P4_4_1_1'),
('OM6_P4_4.1.2', 'OM', '6.0', 4, '4.1.2', 'IT & Facilities Course', '4.1.2 IT & Facilities Course\nThe aim of the IT & Facilities Standardization course is to familiarize the the Instructor with the IT infrastructure, training aids, EuroPilot Center premises and facilities.\n\nDuration: Initial Course (1h00)\nRefresher course: Not Applicable\n\nCourse Method: Briefing\n\nStudy Materials: N.A.\n\nKnowledge Test: N.A.\n\nThe IT Manager, Ops Officers or Facility Manager will provide a briefing of 1h.', 'OM_REV_6.0_CANONICAL_PART_4.txt', '0a8857f46c1b6448fc4b060c5642e8e24ad6e51c298f6b7d219b7e5087e67852', 'OM6_P4_4_1_2'),
('OM6_P4_4.1.3', 'OM', '6.0', 4, '4.1.3', 'Garmin G1000 Course', '4.1.3 Garmin G1000 Course\nThe aim of the G1000 course is to familiarize the Instructor with the Garmin G1000 Avionics Suite.\n\nDuration: N.A.\n\nCourse Method: Self-Study\n\nStudy Materials:\nGarmin G1000 Operating Manual\nGarmin G1000 Cockpit Reference Guide C172SP FNPT\n\nKnowledge Test: N.A.\n\nA passmark of 75% is applicable and the questions missed should be discussed during a debriefing.', 'OM_REV_6.0_CANONICAL_PART_4.txt', '1afcc07a76ab32e3ef1d6bad240ca5979b23f3fb4547edc443598d0173af1dd1', 'OM6_P4_4_1_3'),
('OM6_P4_4.1.4', 'OM', '6.0', 4, '4.1.4', 'Aircraft SOP Course', '4.1.4 Aircraft SOP Course\nThe aim of the Aircraft SOP Standardization course is to familiarize the Instructor with the relevant Standard Operating Procedures of the training aircraft to be used.\n\nDuration: N.A.\n\nCourse Method: Self-Study\n\nStudy Materials:\nOM Annex 07 (for the C172SP)\nOM Annex 08 (for the R44)\nTM Annex 09 (for the DA42)\n\nKnowledge Test:\nThe Initial and refresher test will contain 20 multiple choice questions.\nA passmark of 75% is applicable and the questions missed should be discussed during a debriefing.', 'OM_REV_6.0_CANONICAL_PART_4.txt', 'd8ee79403f8cfd819a479336b982a878ce224922c783584694f983d4e53d59e8', 'OM6_P4_4_1_4'),
('OM6_P4_4.1.5', 'OM', '6.0', 4, '4.1.5', 'Training Manual Course', '4.1.5 Training Manual Course\nThe aim of the Training Manual Standardization Course is to familiarize the Instructor with the course syllabus used for the course he/she will teach.\n\nDuration: N.A.\n\nCourse Method: Self-Study\n\nStudy Materials:\nRelevant Training Manual for the course\nBriefing and Air Exercises relevant for the course\n\nKnowledge Test:\nFor the Initial Course, a 1h oral quiz/discussion with the (Deputy) Head of Training, Chief Theoretical Knowledge Instructor or Chief Flight Instructor or any of his/her delegated Flight or Theoretical Knowledge Instructors is required.\n\nRefresher course: Not Applicable\n\nThe assessor should verify if the Instructor possesses sound knowledge of the training syllabus, the standardized teaching methods required to execute the described (Long) Briefings, FSTD scenario’s, Aircraft Scenario’s and Progress Tests.', 'OM_REV_6.0_CANONICAL_PART_4.txt', 'edd0bd3bc41e6af8fba6bd62cc9660950a78540099ebfe7cc4d6e6c03cfe044a', 'OM6_P4_4_1_5'),
('OM6_P4_4.1.6', 'OM', '6.0', 4, '4.1.6', 'FSTD Operations Course', '4.1.6 FSTD Operations Course\nThe aim of the FSTD Standardization Course is to familiarize the Instructor with the FSTD, Safety Procedures, Loading Training Scenarios and using the the Instructor Station as well as minor troubleshooting.\n\nDuration: Initial course (1h00)\n\nRefresher course: Not Applicable\n\nCourse Method: Simulator Assisted Briefing\n\nStudy Materials:\nOM Annex 02 (FSTD Safety Briefing)\nFSTD Operating Handbook\n\nKnowledge Test: N.A.\n\nA Flight Instructor appointed by the (Deputy) Head of Training will provide a briefing of 1h.', 'OM_REV_6.0_CANONICAL_PART_4.txt', '8fde5193b8142bc27b9d3938753382d9ac7650f81c8271b54c711b368650cfd5', 'OM6_P4_4_1_6'),
('OM6_P4_4.1.7', 'OM', '6.0', 4, '4.1.7', 'Practical Training', '4.1.7 Practical Training\nThe aim of the Practical Training Standardization Course is to apply the Standard Operating Procedures into a practical teaching environment and to familiarize with the Aircraft/FSTD used.\n\nThe (Deputy) Head of Training / Chief Flight Instructor shall determine the duration of the Initial training program, based upon the individual experience of the Instructor, with a minimum of no less than:\n1h training in the FSTD (if an FSTD is available); and\n1h in the Aircraft.\n\nThe (Deputy) Head of Training / Chief Flight Instructor shall determine the duration of the Refresher training program, based upon the individual experience of the Instructor, with a minimum of no less than:\n1h training in the FSTD (if an FSTD is available); or\n1h in the Aircraft.\n\nThe exercises of the training session will be allocated by the (Deputy) Head of Training / Chief Flight Instructor and should be based on the Briefing and Air Exercises of the course to be taught with the focus on Safety, Standard Operating Procedures and Teaching Methods.', 'OM_REV_6.0_CANONICAL_PART_4.txt', '495bf3f2768f2494ccebb42d2e85e32c86b67b06f7e71f14b59f8505c80fb553', 'OM6_P4_4_1_7'),
('OM6_P4_4.1.8', 'OM', '6.0', 4, '4.1.8', 'KSA.100 Training', '4.1.8 KSA.100 Training\nThe aim of the EuroPilot Center KSA.100 Training Course is to ensure that:\n\nAll Theoretical Knowledge Instructors and Flight Instructors, delivering Area 100 KSA (Knowledge, Skills, Attitudes) instruction, are proficient in accordance with AMC2.ORA.ATO.230(a)(c), including:\nLearning styles;\nTeaching methods;\nFacilitation techniques;\nThreat and error management (TEM);\nThe applicable competencies; and\nThe content of the subject(s) and exercises that they are to deliver.\n\nAll Theoretical Knowledge Instructors and Flight Instructors assessing Area 100 KSA (Knowledge, Skills, Attitudes), are proficient in accordance with AMC2.ORA.ATO.230(a)(e) on how to conduct these assessment(s) in a standardized fashion, whereby assessment grades awarded are consistent across EuroPilot Center.\n\nNote: Since EuroPilot Center ATO has designed a proprietary algorithm and unique methodology, ensuring 100% objectivity of the evaluator(s), this standardization is guaranteed.\n\nStandardisation includes:\nFamiliarization with the KSA.100 performance indicators (PI’s);\nWord pictures for grading; and\nThe E-gle grading and debriefing system.\n\nAfter having successfully completed the Initial KSA.100 Training Course, the Instructor is proficient in both delivering KSA.100 training (“Formative”) AND assessing (“Summative”) of the approved training courses within EuroPilot Center, during a period of 1 year.\n\nRecurrent KSA.100 Training is required each year as per AMC2.ORA.ATO.230(a)(d) and (f).\n\nDuration: Initial course (8h00):', 'OM_REV_6.0_CANONICAL_PART_4.txt', '40cabba750f8d7dc92faf2e16041e2ba52eddddeefb92dd38fcafd34d14478c6', 'OM6_P4_4_1_8'),
('OM6_P4_4.2', 'OM', '6.0', 4, '4.2', 'Standardisation Meetings', '4.2 Standardisation Meetings\n\nA yearly Standardization Meeting will be organized by the Accountable Manager and (Deputy) Head of Training for all training staff whereby common errors/problems will be discussed.\n\nThese meeting shall take place via the Online Webinar System of EuroPilot Center and will be recorded for future reference.\n\n\n\n5. PROFICIENCY CHECKS\n\nFor the purpose of training staff checking, the following Proficiency Checks will be performed once a year:\nCompany Refresher – Multiple Choice Questionnaire (30 questions)\nAircraft SOP Refresher – Multiple Choice Questionnaire (20 questions)\nPractical Training Refresher – 1h training in the FSTD or in the Aircraft\nKSA.100 Training Refresher – Multiple Choice Questionnaire (20 questions) + 1h training in the FSTD\n\nWe refer to the Proficiency Forms on the E-Gle Online System.\n\n6. UPGRADE TRAINING\n\nNot applicable within EuroPilot Center.\n\n\n\n7. PERSONNEL STANDARDS EVALUATION', 'OM_REV_6.0_CANONICAL_PART_4.txt', '20fe693b1ff66038494439535f1ec1b01d7fed6f4d0dc3287f1e99a659f09eb7', 'OM6_P4_4_2'),
('OM6_P4_7.1', 'OM', '6.0', 4, '7.1', 'Training Feedback Forms', '7.1 Training Feedback Forms\n\nAs a means of improving the quality of EuroPilot Center training courses, students are requested to file Training Feedback Forms for Theory, Synthetic or Flight Training sessions. The Chief Operations Officer will be responsible for collecting the forms and store them at a secure location within the EuroPilot premises.\n\nWe refer to OM Annex 22: Training Feedback Form.', 'OM_REV_6.0_CANONICAL_PART_4.txt', 'd3ab7cb3e93009f726611b4472c6583ab9f580bb819cc58b814b287e612f8382', 'OM6_P4_7_1'),
('OM6_P4_7.2', 'OM', '6.0', 4, '7.2', 'Instructor Evaluation', '7.2 Instructor Evaluation\n\nThe Head of Training is responsible for organizing a yearly individual Instructor evaluation. The evaluation shall be based on:\nThe Proficiency Check results;\nHomestudy Progress Check results;\nThe Training Feedback Forms;\nOccurence Reports.\n\nA digital Instructor Evaluation Report will be produced and discussed during the individual Instructor Evaluation.\n\nWe refer to OM Annex 23: Instructor Evaluation Report.', 'OM_REV_6.0_CANONICAL_PART_4.txt', '1b1ecadff05f8ed000148a7a1b4411e91adbad8cbc4ee095a95fcc404e3aa827', 'OM6_P4_7_2'),
('OMM_P0_0', 'OMM', '4.0', 0, '0', 'OUTLINE', 'This part describes the administration, control, revision, distribution, and amendment tracking of the Organization Management Manual (OMM).\n\n0.1 List of Effective Pages\n0.2 Revision System\n0.3 Amendment List\n0.4 Distribution List\n0.5 Highlight of Changes\n\n\n0.1 List of Effective Pages\n\nEuroPilot Center’s nominated persons certify that the content of this Organization Management Manual (OMM) complies with all applicable EASA Part FCL, Part ORA and all other relevant subparts.\n\nAccountable Manager\nMaria A. Paz\n\nCompliance Monitoring Manager\nStef Van De Sompele\n\nEffective Parts:\nPart 0 – Pages 1–9 – Revision 4 – Date 24/12/2022\nPart 1 – Pages 1–23 – Revision 4 – Date 24/12/2022\nPart 2 – Pages 1–33 – Revision 4 – Date 24/12/2022\nPart 3 – Pages 1–57 – Revision 4 – Date 24/12/2022\n\n\n0.2 Revision System\n\nThe Organization Management Manual and its amendments are proposed, drafted, issued, accepted and implemented by the Head of Training after a BCAA spot check.\n\nThe Compliance Monitoring Manager ensures that the content of the Organization Management Manual complies with all applicable regulations and requirements.\n\nAny amendment proposal by the Head of Training shall be executed by sending an e-mail to the Compliance Monitoring Manager and the Accountable Manager. The e-mail shall include the revised draft of the applicable manual, section or paragraph, as well as the reason(s) for the amendment.\n\nUpon verification of the draft by the Compliance Monitoring Manager, the amendment shall be sent to the BCAA.\n\nAll amendments shall be accompanied by an updated List of Effective Parts. Changes, additions or deletions are identified by a vertical bar placed in front of the revised text.\n\nA “Highlight of Changes” paragraph shall contain a full history of changes between revisions.\n\nDigital, password-protected PDF versions of the Organization Management Manual may be distributed and shall be marked “Uncontrolled Copy” on each page and protected against printing.\n\nA Temporary Revision Procedure is not applicable within EuroPilot Center B/ATO-017.\n\n0.3 Amendment List\n\nOriginal – First issue of the Organization Management Manual – 01/07/2013\nRevision 1 – Amendment 1 – 30/06/2017\nRevision 2 – Addition NQ to ATO – 28/08/2018\nRevision 3 – Audit findings and miscellaneous changes – 02/11/2019\nRevision 4 – Audit findings and miscellaneous changes – 24/12/2022\n\nThe Amendment List records all revisions and is retained until replaced by a new issue.\n\n0.4 Distribution List\n\nCopy 0 – Master Copy\nCopy 1 – BCAA – Training Department (Signed Digital PDF file)\n\nNo hard copies are required by the BCAA since 2018.\n\n0.5 Highlight of Changes\n\nRevision 3 Changes\n\n• Part 0 – List of Effective Pages, BCAA Acceptance-stamp box removed.\n• Part 1 – Chapter 1, Chapter 1.2, address change of USA Training satellite location.\n• Part 1 – Addition of the Private Pilot PPL(A) and Theoretical Course PPL(A).\n• Part 2 – Chapter 5, Paragraph 5.1.4, text amended: If no action is taken within the extended time limit, it is the responsibility of the Compliance Monitoring Manager to inform the Civil Aviation Authorities according and suggest an acceptable solution.\n• Part 2 – Chapter 7.2.3, defect Reporting, added the Alsim Techlog Procedure for BE/FNPT-024.\n• Part 2 – Chapter 12, Paragraph 12.2.4 added in order to describe the action required in case of a major change, relocation, deactivation, major failure or safety issue with an FSTD.\n• Part 2 – Chapter 6, Paragraph 6.1.5 details for a dossier for recurrent evaluation added.\n• Part 3 – Chapter 3, Paragraph 3.2.1 change of nominated persons.\n• Part 3 – Safety Management Manual, Chapter 5, Paragraph 5.6.1 updated to include preliminary and final reporting timelines.\n• Part 3 – Safety Management Manual, Chapter 5, Paragraph 5.6.5 anonymous reporting URL added.\n• Annex 20 – FSTD updated with FNPT-024.\n• Annex 24 – FNPT-02 Difference List added.\n\nRevision 4 Changes\n\n• Part 0 – Title page added.\n• Part 0 – Chapter 0.1 page numbers updated.\n• Part 0 – Chapter 0.2 revision procedure updated per BCAA remarks.\n• Part 0 – Temporary Revision Procedure note added.\n• Part 0 – Record of Revision updated.\n• Part 0 – Distribution List updated.\n• Part 1 – Satellite base information updated.\n• Part 1 – Legal Status updated with resignation statement and Annex 25 added.\n• Part 1 – Training courses overview updated.\n• Part 1 – Organization chart updated.\n• Part 1 – Facilities annex updated.\n• Part 1 – Contracted Training updated.\n• Part 1 – Change procedures updated.\n• Part 2 – Compliance Monitoring Policy updated.\n• Part 2 – Inspection Scopes updated and new annexes added.\n• Part 2 – Regulatory Changes Follow-up Procedures added.\n• Part 3 – Safety Policy updated and Annex 29 added.\n• Part 3 – Safety Review Board procedures updated.\n• Part 3 – Management of Change updated.\n• Part 3 – Safety Committee Airport Meetings added.\n• Manual renamed to Organization Management Manual following BCAA remarks.', NULL, NULL, 'OMM_P0_0'),
('OMM_P1_0', 'OMM', '4.0', 1, '0', 'OUTLINE', '1.	GENERAL INFORMATION\n 1.1 Principle Place of Business\n 1.2 Training Locations\n	2.	LEGAL STATUS OF THE ATO\n	3.	TRAINING COURSES OFFERED\n	4.	ORGANIZATION CHART\n	5.	MANAGEMENT AND STAFF\n	6.	INSTRUCTION STAFF\n	7.	ADMINISTRATIVE STAFF\n	8.	AERODROMES AND OPERATING SITES\n	9.	FLIGHT OPS ACCOMMODATION\n	10.	THEORETICAL INSTRUCTION FACILITIES\n	11.	DESCRIPTION OF TRAINING DEVICES\n	12.	DESCRIPTION OF AIRCRAFT\n	13.	DIDACTIC MATERIAL\n	14.	CONTRACTED TRAINING\n 14.1 General\n  14.1.1 Organizations certified\n  14.1.2 Organizations not certified\n 14.2 Procedure to establish a contracted activity\n	15.	ACCESS\n	16.	CHANGES NOT REQUIRING PRIOR APPROVAL OF THE BCAA\n 16.1 Hiring new Theoretical Knowledge Instructors (TKI’s)\n 16.2 Hiring new Flight Instructors (FI(A), CRI, IRI, MCCI’s)\n 16.3 Adding / Removing Aircraft\n 16.4 Notification of changes to the BCAA\n  16.4.1 Flight / Theoretical Knowledge Instructors\n  16.4.2 Aircraft', NULL, NULL, 'OMM_P1_0'),
('OMM_P1_1', 'OMM', '4.0', 1, '1', 'GENERAL INFORMATION', '1.1 Principle Place of Business\n\nEuroPilot Center\nLuchthavenlei EPC Building Box 210\nB-2100 Antwerp\nBelgium\n\n1.2 Training Locations\n\nMain Training Location\nEuroPilot Center\nLuchthavenlei EPC Building Box 210\nB-2100 Antwerp\nBelgium\n\nSatellite Training Location (USA)\nSoCal Pilot Center\nThermal Airport (KTRM)\nThermal, California\nUnited States of America', NULL, NULL, 'OMM_P1_1'),
('OMM_P1_10', 'OMM', '4.0', 1, '10', 'THEORETICAL INSTRUCTION FACILITIES', 'We refer to OMM Annex 18 – EuroPilot Center’s premises.\n\nWe refer to OMM Annex 19 – SoCal Pilot Center’s premises.', NULL, NULL, 'OMM_P1_10'),
('OMM_P1_11', 'OMM', '4.0', 1, '11', 'DESCRIPTION OF TRAINING DEVICES', 'We refer to OMM Annex 20 – EuroPilot Center FSTD’s.\n\nWe refer to the BCAA LA/L-TRA/0155EE procedure “Modify ATO FSTD List” which can be found on the BCAA website.\n\nAlways consult the latest version of the published BCAA LA/L-TRA/0155EE procedure in order to comply with the latest requirements.', NULL, NULL, 'OMM_P1_11'),
('OMM_P1_12', 'OMM', '4.0', 1, '12', 'DESCRIPTION OF AIRCRAFT', 'We refer to OMM Annex 21 – EuroPilot Center’s Training Aircraft.\n\nWe refer to OMM Part 1, Chapter 16 – Changes not requiring prior approval of the BCAA.', NULL, NULL, 'OMM_P1_12'),
('OMM_P1_13', 'OMM', '4.0', 1, '13', 'DIDACTIC MATERIAL', 'We refer to the Training Manual of the applicable Training Course for a detailed overview of the training materials (Books, CBT’s) used.\n\nA cross reference list can also be found as an annex to the applicable Training Course.', NULL, NULL, 'OMM_P1_13'),
('OMM_P1_14', 'OMM', '4.0', 1, '14', 'CONTRACTED TRAINING', '14.1 General\n\nIn accordance with ORA.GEN.205, contracted activities include all activities within EuroPilot Center’s ATO scope of approval that are performed by another organization either:\n\n• itself certified to carry out such activity; or\n• working under the EuroPilot Center’s approval.\n\nEuroPilot Center is responsible to ensure that all contracted activities are subject to hazard identification and risk management as required by ORA.GEN.200(a)(3) and to compliance monitoring as required by ORA.GEN.200(a)(6).\n\n\n\n14.1.1 Organizations certified\n\nA written agreement should exist between the organization and the contracted organization clearly defining the contracted activities and the applicable requirements.\n\nA copy of this agreement must be sent to the BCAA prior to the start of the contracted activities.\n\nEuroPilot Center’s compliance monitoring system will at least check that the approval of the contractor effectively covers the contracted activities and that it is still valid.\n\n\n\n14.1.2 Organizations not certified\n\nWhen EuroPilot Center contracts any part of its activity to an organization that is not itself certified in accordance with this Part to carry out such activity, the contracted organization shall work under the approval of EuroPilot Center.\n\nA written agreement should exist between the organization and the contracted organization clearly defining the contracted activities and the applicable requirements.\n\nA copy of this agreement must be sent to the BCAA prior to the start of the contracted activities.\n\nIn addition, EuroPilot Center shall ensure that the BCAA is given access to the contracted organization, to determine continued compliance with the applicable requirements.\n\n\n\n14.2 Procedure to establish a contracted activity\n\nThe requirements as mentioned under the EuroPilot Center OMM must be met prior to the start of the contracted activities:\n\n• Part 2, Compliance Monitoring Management, Chapter 8 – Contractor / Supplier Management; and\n• Part 3, Safety Management Manual, Chapter 7 – Contracted Activities.\n\nThe Accountable Manager is responsible to evaluate the financial and safety aspects of the cooperation and send a “Change Request” to the Safety Manager AND Compliance Monitoring Manager in order to trigger a “Management of Change” procedure.\n\nWe refer to the procedure in OMM Part 3 – Chapter 5.9 Management of Change.', NULL, NULL, 'OMM_P1_14'),
('OMM_P1_15', 'OMM', '4.0', 1, '15', 'ACCESS', 'Access to the EuroPilot Center premises is provided to all Flight Instructors, Theoretical Knowledge Instructors, FSTD maintenance personnel and students enrolled in the training programs.\n\nA badge system restricts the access to the EuroPilot Center building after office hours.\n\nHangars accessibility is restricted by use of the Antwerp Airport badge.', NULL, NULL, 'OMM_P1_15'),
('OMM_P1_16', 'OMM', '4.0', 1, '16', 'CHANGES NOT REQUIRING PRIOR APPROVAL OF THE BCAA', 'In accordance with ORA.GEN.130(c), the following changes do not require prior approval by the BCAA:\n\n• changes in Theoretical Knowledge Personnel;\n• changes in Flight Instruction Personnel;\n• adding or removing aircraft.\n\nThe Accountable Manager is authorized to hire new training staff and add or remove aircraft to the training fleet as required by the operational needs of the organization.\n\nWe refer to OM Part 4 – Chapter 1, Responsibilities.\n\nFor every change, the Accountable Manager is responsible to send a “Change Request” to the Safety Manager AND Compliance Monitoring Manager in order to trigger a “Management of Change” procedure.\n\nWe refer to the procedure in OMM Part 3 – Chapter 5.9 Management of Change.\n\n\n\n16.1 Hiring new Theoretical Knowledge Instructors (TKI’s)\n\nEvery new Theoretical Knowledge Instructor shall in accordance with AMC1 ORA.ATO.110(c) have a practical background in aviation in the areas relevant for the training provided and have undergone a course of training in instructional techniques, or have previous experience in giving theoretical knowledge instruction and an appropriate theoretical background in the subject on which the candidate will provide theoretical knowledge instruction.\n\nThe defined hiring procedure shall be followed.\n\n• Step 1 – The Accountable Manager sends a “Change Request” to the Safety Manager AND Compliance Monitoring Manager via e-mail. The header of the e-mail must contain: “Change Request: New TKI + FIRST NAME, LAST NAME” and the content of the e-mail should outline the details of the proposed changes, including the Resume of the applicant and additional relevant data.\n\n• Step 2 – Upon receiving this e-mail, the Safety Manager creates a new “Change Request Project” in Pipedrive and saves it under Phase 1 of the Project Pipeline in Pipedrive.\n\n• Step 3 – The Safety Manager moves on to Phase 2 of the Project Pipeline in Pipedrive and executes the “Management of Change” procedure as described in the OMM Part 3.\n\n• Step 4 – The Safety Manager drafts his/her findings in the Project Notes and uploads any additional required PDF documents (if required) in the project.\n\n• Step 5 – the Safety Manager moves on to Phase 3 of the Project Pipeline and creates an “Assessment Task/Event Checklist” (this process is monitored by the CMM) containing:\n	1.	Verification of relevant experience by the Safety Manager + Deadline.\n	2.	Uploading ID/Passport in the Project.\n	3.	Scheduling and executing a Psychological Assessment: PELICAN Test online.\n	4.	Motivational Interview (in-person or online) by: AM, SM, HT or Chief TKI.\n	5.	Scheduling/executing a supervised Test Lecture, by the HT or Chief TKI.\n	6.	Scheduling/execution “Decision Meeting” with AM, CMM, HT and Chief TKI.\n	7.	Final Verification of the CMM performed.\n\n• Step 6 – The Safety Manager records the minutes of the “Decision Meeting” in the Project Notes and sends an e-mail to the AM, CMM, HT and Chief TKI which must include the final decision on hiring the applicant or not.\n\nOption A - After a positive evaluation of steps 1 to 6 above:\n\n• Step 7a - The Safety Manager creates a “Hiring Task/Event Checklist” containing:\n	1.	Sending an e-mail to applicant notifying about the decision taken.\n	2.	Sending out the Theoretical Knowledge Instructor Contract via Docusign.\n	3.	Scheduling the require standardization training.\n	4.	Sending an e-mail to the applicant outlining the standardization training items.\n	5.	Adding the applicant to the Theoretical Knowledge Instructor Annex.\n	6.	The Accountable Manager notifies the BCAA of the upcoming change via e-mail, at least 10 days before the new Theoretical Knowledge Instructor will start his/her duties. He/she shall attach the updated Theoretical knowledge Instructor Annex.\n	7.	Instructor Data saved in E-gle + FlightCircle by the Operations Manager.\n	8.	Final Verification by the CMM performed.\n\nOption B - After a negative evaluation of steps 1 to 6 above:\n\n• Step 7b - The Safety Manager creates an “End of Project Checklist” containing:\n	1.	Sending an e-mail to applicant notifying about the decision taken.\n	2.	Sending an e-mail to the AM, CMM, HT and Chief TKI about the outcome.\n\n• Step 8 - The Compliance Monitoring Manager verifies if all steps in the process above are executed as described and moves the Project to Stage 4 of the Project Pipeline: End.\n\n\n\n16.2 Hiring new Flight Instructors (FI(A), CRI, IRI, MCCI’s)\n\nEvery new Flight Instructor shall in accordance with ORA.ATO.110(d) hold the qualifications required by Part-FCL for the type of training that the candidate will provide on an aircraft and/or FSTD.\n\nThe defined hiring procedure shall be followed.\n\n• Step 1 – The Accountable Manager sends a “Change Request” to the Safety Manager AND Compliance Monitoring Manager via e-mail. The header of the e-mail must contain: “Change Request: New FI/CRI/IRI/MCCI + FIRST NAME, LAST NAME” and the content of the e-mail should outline the details of the proposed changes, including the Resume of the applicant and additional relevant data (e.g. Medical, License, Logbook Scan, Additional Certificates).\n\n• Step 2 – Upon receiving this e-mail, the Safety Manager creates a new “Change Request Project” in Pipedrive and saves it under Phase 1 of the Project Pipeline in Pipedrive.\n\n• Step 3 – The Safety Manager moves on to Phase 2 of the Project Pipeline in Pipedrive and executes the “Management of Change” procedure as described in the OMM Part 3.\n\n• Step 4 – The Safety Manager drafts his/her findings in the Project Notes and uploads any additional required PDF documents (if required) in the project.\n\n• Step 5 – the Safety Manager moves on to Phase 3 of the Project Pipeline and creates an “Assessment Task/Event Checklist” (this process is monitored by the CMM) containing:\n	1.	Verification of relevant experience by the Safety Manager + Deadline.\n	2.	Uploading: ID/Passport, Medical Class, Pilot License and the last page of the applicant’s Logbook in the Project.\n	3.	Scheduling and executing a Psychological Assessment: PELICAN Test online.\n	4.	Motivational Interview (in-person or online) by: AM, HT or CFI.\n	5.	Scheduling/executing a 1 hour assessment by the HT or his/her deputy or CFI on the FSTD in order to verify the instructional skills of the applicant.\n	6.	Scheduling/execution of a “Decision Meeting” with the AM, CMM, HT and CFI.\n	7.	Final Verification of the CMM performed.\n\n• Step 6 – The Safety Manager records the minutes of the “Decision Meeting” in the Project Notes and sends an e-mail to the AM, CMM, HT and CFI which must include the final decision on hiring the applicant or not.\n\nOption A - After a positive evaluation of steps 1 to 6 above:\n\n• Step 7a - The Safety Manager creates a “Hiring Task/Event Checklist” containing:\n	1.	Sending an e-mail to applicant notifying about the decision taken.\n	2.	Sending out the Flight Instructor Contract via Docusign.\n	3.	Scheduling the require standardization training.\n	4.	Sending an e-mail to the applicant outlining the standardization training items.\n	5.	Adding the applicant to the Flight Instructor Annex.\n	6.	The Accountable Manager notifies the the BCAA of the upcoming change via e-mail, at least 10 days before the new Flight Instructor will start his/her duties. He/she shall attach the updated Flight Instructor Annex.\n	7.	Instructor Data saved in E-gle + FlightCircle by the Operations Manager.\n	8.	Final Verification by the CMM performed.\n\nOption B - After a negative evaluation of steps 1 to 6 above:\n\n• Step 7b - The Safety Manager creates an “End of Project Checklist” containing:\n	1.	Sending an e-mail to applicant notifying about the decision taken.\n	2.	Sending an e-mail to the AM, CMM, HT and CFI about the outcome.\n\n• Step 8 - The Compliance Monitoring Manager verifies if all steps in the process above are executed as described and moves the Project to Stage 4 of the Project Pipeline: End.\n\n\n\n16.3 Adding / Removing Aircraft\n\nA new training aircraft shall fulfill the requirements in accordance with ORA.ATO.135 and AMC1 ORA.ATO.135.\n\nThe following procedure applies:\n\n• Step 1 – The Accountable Manager sends a “Change Request” to the Safety Manager AND Compliance Monitoring Manager via e-mail. The header of the e-mail must contain: “Change Request: New Aircraft + REGISTRATION” and the content of the e-mail should outline the details of the proposed changes, including the relevant data (e.g. Aircraft Documents).\n\n• Step 2 – Upon receiving this e-mail, the Safety Manager creates a new “Change Request Project” in Pipedrive and saves it under Phase 1 of the Project Pipeline in Pipedrive.\n\n• Step 3 – The Safety Manager moves on to Phase 2 of the Project Pipeline in Pipedrive and executes the “Management of Change” procedure as described in the OMM Part 3.\n\nAs a guideline, the following items should at least be taken into consideration by the SM:\n	•	Is the new aircraft suitable for the home and alternate bases (are there any limitations)?\n	•	Is the development of new SOP’s required?\n	•	Is an update of the relevant parts of the OM and Training Manuals required?\n	•	Is a refresher/standardization training required for Flight Instructors needed?\n	•	Is there maintenance available?\n\n• Step 4 – The Safety Manager drafts his/her findings in the Project Notes and uploads any additional required PDF documents (if required) in the project.\n\n• Step 5 – the Safety Manager moves on to Phase 3 of the Project Pipeline and creates an “Assessment Task/Event Checklist” (this process is monitored by the CMM) containing:\n	1.	Management of Change Procedure Safety Item(s) + Mitigation Actions added by the Safety Manager.\n	2.	Certificate of Registration checked/uploaded (Pipedrive) by the SM.\n	3.	Certificate of Airworthiness checked/uploaded (Pipedrive) by the SM.\n	4.	Valid Airworthiness Review Certificate checked/uploaded (Pipedrive) by the SM.\n	5.	Noise Certificate checked/uploaded (Pipedrive) by the SM.\n	6.	Aircraft Radio Station License checked/uploaded (Pipedrive) by the SM.\n	7.	Last page of the Journey Log checked/uploaded (Pipedrive) by the SM.\n	8.	MEL/CDL (if applicable) checked/uploaded (Pipedrive) by the SM.\n	9.	Last revision of POH/checklist checked/uploaded (Pipedrive) by the SM.\n	10.	Maintenance (eg. Last 100h/Annual) checked/uploaded (Pipedrive) by the SM.\n	11.	Third Party Liability Insurance checked/uploaded (Pipedrive) by the SM.\n	12.	Copy of CAMO Contract checked/uploaded (Pipedrive) by the SM.\n	13.	Verification of Squawk Items: checked/uploaded (Pipedrive) by the SM.\n	14.	Final Verification of the CMM performed.\n\n• Step 6 – The Safety Manager records possible findings in the Project Notes and sends an e-mail to the AM, CMM, and HT outlining these findings.\n\n\n\n\n16.4 Notification of changes to the BCAA\n\nA notification shall be sent by the Accountable Manager via e-mail at least 10 working days before the date of the proposed change.\n\n• The e-mail address to be used: BCAA.ATO@mobilit.fgov.be\n\n16.4.1 Flight/Theoretical Knowledge Instructors\nThe subject of the e-mail to be sent by the Accountable Manager shall be as follows:\n\n• “EuroPilot Center B/ATO-017 (L-TRA/0153)”\n\nFor Flight Instructors, the OMM Annex – Flight Instructors, shall be attached in a PDF format with the following file name:\n\n• BE_ATO-017_FI list_Vx.x_yyyy-mm-dd.pdf\n\nFor Theoretical Knowledge Instructors, the OMM Annex – Theoretical Knowledge Instructors, shall be attached in a PDF format with the following file name:\n\n• BE_ATO-017_TKI list_Vx.x_yyyy-mm-dd.pdf\n\nNote: The email shall include the request and indicate the date at which the instructor will start his duty.\n\n\n\n16.4.2 Aircraft\nFor Aircraft, the OMM Annex – Aircraft List, shall be attached in a PDF format with the following file name:\n\n• BE_ATO-017_AC list_Vx.x_yyyy-mm-dd.pdf', NULL, NULL, 'OMM_P1_16'),
('OMM_P1_2', 'OMM', '4.0', 1, '2', 'LEGAL STATUS OF THE ATO', 'The legal status of EuroPilot Center is documented and established in accordance with the applicable Belgian and EASA regulations.\n\nReference is made to the relevant annexes describing the legal status of the organization and any declarations regarding vested interests.', NULL, NULL, 'OMM_P1_2'),
('OMM_P1_3', 'OMM', '4.0', 1, '3', 'TRAINING COURSES OFFERED', 'EuroPilot Center offers approved training courses in accordance with its ATO certificate.\n\nThe scope of training includes theoretical knowledge instruction, flight training, and simulator training as applicable.\n\nDetails of the courses offered are provided in accordance with the applicable Training Manuals and annexes.', NULL, NULL, 'OMM_P1_3'),
('OMM_P1_4', 'OMM', '4.0', 1, '4', 'ORGANIZATION CHART', 'The organization chart defines the management structure, lines of responsibility, and reporting relationships within EuroPilot Center.\n\nReference is made to the applicable annexes and procedures for the acceptance of nominated persons.', NULL, NULL, 'OMM_P1_4'),
('OMM_P1_5', 'OMM', '4.0', 1, '5', 'MANAGEMENT AND STAFF', 'The management and staff structure of EuroPilot Center ensures that sufficient qualified personnel are available to support all approved training activities.\n\nResponsibilities and qualifications of management and staff are defined in accordance with the applicable regulations and internal procedures.', NULL, NULL, 'OMM_P1_5'),
('OMM_P1_6', 'OMM', '4.0', 1, '6', 'INSTRUCTION STAFF', 'Reference is made to:\nOMM Annex 15 – Theoretical Knowledge Instructors\nOMM Annex 16 – Flight Instructors\n\nReference is also made to OMM Part 1, Chapter 16 – Changes not requiring prior approval of the BCAA.', NULL, NULL, 'OMM_P1_6'),
('OMM_P1_7', 'OMM', '4.0', 1, '7', 'ADMINISTRATIVE STAFF', 'Reference is made to:\nOMM Annex 17 – Administrative Staff', NULL, NULL, 'OMM_P1_7'),
('OMM_P1_8', 'OMM', '4.0', 1, '8', 'AERODROMES AND OPERATING SITES', 'Reference is made to:\nOM Part 3 Route, Chapter 5 – Training Area\n\nReference is also made to the applicable Training Manual (TM) for the relevant training course.', NULL, NULL, 'OMM_P1_8'),
('OMM_P1_9', 'OMM', '4.0', 1, '9', 'FLIGHT OPS ACCOMMODATION', 'We refer to OMM Annex 18 – EuroPilot Center’s premises.\n\nWe refer to OMM Annex 19 – SoCal Pilot Center’s premises.', NULL, NULL, 'OMM_P1_9'),
('OMM_P2_0', 'OMM', '4.0', 2, '0', 'OUTLINE', '1.	COMPLIANCE MONITORING POLICY\n 1.1 Compliance Monitoring Policy\n 1.2 Relevant External Standards\n 1.3 Internal Standards and Procedures\n 1.4 Policy Deployment\n  1.4.1 Annual Company Goals\n	2.	CONCEPT OF COMPLIANCE MONITORING SYSTEM\n 2.1 Purpose of the Compliance Monitoring System\n 2.2 Overview of the Compliance Monitoring System\n 2.3 Core Elements of the Compliance Monitoring System\n 2.4 Organization Changes\n	3.	ORGANIZATION, RESPONSIBILITIES AND DUTIES\n 3.1 EuroPilot Center – ATO Organigram\n 3.2 Duties and Responsibilities\n  3.2.1 Accountable Manager\n  3.2.2 HOT, CFI, CTKI, CAM and FSTD Manager\n  3.2.3 Compliance Monitoring Manager / Auditor\n   3.2.3.1 Requirements\n   3.2.3.2 Duties and Responsibilities\n  3.2.4 Compliance Monitor / Auditor Training (Initial & Recurrent)\n	4.	COMPLIANCE MONITORING INSPECTIONS\n 4.1 Inspection Procedure\n 4.2 Inspection Scopes\n	5.	COMPLIANCE MONITORING AUDITS\n 5.1 Audit Procedure\n  5.1.1 Audit Planning\n   5.1.1.1 Audit Checklist\n  5.1.2 Performance of the Audit\n   5.1.2.1 Interviews\n   5.1.2.2 Observation of activities\n   5.1.2.3 Review and Examination\n  5.1.3 Reporting\n   5.1.3.1 Initiating of measures\n  5.1.4 Follow-up of corrective actions\n 5.2 Qualification of Auditors\n  5.2.1 Auditor Independence\n  5.2.2 Code of Ethics\n 5.3 Audit Scope\n 5.4 Classification of Audit Findings\n 5.5 List of Auditors\n	6.	QTG RUNNING, QTG CHECKING AND FLY-OUT PROCEDURES\n 6.1 Procedure\n  6.1.1 FSTD Audit Planning\n   6.1.1.1 FSTD Audit Checklist\n  6.1.2 Execution of the FSTD Audit\n   6.1.2.1 QTG Tests\n  6.1.3 Reporting\n   6.1.3.1 Initiating of measures\n  6.1.4 Follow-up of corrective actions\n  6.1.5 Dossier for recurrent evaluation\n 6.2 Qualification of FSTD Auditors\n  6.2.1 Auditor Independence\n  6.2.2 Code of Ethics\n 6.3 Audit Scope\n 6.4 Classification of FSTD Audit Findings\n	7.	FEEDBACK AND REPORTING\n 7.1 General\n 7.2 Kind of Reports\n  7.2.1 Flight Training Comment Form\n  7.2.2 Theoretical Training Comment Form\n  7.2.3 FSTD Defect Reporting System\n	8.	CONTRACTOR / SUPPLIER MANAGEMENT\n 8.1 Evaluation of contractors / suppliers\n 8.2 Supervision of contractors / suppliers\n  8.2.1 Initial Evaluation / Audit\n  8.2.2 Recurrent Audit\n	9.	MANAGEMENT EVALUATION\n 9.1 Purpose of Management Evaluation\n 9.2 Process of Management Evaluation\n 9.3 Data to be evaluated\n	10.	COMPLIANCE MONITORING SYSTEM TRAINING AND PROMOTION\n 10.1 Initial Training\n 10.2 Recurrent Training\n 10.3 Compliance Monitoring System Training Records\n	11.	DOCUMENT CONTROL\n 11.1 Control of Specifications / Prescriptive Documents\n 11.2 Control of Compliance Monitoring System Records\n 11.3 EDP Back-up Concept\n	12.	FSTD COMPLIANCE MONITORING MEASURES\n 12.1 Purpose\n 12.2 FSTD Metrics\n  12.2.1 FSTD Actual Operating Time\n  12.2.2 FSTD Defects\n  12.2.3 FSTD Availability\n  12.2.4 Mean Time Between Failures\n  12.2.5 FSTD Reliability\n  12.2.6 FSTD Major Issues	\n	13.	REGULATORY CHANGES FOLLOW-UP PROCEDURES\n 13.1 Phase 1 – Actively Monitoring Regulatory Changes\n 13.2 Phase 2 – Analyzing Changes\n 13.3 Phase 3 – Drafting Bulletin & Action Planning\n 13.4 Phase 4 – Closing', NULL, NULL, 'OMM_P2_0'),
('OMM_P2_1', 'OMM', '4.0', 2, '1', 'COMPLIANCE MONITORING POLICY', '1.1 Compliance Monitoring Policy\n\nThe Accountable Manager has the overall responsibility for the EuroPilot Center Compliance Monitoring System and states the following Compliance Monitoring Policy:\n\n“The EuroPilot Center Compliance Monitoring System ensures the continuous aim of providing Personalized Flight Training in the most efficient and economic way possible, with only the most advanced Training Methods and Training Aids available with the ultimate goal of achieving the highest level of safety.”\n\nBy applying the EuroPilot Center Compliance Monitoring System we ensure the continued compliance the applicable Belgian Regulations.\n\nMaria A. Paz\nAccountable Manager\nEuroPilot Center\n\n\n\n1.2 Relevant External Standards\n\nThe following external standards apply:\n\n• EASA PART FCL\n• EASA PART ORA\n• EASA CS FSTD\n• Belgian Regulations\n• AIP\n\n\n\n1.3 Internal Standards and Procedures\n\n• EuroPilot Center OM\n• EuroPilot Center OMM\n• EuroPilot Center TM\n• FSTD Master Qualification Test Guide\n\n\n\n1.4 Policy Deployment\n\n\n\n1.4.1 Annual Company Goals\nAt latest by December 31, the Accountable Manager publishes the Annual Company Goals based on the Compliance Monitoring policy. It states the budgets, target training figures and milestones for the next year. It forms the basis for the yearly strategy adjustment.', NULL, NULL, 'OMM_P2_1'),
('OMM_P2_10', 'OMM', '4.0', 2, '10', 'COMPLIANCE MONITORING SYSTEM TRAINING AND PROMOTION', 'The goal of the Compliance Monitoring System is to raise awareness among all EuroPilot Center personnel and students on all levels towards accident prevention, flight safety and Compliance Monitoring. The Compliance Monitoring Manager establishes the necessary training tools and records.\n\n\n\n10.1 Initial Training\n\nEvery new EuroPilot Center employee will, within respect of his or her function, be introduced to the EuroPilot Center Compliance Monitoring System by the Compliance Monitoring Manager by means of a self-study course.\n\n\n\n10.2 Recurrent Training\n\nRecurrent Training is based on safety and Compliance Monitoring related conclusions, experiences and changes, resulting from evaluation of data gathered by the implemented Compliance Monitoring Assurance Program.\n\nThe responsible person decides upon the form of training (self-study course, hand-outs, class room training, e-mail, computer based training).\n\n\n\n10.3 Compliance Monitoring System Training Records\n\nAll Compliance Monitoring Training shall be recorded in the E-Gle Online System by the applicable Manager.\n\nSource | Responsibility for Training\n\nCompliance Monitoring System Documentation Changes\n• Compliance Monitoring Manager\n\nFeedback and Reports\n• Relevant Manager\n\nCompliance Monitoring Audits\n• Compliance Monitoring Manager\n\nManagement Evaluation\n• Accountable Manager\n\nCompliance Monitoring Goals / Company Goals\n• Accountable Manager\n\nFSTD Audits\n• FSTD Compliance Monitoring Manager', NULL, NULL, 'OMM_P2_10');
INSERT INTO `manual_excerpts` (`excerpt_id`, `manual_code`, `manual_rev`, `manual_part`, `section_ref`, `title`, `text`, `source_file`, `sha256`, `excerpt_id_norm`) VALUES
('OMM_P2_11', 'OMM', '4.0', 2, '11', 'DOCUMENT CONTROL', '11.1 Control of Specifications / Prescriptive Documents\n\nFor all internal Standards and Procedures, EuroPilot Center ensures that the current versions are available in the right time at the right place. The amendment procedure of the OM, TM and QTG is specified in the introduction part of the respective manual.\n\n\n\n11.2 Control of Compliance Monitoring System Records\n\nRecords are documents or data stating results achieved, or providing evidence of activities performed. To ensure an authorized and quick access to records, they have to be:\n\n• Properly identified\n• Systematically stored for the period required\n• Destroyed after storage period in a controlled manner\n\nDocument | Responsibility | Place of Storage | Storage\n\nManagement Evaluation Report\n• AM\n• EPC Administration Archives\n• 5 Years\n\nIndividual Feedback Reports\n• EPC Administration Archives\n• 5 Years\n\nCompliance Monitoring Audit Reports (CMAR)\n• CMM\n• EPC Administration Archives\n• 5 Years\n\nNon Conformity Reports (NCR)\n• CMM\n• EPC Administration Archives\n• 5 Years\n\nList of Inspections Performed\n• CMM\n• EPC Administration Archives\n• 5 Years\n\nEmployees Introduction Certificate\n• CMM\n• EPC Administration Archives\n• 5 Years\n\nCompliance Monitoring Training Attendance Record\n• CMM\n• EPC Administration Archives\n• 5 Years\n\nList of Pending Items\n• CMM\n• EPC Administration Archives\n• 5 Years\n\nAudit Checklists\n• CMM\n• EPC Administration Archives\n• 5 Years\n\nQTG Test Reports\n• FSTD CMM\n• EPC Administration Archives\n• 5 Years\n\n\n\n11.3 EDP Back-up Concept\n\nFor all electronic files and documents, if any, EuroPilot Center shall provide a back-up in accordance with EASA ORA.GEN.220 and ORA.ATO.120:\n\n• The responsibility for such back-up lies with the Accountable Manager;\n• The back-ups will be taken on a Quarterly basis;\n• The back-ups will be stored in a different location from that containing the working data and in an environment that ensures they remain in good condition. The EuroPilot Center Administration archives will satisfy this requirement, currently located at Antwerp Airport Office 2.\n\n• All data should be kept for a period of at least 5 years:\na) details of ground, flight, and simulated flight training given to individual students;\nb) detailed and regular progress reports from instructors including assessments, and regular progress flight tests and ground examinations; and\nc) information on the licenses and associated ratings and certificates of the students, including the expiry dates of medical certificates and ratings.\n\n• When hardware or software changes take place, special care should be taken that all necessary data continues to be accessible for at least 5 years.\n\n• Other data then the one specified above, should be kept for a period of at least 5 years.', NULL, NULL, 'OMM_P2_11'),
('OMM_P2_12', 'OMM', '4.0', 2, '12', 'FSTD COMPLIANCE MONITORING MEASURES', '12.1 Purpose\n\nFor the purpose of measuring the effectiveness of the FSTD Compliance Monitoring System, EuroPilot Center applies simplified performance measures that can be monitored against the FSTD Compliance Monitoring Objectives. These measures, referred to as Metrics can be reviewed by the BCAA as part of their oversight of Compliance Monitoring System and will be examined for each FSTD on an annual basis.\n\nThe FSTD Compliance Monitoring Objectives are published in the Annual Company Goals by the Accountable Manager.\n\n\n\n12.2 FSTD Metrics\n\nAll FSTD times must be recorded in the Annual FSTD Logbook. We refer to Annex 5.\n\n\n\n12.2.1 FSTD Actual Operating Time\nThe actual time the FSTD is operational, recorded in the FSTD Logbook under column “A-TIME” (meaning Actual Operating Time).\n\n\n\n12.2.2 FSTD Defects\n\nAn FSTD defect is any unanticipated occurrence which causes an operationally significant period during which the FSTD cannot be used within the specified tolerances.\n\nFSTD defects will result in Training Sessions Interruptions and consequently result in a Downtime Period.\n\nThe Downtime Period will be recorded in the FSTD Logbook under the column “D-TIME” (meaning Downtime) in case of a scheduled Training Session Interruption caused by an FSTD Defect.\n\nThe total number of FSTD defects leading to a Training Session Interruption, resulting in a Downtime Period must be recorded at the bottom of each FSTD Logbook page.\n\n\n\n\n12.2.3 FSTD Availability\n\nThe FSTD availability is determined on a yearly basis by the ratio of Actual Operating Time compared to Specified Operating Time.\n\nThe Specified Operating Time can be calculated by the sum of the total time of column “A-TIME” and the total time of column “D-TIME”.\n\nThe FSTD Availability can be calculated by the following formula:\n\nAnnual Actual Operating Time\nFSTD AVAILABILITY = —————————— × 100\nAnnual Specified Operating Time\n\nNote: the FSTD Availability is one of the FSTD Compliance Monitoring Objectives.\n\n\n\n\n12.2.4 Mean Time Between Failures\n\nThe FSTD Mean Time Between Failures is determined on a yearly basis by the ratio of the Actual Operating Time and the number of FSTD Defects.\n\nIt can be calculated by the following formula:\n\nActual Operating Time\nFSTD MEAN TIME BETWEEN FAILURES = ——————————\nNumber of FSTD Defects\n\n\n\n12.2.5 FSTD Reliability\n\nThe FSTD reliability is the probability that the specific installation operates within the specified tolerances and refers to the probability that the facility will operate for a specified period of time.\n\nIt corresponds to the Mean Time Between Failure value.\n\nNote: the FSTD Reliability is one of the FSTD Compliance Monitoring Objectives.\n\nFactors which affect MTBF and hence facility reliability are:\n\n• Inherent equipment reliability;\n• Degree and type of redundancy;\n• Reliability of the serving utilities such as power and telephone or control lines;\n• Degree and Compliance Monitoring of maintenance;\n• Environmental factors such as temperature and humidity.\n\n\n\n\n12.2.6 Major FSTD Issues\n\nIn case of an FSTD:\n\n• Major change;\n• Relocation;\n• Deactivation;\n• Major failure;\n• Major safety issue associated with the installation.\n\nThe BCAA shall be informed by e-mail immediately by the FSTD Compliance Monitoring Manager and discuss the appropriate actions required.', NULL, NULL, 'OMM_P2_12'),
('OMM_P2_13', 'OMM', '4.0', 2, '13', 'REGULATORY CHANGES FOLLOW-UP PROCEDURES', 'The purpose of the below Regulatory follow-up procedure is to maintain compliance with ORA.GEN.135.\n\nBy integrating a monthly Regulatory Change follow-up procedure, the CMM will be required to perform the following tasks:\n\n• Enroll in the official EASA and FAA Online Notification Services (we refer to Annex 26 for more details).\n• Daily, receives/collects all Regulatory changes relevant to the ATO (we refer to Annex 26 for a detailed overview of all relevant Regulations pertaining to the organization in Belgium and the USA).\n• As part of the Scope, executes a manual verification of the Regulations relevant to the ATO (we refer to Annex 26).\n• Publishes a “Regulatory Changes Bulletin” on a monthly basis which should be sent to the AM, HT and SM via e-mail.\n• Depending on a) the nature; and/or b) the urgency of a future Regulatory Change, the CMM can call for a “Regulatory Change Meeting“, to be attended by the AM, HT and SM.\n• Creation of an “Action Plan Proposal” to the AM, HT and SM.\n\nThe process consists of 4 phases:\n\nPHASE 1 – Actively Monitoring Regulatory Changes\nPHASE 2 – Analyzing Changes\nPHASE 3 – Drafting Bulletin & Action Planning\nPHASE 4 – Closing\n\n\n\n13.1 Phase 1 – Actively Monitoring Regulatory Changes\n\n\n• Login to PipeDrive and Click on “Projects”.\n• From the Dropdown list on the right, select the “CMM - Regulatory Changes” -Project.\n• Click on “plus symbol” located inside the first Phase of the Project (or the Green “+ Project” button on the left).\n• Select the “Regulator Changes” Template.\n• Name the Project as per following convention: “Regulatory Changes: MM/YYYY” (e.g. Regulatory Changes: 02/2023”).\n• Enter “Start Date” (Should be the first day of the month).\n• Enter “End Date” (Should be the last day of the month).\n• Select Label” In Progress”.\n• Perform the checklist items under the “PLAN” section of the Project.\n• When receiving relevant regulatory changes containing a PDF file or other document, the CMM must upload this document via the “FILES” section of the Project.\n• Upon receiving relevant regulatory changes via ANY official SOURCE, a note must be made in the “NOTES” Section of the Project, including comments.\n• When receiving relevant e-mails from official sources, they should be linked to the Project by opening the e-mail in PipeDrive, on the right, enter the Project Name in the textfield underneath the “Link to a deal/lead/project” -box.\n\n\n\n13.2 Phase 2 – Analyzing Changes\n\n• Go to the Project section in Pipedrive to obtain all the data collected during Phase 1.\n• Move the Project to Phase 2.\n• Start with the Analysis Process based on the PLAN Checklist for this Phase.\n• Update the overview of all relevant Regulatory Changes in the “NOTES” section of the Project, already made during Phase 1.\n\n\n\n13.3 Phase 3 – Drafting Bulletin & Action Planning\n\n\n• Go to the Project section in Pipedrive.\n• Move the Project to Phase 3.\n• Execute the PLAN Checklist for this Phase.\n• Start drafting the “Regulatory Changes Bulletin” via de “EMAILS” section of the Project by creating a new e-mail via the Template Menu. Select the “Regulatory Change Bulletin” template.\n• Create an Action Plan via the “PLAN” Section.\n• Select a “TASK” for each Action Item requiring a Task to be fulfilled, add sub-tasks if required.\n• Allocate the “TASK” to the responsible person within the organization and add a due-date (proposal).\n• Only select “ACTIVITY” when a certain Action requires a Calendar event such as a Meeting etc.\n• Once the Regulatory Changes Bulletin (or Minutes of the Regulatory Changes Meeting, if held) has been drafted and the Action Plan is prepared under the PLAN section, send the e-mail to the AM, HT, SM.\n\n\n\n13.4 Phase 4 – Closing\n\n• After either the “Regulatory Changes Bulletin” or the Minutes of “Regulatory Changes Meeting” have been reviewed by the AM, HT and SM, feedback obtained shall be used to update the Action Plan via the “PLAN” Section.\n• Based on the deadlines for each Action item, the CMM shall follow-up with the person to whom the Task was allocated. Pipedrive will generate automatic triggers if required.\n• The CMM ensures all Task Items are closed and “archives” the Project.', NULL, NULL, 'OMM_P2_13'),
('OMM_P2_2', 'OMM', '4.0', 2, '2', 'CONCEPT OF COMPLIANCE MONITORING SYSTEM', '2.1 Purpose of the Compliance Monitoring System\n\nThe Compliance Monitoring System, as described in this Manual, established by the EuroPilot Center Accountable Manager:\n\n• monitors the compliance, implementation, effectiveness and efficiency of EuroPilot Center’s specific policies, standards and procedures for training and FSTD operations;\n• ensures a systematic recording and analysis of non-compliances and occurrences;\n• ensures a systematic implementation and monitoring of corrective actions;\n• ensures an evaluation of the overall effectiveness of the organization in achieving stated objectives.\n\nThe principles and procedures stated in this chapter shall be adhered to by all EuroPilot Center involved students and personnel.\n\nThe Compliance Monitoring System is structured to be in compliance with EASA Part FCL, Part ORA, all other relevant Subparts and CS-FSTD.\n\n\n\n2.2 Overview of the EuroPilot Center Compliance Monitoring System\n\nTCMM Total Compliance Monitoring Management\nTCMM for continuous improvement\n\nCompliance Assurance\nCompliance Control\nCompliance Inspection\n\n• Whole operation involved\n• Compliance Monitoring Strategy\n• Team Work\n• Staff Improvement\n• Involves Customer and Suppliers\n\n• Compliance Monitoring System including Audits\n• Compliance Monitoring costing\n• Problem Solving\n• Compliance Monitoring Planning\n\n• Compliance Monitoring Requirements and Standards\n• Process Performance\n• Statistical Methods\n• Error Detection\n• Rectification\n\n\n\n2.3 Core Elements of the Compliance Monitoring System\n\nElements – Responsible – Explanation – Reference\n\nPolicy\n• Accountable Manager\n• Commitment Compliance Monitoring\n• CMM Chapter 2\n\nStrategy / Resources / Annual Goals\n• Accountable Manager\n• Review of Company Strategy based on Management Evaluation\n• Definition of annual budget and goals\n• CMM Chapter 2\n\nFacilities / Flight Training / Theoretical Knowledge Training / Training Procedures / Flight Safety / Flight duty and rest / Aircraft Maintenance / FSTD Operations\n• Head of Training\n• Chief Flight Instructor\n• Chief TK Instructor\n• CAM\n• FSTD Manager\n\n• Definition of internal standards\n• Ensuring conformity with internal standards and requirements by means of control and supervision (inspections) of the daily activities\n• Analysis of feedback and reports\n• Supervision of the relevant subcontractors\n• Initiation and monitoring of implemented actions\n\n• OMM\n• OM\n• TM\n• CAME\n• CMM Chapter 5\n• CMM Chapter 8\n• CMM Chapter 9\n• FSTD MQTG\n\nFeedback and Reporting\n• All EuroPilot Center personnel\n• Identifies and reports divergences, non-conformities and chances\n• CMM Chapter 8\n\nAudits\n• Compliance Monitoring Manager\n• Compliance Monitoring Auditor\n\n• Independent Compliance Monitoring Auditors monitor the adherence to standards and requirements by means of Compliance Monitoring Audits\n• CMM Chapter 6\n\nInspections\n• Head of Training\n• Chief Flight Instructor\n• Chief TK Instructor\n• CAM\n• FSTD Manager\n• Compliance Monitoring Manager\n\n• Ensuring conformity with internal standards and requirements by means of control and supervision (inspections) of the daily activities\n• CMM Chapter 5\n\nData Evaluation\n• Accountable Manager\n• Head of Training\n• Chief Flight Instructor\n• Chief TK Instructor\n• CAM\n• FSTD Manager\n• CMM Manager\n\n• Evaluation of data in the specific field of activity to identify trends and systematic gaps\n• Conclusions resulting from the Data Evaluation\n• CMM Chapter 10\n\n\n\n2.4 Organization Changes\n\nThe following changes affect the terms of approval of the ATO and are subjected to prior approval from the BCAA:\n\n• the name of the organization;\n• the organization’s principal place of business;\n• the organization’s scope of activities;\n• additional locations of the organization;\n• the accountable manager;\n• any of the persons referred to in ORA.GEN.210(a) and (b);\n• the organization’s documentation as required by this Part, safety policy and procedures;\n• the facilities.\n\nThe Accountable Manager is responsible for sending out a “Change Request” to the Safety Manager AND Compliance Monitoring Manager via e-mail.\n\nThe header of the e-mail must contain:\n“Change Request: ORGANIZATION, TITLE OF CHANGE”\n(e.g. Change Request: ORGANIZATION, Principal Place of Business).\n\nWe refer to the updated Management of Change Procedure outlined in OMM Part 3, Chapter 5.9.', NULL, NULL, 'OMM_P2_2'),
('OMM_P2_3', 'OMM', '4.0', 2, '3', 'ORGANIZATION, RESPONSIBILITIES AND DUTIES', '3.1 EuroPilot Center – ATO Organigram\n\nWe refer to the OM, Part 1, Chapter 2.1.2.\n\n\n\n3.2 Duties and Responsibilities\n\nEuroPilot Center’s organizational structure (organogram) and the Compliance Monitoring System related roles, duties, responsibilities, accountabilities and authorities of managing staff are described in the below paragraphs.\n\n\n\n3.2.1 Accountable Manager\nThe duties and responsibilities of the Accountable Manager are described in the OM Part 1, Chapter 2.\n\nThe Compliance Monitoring System related duties and responsibilities of the Accountable Manager are:\n\n• having the corporate authority for ensuring that all operations and maintenance activities can be financed and carried out to the standard required by the BCAA;\n• establishing a formal written Compliance Monitoring Policy Statement;\n• having the overall responsibility for the organization’s Compliance Monitoring System, including the frequency, format and structure of the internal management evaluation activities;\n• having the ultimate responsibility to provide for the necessary resources for the implementation of corrective actions.\n\n\n\n3.2.2 HOT, CFI, CTKI, CAM and FSTD Manager\nThe duties and responsibilities of the Head of Training, Chief Flight Instructor, Chief Theoretical Knowledge Instructor, Continuing Airworthiness Manager and FSTD Manager are described in the OM, Part 1, Chapter 2.\n\nThe Compliance Monitoring System related duties and responsibilities of these postholders are:\n\n• supervising their respective field of activities and conduct / document inspections;\n• implementing corrective actions;\n• conducting periodical data evaluations as an input to the management evaluation.\n\n\n\n3.2.3 Compliance Monitoring Manager / Auditor & Assistant Compliance Monitoring Manager / Auditor\n\n\n\n3.2.3.1 Requirements\nThe following experience/qualifications are required for a Compliance Monitoring Manager / Auditor and Assistant Compliance Monitoring Manager / Auditor within EuroPilot Center:\n\n• Has extensive knowledge of Aviation Rules and Regulations (including FSTD’s);\n• Preferably hold or have held a Commercial (or Airline Pilot License);\n• Has been a Compliance Monitoring Manager for an Aviation Organization for at least 1 year; or\n• Has been an Assistant Compliance Monitoring Manager within EuroPilot Center for 1 year; or\n• Has extensive experience in auditing techniques; or\n• Has attended the Compliance Monitoring Manager / Auditor Course (e.g. internal course or through an entity such as JAATO);\n• Possesses sound managerial skills;\n• Speaks, writes and understands the English language.\n\n\n\n3.2.3.2 Duties and Responsibilities\nThe duties and responsibilities of the Compliance Monitoring Manager / Assistant Compliance Monitoring Manager are:\n\n• having direct access to the Accountable Manager;\n• having access to all parts of the organization and, if required, any subcontractor’s organization;\n• verification performed by independent Compliance Monitoring Assurance Activities in the fields of Training, Maintenance and FSTD operations that the standards required by the BCAA, and any additional requirements defined by the organization, are adequate and are being carried out under the supervision of the relevant responsible managers;\n• monitoring the implementation and completion of corrective actions;\n• providing the management with an independent assessment of corrective actions, implementation and completion;\n• evaluation of the effectiveness of corrective actions through the follow-up process;\n• conducting periodical data evaluations as an input to the management evaluation.\n\nAn Assistant Compliance Monitoring Manager shall have the same duties as the Compliance Monitoring Manager and should provide support to the Compliance Monitoring Manager in executing his duties. The final responsibility however lies with the Compliance Monitoring Manager.\n\n\n\n3.2.4 Compliance Monitor / Auditor Training (Initial & Recurrent)\nHas received a course from an experienced Compliance Monitoring Manager in the following topics:\n\n• Basic Aviation Management Systems (minimum 1h00);\n• Compliance Monitoring Audits & Audit Techniques (minimum 1h00);\n• The Audit Planning Process (minimum 2h00);\n• Interview & Questioning techniques (minimum 1h00);\n• Evaluation and Reporting of Audit Findings (minimum 1h00);\n• The Corrective Actions and Close-out Process (minimum 1h30).\n\nOr has attended the same course through another entity (e.g. JAATO) and has provided EuroPilot Center with an appropriate Certificate of Training.\n\nIn addition, the applicant shall be trained on:\n\n• compliance monitoring system procedures within EuroPilot Center (minimum 1h00);\n• EuroPilot Center manuals and document control procedures (minimum 1h00);\n• EuroPilot Center ATO OMM and OM procedures (minimum 1h00);\n• EuroPilot Center audit techniques and code of conduct of the compliance auditor (minimum 1h00);\n• EuroPilot Center audit reporting and recording (minimum 1h00);\n• FSTD management and FSTD auditing techniques (minimum 1h00).\n\nPractical training shall consist of conducting at least three supervised audits with an experienced Compliance Monitoring Manager.\n\nAll training shall be logged in the E-gle system by the Compliance Monitoring Manager.\n\nRecurrent training does not apply to Compliance Monitoring Managers / Auditors.', NULL, NULL, 'OMM_P2_3'),
('OMM_P2_4', 'OMM', '4.0', 2, '4', 'COMPLIANCE MONITORING INSPECTIONS', 'The Compliance Monitoring Inspection is an instant inspection to observe a particular event, action or document in order to verify whether the established procedures and requirements are followed during the accomplishment of that event, and whether the required standards are achieved.\n\n\n\n4.1 Inspection Procedure\n\nThe Compliance Monitoring Inspector shall fulfill at least the following:\n\n• being familiar with the type of training conducted;\n• having knowledge of FSTD requirements and operation;\n• having knowledge of the maintenance of aircraft.\n\nStep | Remarks | Tool | Responsibility\n	1.	Planning and preparations\n• ad-hoc planning;\n• study relevant procedures;\n• consider feedback and reporting system.\nTool: /\nResponsibility: CMM / Inspector\n	2.	Execution\nTool: /\nResponsibility: Inspector\n	3.	Reporting\n• performed inspections are recorded on a list of inspections to ensure coverage of all scopes.\nTool: Compliance Monitoring Audit Plan\nResponsibility: CMM\n	4.	Initiation of measures\n• in case of need, preventive and corrective action shall be initiated.\nTool: List of Pending Items\nResponsibility: AM / CMM\n	5.	Monitoring\n• verify implementation of measures.\nTool: /\nResponsibility: AM / CMM\n\n\n\n4.2 Inspection Scopes\n\nNote 1: Please refer to OMM Annex 26 – Regulatory Changes Notifications\nNote 2: Please refer to OMM Annex 27 – Regulatory Changes Checklist\n\nScope | Main | US Satellite | Frequency | Responsibility\n\n01 Actual Flight Training | Yes | Yes | Yearly | CFI\n02 Actual Theory Training | Yes | Yes | Yearly | CTKI\n03 Training Standards | Yes | Yes | Yearly | HOT\n04 Maintenance of Aircraft | Yes | Yes | Yearly | CAM\n05 Technical Standards | Yes | Yes | Yearly | CAM\n06 Maintenance of FSTD | Yes | No | Yearly | FSTD Manager\n07 Technical Standards FSTD | Yes | No | Yearly | FSTD Manager\n08 Actual FSTD Operation | Yes | No | Yearly | FSTD Manager\n09 Safety Features FSTD | Yes | No | Yearly | FSTD Manager\n10 Regulatory Changes | Yes | Yes | Monthly | CMM', NULL, NULL, 'OMM_P2_4'),
('OMM_P2_5', 'OMM', '4.0', 2, '5', 'COMPLIANCE MONITORING AUDITS', 'The Compliance Monitoring Audit procedure is applied to achieve a systematic and independent revision of the Compliance Monitoring Standards within EuroPilot Center.\n\nThis is to secure that the level of training, established flight safety standards, instructions and regulations are complied with and that the performance is satisfactory and efficient.\n\nThe Compliance Monitoring Audits are conducted for the following purposes:\n\n• to determine the conformity or non-conformity of the EuroPilot Center Compliance Monitoring System elements with specified requirements;\n• to determine the effectiveness of the implemented Compliance Monitoring System in meeting specified Compliance Monitoring objectives;\n• to provide the Auditee with an opportunity to improve the Compliance Monitoring System;\n• to ensure that the applicable BCAA requirements are met.\n\n\n\n5.1 Audit Procedure\n\nThe Compliance Monitoring Assurance Program includes a defined audit schedule and a periodic review cycle.\n\nThe schedule is flexible and allows unscheduled audits when certain trends are identified.\n\nFollow-up audits are scheduled when necessary to verify that corrective actions were carried out and that they were effective.\n\nAll parts of the operation shall be reviewed within 12 months in accordance with the program, unless an extension of the audit period is accepted by the BCAA.\n\nAll requirements as well as company standards shall be reviewed under each part covered by scheduled and unscheduled audits.\n\nRegulatory Compliance Monitoring System Audits are conducted in accordance with the Compliance Monitoring Audit Schedule, covering the audit periods.\n\nThe actual time when the audit of an area is performed shall not differ more than 3 months (one quarter of a year) from the planned date in the Compliance Monitoring Audit Schedule.\n\nThe schedule shall be re-evaluated on a yearly basis.\n\nThe schedule shall assure that every audit area shall be covered within a period of 12 months.\n\nThe Accountable Manager or the Compliance Monitoring Manager may increase the frequency of the audits, but they are not entitled to decrease the frequency without the acceptance from the BCAA.\n\nIn case of an organization change in a significant way (change of company name, location, management), an audit has to be performed within 45 calendar days after implementation of the new structure.\n\nIn case of:\n• any major change to, any failure of or any major safety issue with a Qualified Flight Training Device;\n• any deactivation or relocation of a Qualified Flight Training Device;\n\nthe BCAA must be informed.\n\nThe current issue of the Compliance Monitoring Audit Schedule is presented in Annex 1 to this part.\n\n\n\n5.1.1 Audit Planning\n\nEach audit shall be planned and may cover one or more areas in the Compliance Monitoring Audit Schedule.\n\nThe plan shall generally refer to the relevant requirements, standards or procedures stated in the EuroPilot Center Manuals.\n\nThe management of the area due for audit (the Auditee) shall be informed in due time before the audit starts, with a minimum of two weeks.\n\nThe notice can be given in writing or by e-mail.\n\nA Compliance Monitoring Audit Plan shall be used and must be issued for each audit element, including specified questions and issues referring to the applicable EuroPilot Center documents.\n\nThe Compliance Monitoring Audit Plan shall cover at least:\n\n• date;\n• place;\n• time schedule;\n• scope of the audit;\n• audit areas;\n• auditor;\n• auditee.\n\n\nThe Compliance Monitoring Audit Plan shall cover at least:\n\n• Date\n• Place\n• Time Schedule\n• Scope of the audit\n• Audit Areas\n• Auditor\n• Auditee\n\nStep | Remarks | Tool | Responsibility\n	1.	Planning\n• Establishing the Audit Plan\n• Considering former:\n\n	•	Audit Plan\n	•	Changes in the organisation\n	•	Changes in regulatory requirements\n	•	Changes in the activities\n	•	Trends\n• Follow-up Audits when necessary\n• Studying the relevant Procedures\n• Considering Feedback and Reporting System\n• Creating/editing the Audit Checklist\n• Assigning Auditors (if applicable)\n\n• The Audit Plan\n• Audit Checklists\n• List of Pending Items\n• List of Auditors\n• OMM, OM, TM\n\n• CMM\n	2.	Execution\n• By means of the following techniques:\n\n	•	Interviews\n	•	Witnessing of activities\n	•	Examination of records\n\n• The Audit Checklists\n\n• CMM\n	3.	Reporting and Initiating Corrective Actions\n• Classifying of Findings\n• Producing the Non Conformity Report (NCR)\n• Initiating preventive and corrective action if required\n• Who, What, Due Date?\n• Producing the Compliance Monitoring Audit Report (CMAR)\n\n• The Audit Checklists\n• Notes\n• The Non Conformity Report (NCR)\n• The Compliance Monitoring Audit Report (CMAR)\n\n• AM\n• CMM\n	4.	Follow-up of Corrective Actions\n• Verify the implementation of corrective actions\n\n• The Compliance Monitoring Audit Report (CMAR)\n\n• AM\n• CMM\n\n\n\n\n5.1.1.1 Audit Checklist\n\nThe Auditor is responsible to develop checklists prior to each audit.\n\nThe Checklist shall be developed as a high-level and low-level checklist.\n\nThe high-level checklist will cover all relevant Authorities’ regulations as required by EASA and the BCAA.\n\nThe low-level checklist will cover all other requirements such as company regulations, manuals, internal procedures and agreements.\n\n\n\n5.1.2 Performance of the Audit\n\nThe Compliance Monitoring Audit starts with a meeting with the Auditee(s) in order to go deeper into the Compliance Monitoring Audit Plan, organize the time schedule and persons to interview.\n\nAs a general rule, the audit should minimize the disturbance of ongoing training activities.\n\n\n\n5.1.2.1 Interviews\n\nThe interview shall be performed with the person concerned, as prior agreed upon.\n\nNotes can be taken and findings will be recorded, if applicable.\n\n\n\n5.1.2.2 Observation of activities\n\nObservation of activities and conditions may be included in the audit as deemed necessary by the Compliance Monitoring Auditor.\n\n\n\n5.1.2.3 Review and Examination\n\nThe review of documentation includes contracts, company manuals, instructions etc.\n\nThe examination of records contains adequate samples of inspection records, reports etc.\n\nThe Auditor shall use these records to be guided towards problem areas or problems which are caused by a weakness in the system or process itself.\n\nPrevious audit reports shall be reviewed in order to examine corrective actions.\n\n\n\n5.1.3 Reporting\n\nAll non-conformities shall be analyzed by the Compliance Monitoring Auditor with the purpose to find the root cause of the finding.\n\nThese shall be specified in the Compliance Monitoring Audit Report (CMAR).\n\nThe Non-Conformity Report (NCR) or a copy of a used Audit Checklist with comments shall be sent together with the enclosed copy of the CMAR to the Auditee within a maximum period of 7 working days after the audit was completed.\n\nReference is made to Annex 2 – NCR.\n\n\n\n5.1.3.1 Initiating of measures\n\nWithin 7 working days after sending the audit result to the Auditee, the Compliance Monitoring Manager shall contact the Auditee with the purpose of discussing the audit results and decide upon the following issues:\n\n• agreed corrective actions;\n• compliance date for the corrective actions.\n\nThe Auditee shall propose the corrective actions to be taken and the Auditor has to agree.\n\n\n\n5.1.4 Follow-up of corrective actions\n\nAll observations shall be numbered and listed in the Compliance Monitoring Audit Report (CMAR).\n\nA time limit for corrective actions shall be stipulated.\n\nIt is the responsibility of the Compliance Monitoring Manager to agree on a time limit for corrective actions.\n\nIt is the responsibility of the Auditee to execute the agreed corrective actions within the stipulated timeframe.\n\nThe Compliance Monitoring Manager is responsible to follow up that the corrective actions were executed in time and to evaluate the effectiveness of those actions.\n\nThe normal time limit should not exceed two months.\n\nIf the corrective action includes a comprehensive project or equivalent, the time limit may be extended.\n\nIf for some reason no action is taken within the agreed time limit, it is the responsibility of the Auditee to report this to the Compliance Monitoring Manager and to ask for agreement of a new time limit.\n\nAn acceptable reason for the delay should be provided.\n\nThe Compliance Monitoring Manager has to inform the Accountable Manager who will take the decision about an extension of the time limit.\n\nIf no action is taken within the extended time limit, it is the responsibility of the Compliance Monitoring Manager to inform the Civil Aviation Authorities accordingly and suggest an acceptable solution.\n\nWhen an audit finding has been sufficiently taken care of, the audit finding shall be declared ‘closed’ by the Compliance Monitoring Manager and this shall be noted in the CMAR.\n\n\n\n5.2 Qualification of Auditors\n\nWe refer to the qualifications for Compliance Monitoring Managers / Auditors & Assistant Compliance Monitoring Managers / Auditors under Chapter 3.2.3.\n\nWe refer to the training requirements under Chapter 3.2.4.\n\n\n\n5.2.1 Auditor Independence\n\nThe Auditor shall be independent with regard to functional connection to the area subject of the audit.\n\nThe Auditor shall be given full access to the documentation and any other relevant information to perform the audit.\n\n\n\n5.2.2 Code of Ethics\n\nThe following rules of ethics apply to all EuroPilot Center audit activities:\n\n• the Auditor shall perform his duties in true confidentiality, sincerity and honesty;\n• the Auditor shall have appropriate respect for the Auditee concerned;\n• all information regarding the respective audit shall never be communicated to persons not involved in the audit;\n• all reported findings must be based on well-documented facts. Personal judgements must be clearly separated from facts. Only actual observations may be reported;\n• Auditors should minimize the disturbance of the ongoing training activities during the performance of the audit.\n\n\n\n5.3 Audit Scope\n\nThe audit scopes are defined in the Audit Plan, which is held as a separate document to ensure the flexibility for recording the audits performed and for scheduling additional audits.\n\nReference is made to Annex 1.\n\n\n\n5.4 Classification of Audit Findings\n\nFindings resulting from audits have to be classified as follows:\n\n• Level 1: Safety is affected, no further (training) operation / activity allowed until closure of finding;\n• Level 2: Safety might be affected, finding to be closed within 2 months;\n• Level 3: Safety not affected, but of importance for the company. Finding to be closed within due date (to be agreed upon).\n\nThe Auditor determines the classification of the audit finding.\n\n\n\n5.5 List of Auditors\n\nWe refer to OMM Annex 23 – List of Auditors.', NULL, NULL, 'OMM_P2_5'),
('OMM_P2_6', 'OMM', '4.0', 2, '6', 'QTG RUNNING, QTG CHECKING AND FLY-OUT PROCEDURES', '6.1 Procedure\n\nThe FSTD Compliance Monitoring Assurance Program includes a defined FSTD audit schedule and a periodic review cycle.\n\nThe schedule is flexible and allows unscheduled audits when certain trends are identified.\n\nFSTD follow-up audits are scheduled when necessary to verify that corrective actions were carried out and that they were effective.\n\nAll parts of the FSTD operation shall be reviewed within 12 months in accordance with the program, unless an extension of the audit period is accepted by the Civil Aviation Authorities.\n\nAll requirements as well as company standards shall be reviewed under each part covered by scheduled and unscheduled audits.\n\nFSTD Compliance Monitoring System Audits are conducted in accordance with the FSTD Compliance Monitoring Audit Schedule, covering the audit periods.\n\nThe actual time when the audit of an area is performed shall not differ more than 3 months (one quarter of a year) from the planned date in the FSTD Compliance Monitoring Audit Schedule.\n\nThe FSTD schedule shall be re-evaluated on a yearly basis.\n\nThe schedule shall assure that every audit area shall be covered within a period of 12 months.\n\nThe Accountable Manager (or the FSTD Compliance Monitoring Manager) may increase the frequency of the audits, but they are not entitled to decrease the frequency without the acceptance from the BCAA.\n\nIf the FSTD operation changes in a significant way, an audit has to be performed within 45 calendar days after implementation of the new structure.\n\nThe current issue of the FSTD Audit Schedule is presented in Annex 4 to this part.', NULL, NULL, 'OMM_P2_6'),
('OMM_P2_7', 'OMM', '4.0', 2, '7', 'FEEDBACK AND REPORTING', '7.1 General\n\nAny hazard having the potential to cause damage or injury, or to threaten the viability of the EuroPilot Center organization has to be reported, in order to get analysed and eliminated to finally increase the level of safety.\n\nHazards and incidents shall be reported in case:\n\n• something can be done to improve safety;\n• other aviation personnel could learn from the report;\n• the system did not work as expected.\n\nIF IN DOUBT, REPORT IT!\n\n\n\n7.2 Kind of Reports\n\n\n\n7.2.1 Flight Training Comment Form\nThe Flight Training Comment Form shall be used by the Flight Instructor for the purpose of documenting student training issues/problems with regard to Flight Training.\n\nReference is made to Chapter 1.5 of the EuroPilot Center Training Manual.\n\n\n\n7.2.2 Theoretical Training Comment Form\nThe Theoretical Training Comment Form shall be used by the Ground Instructor for the purpose of documenting student training issues/problems with regard to Theoretical Training.\n\nReference is made to Chapter 1.5 of the EuroPilot Center Training Manual.\n\n\n\n7.2.3 FSTD Defect Reporting System\nThe FSTD Defect Reporting System shall be used to report any FSTD defect.\n\nThe system consists of an online password-protected web-application that can be accessed via:\n\nFor the BE/FNPT-014:\nhttp://customers.europilotcenter.be\n\nFor the BE/FNPT-024:\nhttp://techlog.alsim.com\n\nFor the BE/FNPT-028:\nhttp://techlog.alsim.com\n\nFor the BE/FNPT-014, defects (Squawks) can be reported as:\n\n• Level A – urgent, no further training possible;\n• Level B – urgent, training can be continued;\n• Level C – not urgent, training can be continued.\n\nFor the BE/FNPT-024 and BE/FNPT-028, defects can be reported as:\n\n• Blocking – urgent, no further training possible;\n• Unblocking – training can be continued.', NULL, NULL, 'OMM_P2_7'),
('OMM_P2_8', 'OMM', '4.0', 2, '8', 'CONTRACTOR / SUPPLIER MANAGEMENT', '8.1 Evaluation of contractors / suppliers\n\nEuroPilot Center has dedicated specific services to contractors. These contractors shall be evaluated on a continuous basis by the respective Manager. Hereto he shall produce a written document where all details concerning Compliance Monitoring are stated.\n\nThese contracting activities can take place in the following areas:\n\n• Training\n• Facilities\n• Assessments\n• Maintenance\n• CAMO\n\nThe most important prerequisite for EuroPilot Center contractor’s / supplier’s evaluation is a clear definition of the relevant Compliance Monitoring / safety requirements and demands. These requirements and demands need to be explicitly stated in the underlying written agreement between EuroPilot Center and the respective contractors / suppliers.\n\nIn order to achieve reliable control of contracted services agreed upon, the standards and procedures shall be continuously monitored by EuroPilot Center.\n\nIn addition, a Compliance Monitoring Audit on the contractor / supplier shall be performed on a two-yearly basis.\n\nBefore the use of a new contractor / supplier, an initial evaluation audit needs to take place.\n\n\n\n8.2 Supervision of contractors / suppliers\n\n\n\n8.2.1 Initial Evaluation / Audit\nBefore initiating an Evaluation / Audit of a contractor / supplier, the Accountable Manager must be satisfied about the financial and safety aspects of the cooperation.\n\nIf the contractor / supplier is judged to be reliable, the Evaluation / Audit will be conducted as follows:\n	1.	Review of the Compliance Monitoring system elements such as organization, procedures and relevant documentation including Authority approvals / certificates and manuals;\n	2.	Physical inspection of the contractor’s / supplier’s facilities and equipment.\n\n\n\n8.2.2 Recurrent Audit\nRecurrent audits of all contractors / suppliers shall be conducted every 2 years or earlier in case of findings, to monitor if contracted activities are carried out in accordance with the applicable contract.\n\nThe contract should clearly state the responsibilities of both parties.\n\nA copy of the signed contract must be sent to the BCAA prior to the start of the contracted activities.', NULL, NULL, 'OMM_P2_8'),
('OMM_P2_9', 'OMM', '4.0', 2, '9', 'MANAGEMENT EVALUATION', '9.1 Purpose of Management Evaluation\n\nThe management evaluation is a comprehensive, systematic review by the management to evaluate:\n\n• the overall effectiveness of the organization;\n• the achievement of stated objectives;\n• the effectiveness of the Compliance Monitoring System;\n• the operational policies and procedures.\n\nBy means of this data evaluation, negative trends and major weaknesses can be identified and corrected by dealing with their root causes.\n\n\n\n9.2 Process of Management Evaluation\n\nThe Compliance Monitoring Manager has a Compliance Meeting with the Accountable Manager on a monthly basis to discuss the results of Audit Findings, discuss corrective actions, and follow up on corrective action closures.\n\nThe minutes of the meeting will be recorded in the Pipedrive CRM system, identically to the procedure described for other meetings held.\n\nStep | Remarks | Tool | Responsibility\n	1.	Perform Data Evaluation\n• Monthly*\n• Periodical evaluation of received reports\n• Identification of trends and systematic deviations\n• Suggestion of additional measures\n\n• Data to be evaluated (See 10.3)\n• Responsible Managers (see 10.3)\n	2.	Establish management review report\n• Consolidate the results of data evaluation\n• Evaluate fulfilment of annual goals\n• Evaluate the overall effectiveness of the organisation\n• Decide upon measures and necessary resources\n• Initiate measures\n\n• List of Pending Items\n• AM\n	3.	Monitor implementation of measures\n• Verify completion and success of initiated measures\n\n• List of Pending Items\n• AM\n\n\n\n9.3 Data to be evaluated\n\nThe following sources of information and criteria are analyzed and evaluated according to the respective frequency:\n\nThe following sources of information and criteria are analyzed and evaluated according to the respective frequency. The reports of the individual responsible managers will be collated into the Management Review Report and discussed during the Management Review Meeting. Corrective and preventive actions are initiated and tracked on the list of Pending Items.\n\nStep | Criteria / Source data | Frequency\n\nAccountable Manager\n• Achievement of annual goals\n• Overall effectiveness of the organization\n• Monthly\n\nCompliance Monitoring manager\n• Status of the implementation and effectiveness\n• Audit results\n• Inspection results\n• 6 months\n\nHead of Training\n• Results from Progress checks and Examinations\n• Theoretical Training Comment Form\n• Flight Training Comment Form\n• Customer satisfaction\n• 6 months\n\nChief Flight Instructor\n• Trainee Feedback\n• Theoretical Training Comment Form\n• Flight Training Comment Form\n• 6 months\n\nChief TK Instructor\n• Trainee Feedback\n• Theoretical Training Comment Form\n• Flight Training Comment Form\n• 6 months\n\nContinuing Airworthiness Manager\n• Technical Logs\n• Effectiveness of Maintenance Program\n• 6 months\n\nFSTD Manager\n• Technical Logs (FSTD)\n• Effectiveness of FSTD Maintenance Program\n• QTG Test reports\n• 6 months\n• 3 months for QTG Test Reports', NULL, NULL, 'OMM_P2_9'),
('OMM_P3_0', 'OMM', '4.0', 3, '0', 'OUTLINE', '0.	GENERAL\n 0.1 Index of Abbreviations\n 0.2 Definitions and Terms\n	1.	SCOPE OF THE SAFETY MANAGEMENT MANUAL\n	2.	SAFETY POLICY AND OBJECTIVES\n 2.1 Objectives\n 2.2 EuroPilot Center Safety Policy\n	3.	SAFETY ACCOUNTABILITY AND RESPONSIBILITIES\n 3.1 Safety accountability of the Accountable Manager\n 3.2 Safety responsibility of Key Safety Personnel\n  3.2.1 Organogram\n 3.3 Safety Manager\n  3.3.1 Requirements\n  3.3.2 Duties and Responsibilities\n 3.2.3 Safety Manager Training (Initial & Recurrent)\n 3.4 Safety Review Board (SRB)\n  3.4.1 SRB Meeting Process\n   3.4.1.1 Phase 1 – Scheduling\n   3.4.1.2 Phase 2 – Recording Minutes\n   3.4.1.3 Phase 3 – Action Planning\n   3.4.1.4 Phase 4 – Closing\n 3.5 Safety Action Group (SAG)\n  3.5.1 SAG Meeting Process\n   3.5.1.1 Phase 1 – Scheduling\n   3.5.1.2 Phase 2 – Recording Minutes\n   3.5.1.3 Phase 3 – Action Planning\n   3.5.1.4 Phase 4 – Closing\n 3.6 Personnel and students\n	4.	DOCUMENTATION CONTROL PROCEDURE\n 4.1 Control of Specifications / Prescriptive Documents\n 4.2 Control of Records\n	5.	SAFETY RISK MANAGEMENT\n 5.1 Safety Risk Assessment\n  5.1.1 Scope\n  5.1.2 Influencing Elements\n  5.1.3 ALARP Concept\n 5.2 Risk Assessment Process Steps\n  5.2.1 Preparation\n  5.2.2 Hazard Identification\n   5.2.2.1 Hazard Classification\n   5.2.2.2 Hazard Identification Sources\n   5.2.2.3 Hazard Consequences\n   5.2.2.4 Hazard Identification Process\n   5.2.2.5 Hazards, Risks and Controls\n   5.2.2.6 Hazard Recording\n   5.2.2.7 Undesirable Events\n  5.2.3 Risk Assessment, Description and Evaluation\n   5.2.3.1 Likelihood\n   5.2.3.2 Severity\n   5.2.3.3 Risk Evaluation\n  5.2.4 Risk Control\n   5.2.4.1 Identification of Risk Mitigation Measures\n   5.2.4.2 Risk Mitigation Priorities\n   5.2.4.3 Risk Control Types\n   5.2.4.4 Risk Control Effect Assessment\n   5.2.4.5 Cost Benefit Analysis			\n  5.2.5 Conclusion and Documentation\n   5.2.5.1 Scope\n   5.2.5.2 Database of Hazards, Risk Assessment and Risk Control	\n 5.3 Changes invalidating risk assessment\n 5.4 Implementation of risk mitigation\n 5.5 Monitoring, Review and Improvement\n 5.6 Occurrence Reporting and Internal Safety Investigations\n  5.6.1 Mandatory Occurrence Reporting\n  5.6.2 Voluntary Occurrence Reporting\n  5.6.3 Exchange of Information\n  5.6.4 Occurrence Reporting Scheme\n  5.6.5 E-Occurrence Report (E-OR)\n 5.7 Safety Performance Monitoring and Measurement\n  5.7.1 Stepwise Approach\n  5.7.2 Fixing Safety Performance Objectives\n  5.7.3 Process\n 5.8 Emergency Response Planning\n  5.8.1 General\n  5.8.2 Aim\n  5.8.3 Events\n  5.8.4 Organization\n  5.8.5 Emergency Call\n  5.8.6 Emergency Numbers\n  5.8.7 Crisis Management Center\n   5.8.7.1 Personnel in charge\n   5.8.7.2 Modes of Activating the Crisis Management Team\n   5.8.7.3 Activation Levels\n   5.8.7.4 Activation\n   5.8.7.5 Crisis Log	\n  5.8.8 Internal & External Communication\n   5.8.8.1 External Communication\n   5.8.8.2 Internal Communication	\n  5.8.9 Roles of the Crisis Management Team\n   5.8.9.1 The Accountable Manager\n   5.8.9.2 The Head of Training   \n   5.8.9.3 The Safety Manager\n 5.9 Management of Change\n   5.9.1 Phase 1 – Receiving the Change Request\n   5.9.2 Phase 2 – Analyzing Changes\n   5.9.3 Phase 3 – Drafting MoC & Action Planning\n   5.9.4 Phase 4 – Obtaining BCAA Approval\n   5.9.5 Phase 5 – Closing	\n 5.10 Continuous Improvement\n   5.10.1 Improvement of Safety Performance	\n	6.	SAFETY PROMOTION\n	7.	CONTRACTED ACTIVITIES\n	8.	TRAINING AND COMMUNICATION ON SAFETY\n 8.1 Training\n 8.2 Communication\n 8.3 Safety Committee Airport Meetings\n   8.3.1 Phase 1 – Preparing for the Safety Committee Airport Meeting\n   8.3.2 Phase 2 – Attending the Meeting and Meeting Minutes\n   8.3.3 Phase 3 – Action Planning', NULL, NULL, 'OMM_P3_0'),
('OMM_P3_0__DUP2', 'OMM', '4.0', 3, '0', 'GENERAL', '0.1 Index of Abbreviations\n\nALARP – As Low as Reasonably Practicable\nAM – Accountable Manager\nAMC – Acceptable Means of Compliance\nASR – Air Safety Report\nATO – Approved Training Organization\nAU – Audit\nCMM – Compliance Monitoring Manager\nEASA – European Aviation Safety Agency\nEGAST – European General Aviation Safety Team\nEHEST – European Helicopter Safety Team\nERP – Emergency Response Planning or Plan\nESSI – European Strategic Safety Initiative\nFDM – Flight Data Monitoring\nGM – Guidance Material\nICAO – International Civil Aviation Organization\nIHST – International Helicopter Safety Team\nMOC – Management of Change\nOMM – Organization Management Manual\nSAG – Safety Action Group\nSM – Safety Manager\nSM ICG – Safety Management International Cooperation Group\nSMM – Safety Management Manual\nSMS – Safety Management System\nSOP – Standard Operating Procedure\nSPI – Safety Performance Indicator\nSPO / SPT – Safety Performance Objective / Target\nSRB – Safety Review Board\nSRM – Safety Risk Management\nSURV – Survey\n\n\n\n0.2 Definitions and Terms\n\nAccident Precursor\nEvent(s) which, without appropriate mitigation, can result in Undesirable Events, incidents and accidents.\n\nAudit\nA systematic, independent and documented process for obtaining evidence and evaluating it objectively to determine the extent to which requirements are complied with.\n\nHazard\nA condition, object, activity or event with the potential of causing injuries to personnel, damage to equipment or structures, loss of material, or reduction of the ability to perform a prescribed function.\n\nInspection\nAn independent documented conformity evaluation by observation and judgement accompanied as appropriate by measurement, testing or gauging, in order to verify compliance with applicable requirements (including procedures, work instruction standards, etc.).\n\nLikelihood\nUsed as a synonym of probability. It is a measure of how likely something is to happen.\n\nManagement of Change\nA documented process to identify external and internal changes that may have an adverse (or positive) effect on safety.\n\nMitigation Barrier\nRisk control mitigating the outcome (severity) of an incident or an accident.\n\nPrevention Barrier\nRisk control aimed at preventing Undesirable Events and Undesirable Operational States.\n\nRecovery Barrier\nRisk control aimed at preventing escalation into an accident.\n\nRisk\nThe combination of occurrence likelihood and severity.\n\nRisk Tolerability Matrix\nA matrix combining risk likelihood and risk severity.\n\nSafety\nThe state in which risks associated with aviation activities are reduced and controlled to an acceptable level.\n\nSafety Assurance\nThe process encompassing safety performance monitoring, management of change and continuous improvement.', NULL, NULL, 'OMM_P3_0__DUP2'),
('OMM_P3_1', 'OMM', '4.0', 3, '1', 'SCOPE OF THE SAFETY MANAGEMENT MANUAL', 'The Safety Management Manual (SMM) is a reference document describing how safety is managed within EuroPilot Center ATO.\n\nThe SMM is the key instrument for communicating EuroPilot Center’s safety approach to all its personnel and students.\n\nThe SMM documents all aspects of safety management, including:\n\n• scope of the SMS;\n• safety policy and objectives;\n• safety accountability of the Accountable Manager;\n• safety responsibilities of key safety personnel;\n• documentation control procedures;\n• hazard identification and risk management schemes;\n• safety action planning;\n• safety performance monitoring;\n• incident investigation and reporting;\n• emergency response planning;\n• management of change;\n• safety promotion.\n\nThe SMM is part of the EuroPilot Center Organization Management Manual (OMM).', NULL, NULL, 'OMM_P3_1'),
('OMM_P3_1__DUP2', 'OMM', '4.0', 3, '1', 'Identify the nature and scope of the change(s).', '', NULL, NULL, 'OMM_P3_1__DUP2'),
('OMM_P3_2', 'OMM', '4.0', 3, '2', 'SAFETY POLICY AND OBJECTIVES', 'By means of the Safety Policy, EuroPilot Center states its intention to maintain and, where practicable, improve safety levels in all its activities and to minimise the risk of an aircraft accident as far as is reasonably practicable.\n\n\n\n2.1 Objectives\n\nThe Safety Policy:\n\n• is endorsed by the Accountable Manager;\n• reflects organizational commitments regarding safety and its proactive management;\n• is communicated throughout EuroPilot Center;\n• includes safety reporting principles.\n\nIt includes a commitment:\n\n• to improve towards the highest safety standards;\n• to comply with applicable legislation and standards;\n• to provide appropriate resources;\n• to enforce safety as a primary responsibility of all managers;\n• not to blame individuals for reporting safety concerns.\n\nEuroPilot Center will:\n\n• continuously promote the safety policy;\n• provide necessary human and financial resources;\n• establish safety objectives and performance standards.\n\n\n\n2.2 EuroPilot Center Safety Policy\nEuroPilot Center\nSafety Policy\n\nSafety is one of EuroPilot Center’s core values. We are committed to developing, implementing, maintaining and constantly improving strategies and processes to ensure that all our aviation training activities take place under an appropriate allocation of organizational resources, aimed at achieving the highest level of safety performance and meeting regulatory requirements, while delivering our services.\n\nAll levels of management and personnel are accountable for the delivery of this highest level of safety performance, starting with the Accountable Manager.\n\nWe are committed to:\n\n• Support the management of safety through the provision of all appropriate resources, that will result in an organizational culture that fosters safe practices, encourages effective safety reporting and communication, and actively manages safety with the same attention to results as the attention to the results of the other management systems within the organization;\n• Ensure the management of safety is a primary responsibility of all managers and employees;\n• Clearly define for all staff, managers and employees alike, their accountabilities and responsibilities for the delivery of the organization‘s safety performance and the performance of our safety management system;\n• Establish and operate hazard identification and risk management processes, including a hazard reporting system, in order to eliminate or mitigate the safety risks of the consequences of hazards resulting from our operations or activities to achieve continuous improvement in our safety performance;\n• Ensure that no action will be taken against any employee/student who discloses a safety concern through the hazard reporting system, unless such disclosure indicates, beyond any reasonable doubt, gross negligence or a deliberate or willful disregard of regulations or procedures;\n• Comply with and, wherever possible, exceed, legislative and regulatory requirements and standards;\n• Ensure that sufficient skilled and trained human resources are available to implement safety strategies and processes;\n• Ensure that all staff members are provided with adequate and appropriate aviation safety information and training, are competent in safety matters, and are allocated only tasks commensurating with their skills;\n• Establish and measure our safety performance against realistic safety performance indicators and safety performance targets;\n• Continually improve our safety performance through continuous monitoring and measurement, and regular review and adjustment of safety objectives and targets, and diligent achievement of these; and\n• Ensure externally supplied systems and services to support our operations are delivered meeting our safety performance standards.\n\nMaria A. Paz\nAccountable Manager\nEuroPilot Center ATO', NULL, NULL, 'OMM_P3_2'),
('OMM_P3_2__DUP2', 'OMM', '4.0', 3, '2', 'Perform the basic initial Impact Assessment study covering:', '• EuroPilot Center’s operational procedures (Operations Manual)\n• Work organization (staffing, composition of the teams, scheduling, additional\ntraining, etc.)\n• Infrastructure (relocation, parking base, etc.)\n• Maintenance of equipment or the aircraft.', NULL, NULL, 'OMM_P3_2__DUP2'),
('OMM_P3_3', 'OMM', '4.0', 3, '3', 'SAFETY ACCOUNTABILITY AND RESPONSIBILITIES', '3.1 Safety accountability of the Accountable Manager\n\nThe Accountable Manager bears the safety accountability which means that he is ultimately accountable for safety within EuroPilot Center.\n\n• He/she endorses the Safety Policy (including the EuroPilot Center statement on the protection of the reporters, OMM Annex 7 - Protection of Reporters).\n• Provides the human and material resources necessary for operating the SMS and achieving the safety objectives.\n• Nominates the Safety Manager, the Compliance Monitoring Manager and the Safety Review Board.\n\nThe Accountable Manager chairs the Safety Review Board and endorses the safety objectives.\n\n\n\n3.2 Safety responsibility of Key Safety Personnel\n\nThe safety management organization includes:\n\n• The Accountable Manager (AM)\n• The Safety Manager (SM)\n• The Compliance Monitoring Manager (CMM)\n• A Safety Review Board (SRB)\n\n\n\n3.2.1 Organogram\nWe refer to OM Annex 35 – Organogram.\n\n\n\n3.3 Safety Manager\n\n\n\n3.3.1 Requirements\nThe following experience/qualifications are required for a Safety Manager within EuroPilot Center:\n\n• Has extensive knowledge of Aviation Rules and Regulations (including FSTD’s).\n• Preferably hold or have held a Commercial (or Airline Pilot License).\n• Has been a Safety Manager for an Aviation Organization for at least 1 year; or\n• Has extensive experience in Safety Management Systems; or\n• Has attended the Safety Management Course (e.g. internal course or through an entity such as JAATO).\n• Possesses sound managerial skills.\n• Speaks, writes and understands the English language.\n\n\n\n3.3.2 Duties and Responsibilities\nThe Safety Manager acts as the focal point and is responsible for the development, administration and maintenance of the SMS.\n\nThe duties of the Safety Manager are to:\n\n• facilitate hazard identification, risk analysis and management;\n• monitor the implementation of actions taken to mitigate risks as listed in the safety action plan;\n• provide periodic reports on safety performance;\n• ensure maintenance of safety management documentation;\n• ensure that there is safety management training available and that it meets acceptable standards;\n• provide advice on safety matters;\n• ensure initiation and follow-up of internal occurrence/accident investigations.\n\nThe Safety Manager is the focal point for:\n\n• collecting and analyzing hazards and maintaining a register of hazards, risks and risk controls (mitigations);\n• development, administration and maintenance of the SMS.\n\n\n\n3.3.3 Safety Manager Training (Initial & Recurrent)\nHas received a course from an experienced Safety Manager in the following topics:\nBasic Safety Management Systems (Min. 2h00).\nEvaluation and Reporting (Min. 2h00).\n\nOr has attended the same course through another entity (e.g. JAATO) and has provided EuroPilot Center with an appropriate Certificate of Training.\n\nIn addition, the applicant shall be trained on:\n\n• Safety Management system procedures within EuroPilot Center (Min. 1h00).\n• EuroPilot Center manuals and document control procedures (Min. 1h00).\n• EuroPilot Center ATO OMM and OM procedures (Min. 1h00).\n• EuroPilot Center Safety Reporting System (Min. 1h00).\n• EuroPilot Center Safety Management Online System (Min. 2h00).\n\nPractical Training shall consist of conducting at least 2 months of Safety Management Training under supervision with an experienced Safety Manager.\n\nAll training should be logged in the E-gle System by the Safety Manager.\n\nRecurrent Training does not apply to Safety Managers.\n\n\n\n3.4 Safety Review Board (SRB)\n\nThe Safety Review Board is a high level committee that considers matters of strategic safety in support of the Accountable Manager.\n\nThe Safety Review Board is chaired by the Accountable Manager and is composed of:\n\n• The Compliance Monitoring Manager\n• The Head of Training\n• The Chief Flight Instructor\n• The Chief Theoretical Knowledge Instructor\n\nThe Safety Review Board monitors the safety performance against the safety policy and safety objectives, monitors that any safety action is taken in a timely manner and that the SMS is effective.\n\nThe Accountable Manager ensures that appropriate resources are allocated to achieve the established safety performance and informs the Safety Review Board accordingly.\n\nThe Safety Manager may attend, as appropriate, Safety Review Board meetings. The Safety Manager may communicate to the Accountable Manager all information, as necessary, to allow decision making based on safety data.\n\n3.4.1 Process of the Safety Review Board Meeting\n\nThe yearly safety Review Board meeting will be scheduled, held, recorded and follow-up actions shall be taken, according to the process below, consisting of 4 phases:\n\nPHASE 1 – Scheduling the Safety Review Board (SRB) Meeting\nPHASE 2 – Recording the Meeting Minutes\nPHASE 3 – Action Planning\nPHASE 4 – Closing\n\n\n\n3.4.1.1 Phase 1 – Scheduling the Safety Review Board (SRB) Meeting\n\n• Login to PipeDrive and Click on “Projects”.\n• From the Dropdown list on the right, select the “AM - Safety Review Board Meeting” -Project.\n• Click on “plus symbol” located inside the first Phase of the Project (or the Green “+ Project” button on the left).\n• Select the “Safety Review Board” Template.\n• Name the Project as per following convention: “SRB Meeting: MM/YYYY” (e.g. SRB Meeting: 02/2023”).\n• Enter “Start Date” (Should be the scheduled day of the SRB Meeting).\n• Enter “End Date” (Should be the scheduled day of the SRB Meeting + 90 days).\n• Select Label” In Progress”.\n• Perform the checklist items under the “PLAN” section of the Project.\n• If relevant for the SRB Meeting, the AM can upload documents via the “FILES” section of the Project.\n• The AM should draft the “Agenda” of the SRB Meeting and use the “NOTES” Section of the Project (this can be performed in close cooperation with the SM).\n• When receiving relevant e-mails from official sources, they should be linked to the Project by opening the e-mail in PipeDrive, on the right, enter the Project Name in the textfield underneath the “Link to a deal/lead/project” -box.\n• The AM sends the invite for the Meeting to the HT, SM, CFI and CTKI including the SRB Meeting “Agenda”.\n\n\n\n3.4.1.2 PHASE 2 – Recording the Meeting Minutes\n\n• The Safety Manager will be in charge.\n• Go to the Project section in Pipedrive to obtain all the data collected during Phase 1.\n• Move the Project to Phase 2.\n• During the SRB Meeting, the minutes will be recorded by the SM by updating the “NOTES” section of the Project.\n\nNote: If the SM is unable to record the SRB Minutes, the CMM will be next, followed by the HT, CFI, CTKI and AM.\n\n\n\n3.4.1.3 PHASE 3 – Action Planning\n\n• The SM will be in charge.\n• Go to the Project section in Pipedrive.\n• Move the Project to Phase 3.\n• Execute the PLAN Checklist for this Phase.\n• Start drafting the “SRB Meeting Minutes” via de “EMAILS” section of the Project by creating a new e-mail via the Template Menu. Select the “SRB Meeting Minutes” template.\n• Create an Action Plan via the “PLAN” Section.\n• Select a “TASK” for each Action Item requiring a Task to be fulfilled, add sub-tasks if required.\n• Allocate the “TASK” to the responsible person within the organization and add a due-date (proposal).\n• Only select “ACTIVITY” when a certain Action requires a Calendar event such as a Meeting etc.\n• Once the SRB Meeting Minutes e-mail has been drafted and the Action Plan is prepared under the PLAN section, the SM sends the e-mail to the AM, CMM, HT, CFI and CTKI.\n\nIMPORTANT! An SRB Meeting may trigger a “Change Request” which shall be sent to the Safety Manager, hence may initiate a Management of Change Procedure.\n\n\n\n3.4.1.4 PHASE 4 – Closing\n\n• The SM will be in charge.\n• After either the “SRB Meeting Minutes” have been reviewed by the AM, CMM, HT, CFI and CTKI, feedback obtained shall be used to update the Action Plan via the “PLAN” Section by the SM.\n• Based on the deadlines for each Action item, the SM shall follow-up with the person to whom the Task was allocated. Pipedrive will generate automatic triggers if required.\n• The SM ensures all Task Items are closed and “archives” the Project.\n\n\n\n3.5 Safety Action Group (SAG)\n\nThe Safety Action Group reports to and takes strategic direction from the Safety Review Board.\n\nIt comprises managers, supervisors and staff from operational areas.\n\nThe Safety Manager may also be included in the Safety Action Group.\n\nThe Safety Action Group:\n\n• oversees operational safety;\n• resolves identified risks;\n• assesses the impact on safety of operational changes;\n• implements corrective action plans;\n• ensures that corrective action is achieved within agreed timescales.\n\n3.5.1 Process of the Safety Action Group Meeting\n\nA Safety Action Group Meeting will be assembled by the SRB on an ad-hoc basis as deemed required by the Safety Review Board, according to the process below, consisting of 4 phases:\n\nPHASE 1 – Scheduling the Safety Action Group (SAG) Meeting\nPHASE 2 – Recording the Meeting Minutes\nPHASE 3 – Action Planning\nPHASE 4 – Closing\n\n\n\n3.5.1.1 Phase 1 – Scheduling the Safety Action Group (SAG) Meeting\n\n• The Safety Manager will be in charge.\n• Login to PipeDrive and Click on “Projects”.\n• From the Dropdown list on the right, select the “SM - Safety Action Group Meeting” -Project.\n• Click on “plus symbol” located inside the first Phase of the Project (or the Green “+ Project” button on the left).\n• Select the “Safety Action Group” Template.\n• Name the Project as per following convention: “SAG Meeting: MM/YYYY” (e.g. SAG Meeting: 02/2023”).\n• Enter “Start Date” (Should be the scheduled day of the SAG Meeting).\n• Enter “End Date” (Should be the scheduled day of the SAG Meeting + 90 days).\n• Select Label” In Progress”.\n• Perform the checklist items under the “PLAN” section of the Project.\n• If relevant for the SAG Meeting, the AM can upload documents via the “FILES” section of the Project.\n• The SM should draft the “Agenda” of the SAG Meeting and use the “NOTES” Section of the Project.\n• When receiving relevant e-mails from official sources, they should be linked to the Project by opening the e-mail in PipeDrive, on the right, enter the Project Name in the textfield underneath the “Link to a deal/lead/project” -box.\n• The SM sends the invite for the Meeting to the AM, HT, CFI and CTKI including the SAG Meeting “Agenda”.\n\n\n\n3.5.1.2 PHASE 2 – Recording the Meeting Minutes\n\n• The Safety Manager will be in charge.\n• Go to the Project section in Pipedrive to obtain all the data collected during Phase 1.\n• Move the Project to Phase 2.\n• During the SAG Meeting, the minutes will be recorded by the SM by updating the “NOTES” section of the Project.\n\nNote: If the SM is unable to record the SAG Minutes, the CMM will be next, followed by the HT, CFI, CTKI and AM.\n\n\n\n3.5.1.3 PHASE 3 – Action Planning\n\n• The SM will be in charge.\n• Go to the Project section in Pipedrive.\n• Move the Project to Phase 3.\n• Execute the PLAN Checklist for this Phase.\n• Start drafting the “SAG Meeting Minutes” via de “EMAILS” section of the Project by creating a new e-mail via the Template Menu. Select the “SAG Meeting Minutes” template.\n• Create an Action Plan via the “PLAN” Section.\n• Select a “TASK” for each Action Item requiring a Task to be fulfilled, add sub-tasks if required.\n• Allocate the “TASK” to the responsible person within the organization and add a due-date (proposal).\n• Only select “ACTIVITY” when a certain Action requires a Calendar event such as a Meeting etc.\n• Once the SAG Meeting Minutes e-mail has been drafted and the Action Plan is prepared under the PLAN section, the SM sends the e-mail to the AM, CMM, HT, CFI and CTKI.\n\nIMPORTANT! An SAG Meeting may trigger a “Change Request” which shall be sent to the Safety Manager, hence may initiate a Management of Change Procedure.\n\n\n\n3.5.1.4 PHASE 4 – Closing\n\n• The SM will be in charge.\n• After either the “SAG Meeting Minutes” have been reviewed by the AM, CMM, HT, CFI and CTKI, feedback obtained shall be used to update the Action Plan via the “PLAN” Section by the SM.\n• Based on the deadlines for each Action item, the SM shall follow-up with the person to whom the Task was allocated. Pipedrive will generate automatic triggers if required.\n• The SM ensures all Task Items are closed and “archives” the Project.\n\n\n\n3.6 Personnel and students\n\nAll EuroPilot Center personnel in charge of operational tasks and all EuroPilot Center students have the following responsibilities:\n\n• ensure both their own and the safety of other personnel and/or students;\n• interrupt or discontinue their tasks if their safety or that of others is at risk;\n• perform their tasks in compliance with regulations and EuroPilot Center procedures;\n• practice and promote the EuroPilot Center safety policy;\n• notify hazards and safety-related events and report any relevant information to the Safety Manager;\n• take note of the lessons learnt from incidents and accidents and take appropriate measures to protect themselves and others;\n• participate in safety briefings, meetings and events;\n• participate, if applicable, in safety analyses;\n• know their role in the Emergency Response Plan.\n\nAll personnel and students have a part in implementing the SMS successfully. It’s the responsibility of everyone within EuroPilot Center to identify and report hazards.\n\nAll personnel and students are to inform the Safety Manager of any situation deemed to be hazardous to flight safety and to their own safety or the safety of others both within or out of EuroPilot Center ATO.\n\nAll personnel and students have to be trained in the SMS and have knowledge of their roles and responsibilities.\n\n• For personnel, this takes place during the initial Standardization course.\n• For students, this takes place immediately after their course enrollment.\n\nSelf-study of the Safety Manual or a Briefing will be foreseen followed by a short multiple choice questionnaire.', NULL, NULL, 'OMM_P3_3'),
('OMM_P3_3__DUP2', 'OMM', '4.0', 3, '3', 'Perform a Safety Risk Analysis (See the Risk Management section', '', NULL, NULL, 'OMM_P3_3__DUP2'),
('OMM_P3_4', 'OMM', '4.0', 3, '4', 'DOCUMENTATION CONTROL PROCEDURE', '4.1 Control of Specifications / Prescriptive Documents\n\nFor all internal Standards and Procedures, EuroPilot Center ensures that the current versions are available in the EuroPilot Center Planning and Operations room. The amendment procedure of the OMM, OM, TM and QTG is specified in the introduction part of the respective manual.\n\n\n\n4.2 Control of Records\n\nRecords are documents or data stating results achieved, or providing evidence of activities performed. To ensure an authorized and quick access to records, they have to be:\n\n• Properly identified\n• Systematically stored for the period required\n• Destroyed after storage period in a controlled manner\n\nNote: Storage can be in an electronic format (cloud-based).\n\nDocument | Responsibility | Place of Storage | Storage\n\nSafety Objectives and Indicators\n• Safety Manager\n• EPC Administration Archives\n• 5 Years\n\nSafety Review Board Reports\n• Accountable Manager\n• EPC Administration Archives\n• 5 Years\n\nEvent Reports\n• Safety Manager\n• EPC Administration Archives\n• Permanent\n\nAudit Reports including the follow-up of corrective actions\n• Safety Manager\n• EPC Administration Archives\n• 5 Years\n\nHazard and Risk Registers\n• Safety Manager\n• EPC Administration Archives\n• Permanent\n\nRisk Mitigations\n• Safety Manager\n• EPC Administration Archives\n• Permanent\n\nSafety Training Reports\n• Head of Training\n• EPC Administration Archives\n• Permanent', NULL, NULL, 'OMM_P3_4'),
('OMM_P3_4__DUP2', 'OMM', '4.0', 3, '4', 'Identify hazards related to implementing the proposed change', '', NULL, NULL, 'OMM_P3_4__DUP2'),
('OMM_P3_5', 'OMM', '4.0', 3, '5', 'SAFETY RISK MANAGEMENT', 'Safety Risk Management combines the following processes and components:\n\n• Hazard identification, risk assessment and mitigation processes\n• Internal safety investigation\n• Safety performance monitoring and measurement\n• Management of change\n• Communication (Safety Notes and yearly Safety Bulletin).\n• Continuous improvement\n• The Emergency Response Plan (ERP)\n\nA formal risk management process has been developed and is maintained to ensure that:\n\n• analysis, in terms of likelihood and severity of occurrence;\n• assessment, in terms of tolerability; and\n• control, in terms of mitigation of risks to an acceptable level.\n\nAdditionally, the levels of management that have the authority to make decisions regarding the tolerability of safety risks are specified in the following paragraphs.\n\n\n\n5.1 Safety Risk Assessment\n\n5.1.1 Scope of Safety Risk Assessment\n\nThe SMS only addresses the assessment of aviation safety risks. This does not mean that financial,\nlegal, or economic aspects do not need to be considered in the risk assessment process. EuroPilot\nCenter identifies all significant influences that may impact aviation safety, in particular when\ndetermining contributing factors for the analysis of consequences of a hazard, and deciding on risk\nmitigation measures.\n\n5.1.2 Elements that influence the Safety Risk Assessment\n\n5.1.2.1 Communication and Consultation\nGood communication within EuroPilot Center and, where relevant, with external parties, students,\npartners, or contractors, should help ensure access to all relevant information, and assist in ensuring\nbuy-in from all those that may be affected by the risk assessment conclusions and\nrecommendations.\n\n5.1.2.2 Regulatory Requirements - Risk addressed by Regulations\nRegulations are generally developed to control common safety risks that stem from specific or\ngeneral hazards through prescriptive, technical standards in the areas of technology, training, or task performance.\nSuch hazards controlled by regulations do not need to be further addressed in the Organization’s\nrisk assessment unless evidence exists that the regulatory provision is not sufficient.\nIf the regulation is not specific, has several options, or directly calls for a risk assessment, the hazard obviously should be assessed, and the appropriate provision implemented.\n\n5.1.2.3 Regulatory Requirements - Organization’s Resources\nAvailable resources are relevant with respect to both capacity and competence:\n• for the risk assessment process itself; and\n• for the activity being assessed (aircraft, equipment, personnel, finances, etc.).\nEuroPilot Center’s current resources in terms of equipment and personnel are normally considered\nin the risk assessment.\n\n5.1.3 The ALARP Concept\n\nRisk Acceptance Criteria are established on the basis of a Safety Policy and Safety Performance\nObjectives. Furthermore, management responsibility for the acceptability of safety risks is defined as part of the SMS.\n\nSafety risk acceptance criteria address the following:\n• Flight Instructors;\n• Theoretical Knowledge Instructors;\n• Students;\n• The natural environment; and\n• The corporate well-being.\n\nEuroPilot Center employs the ‘As Low As Reasonably Practicable’ (ALARP) risk acceptance\ncriterion.\n\nThis ALARP criterion is not exclusively based on fixed risk level targets but is a systematic and documented process to reduce safety risks below the maximum allowed by regulations or\nstandards or when the risk is otherwise considered unacceptable.\n\nALARP means that the safety risk is being managed to as low a level as reasonably practicable\nwhilst at all times staying below the maximum allowed risk.\n\n5.2 Risk Assessment Process Steps\n\n5.2.1 Preparation\n\nThe Safety Risk Assessment should be initiated in time for the results to be available before any decisions regarding the activity concerned have to be made.\n\nThe Safety Manager:\n\n• shall determine the need for a dedicated working group comprised of suitable subject matter experts and personnel involved in EuroPilot Center’s activities;\n• shall also decide whether, and what other methods and sources are used to determine hazard causes, likelihood and consequences;\n• progressively extend and personalize the data base;\n• shall decide whether to use additional data sources.\n\nThe EuroPilot Center database shall contain:\n\n• information resulting from the investigation of internal occurrences and accidents;\n• reported deviations and proposals for improvement;\n• experience collected from the monitoring of normal operations.\n\nThe EuroPilot Center database may be augmented with similar data exchanged with other operators. Whenever possible, the process of risk assessment should further build upon experience derived from risk assessments carried out previously.\n\n\n\n5.2.2 Hazard Identification\n\n\n\n5.2.2.1 Hazard Classification\nHazards can come from different sources, including but not limited to:\n\n• Natural and environmental: weather, earthquake, wind and sand, sea water, rocks, cliffs, ice structures, rough waters, volcano lava and dusts, etc.;\n• Economic: competition, production pressure, cost pressure, etc.;\n• Unsafe conditions: use of unofficial documentation or documents not up to date, poor resources;\n• Psychological: mood, external pressure, personality issues, etc.;\n• Physiological: diseases, hypoxia, perceptual illusions, fatigue, sleep deprivation, jet lag, medication, alcohol, intoxication, digestion troubles, etc.;\n• Technological: design or maintenance related, hazardous material, pollution, explosions, etc.;\n• Operational or mission specific: obstacles, cables, demanding landing sites (moving platforms/off airfield sites), degraded visual cuing (brown-out and white-out), demanding/overbearing customers (VIPs), etc.;\n• Unsafe acts: errors, violations, negligence, sabotage, excessive/uncontrolled performance variations.\n\n\n\n5.2.2.2 Hazard Identification Sources\nHazards can be identified from different internal and external sources and are elements, in isolation or in combination, which may have contributed or could contribute to an incident or accident.\n\nInternal sources\n\n• Safety assessment of systems and operations;\n• Voluntary reports, spontaneous identification;\n• Safety indicator tendencies;\n• Inspections and audits.\n\nExternal sources\n\n• Accident and incident reports;\n• Technical publications from manufacturers (for instance Safety Information Bulletins);\n• Safety Information Bulletins, safety alerts and other safety publications from EASA, the European Commission, the National Aviation Authorities, ICAO, Eurocontrol, the FAA and other authorities worldwide;\n• Websites such as SKYbrary and Wikipedia;\n• Safety publications by national or international associations and safety initiatives such as AGAST, EHEST and IHST, the Helicopter Association International (HAI), the Royal Aeronautical Society (RAeS), the Flight Safety Foundation (FSF), Aircraft Owners and Pilots Association (AOPA), etc.;\n• Safety publications by industry, research Organizations and academia;\n• Professional journals, conference proceedings, safety campaigns, helicopter safety days;\n• Benchmarks between operators, data aggregated at sector level or by the manufacturers, etc.\n\n\n\n5.2.2.3 Hazard Consequences Identification Sources\n\nHazards are distinguished from hazard consequences.\n\nConsequences can be described based on the hazard information specifying the place, time, extent, nature, etc. of the event as required.\n\nHazard identification also provides a systematic overview of all possible consequences.\n\nFor each hazard, the following question should be asked:\nWhat were or could have been the possible hazard consequences?\n\nWhere information on the consequence of a hazard has been identified for a specific type of activity it should be available directly from data sources.\n\nIt is also worth noting that the absence of past incidents/accidents does not mean absence of risk.\n\nAids to the identification of possible consequences include:\n\n• Other risk assessments;\n• Occurrence and accident reports;\n• Audits/non-compliance reports;\n• Internal reviews;\n• Instructor Meetings;\n• Threat assessments;\n• Standard checklists.\n\n\n\n5.2.2.4 Hazard Identification Process\n\nHazards are identified through the application of a hazard identification process. The hazard\nidentification process is the formal means of collecting, recording, analyzing, acting on and\ngenerating feedback about hazards and the associated risks that affect the safety of EuroPilot\nCenter’s operational activities.\n\nThe hazards identification process features several components:\n\nThe reactive approach consists of analyzing accidents and incidents that have occurred and trying to understand why. Based on the analysis of reported accidents and incidents, the following questions should be asked:\n\n• What accidents or incidents did happen and why?\n• For what reasons did these occur? Because of what causal factors?\n• What barriers or risk controls failed and what barriers worked?\nThe proactive approach consists of analyzing the conduct of operations to identify potential\nhazards and assess the associated risks and then to mitigate risks factors before they result in an accident or incident. This approach should trigger the following questions:\n• What accidents or incidents could happen and why?\n• For what reasons could these occur?\n• Do we feel protected enough? Any action we should take now to prevent these from\noccurring?\n\nHazard identification also features a predictive approach. It consists of conducting a predictive analysis using for instance data extrapolation (estimating for instance the future risk level based on the data collected over the past 3 or 5 years) or statistical modeling (a more complex way).\n\nA predictive approach aims at identifying and mitigating risks before they become evident\n(addressing today the risks of tomorrow). This approach poses the following question:\n• What accidents or incidents could happen in the future and why?\n• Do we feel protected enough? Any action we should take now to avoid such future risks and\noccurrences (addressing today the risks of tomorrow)?\n\nThe predictive and proactive approaches are very effective tools for the management of safety,\nthey should build upon the basis of solid reactive processes.\n\n\n\n5.2.2.5 Hazard, Risks and Risk Controls\n\nEuroPilot Center applies the Safety Risk Control Modeling approach.\nThe purpose of this approach is to consider “Undesirable Events” as an intermediate step between\nhazards and risks, and incidents and accidents.\nHazards can, in isolation or in combination, lead to Undesirable Events.\nThey trigger a stage in the escalation of an accident scenario, called the Undesirable Operational State, where the scenario has escalated to the point that the accident can only be avoided through successful recovery measure(s) or by chance.\n• Prevention Barriers are risk controls aimed at preventing Undesirable Events and Undesirable\nOperational States.\n• Recovery Barriers are risk controls that prevent these events from resulting in an accident.\n• Mitigation barriers are risk controls that mitigate the effect of an incident or an accident\n\n\n\n5.2.2.6 Hazard Recording\n\nThe Safety Manager will maintain a register (or log) of hazards.\n\n\n\n5.2.2.7 Identification of Undesirable Events and their Consequences\n\nEuroPilot Center has created a list of Undesirable Events, based on our experience as RF and FTO, as a means to start our SMS. This list will be updated and adapted through the operation of the SMS.\n\n\n5.2.3 Risk Assessment, Description and Evaluation\n\nRisk combines two dimensions: likelihood of hazard consequences and their severity. Both\ndimensions will be assessed.\n\n5.2.3.1 Likelihood\n\nAssessment of likelihood is based on the following two way process:\n• hazard consequences are analyzed to establish possible causes, contributing factors and\nexisting barriers.\n• causes, contributing factors and barriers are then further analyzed to determine likelihood of an occurrence.\n\nIn the causal analysis of consequence, human and Organizational factors are considered for their\npossible contributing effects. We normally consider direct causes (‘unsafe acts’), workplace factors and Organizational factors (‘error provoking or latent conditions’).\nThe effects of existing likelihood-reducing factors and barriers (See the Section Safety Model) that influence the chain of events are considered and documented, taking into account the following:\n• certification requirements;\n• maintenance procedures;\n• existing normal and abnormal procedures;\n• technical measures/equipment;\n• training;\n• other human and Organizational factors.\n\nCausal analysis is performed to the level of detail necessary to establish relevant likelihood values.\n\nLikelihood may be expressed using terminology such as:\n• very low\n• low\n• medium\n• high\n• very high\nLikelihood will be determined by EuroPilot Center as follows:\nLikelihood will be determined by EuroPilot Center as follows:\n\nRisk Likelihood\nMeaning\nValue\n\nFREQUENT\nLikely to occur many times. Has already occurred within EuroPilot Center (Freq. > 3 times per year ).\nHas occurred frequently in the history of the aviation industry.\n5\n\nOCCASIONAL\nLikely to occur sometimes. Has already occurred within EuroPilot Center (Freq. < 3 times per year).\nHas occurred infrequently in the history of the aviation industry.\n4\n\nREMOTE\nUnlikely to occur, but possible. Has already occurred within EuroPilot Center at least once or more.\nHas seldom occurred in the history of the aviation industry.\n3\n\nIMPROBABLE\nVery unlikely to occur. Not known to have occurred within EuroPilot Center but has already occurred at least once in the history of the aviation industry.\n2\n\nEXTREMELY IMPROBABLE\nAlmost inconceivable that the event will occur. It has never occurred in the history of the aviation industry.\n1\n\nWithin EuroPilot Center, a causal and likelihood analysis will be performed by one or a combination of the following methods:\n\nfault tree analysis;\nFMECA (Failure Mode, Effects and Critical Analysis);\ninfluence diagrams;\nbow-tie diagrams;\nbrainstorming.\n\nAs the risk assessment progresses, an iterative process may help to identify new factors and barriers. These can then be included in the analysis.\n\n5.2.3.2 Severity\n\nThe severity of all hazard consequences is analyzed. The analysis considers both short-term and long-term consequences, such as effects on the natural and work environment.\nConsequences are grouped such as loss or damage of life/health, environment, material values/assets, functions and reputation.\nThe determination of severity is normally of a descriptive (qualitative/ordinal terms) nature, except when relevant calculations (quantitative) can or should be applied. A qualitative analysis describes the chains of events that could follow from the hazard and its possible consequences. Quantitative analysis is used to calculate the extent of damage that could be caused.\n\nSeverity can be expressed using terminology like:\nvery small;\nsmall;\nmedium;\nlarge; and\nvery large.\n\nSeverity will be determined by EuroPilot Center as follows:\n\nSeverity\nMeaning\nValue\n\nPersonnel\nEnvironment\nMaterial & Values Assets\nReputation\n\nCATASTROPHIC\nMultiple fatalities\nMassive effects (pollution, destruction)\nCatastrophic financial loss. Damage > 1M EUR\nInternational Impact\nE\n\nHAZARDOUS\nFatality\nEffects difficult to repair\nSevere financial loss with long term effects.\nDamage < 1M EUR\nNational Impact\nD\n\nMAJOR\nSerious Injuries\nNoteworthy local effects\nSubstantial Financial Loss. Damage < 250K EUR\nConsiderable Impact\nC\n\nMINOR\nLight Injuries\nLittle impact\nFinancial loss with little impact.\nDamage < 50K EUR\nLimited Impact\nB\n\nNEGLIGIBLE\nSuperficial or no injuries\nNegligable or no effects\nFinancial loss with negigible impact. Damage < 10K EUR\nLight or no Impact\nA\n\nIn the analysis of severity of each consequence, human and Organizational factors are primarily considered for their possible contributing effects.\n\nThe effects of existing recovery controls and barriers that influence the consequence itself or the consequence chain should be considered, as applicable:\n\ncertification requirements (e.g. fire protection);\nexisting abnormal and emergency procedures;\nsecondary safety measures (e.g. crashworthiness, personal protective equipment);\ntechnical measures/equipment;\ntraining;\nhuman and Organizational factors;\nemergency preparedness.\n\nAs the risk assessment progresses, it is possible that an iterative process may help to identify new factors and barriers. These are then added to the procedure and included in the analysis.\n\nRisk levels may vary over time depending on the nature of the operation(s) (machines and equipment, procedures and documentation, flight environment, personnel qualification, duration of the tasks, etc.). Comprehensive and up to date data such as risk assessments and risk descriptions help in the task of performing good and effective risk assessments.\nRisk must be re-assessed, in particular when a change is introduced.\n\n5.2.3.3 Risk Evaluation\n\nThe risk description forms the basis for risk evaluation and mitigation. Based on the results of the likelihood and severity analysis, the risk is described as a combination of the likelihood of occurrence and the associated severity.\n\nDepending on the analysis method and the risk acceptance criteria, the description is either qualitative and/or quantitative. The level of detail depends on the level of detail in the likelihood and severity analysis.\nThe method used for risk description is a risk matrix combining risk likelihood and risk severity. If a hazard has more than one consequence, the risk may be expressed as a combination of the likelihood and severity for each of the consequences.\nUncertainties in the risk description are to be identified and documented. If the analysis is based on critical assumptions or other conditions that could affect the assessment, these are to be identified and documented (if necessary in the form of a sensitivity analysis).\nHazards can lead to Undesirable Events (UE’s), which can deteriorate into incidents and accidents. Hazards can contribute to several UE’s and are generally related to several Hazards (many-to-many mapping), which all have an associated risk level. The level of risk associated to an UE is, however, not the average of the risk levels associated to the hazards that contribute to the risk.\nThis is why UE’s are also subject to a separate risk rating. Risk rated UE’s are then used as an input to Safety Cases.\n\nThe results of the risk analysis are compared to the criteria for acceptable risk.\nThis comparison is documented using a format that can be used by decision makers.\nThe method used for this is the Risk Tolerability Matrix combining the analysis results and the risk acceptance criteria.\n\nRisk\nRisk Severity\nLikelihood\n\nNEGLIGIBLE-A\nMINOR-B\nMAJOR-C\nHAZARDOUS-D\nCATASTROPHIC-E\n\nFREQUENT-5\n5A\n5B\n5C\n5D\n5E\n\nOCCASIONAL-4\n4A\n4B\n4C\n4D\n4E\n\nREMOTE-3\n3A\n3B\n3C\n3D\n3E\n\nIMPROBABLE-2\n2A\n2B\n2C\n2D\n2E\n\nEXTREMELY IMPROBABLE-1\n1A\n1B\n1C\n1D\n1E\n\nThe red-colored values indicate unacceptable risk levels, the yellow-coded values are tolerable risk levels and the green-coded values establish acceptable risk levels.\nEach risk level calls for a particular action and the levels of management who have the authority to make decisions regarding the tolerability of safety risks need to be specified.\n\nUnacceptable Risk Level - the red zone in the matrix: risk is too high to continue operating.\nAction required: Prohibit/suspend the operation. Operation may be resumed only when risk level is returned to tolerable or acceptable.\nManagement levels who have the authority to make decisions regarding risk tolerability:\nFor the risk evaluation validation: The assumptions made for the determination of the risk level and its tolerability are to be validated by the Safety Manager.\nFor the authorization of operations: not applicable: operations cannot be authorized.\n\nTolerable Risk Level - the yellow zone in the matrix: the risk level can be tolerated for the operation, providing that appropriate mitigation measures are in place.\nAction required: Introduce appropriate mitigation measures.\nManagement levels who have the authority to make decisions regarding risk tolerability:\nFor the risk evaluation validation: The assumptions made for the determination of the risk level and its tolerability are to be validated by the Safety Manager.\nFor the authorization of operations: Management who have the authority to authorize operations at this level of risk: the Accountable Manager.\n\nAcceptable Risk Level - the green zone in the matrix: risk is tolerable and can be accepted for the operation.\nAction required: Monitor. Risk is considered sufficiently controlled and no additional risk mitigation measures are required. However, in line with the ALARP concept, actions may still be taken to further reduce the risk level if feasible and reasonable. Additionally, any assumptions used to make an assessment must be monitored to ensure they remain valid.\nManagement levels who have the authority to make decisions regarding risk tolerability:\n\nFor the risk evaluation validation: The assumptions made for the determination of the risk level and its tolerability are to be validated by the Safety Manager.\n\nFor the authorization of operations: not applicable; no special authorization is required; the authorization of activities featuring ‘acceptable risks’ fall within the regular operational control for operations.\n\n5.2.4 Risk Control\n\n5.2.4.1 Identification of Risk Mitigation Measures\n\nThe risk evaluation is the basis for deciding on risk control (mitigating) measures and in assessing the effectiveness of these measures.\n\nRisk control measures identify the consequences associated with both an unacceptable risk and tolerable risk and determine where further risk reduction measures are feasible and reasonable.\n\nIdentification of possible mitigation is based on the risk description and evaluation, considering in particular any uncertainties identified and critical assumptions made.\n\nControls that may eliminate the consequence of a hazard, likelihood-reducing measures and severity-reducing measures are identified. The measures should address the human factors (e.g. training and competence), equipment or Organizational factors (e.g. procedures).\n\nWithin EuroPilot Center, all personnel and students contributes to the definition of risk control measures in particular where they concern personal equipment, by their acceptance and use.\n\n\n\n5.2.4.2 Risk Mitigation Priorities\n\nRisk control measures are implemented based on the following priorities:\n\neliminate the consequences of the hazard;\nreduce the likelihood of occurrence;\nreduce the severity.\n\n\n\n5.2.4.3 Risk Control Types\n\nExamples of risk control include:\n\npassive technical controls (e.g. system redundancy, firewall);\nactive technical controls (e.g. automatic fire extinguishing system).\n\n\n\n5.2.4.4 Risk Control Effect Assessment\n\nThe risk mitigating effect of the controls is assessed with respect to:\n\nFunctionality: does the measure influence the ability to perform the activity?\nRobustness: will the measure be effective under varying conditions and over time?\nPossible other effects such as introduction of new risks.\n\nWhen identifying risk control measures, any new risks that may arise from the implementation of such measures (‘substitution risks’) should be identified.\n\nRisk is re-assessed considering the effects of the proposed risk control effects, as illustrated in the table below:\n\nRisk Assessed\nInitial Risk Level\nRisk Control\nResulting Risk Level\n\nRisk 1\n\nRisk 2\n\nRisk 3\n\nThe measures are not necessarily sufficient to bring the risk level back to an acceptable or tolerable level in a first round. If the risk acceptance criteria require further risk reduction, the comparison (iterative process) describes the optimization process. So new risk controls are added, or existing risk controls are modified, until the risk is as low as reasonably practicable (ALARP).\n\nNote that the ALARP concept combines the technical feasibility of further reducing the safety risk and the cost; demonstrating that the safety risk is ALARP means that any further risk reduction is either impracticable or grossly outweighed by the cost.\n\n\n\n5.2.4.5 Cost Benefit Analysis\n\nThe contemplated mitigation measures should be subjected to a Cost Benefit Analysis, which helps determine the most appropriate measures. The mitigation considered appropriate should achieve the safety benefits desired and should be economically acceptable.\n\nA Cost Benefit Matrix is provided here as an illustration:\n\nBenefits\n\nHIGH  AVERAGE  LOW\n\nCOSTS\nLOW  1  2  3\nAVERAGE  2  3  4\nHIGH  3  4  5\n\nAcceptance criteria with regard to the costs of implementing mitigation measures and the expected benefits, are decided by the Accountable Manager.\n\n\n\n5.2.5 Conclusion and Documentation\n\nAny risk assessment should be documented and contain unambiguous, precise and robust conclusions to enable decision makers to arrive at appropriate control reduction decisions.\n\nDocumentation includes references to other documents (when applicable) and points out any need for further work.\n\n\n\n5.2.5.1 Scope\n\nThe risk assessment documentation includes or references, as required, descriptions of the following:\n\n• the purpose of the risk assessment;\n• the activity/issue analyzed;\n• involvement of personnel and other operators with whom we interact;\n• context/framework for the activity/issue;\n• the assessment of who is affected by the activity/issue and how;\n• data used;\n• the analysis method;\n• the hazard(s);\n• the contributing factors and consequences\n• uncertainties and assumptions made for the assessment;\n• the likelihood and severity;\n• the risk mitigation measures;\n• the risk evaluation;\n• the conclusions.\n\n\n\n5.2.5.2 Database of Hazards, Risk Assessment and Risk Control\n\nThe Safety Manager shall maintain a database of hazards, and of the corresponding risk assessments and mitigations. This risk database records hazards per activity and indicates how these have been addressed in the past and are currently being addressed.\n\nAny future risk assessment may then draw upon the information already available.\n\nThe information is both communicated and made available within EuroPilot Center with special attention to the managers in charge, depending on the nature of the risks.\n\nThe database of “Hazards” and “Hazards and Undesirable Events” are updated at each step of the risk management processes. These databases also record the results of the processes and serve as a basis for risk monitoring, review and improvement.\n\nWe refer to the EuroPilot Center Online Safety Management System for this purpose (http://sms.europilotcenter.be)\n\n\n\n5.3 Changes that could Invalidate the Conclusion of a Risk Assessment\n\nChanges that could invalidate the conclusion of a risk assessment could be:\n\nsignificant changes in the preconditions and context;\nnew knowledge of risks involved (experience from accidents and occurrences, reporting of safety concerns, research, better risk analysis methods, internal inspections, audits and reviews, hazard reporting);\nsignificant changes in the underlying data used for the assessment;\nsignificant organizational changes that could affect the assessment; and\nseveral smaller changes that together might constitute a significant change.\n\nDepending on the type of activity affected and the nature of the changes, the Safety Manager may decide to reassess the risk.\n\n\n\n5.4 Implementation of Risk Mitigation\n\nImplementation of the risk control (mitigation) measures may, depending on the nature of these measures, give rise to an implementation plan identifying who is in charge, the resources needed, the deadline, and the stages of implementation.\n\nThe implementation plan is periodically reviewed until completion or revision.\n\n\n\n5.5 Monitoring, Review and Improvement\n\nThe risk assessment process is monitored for the purpose of:\n\nanalyzing and learning from events, changes and trends;\ndetecting changes in the internal and external context including changes to the risk itself;\nensuring that the risk mitigation measures remain effective; and\nidentifying emerging risks.\n\nMonitoring and review can be performed through periodic reviews, inspections and audits, risk assessments and the risk management process itself, with the aim to strive for a continuous reduction in the risk level.\n\n\n\n5.6 Occurrence Reporting and Internal Safety Investigations\n\n5.6.1 Mandatory Occurrence Reporting\n\nThe mandatory reporting of occurrences to the Belgian Civil Aviation Authority applies to natural persons under Article 4 paragraph 6 of the (EU) Regulation No 376/2014.\n\nThe Safety Manager is the designated person who is responsible for notifying occurrences to the Belgian Civil Aviation Authority.\n\nThe collected information on the occurrences must be reported as soon as possible, and in any case within a period not exceeding 72 hours after becoming aware of the occurrence.\n\nThe preliminary results and any action taken, based on the analysis performed by the Safety Manager, on occurrences collected to identify the safety hazards associated with identified occurrences or groups of occurrences, shall be reported within 30 days from the date of notification of the occurrence.\n\nThe final results of the analysis, where required, shall be reported as soon as they are available and, in principle, no later than three (3) months from the date of notification of the occurrence.\n\nNote: The European Commission (EC) has established, with the aid of the Implementing Regulation (EU) No 2015/1018, a list classifying the occurrences which should be referred to in the mandatory occurrence reporting under Article 4 paragraph 1 of the Regulation (EU) No 376/2014.\n\nWe refer to the BCAA Circular MAS-01 and (EU) 2015/1018.\n\n\n\n5.6.2 Voluntary Occurrence Reporting\n\nA system of voluntary occurrence reporting is used to collect information on occurrences:\n\nreported by persons who are not mentioned in Article 4 paragraph 6 of the Regulation (EU) No 376/2014;\nwhich are not included in the list found in the Implementing Regulation (EU) No 2015/1018 classifying occurrences into categories, which must be referred to in case of mandatory occurrence reporting under Article 4 paragraph 1 of the Regulation (EU) No 376/2014.\n\nOnly the occurrences presenting a real or potential risk for safety should be reported to the Belgian Civil Aviation Authority. This requires that the aviation organization carries out an analysis to establish the risk of these occurrences for safety.\n\n\n\n5.6.3 Exchange of Information\n\nIn order to allow the exchange of information, mandatory and voluntarily occurrence reports are sent to the Belgian Civil Aviation Authority using a format compatible with the ECCAIRS software and ADREP system.\n\nEuroPilot Center has opted to use the European reporting portal intended for small and medium-sized aviation organizations that produce few monthly reports.\n\nThe mandatory and voluntary reporting of occurrences to the Belgian Civil Aviation Authority is done via the European reporting portal at the following address:\n\nhttp://www.aviationreporting.eu\n\n\n\n5.6.4 Occurrence Reporting Scheme\n\nThe overall purpose of the scheme is to make best use of reported information to improve the level of safety performance and not to attribute blame.\n\nThe scope of this scheme also includes occurrences not reportable to the authorities. The objectives of the occurrence reporting scheme are to:\n\nenable an assessment to be made of the safety implications of each relevant incident and accident, including previous occurrences of a similar nature, so that any necessary action can be initiated; and\nensure that knowledge of relevant incidents and accidents is disseminated, so that other persons and operators may learn from them.\n\nThe scheme is an essential part of the overall monitoring function and it is complementary to the normal day-to-day procedures and ‘control’ systems and is not intended to duplicate or supersede any of them.\n\nAll occurrence reports judged reportable by the person submitting the report should be retained as the significance of such reports may only become obvious at a later date.\n\nEvery occurrence identified through occurrence reports, voluntary reports or other sources provides the opportunity to draw safety lessons. Learning from experience is only possible if all events are reported and analyzed and their causes and factors (technical, operational, or environmental) are determined and analyzed.\n\nOn a daily basis, occurrences (down to simple malfunctions) may affect any process. Some of these occurrences are defined as accident precursors. Accident precursors are occurrences which, without appropriate mitigation, can result in Undesirable Events or accidents.\n\nThe Safety Manager is to record, analyse and monitor these occurrences via the Online Safety Management System.\n\nOccurrences are reported via the E-Occurrence Reporting System (E-OR) and recorded in the Online Safety Management System database. The database is analyzed to identify trends and define recommendations to correct possible deviations and avoid accidents.\n\nAn occurrence is classified as:\n\nTechnical: when its cause is mainly technical;\nOperational: when it is mainly due to one or several unsafe acts or unsafe conditions;\n\nIt should be recognized, however, that occurrences can feature more than one of these\ncomponents.\n\n\n\n5.6.5 E-Occurrence Report (E-OR)\n\nAn occurrence report shall be filed immediately by any person within EuroPilot Center via the Online E-OR System.\n\nThe system can be accessed via the following link:\n\nhttp://safety.europilotcenter.be\n\nReports can be filed anonymously via:\n\nhttp://anoymous.europilotcenter.be\n\nReporting occurrences is essential for improving safety and is strongly encouraged. EuroPilot Center guarantees that the reporter(s) will not be punished for reporting safety concerns except in the case of illegal act, gross negligence, or a deliberate disregard for regulations and applicable procedures.\n\nEach occurrence report is analyzed, processed and saved by the Safety Manager in the Online Safety Management System.\n\nThe analysis focuses on assessing the potential impact on flight safety and may include impacts on personnel, third parties, material, the environment, and EuroPilot Center’s reputation.\n\n\n\n5.6.6 Internal Safety Investigation\n\nThe scope of internal safety investigations should extend beyond the scope of occurrences required to be reported to the competent authority.\n\nInvestigations consist of collecting and analyzing events, determining causal and contributing factors, drawing up conclusions and making safety recommendations.\n\nInvestigations are carried out in particular in the case of:\n\naccidents and incidents;\ndiscovery of new hazards and risks;\nrecurrent safety risks.\n\nMoreover, the Safety Manager may at any time decide to launch an investigation procedure on an opportune basis.\n\nInternal Safety Investigation Process\n\nStage\nDecision to launch an investigation\nPut together an investigation team.\n\nActivity Planning\nDefine and breakdown the activities.\nDefine the investigation needs.\n\nData collection\nCollect evidence about the event. The following relevant sources can be used:\nPhysical examination;\nDocumentation and files;\nInterviews with the persons involved;\nObservation of actions;\nSimulations;\nExpert consultancy;\nSafety database.\n\nScenario Identification\nIdentify/reconstruct the scenario\n\nScenario Analysis\nAnalyse the facts, determine the causes and identify the associated hazards.\nIntegrate all investigation elements.\n\nRisk Assessment\nDetermine the risk level and assess risk acceptability.\n\nRisk Control/Mitigation Analysis\nDetermine Corrective/Preventive Action.\n\nSafety Communication\nCommunicate the investigation results to everyone in the organization by means of Safety Notes and the yearly Safety Bulletin.\n\nCompletion of the investigation\nClose and archive the file.\n\n\n\n5.7 Safety Performance Monitoring and Measurement\n\nSafety performance monitoring and measurement is the process by which the EuroPilot Center’s safety performance is verified in comparison to the overall safety policy and objectives.\n\nSafety performance is defined as the level of safety achievement against the Safety Performance Objectives (SPO’s), using specific Safety Performance Indicators (SPI’s).\n\n\n\n5.7.1 Stepwise Approach to Safety Performance Measurement\n\nEuroPilot Center has adopted a step-wise approach to safety performance measurement, based on three levels of SMS maturity.\n\n5.7.1 Stepwise Approach to Safety Performance Measurement\n\nAt different levels of maturity of the SMS, the amount of quality safety data available and the issues and actions that are most important for improving safety performance and actions will differ.\n\nEuroPilot Center has, therefore, adopted a step-wise approach to safety performance measurement, based on three levels of SMS maturity.\n\n\n\nLEVEL 1 of SMS implementation - Present and Suitable\n\nAt the first level, the SMS will have achieved compliance with the applicable requirements. SPI’s should focus on the activities required to maintain basic compliance with the SMS regulatory framework. These can be of a quantitative (numerical) or qualitative (non-numerical) nature:\n\nQuantitative indicators (examples):\nthe number of safety reviews performed;\nthe number of staff that received training in SMS;\nthe number of internal audits performed versus the number of audits planned;\n\nQualitative indicators (examples):\nfeedback received from staff on the safety policy;\nfeedback received from staff on new procedures implemented in the area of internal occurrence reporting or hazard identification.\n\n\n\nLEVEL 2 of SMS implementation - Operating and Effective\n\nAt this level, EuroPilot Center will start to define more specific SPI’s on the basis of safety data collected through the hazard identification and internal occurrence reporting processes.\n\nMore specific, objective and reliable leading performance indicators and precursor event indicators are introduced to identify any weaknesses and areas where improvement is required. These can include:\nthe number of risk assessments performed following Organizational changes;\nthe percentage of standard operating procedures that have been subject to hazard identification;\naverage lead time for completing corrective actions following internal audit;\nnumber of additional procedural controls implemented;\n\nAt this level of SMS maturity, EuroPilot Center will be getting a better picture of the risks affecting the operations and the solidity of the risk controls in place.\n\n\n\nLEVEL 3 of SMS Implementation - Best Practice\n\nLevel 3 is the level where EuroPilot Center will have achieved continuous learning and improvement for all parts of the SMS.\n\nSPI’s are focused around local issues identified from the safety data already collected, and from key safety areas identified by the regulator or identified at an aggregate level from within the industry sector.\n\nSPI’s allow the risk levels related to occurrences to be monitored, the solidity of any barriers and relationship to any accidents.\n\nRisk mitigation actions focus on those issues that present the greatest risks or offer the greatest potential for improvement.\n\nQuantitative indicators:\n\nnumber of high risk occurrences (coded amber and red);\nmean value of risk ratings (over a reference period, e.g. 1 year);\nsum of risk ratings (over a reference period, e.g. 1 year);\nsolidity of risk controls (defenses) (rated from 0 to 5; over a reference period, e.g. 1 year).\n\nFollowing the implementation of risk mitigation actions, risks are monitored to ensure that risk controls are effective and are indicative of how these controls could be improved.\n\n\n\n5.7.2 Fixing Safety Performance Objectives\n\nThe process for determining quantitative safety performance objectives for a given period consists of:\n\nmeasuring the baseline against which safety improvements are to be assessed;\nfixing reasonable, yet ambitious targets; and\nmonitoring target achievement over time and reviewing targets as necessary.\n\nThe Safety Manager shall ensure that both the SPO’s and the SPI’s are pertinent and documented.\n\n\n\n5.7.3 Process\nThe Safety Manager shall ensure that the process for safety performance measurement is established and implemented.\n\nSPO’s are monitored over time by the Safety Manager and reviewed by the Safety Review Board or by the Accountable Manager with the Safety Manager.\n\nSPI’s are also reviewed following the implementation of a change.\n\nA report is provided annually to the Safety Review Board and the Accountable Manager. The process of safety performance monitoring and measurement shall include the following:\n\n\n\nSAFETY REPORTING\nThe Safety Manager collects and centralizes EuroPilot Center’s safety reports and monitors the type and number of reported events over time. Additionally, he/she addresses the status of compliance with the applicable requirements.\n\n\n\nSAFETY STUDIES\nSafety studies consist of a detailed analysis which is used to target broad safety concerns. The Safety Manager shall, whenever appropriate, initiate safety studies addressing subjects of safety relevant to EuroPilot Center.\n\nSafety studies are aimed at gathering additional information on selected topics that has been identified by safety reports or other means. Safety studies are by their nature larger in scope than the analysis of specific hazards. Safety surveys, for example, belong in this category.\n\nSafety studies can address a variety of subjects such as compliance with Standard Operating Procedures, mission preparation and risk assessment of specific operations such as dealing with deteriorating weather, resisting customer pressure, etc.\n\nSafety studies can make use of information published in technical publications from manufacturers, OEM’s, the regulatory authorities, Helicopter Associations and national, European or international Helicopter Safety Initiatives such as EHEST and IHST. This can also include a review of journal articles, accident and incident reports, conference proceedings, press releases and other safety information often available on the internet.\n\nSafety Studies are saved as PDF files and stored in the Safety Study Folder.\n\n\n\nSAFETY REVIEWS\nSafety reviews, including trend reviews, are conducted during the introduction and deployment of new technologies, change or implementation of procedures, or in situations of structural change to operations.\n\nA safety review should be performed at least once each year by the Safety Review Board and/or by the Safety Manager and Accountable Manager.\n\nThe aim of the safety review is to assess:\nsafety performance against the safety indicators and objectives,\nthe effectiveness of Safety Management System, including through an assessment of the effect of the corrective and/or preventive actions,\nprocedures and policies,\nHealth and Safety.\n\nPossible negative trends and deficiencies may be identified, as well as actions taken to correct these deficiencies by targeting their causes. Corrective actions are to be recorded. A Model is provided under OMM Annex 9 - Corrective Action Follow Up.\n\n\n\nSAFETY AUDITS\nSafety audits focus on the integrity of the management system and periodically assess the status of safety risk controls.\n\nAn audit schedule can be found in Annex 12 - Safety Audit Schedule.\n\nEuroPilot Center addresses all audit findings through appropriate corrective actions in an effort to restore and/or improve the effectiveness of the SMS and safety performance. A Model of is provided under OMM Annex 9 - Corrective Action Follow Up.\n\n\n\nInternal Audits\nThe Safety Manager shall have the responsibility for the internal Safety Audits but may be assisted by another internal or external auditor.\n\n\n\nSAFETY SURVEYS\nSafety surveys are dedicated qualitative or quantitative (statistical) studies targeting specific safety subjects.\n\nSafety surveys allow particular elements or procedures of a given operation to be evaluated, such as problem areas in daily operations, perceptions, opinions, satisfaction levels and areas of dissent or confusion. Safety surveys can also be used to gather comments and suggestions.', NULL, NULL, 'OMM_P3_5'),
('OMM_P3_5__DUP2', 'OMM', '4.0', 3, '5', 'Identify existing risk controls and define, as appropriate, additional mitigation measures.', '', NULL, NULL, 'OMM_P3_5__DUP2'),
('OMM_P3_5_8', 'OMM', '4.0', 3, '5.8', 'Emergency Response Planning', '5.8.1 General\n\nThe EuroPilot Center Emergency Response Plan complies with ORO.GEN.200 and AMC1 ORO.GEN,200(a)(1);(2);(3)(5) point (f) and is designed to help the Organization respond in the case of accidents, serious incidents or any other abnormal events triggering a crisis.\n\nThe number of phases that need to be implemented need to be established in order to prevent the confusion which may result when emergency situations arise.\n\nThe management must:\nidentify the responsibilities;\nrespond to the needs of the applicable Flight Instructor and/or student;\nprovide assistance to the emergency services, and\ninform the authority in charge of any investigation.\n\n\n\n5.8.2 Aim of the Emergency Response Plan (ERP)\n\nThe EuroPilot Center ERP is designed to cover safety situations which cannot be specifically or precisely defined. An Organizational framework of the actions and policies required to be implemented is presented.\n\nHowever, it is unlikely that an actual emergency situation will adapt to a precise framework. Adaptability and flexibility should therefore be demonstrated when handling such events.\n\n\n\n5.8.3 Events that may activate the ERP\n\nThe following events may result in a crisis situation and activate the Emergency Response Plan:\nAviation accident/serious incident;\nDisaster in the EuroPilot Center premises: fire, explosion, pollution, flood, etc.;\nLoss of the working resource: offices, hangar, aircraft;\nImpact of a disaster that happened within the vicinity of the establishment;\nClimatic event: snow, storm, flood, lightning, etc.;\nNatural disaster: earthquake, etc.;\nFood poisoning, epidemic;\nDeath, suicide at the workplace;\nMultiple victims connected to a disaster, illness or contagion;\nAccident during the public transportation of the personnel;\nSocial movements: strike, blocking of the accesses;\nInternal or external threat: attack, bomb alert, sabotage, terrorism;\nLoss of energy: electricity, gas;\nLoss of communication means: internet, landlines or mobile telephones;\nMajor media event;\nAccident during missions: business trip abroad.\n\n5.8.4 Organization\n\nIt is vitally important that EuroPilot Center is thoroughly prepared in how to react effectively in the case of an emergency. The progress of events will depend on how the Organization initiates an alert (or relays an alert message).\n\nThe EuroPilot Center Head of Training is the single point of contact that any member of staff may alert in the case of an emergency. His cellphone number is distributed so this person can be\nreached out of normal working hours.\nThis single point of contact will be responsible for disseminating the alert to the Organization’s managers and the relevant official authorities.\n\nIn order to prevent unnecessary delay, the nominated contact must have immediate access to the\nfollowing:\n• Emergency checklists to cover the nature of the event.\n• An up to date list of managers to be contacted and their deputies in the case of absence (a\nschedule of \'on-call\' executives to be contacted should be created).\n• A list of emergency services and official Organizations to be contacted in the event of an\nemergency.\n\nAll employees should know their role in case a serious event occurs, including how to raise the alert, what immediate actions to take to try and resolve the crisis or to prevent the situation deteriorating. EuroPilot Center will carry out an emergency training exercise once a year to practice and refine the procedures and to train personnel.\n\nWherever possible the normal activity of the Organization must be maintained. To this end,\nemployees whose activity is not affected by the situation should continue to carry out their normal duties. Personnel should, however, contact their family and friends to reassure them in an attempt to prevent congest of external communications.\n\nIf the presence of an employee is not required at the accident/incident site, or at the location of the Crisis Management Team, they should be discouraged from going to these locations so as not to hinder the emergency services and/or any investigation team(s).\nIt is important that personnel not involved in the management of the situation does not contact the Crisis Management Team or speak to the media.\n\n5.8.5 Reaction to an Emergency Call\n\nWhenever EuroPilot Center is made aware of an accident or incident, the person or department\nthat receives the alert must endeavor to establish the following information points:\n• Date and time of the call.\n• Name and contact details of the informant.\n• The authenticity of the call (where possible).\n• In the event that the call is made anonymously, try and obtain information concerning the other\nparty and their position (where possible, try to record the conversation and listen to background\nnoise).\n• Initiate the alert process both in-house and externally.\n\n5.8.6 Emergency Numbers\n\nThe direct contact details for the members of the Crisis Management Team and the Emergency\nServices must be readily accessible and up to date. We refer to OMM Annex 10 - Emergency Contact List\n\n5.8.7 The Crisis Management Center\n\n5.8.7.1 Personnel in charge\n\nThe Crisis Management Team consists of:\n• the Accountable Manager\n• the Head of Training\n• the Chief Operations Officer\n• the respective Chief Flight Instructor or Chief Theoretical Knowledge Instructor (depending on\nthe situation)\n• the Safety Manager\n\n5.8.7.2 Modes of Activating the Crisis Management Team\n\nA. Accidents occurring within EuroPilot Center Premises\nAny person who witnesses an accident on the EuroPilot Center premises should comply with the\nfollowing fundamental safety rules:\n• Alert the Head of Training\n• Alert the emergency services (where appropriate)\n• Protect any victims/casualties\nIf qualified, apply basic first aid while awaiting the arrival of the emergency services.\n\nB. Accidents occurring outside of the EuroPilot Center Premises\nIf the call is received by the Head of Training:\nThe On-call Manager informs the Accountable Manager who decides whether or not to activate\nthe Crisis Management Center.\nThe Chief Operations Officer contacts the members of the Crisis Management Team.\nIf the call is received by a Flight Instructor or Theoretical Knowledge Instructor, or a Student, he/she contacts the Head of Training or, if he is unavailable, the Accountable Manager.\n\n5.8.7.3 Activation Levels\n\nLevel 1: Event with potentially hazardous impact but without immediate consequences\nThe members of the Crisis Management Team are placed on alert in order to reduce the response\ntime should the situation deteriorate. At this level of preparedness, the Crisis Management Team\nmembers should be contactable and available at all times.\n\nLevel 2: Event that may have one or several significant impacts on the safety of people or property and on the normal state of operation of the company.\nThe members of the Crisis Management Team should be called to the Crisis Management Center in\norder to have a preparatory decision and thereby be in a position to react immediately.\n\n5.8.7.4 Activation\n\nMembers of the Crisis Management Team should report to the crisis cell equipped with the\nfollowing:\n\n• Cellphone;\n• Crisis management file containing the Emergency Checklists to be followed and the actions to\nbe taken;\n\n• Laptop computer, if required;\n• An adequate supply of writing material such as notebooks, pencils, pens, etc.;\n\n5.8.7.5 Crisis Log\n\nOnce the Crisis Management Center has been activated, all events, decisions and subsequent\nactions must be recorded in a Crisis Log. This will ensure that an accurate record of actions taken in response to the emergency situation is retained.\n\n5.8.8 Internal and External Communication\n\n5.8.8.1 External Communication\n\nIn the situation where a major event has occurred, it is essential that the Organization implements a detailed communication plan.\nOnce an emergency call has been received and the Crisis Management Center has been\nmanned, an initial press release should be disseminated in an attempt to prevent the saturation of lines of communication. Press releases should not contain the name(s) of the persons involved in the accident/incident unless they have been definitively established.\nAdditionally, the names of senior or departmental managers should not be released unless\nauthorized.\n\n5.8.8.2 Internal Communication\n\nIn responding to an emergency situation, all or part of the Organizations personnel may be\naffected by the event.\n\nThe management must make a concerted effort, by whatever means appropriate, to inform all\npersonnel and students regarding the event.\nThe management must in a timely manner inform the personnel of the steps to be taken in\naccordance with the Crisis Management Manual.\nEuroPilot Center has a strict policy to utilize a ban on disclosing any information outside of the Organization and with the media. Additionally, it is prohibited to all personnel and students to be at the accident/location or at the\nCrisis Management Center unless required to do so within the scope of their duties.\n\n5.8.9 Roles of the Crisis Management Team\nThe following paragraphs describe the roles and responsibilities required to be carried out by the Crisis Management Team.\n\n5.8.9.1 The Accountable Manager\n\n• Manage internal operations by relying on the members of the Crisis Management Team.\n• Draws up in conjunction with the Chief Operations Officer press releases to the media.\n• Appoints or be a spokesperson to communicate with the media.\n• Ensure that the activities of the company are maintained if not affected by the event.\n• Be at the disposal of the relevant official Organizations.\n\n5.8.9.2 The Head of Training\n\nA. Gathers any information about the flight and the nature of the accident.\n\nB. Compiles a list of all documents about the flight and have them available for the authorities\nincluding:\n• Copies of weather reports (PIB’s etc.);\n• Copies of pre-flight planning documents;\n• Copies of Mass and Balance planning;\n• Copies of fuel planning and fuel uplift receipts.\n\nC. Compiles a list of the administrative documents pertaining to the crew member(s) involved\nincluding as a minimum:\n• Individual Training File(s)\n• Flight Time and Duty Records\n• Logbook (if available)\n• Copy of medical certificates\n• Copy of flight crew licenses\n\nD. In co-operation with the Maintenance Organization, gathers the technical documents relating\nto the aircraft involved in the accident.\n\nE. Contacts the customer(s) affected by the accident in accordance with any contractual\nagreements in place.\n\nF. Contacts any sub-contracted companies affected by the accident, where appropriate.\n\nG. Carries out a short briefing to advise the personnel and students about the situation and the\nactions to be taken.\n\nH. Assists in establishing a list of casualties involved in the accident.\n\nI. Compiles a list of all HR documents relating to the personnel and/or students involved in the\naccident and have them available for the authorities.\n\nJ. Ensures that any personnel assigned to carry out any duty at the accident location is provided with the necessary logistics and equipment.\n\nK. If necessary, contacts the medical professionals for dealing with emotional trauma.\n\nL. Contacts employees who have volunteered to assist in dealing with the families of victims.\n\nM. Contacts any consultant/lawyer deemed necessary, dependent on the event.\n\nN. Informs the Insurance Companies, depending on the event.\n\n5.8.9.3 The Safety Manager\n\n• Draws up conclusions from the EuroPilot Center SMS and safety database(s) regarding previous\noccurrences and risk assessments, mitigation and control (various risk controls in place)\nconcerning the safety risk(s) revealed by the event at hand.\n• Provides these conclusions on previous occurrences and risk assessments to the Accountable\nManager to enable them to answer any questions correctly to support the protection of\ncompany’s reputation.\n• Assists the Accountable Manager in any other way.\n• Remains at the disposal of the relevant official organizations.\n• Updates SMS information (after the crisis).', NULL, NULL, 'OMM_P3_5_8'),
('OMM_P3_5_9', 'OMM', '4.0', 3, '5.9', 'Management of Change', 'EuroPilot Center will manage safety risks related to a change. Management of change is a\ndocumented process to identify external and internal change that may have an adverse effect on\nsafety. It makes use of existing hazard identification, risk assessment and mitigation processes.\n\nChanges may have various positive or negative safety impacts. Any change that may have an\nadverse effect on safety shall be identified and managed through EuroPilot Center’s existing\nprocesses for hazard identification, risk assessment and mitigation.\nThe EuroPilot Center Online Safety Management System (http://sms.europilotcenter.be), contains a\ndatabase of “Hazards” and “Undesirable Events” that needs to be updated for each internal or\nexternal change.\n\nDifferent changes can be grouped in a common Safety Impact Assessment, especially if they are\nintroduced together or if they are inter-related.\nEuroPilot Center’s change impact assessment procedure is described as follows:\n\nManagement of Change Procedure\n\nThe accountable Manager will initiate a “change request” to the Safety Manager AND\nCompliance Monitoring Manager via e-mail. These could be caused by: e.g. a consequence of a\n“Regulatory Change Meeting”, changes to the Organization not requiring prior BCAA Approval\n(e.g Changes in TKI’s FI’s etc), changes to the Organization requiring prior BCAA Approval (e.g\nchange of name, principle place of business etc.).\nThe Management of Change Procedure, to be executed and managed by the Safety Manager,\nconsists of 4 phases:\n\nPHASE 1 – Receiving the Change Request\nPHASE 2 – Analyzing Changes\nPHASE 3 – Drafting MoC & Action Planning\nPHASE 4 – Closing\n\n5.9.1 Phase 1 – Receiving the Change Request\n\n• Login to PipeDrive and Click on “Projects”.\n• From the Dropdown list on the right, select the “SM - Regulatory Changes” -Project.\n• Click on “plus symbol” located inside the first Phase of the Project (or the Green “+ Project”\nbutton on the left).\n• Select the “Management of Change” Template.\n• Name the Project as per following convention: “Management of Change: MM/YYYY/NR” (e.g.\nRegulatory Changes: 02/2023/001”)\n• Enter “Start Date” (Should be the date upon receiving the “Change Request” e-mail from the\nAccountable Manager).\n• Enter “End Date” (Should be the anticipated date on when the change should be\nimplemented).\n• Select Label” In Progress”\n• Perform the checklist items under the “PLAN” section of the Project.\n• When receiving relevant PDF files or other documents, the SM must upload this document via\nthe “FILES” section of the Project.\n• The SM should make any notes necessary under the “NOTES” Section of the Project.\n• When receiving relevant e-mails from official sources, they should be linked to the Project by\nopening the e-mail in PipeDrive, on the right, enter the Project Name in the textfield underneath\nthe “Link to a deal/lead/project” -box.\n\n\n5.9.2 Phase 2 – Analyzing Changes\n\n• Go to the Project section in Pipedrive to obtain all the data collected during Phase 1.\n• Move the Project to Phase 2.\n• Start with the Analysis Process based on the PLAN Checklist for this Phase and use the foreseen\nManagement of Change Worksheet (OMM Annex 28):', NULL, NULL, 'OMM_P3_5_9'),
('OMM_P3_6', 'OMM', '4.0', 3, '6', 'Identify key personnel who will assist in implementing the change', '5.9.3 Phase 3 – Drafting MoC & Action Planning\n\n• Go to the Project section in Pipedrive.\n• Move the Project to Phase 3.\n• Execute the PLAN Checklist for this Phase.\n• Start drafting the “MoC Worksheet”.\n• Start drafting the Action Plan.\n• Start assessing the financial cost of the proposed Action Plan\n• Export the “MoC Worksheet” into a PDF file and upload this document via the “FILES” section of\nthe Project.\n• Create an Action Plan via the “PLAN” Section.\n• Select a “TASK” for each Action Item requiring a Task to be fulfilled, add sub-tasks if required.\n• Allocate the “TASK” to the responsible person within the organization and add a due-date\n(proposal).\n• Only select “ACTIVITY” when a certain Action requires a Calendar event such as a Meeting etc.\n• Once all of the above items have been completed and the Action Plan is prepared under the\nPLAN section, send the “Management of Change Action Plan” e-mail to the AM, HT, CMM.\n\n5.9.4 Phase 4 – Obtaining BCAA Approval\n\n• After the “Management of Change Action Plan” has been reviewed by the AM, HT and CMM,\nfeedback obtained shall be used to update the Action Plan via the “PLAN” Section.\n• The AM sends an e-mail to the BCAA, clearly outlining the proposed changes, including a\nsigned copy of the Management of Change procedure and Action Plann, in order to obtain\nprior approval to implement the changes.\n• Once Approval has been obtained, continue with Phase 5. If unsuccessful, return to Phase 2.\n\n5.9.5 Phase 5 – Closing\n\n• When receiving the formal Approval E-mail from the BCAA, it should be immediately linked to\nthe Project by opening the e-mail in PipeDrive, on the right, enter the Project Name in the\ntextfield underneath the “Link to a deal/lead/project” -box.\n• Based on the deadlines for each Action item, the SM shall follow-up with the person to whom\nthe Task was allocated. Pipedrive will generate automatic triggers if required.\n• The SM ensures all Task Items are closed and “archives” the Project.\n\n\n\n5.10 Continuous Improvement\n\nEuroPilot Center shall continuously seek to improve its SMS and safety performance.\n\n5.10.1 Improvement of Safety Performance Improvement of Safety Performance\n\nThe Safety Manager shall provide a report on safety performance (risk levels, incident and accident figures, etc.) annually to the Accountable Manager.\n\nThe report should include a comparison with the levels of safety achieved in previous years. This report can be merged with the one mentioned in the previous paragraph.\n\nContinuous improvement of safety performance should be achieved through:\nproactive and reactive evaluations of facilities, equipment, documentation and procedures through safety audits and surveys;\nproactive evaluation of each individuals performance to verify the fulfillment of their safety responsibilities; and\na reactive evaluation in order to verify the effectiveness of the system for control and mitigation of risk.\n\n\n\n5.10.2 Improvement of the SMS\n\nContinuous improvement of the SMS is achieved through:\nAssessment of how the SMS is functioning;\nIdentification and analysis of possible issues/challenges associated with the running of the SMS;\nImplementing changes aimed at improving the SMS;\nMonitoring and reviewing the effects of any changes.\n\nContinuous improvement can also be achieved when the SMS is functioning well, performance of the SMS can always be improved.\n\nMeasures that can improve the SMS include:\nLeaner procedures;\nImproved safety reviews, studies and audits;\nImproved reporting and analysis tools;\nImproved hazards identification and risk assessment processes and improved awareness of risks within EuroPilot Center;\nImproved relations with the subcontractors, suppliers and customers regarding safety;\nImproved communication processes, including feedback from the personnel and students.\n\nContinuous improvement of the SMS may target any component of the SMS, in other words any subject addressed in this SMM which has the objective of increasing the effectiveness of the system over time.\n\nThe Safety Manager performs a review of the SMS (how effectively goals and objectives were met) and he/she provides a report on the SMS (how effectively the SMS works, the stage of implementation, results of audits and review of actions, any issues/challenges and proposals for improvement) annually to the Accountable Manager.', NULL, NULL, 'OMM_P3_6'),
('OMM_P3_6__DUP2', 'OMM', '4.0', 3, '6', 'SAFETY PROMOTION', 'Safety Promotion is a process aimed at promoting a culture of safety by ensuring that all personnel in an Organization is aware that, at their level and in their day-to-day activity, they are key players in safety and that everyone, therefore, contributes to an effective SMS.\n\nManagers are important actors of the EuroPilot Center’s Safety Management System. In all the activities they manage, they demonstrate commitment to safety and take care of safety aspects.\n\nThey lead by example and have an essential role to play for safety promotion.\n\nTraining and effective communication on safety are two important processes supporting safety promotion.', NULL, NULL, 'OMM_P3_6__DUP2'),
('OMM_P3_7', 'OMM', '4.0', 3, '7', 'CONTRACTED ACTIVITIES', 'EuroPilot Center may contract certain activities to external Organizations for the provision of services related to areas.\n\nThe ultimate responsibility for contracted activities, i.e. for the product or service provided by external Organizations always remains with EuroPilot Center.\n\nA written agreement signed between the EuroPilot Center and the contracted Organization shall clearly define the contracted activities and the applicable requirements.\n\nActivities performed by sub-contractors may have an impact on safety, therefore, the contracted safety related activities need to be addressed through the EuroPilot Center’s Safety Management and Compliance Monitoring program.\n\nAs part of the SMS, a risk analysis is to be carried out on any newly contracted activity as part of the Change Management process.\n\nIf corrective and/or preventive actions need to be implemented, they are to be submitted in writing to the sub-contractors or suppliers. Effective application of these measures needs to be checked and monitored under the supervision of the Safety Manager.', NULL, NULL, 'OMM_P3_7'),
('OMM_P3_8', 'OMM', '4.0', 3, '8', 'Training and Communication on Safety', 'Safety training is an integral part of the EuroPilot Center Training Manuals.\n\n\n\n8.1 Training\n\nAll personnel receives safety training as appropriate for their safety responsibilities. All the records of the safety training provided must be stored in the EuroPilot Center archives.\n\nAll personnel receive training to maintain their competences. This includes notification of any changes to applicable regulations and rules, EuroPilot Center’s procedures, and safety-relevant technical matters. This will be communicated through Safety Notes and the yearly Safety Bulletin.\n\nThere is a link between training and safety risk management as training and competence development is one of the means through which identified risks can be reduced. Other types of risk controls concern equipment or Organizational factors (e.g. procedures), which in turn can also be addressed in training.\n\nThe safety training program may consist of self-study via a Computer Based Training Course, organized by the Safety Manager.\n\n\n\nContents and Training objectives:\n\nSafety Policy\nUnderstand the main elements of the Safety Policy.\n\nOrganization, roles and responsibilities\nUnderstand the Organization, roles and responsibilities concerning the SMS. Everyone is to know his or her own role in the SMS.\n\nSafety Objectives\nUnderstand the EuroPilot Center’s safety objectives.\n\nEmergency Response Planning (ERP)\nUnderstand the various roles and responsibilities in the EuroPilot Center’s ERP. Everyone is to know his or her own role in the ERP.\n\nOccurence and hazards reporting\nKnow the means and procedures for reporting occurrences and hazards.\n\nSafety Risk Management (SRM) process including roles and responsibilities\nUnderstand the Safety Risk Management process. Everyone is to know his or her own role in the SRM.\n\nContinuous improvement of Safety Performance\nUnderstand the principles of continuous improvement of safety performance.\n\nResponsibility when contracting activities\nUnderstand EuroPilot Center’s responsibilities when contracting activities. Everyone is to know his or her own roles and responsibilities regarding this subject.\n\n\n\n8.2 Communication\n\nEuroPilot Center has established an effective communication system regarding safety related matters that:\nensures that all personnel is aware of safety management activities as appropriate to their safety responsibilities;\nconveys safety critical information, especially related to assessed risks and analyzed hazards;\nexplains why particular actions are taken; and\nexplains why safety procedures are introduced or changed.\n\nCommunication also reinforces the commitment of everyone to report hazards and occurrences and provides feedback to the reporters (an essential condition for sustained reporting).\n\nRegular meetings are organized with the personnel to communicate safety matters and discuss information, actions and procedures.\n\nCommunication is kept simple and appropriate to maximize effect, involve all personnel, and reinforce personal and team commitment to safety.\n\nCommunication is open. It encourages discussion, develops EuroPilot Center’s safety culture and makes the most of the lessons learned from running the SMS.\n\nDifferent communication means can be used:\nSafety meetings;\nSafety briefings;\nSafety Notes via e-mail;\nSafety campaigns, safety posters;\nThe Yearly Safety Bulletin;\nFlight safety digests, digest of accidents and incidents (appropriately de-identified), from within and outside EuroPilot Center;\nDigest of safety studies, audit reports, survey reports, and safety reviews;\nCompany forum(s) or professional networks (e.g. LinkedIn, Facebook, Twitter, etc.);\nSubscription to publications and journals.\n\n\n\n8.3 Safety Committee Airport Meetings\n\nEuroPilot Center is invited at both training locations for Safety Committee Airport Meetings.\nWhen informed by the local Airport Authorities that a Safety Meeting will be held, the SM is the first in line to attend the meeting, followed by the CMM, HT and AM.\nIf no in-person attendance is possible, the e-mail sent by the local Airport Authorities, containing the Safety Meeting Agenda and Minutes, will be used by the SM to execute the following process, consisting of 4 phases:\n\nPHASE 1 – Preparing for the Safety Committee Airport Meeting\nPHASE 2 – Attending the Meeting and Meeting Minutes\nPHASE 3 – Action Planning\nPHASE 4 – Closing\n\n8.3.1 Phase 1 – Preparing for the Safety Committee Airport Meeting\n• The Safety Manager receives an invite for a Safety Committee Airport Meeting via e-mail.\n• He/she logs into PipeDrive and Click on “Projects”.\n• From the Dropdown list on the right, select the “SM - Safety Committee Airport Meeting”\n-Project.\n• Click on “plus symbol” located inside the first Phase of the Project (or the Green “+ Project”\nbutton on the left).\n• Select the “Safety Committee Airport Meeting” Template.\n• Name the Project as per following convention: “Safety Committee Airport Meeting ICAO IDENT:\nMM/YYYY” (e.g. Safety Committee Airport Meeting EBAW: 02/2023”)\n• Enter “Start Date” (Should be the scheduled day of the Safety Meeting).\n• Enter “End Date” (Should be the scheduled day of the Safety Meeting + 90 days).\n• Select Label” In Progress”\n• Perform the checklist items under the “PLAN” section of the Project.\n• Link the e-mail received from the Airport Authorities to the Project by opening the e-mail in\nPipeDrive, on the right, enter the Project Name in the textfield underneath the “Link to a deal/\nlead/project” -box.\n• If relevant for the Meeting, the SM can upload documents via the “FILES” section of the Project.\n• The SM should briefly analyse the received “Agenda” of the Meeting and use the “NOTES”\nSection of the Project to provide comments or questions to ask during the meeting.\n• If the SM cannot attend the Meeting, he/she sends an invite to the CMM, HT and AM including\nthe Meeting “Agenda” and his/her notes. I no person can attend the meeting, proceed to\nPhase 2.\n\n8.3.2 Phase 2 – Attending the Meeting and Meeting Minutes\n\n• The person attending the meeting should open the Project section in Pipedrive in order to\nobtain all the data collected during Phase 1 and move the Project to Phase 2.\n• If no person was able to attend the meeting, the SM moves the Project to Phase 2.\n• During the Meeting (if attended), notes should be updated via the “NOTES” section of the\nProject.\n• After the meeting has been held, the Safety Committee Airport Meeting Minutes are received\nvia e-mail, usually in a PDF format.\n• The Safety Manager is in charge of Linking the e-mail received from the Airport Authorities\ncontaining the Meeting Minutes to the Project by opening the e-mail in PipeDrive, on the right,\nenter the Project Name in the textfield underneath the “Link to a deal/lead/project” -box.\n• The Safety Manager shall upload the PDF file via the “FILES” section of the Project.\n\n8.3.3 Phase 3 – Action Planning\n\n• The SM will be in charge.\n• Go to the Project section in Pipedrive.\n• Move the Project to Phase 3.\n• Analyse the content of the meeting minutes and evaluate if the organization is affected.\n• Execute the PLAN Checklist for this Phase.\n• Create an Action Plan via the “PLAN” Section.\n• Select a “TASK” for each Action Item requiring a Task to be fulfilled, add sub-tasks if required.\n• Allocate the “TASK” to the responsible person within the organization and add a due-date.\n• Only select “ACTIVITY” when a certain Action requires a Calendar event such as a Meeting etc.\n• Once the Action Plan is prepared under the PLAN section, the SM sends the e-mail to the CMM,\nHT and AM.\nIMPORTANT! A Safety Committee Airport Meeting may trigger a “Change Request” handled by the\nSafety Manager, hence may initiate a Management of Change Procedure.\n8.3.4 PHASE 4 – Closing\n• The SM will be in charge.\n• Based on the deadlines for each Action item, the SM shall follow-up with the person to whom\nthe Task was allocated. Pipedrive will generate automatic triggers if required.\n• The SM ensures all Task Items are closed and “archives” the Project.', NULL, NULL, 'OMM_P3_8');
