(6, 6, 'OM6.0|P0|2|1', 'OM REV 6.0', 'BCAA', 'ORA.GEN.210', 'Operations Manual (OM)', 'PART 0', 2, 1, 'Approval page', 'The approval page must be signed by the Accountable Manager (AM) and the Compliance Monitoring Manager (CMM).  ', 'Part 0 – Ch. 0.1', 'Yes', NULL),
(7, 7, 'OM6.0|P0|3|1', 'OM REV 6.0', 'BCAA', 'AMC1 ORA.ATO.230(b)', 'Operations Manual (OM)', 'PART 0', 3, 1, 'Distribution list', 'Gives a cross reference of who is in possession of which copy number of the manual.', 'Part 0 – Ch. 0.4', 'Yes', NULL),
(8, 8, 'OM6.0|P0|4|1', 'OM REV 6.0', 'BCAA', 'AMC1 ORA.ATO.230(b)', 'Operations Manual (OM)', 'PART 0', 4, 1, 'Record of revision', 'Gives all the revisions issued for this manual, their revision date and an abstract of the changes performed for each revision.', 'Part 0 – Ch. 0.3', 'Yes', 'Revision 6 added  INSERT INTO `mccf_requirements_omm4_backup` (`id`, `mccf_row_id`, `manual_code`, `requirement_key`, `mccf_id`, `authority`, `regulation_ref`, `manual_type`, `manual_part`, `item_no`, `sub_item_no`, `subject`, `requirement_text`, `manual_section_ref`, `excerpt_id`, `applicable`, `remarks`, `finding_ref`) VALUES
