(3, 106, 'OMM', 'OMM4.0|P0|1|3', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.GEN.200(a)(5); GM1 ORA.GEN.200(a)(5); ORA.GEN.200(a)(5)', 'Organization Management Manual (OMM)', 'PART 0', '1', '3', 'Title page', 'Date of revision', '0.1', NULL, 'Yes', NULL, NULL),
(4, 107, 'OMM', 'OMM4.0|P0|1|4', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.GEN.200(a)(5); GM1 ORA.GEN.200(a)(5); ORA.GEN.200(a)(5)', 'Organization Management Manual (OMM)', 'PART 0', '1', '4', 'Title page', 'Revision number. The first issue shall be notified as “Original” or 1.0. The following revision shall be notified as “2.0,3.0,…”.', '0.1', NULL, 'Yes', NULL, NULL),
