);

DROP TABLE IF EXISTS `audit_documents`;
CREATE TABLE "audit_documents" (
  "id" int NOT NULL,
  "audit_id" binary(16) NOT NULL,
  "doc_type" enum('AUTHORITY_EMAIL','PLAN','MINUTES','OTHER') NOT NULL,
