(96, 'OM', 'OM6.0|P4|42|2', 'OM REV 6.0', 'BCAA', 'AMC1 ORA.ATO.230(b)(d)(4)', 'Operations Manual (OM)', 'PART 4', '42', '2', 'Standardisation training.', 'When will the standardisation training be organised?', 'Part 4 – Ch. 4.1', NULL, 'Yes', NULL, NULL),
(97, 'OM', 'OM6.0|P4|42|3', 'OM REV 6.0', 'BCAA', 'AMC1 ORA.ATO.230(b)(d)(4)', 'Operations Manual (OM)', 'PART 4', '42', '3', 'Standardisation training.', 'Forms to be used to report the standardisation training. The forms assessing the standardisation training can be based on the BCAA documents “FI Standardisation Certificate – DOC/L-TRA-0153-53E” and “TKI Standardisation Certificate – DOC/L-TRA-0153-54E”.\nStandardisation training is to prevent deviation from ATO SOPs or ATO training manuals.', 'Part 4 – Ch. 4.1', NULL, 'Yes', NULL, NULL),
(98, 'OM', 'OM6.0|P4|43|1', 'OM REV 6.0', 'BCAA', 'AMC1 ORA.ATO.230(b)(d)(5)', 'Operations Manual (OM)', 'PART 4', '43', '1', 'Proficiency checks.', 'Describe for each type of training the content of a proficiency check that a FI or a TKI must perform.\nThis proficiency check is not about the ratings of the FIs but the proficiency towards the ATO standards. This check must be developed in order to remain certain of the standardisation among the training staff.', 'Part 4 – Ch. 5', NULL, 'Yes', NULL, NULL),
(99, 'OM', 'OM6.0|P4|43|2', 'OM REV 6.0', 'BCAA', 'AMC1 ORA.ATO.230(b)(d)(5)', 'Operations Manual (OM)', 'PART 4', '43', '2', 'Proficiency checks.', 'Define the criteria for this evaluation, define the key elements that must be evaluated (skill, behaviour, pedagogy,…).', 'Part 4 – Ch. 5', NULL, 'Yes', NULL, NULL),
(100, 'OM', 'OM6.0|P4|43|3', 'OM REV 6.0', 'BCAA', 'AMC1 ORA.ATO.230(b)(d)(5)', 'Operations Manual (OM)', 'PART 4', '43', '3', 'Proficiency checks.', 'When will the proficiency checks be organised?', 'Part 4 – Ch. 5', NULL, 'Yes', NULL, NULL),
(101, 'OM', 'OM6.0|P4|43|4', 'OM REV 6.0', 'BCAA', 'AMC1 ORA.ATO.230(b)(d)(5)', 'Operations Manual (OM)', 'PART 4', '43', '4', 'Proficiency checks.', 'Forms to be used to report the proficiency check.', 'Part 4 – Ch. 5', NULL, 'Yes', NULL, NULL),
(102, 'OM', 'OM6.0|P4|44|1', 'OM REV 6.0', 'BCAA', 'AMC1 ORA.ATO.230(b)(d)(6)', 'Operations Manual (OM)', 'PART 4', '44', '1', 'Upgrading training.', 'Define the training plan and content for a FI or TKI that is promoted to give instruction in a higher phase of the training or in another branch of the theoretical knowledge instruction/long briefing.\nA certificate, signed by the applicant and countersigned by the HT, must be delivered at the end of the upgrading training course.', 'Part 4 – Ch. 6', NULL, 'Yes', NULL, NULL),
(103, 'OM', 'OM6.0|P4|45|1', 'OM REV 6.0', 'BCAA', 'AMC1 ORA.ATO.230(b)(d)(7)', 'Operations Manual (OM)', 'PART 4', '45', '1', 'ATO personnel standards evaluation.', 'Define the procedure to evaluate ATO personnel standards.\nThis evaluation should be composed of proficiency checks and standardisation trainings.', 'Part 4 – Ch. 7', NULL, 'Yes', NULL, NULL),
(104, 'OMM', 'OMM4.0|P0|1|1', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.GEN.200(a)(5); GM1 ORA.GEN.200(a)(5); ORA.GEN.200(a)(5)', 'Organization Management Manual (OMM)', 'PART 0', '1', '1', 'Title page', 'Title of the manual', 'Header', NULL, 'Yes', NULL, NULL),
(105, 'OMM', 'OMM4.0|P0|1|2', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.GEN.200(a)(5); GM1 ORA.GEN.200(a)(5); ORA.GEN.200(a)(5)', 'Organization Management Manual (OMM)', 'PART 0', '1', '2', 'Title page', 'A unique reference of the manual', 'Header', NULL, 'Yes', NULL, NULL),
(106, 'OMM', 'OMM4.0|P0|1|3', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.GEN.200(a)(5); GM1 ORA.GEN.200(a)(5); ORA.GEN.200(a)(5)', 'Organization Management Manual (OMM)', 'PART 0', '1', '3', 'Title page', 'Date of revision', '0.1', NULL, 'Yes', NULL, NULL),
(107, 'OMM', 'OMM4.0|P0|1|4', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.GEN.200(a)(5); GM1 ORA.GEN.200(a)(5); ORA.GEN.200(a)(5)', 'Organization Management Manual (OMM)', 'PART 0', '1', '4', 'Title page', 'Revision number. The first issue shall be notified as “Original” or 1.0. The following revision shall be notified as “2.0,3.0,…”.', '0.1', NULL, 'Yes', NULL, NULL),
(108, 'OMM', 'OMM4.0|P0|1|5', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.GEN.200(a)(5); GM1 ORA.GEN.200(a)(5); ORA.GEN.200(a)(5)', 'Organization Management Manual (OMM)', 'PART 0', '1', '5', 'Title page', 'Copy number', '0.4', NULL, 'Yes', NULL, NULL),
(109, 'OMM', 'OMM4.0|P0|2|1', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.GEN.200(a)(6); ORA.GEN.200(a)(6); ORA.GEN.210', 'Organization Management Manual (OMM)', 'PART 0', '2', '1', 'Approval page', 'The approval page must be signed by the Accountable Manager (AM) and the Compliance Monitoring Manager (CMM).  ', '0.1', NULL, 'Yes', NULL, NULL),
(110, 'OMM', 'OMM4.0|P0|3|1', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.GEN.200(a)(5); GM1 ORA.GEN.200(a)(5); ORA.GEN.200(a)(5)', 'Organization Management Manual (OMM)', 'PART 0', '3', '1', 'Distribution list', 'Gives a cross reference of who is in possession of which copy number of the manual.', '0.4', NULL, 'Yes', NULL, NULL),
(111, 'OMM', 'OMM4.0|P0|4|1', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.GEN.200(a)(5); GM1 ORA.GEN.200(a)(5); ORA.GEN.200(a)(5)', 'Organization Management Manual (OMM)', 'PART 0', '4', '1', 'Record of revision', 'Gives all the revisions issued for this manual, their revision date and an abstract of the changes performed for each revision.', '0.3', NULL, 'Yes', 'Updated, Revision 4 added including a detail of all changes.', NULL),
(112, 'OMM', 'OMM4.0|P0|5|1', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.GEN.200(a)(5); GM1 ORA.GEN.200(a)(5); ORA.GEN.200(a)(5)', 'Organization Management Manual (OMM)', 'PART 0', '5', '1', 'Revision Procedure', 'The procedure to follow to revise this manual.', '0.2', NULL, 'Yes', NULL, NULL),
(113, 'OMM', 'OMM4.0|P0|5|2', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.GEN.130; GM1 ORA.GEN.130(a); ORA.GEN.130', 'Organization Management Manual (OMM)', 'PART 0', '5', '2', 'Revision Procedure', 'By who and how amendment can be proposed.', '0.2', NULL, 'Yes', NULL, NULL),
(114, 'OMM', 'OMM4.0|P0|5|3', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.GEN.200(a)(5); GM1 ORA.GEN.200(a)(5); ORA.GEN.200(a)(5)', 'Organization Management Manual (OMM)', 'PART 0', '5', '3', 'Revision Procedure', 'Who is in charge to include the revision in the manual when it has been approved by the BCAA.', '0.2', NULL, 'Yes', NULL, NULL),
(115, 'OMM', 'OMM4.0|P0|6|1', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.GEN.200(a)(5); GM1 ORA.GEN.200(a)(5); ORA.GEN.200(a)(5)', 'Organization Management Manual (OMM)', 'PART 0', '6', '1', 'Temporary revisions', 'What is the procedure to implement a temporary revision.', '', NULL, 'No', NULL, NULL),
(116, 'OMM', 'OMM4.0|P0|6|2', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.GEN.200(a)(5); GM1 ORA.GEN.200(a)(5); ORA.GEN.200(a)(5)', 'Organization Management Manual (OMM)', 'PART 0', '6', '2', 'Temporary revisions', 'By who and how a temporary revision can be proposed.', '', NULL, 'No', NULL, NULL),
(117, 'OMM', 'OMM4.0|P0|7|1', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.GEN.200(a)(6); ORA.GEN.200(a)(6)', 'Organization Management Manual (OMM)', 'PART 0', '7', '1', 'Record of temporary revisions', 'Gives all the temporary revisions issued for this manual, their issue date and an abstract of the changes implemented by the temporary revision.\nThis page must be signed by the compliance monitoring manager.', '', NULL, 'No', NULL, NULL),
(118, 'OMM', 'OMM4.0|P1|8|1', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.105', 'Organization Management Manual (OMM)', 'PART 1', '8', '1', 'General Information\nORA.GEN.105', 'Name of the ATO', 'Part 1, Chapter 1', NULL, 'Yes', NULL, NULL),
(119, 'OMM', 'OMM4.0|P1|8|2', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.105', 'Organization Management Manual (OMM)', 'PART 1', '8', '2', 'General Information\nORA.GEN.105', 'Principle place of business (trading address):\nAddress;\nPhone;\nFax;\nGeneral email address.', 'Part 1, Chapter 1', NULL, 'Yes', NULL, NULL),
(120, 'OMM', 'OMM4.0|P1|8|3', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.105', 'Organization Management Manual (OMM)', 'PART 1', '8', '3', 'General Information\nORA.GEN.105', 'Alternate place(s) of business:\nAddress;\nPhone;\nFax;\nGeneral email address;\nName of the site manager.\nThe BCAA shall have access to any alternate place of business of the ATO.\nIf abroad, the travel expenses shall be covered to the ATO as defined in the BCAA travel policy.', 'Part 1, Chapter 1', NULL, 'Yes', 'Updated with additional information on the location of the Hangars. (No new address).\nAlso added an additional phone number. Site manager is described as the Deputy HT, Mr. Jasper De Hertog.', NULL),
(121, 'OMM', 'OMM4.0|P1|9|1', 'OMM REV 4.0', 'BCAA', 'ORA.ATO.100; ORA.ATO.105; ORA.ATO.110; ORA.ATO.125; ORA.ATO.130; ORA.ATO.230; ORA.GEN.135', 'Organization Management Manual (OMM)', 'PART 1', '9', '1', 'Legal status of the organisation', 'Name of the legal entity detaining the ATO certificate.', 'Part 1, Chapter 1', NULL, 'Yes', NULL, NULL),
(122, 'OMM', 'OMM4.0|P1|9|2', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.GEN.200(a)(5); GM1 ORA.GEN.200(a)(5); ORA.GEN.200(a)(5)', 'Organization Management Manual (OMM)', 'PART 1', '9', '2', 'Legal status of the organisation', 'Legal status (SA/NV, SPRL/BVBA, ASBL/VZW,…).', 'Part 1, Chapter 2, OMM Annexes 12 and 13', NULL, 'Yes', 'Added details on resignation of Manager + reference made to OMM Annex 25 – Manager Resignation.', NULL),
(123, 'OMM', 'OMM4.0|P1|9|3', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.GEN.200(a)(5); GM1 ORA.GEN.200(a)(5); ORA.GEN.200(a)(5)', 'Organization Management Manual (OMM)', 'PART 1', '9', '3', 'Legal status of the organisation', 'BCE/KBO number.', 'Part 1, Chapter 2, OMM Annexes 12 and 13', NULL, 'Yes', NULL, NULL),
(124, 'OMM', 'OMM4.0|P1|9|4', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.GEN.200(a)(5); GM1 ORA.GEN.200(a)(5); ORA.GEN.200(a)(5)', 'Organization Management Manual (OMM)', 'PART 1', '9', '4', 'Legal status of the organisation', 'Address of the legal entity.', 'Chapter 1', NULL, 'Yes', NULL, NULL),
(125, 'OMM', 'OMM4.0|P1|10|1', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.125', 'Organization Management Manual (OMM)', 'PART 1', '10', '1', 'Training courses offered.\nORA.GEN.125', 'List all the training courses offered by the organisation (theoretical and practical). The ATO shall notify the BCAA by email on BCAA.ATO@mobilit.fgov.be when a course will begin and the name of the candidates enrolled in the course.', 'Part 1, Chapter 3 ', NULL, 'Yes', 'Updated the list in accordance with the current ATO Approvals. Corrected the naming of the courses in order to be identical to the ATO Certificate.', NULL),
(126, 'OMM', 'OMM4.0|P1|11|1', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.200', 'Organization Management Manual (OMM)', 'PART 1', '11', '1', 'Organisation chart.\nORA.GEN.200', 'An organisation chart providing the relationships between the nominated persons (AM, HT, CFI, CTKI, CMM and SM) their assistants/deputies, the compliance auditors and the rest of the staff.', 'Part 1, Chapter 4', NULL, 'Yes', 'Reference made to OM Part 1, chapter 2.1.3 (which refers to Annex 35 – Organogram, UPDATED)', NULL),
(127, 'OMM', 'OMM4.0|P1|12|1', 'OMM REV 4.0', 'BCAA', 'ORA.ATO.210; ORA.GEN.210', 'Organization Management Manual (OMM)', 'PART 1', '12', '1', 'Management Staff.\nORA.GEN.210\nORA.ATO.210', 'Accountable manager. Provide the following information for each ATO nominated persons:\nContact information (Name, phone, mobile, email, full time/part time);\nRequired qualifications and/or training;\nResponsibilities. \nSee the BCAA procedure “Accept a nominated person of an ATO – LA/L-TRA/0152” for further information on nominated person approval.\nDefine also their responsibilities or give the reference of OM item 10.\nSee document L-TRA/0152-71 for the minimum applicable responsibilities of each nominated persons.', 'Ref. OM Part 1, Chapter 2.1.1', NULL, 'Yes', NULL, NULL),
(128, 'OMM', 'OMM4.0|P1|12|2', 'OMM REV 4.0', 'BCAA', 'ORA.ATO.210; ORA.GEN.210', 'Organization Management Manual (OMM)', 'PART 1', '12', '2', 'Management Staff.\nORA.GEN.210\nORA.ATO.210', 'Head of Training. Provide the following information for each ATO nominated persons:\nContact information (Name, phone, mobile, email, full time/part time);\nRequired qualifications and/or training;\nResponsibilities. \nSee the BCAA procedure “Accept a nominated person of an ATO – LA/L-TRA/0152” for further information on nominated person approval.\nDefine also their responsibilities or give the reference of OM item 10.\nSee document L-TRA/0152-71 for the minimum applicable responsibilities of each nominated persons.', 'Ref. OM Part 1, Chapter 2.1.1', NULL, 'Yes', NULL, NULL),
(129, 'OMM', 'OMM4.0|P1|12|3', 'OMM REV 4.0', 'BCAA', 'ORA.ATO.210; ORA.GEN.210', 'Organization Management Manual (OMM)', 'PART 1', '12', '3', 'Management Staff.\nORA.GEN.210\nORA.ATO.210', 'Chief Flight Instructor. Provide the following information for each ATO nominated persons:\nContact information (Name, phone, mobile, email, full time/part time);\nRequired qualifications and/or training;\nResponsibilities. \nSee the BCAA procedure “Accept a nominated person of an ATO – LA/L-TRA/0152” for further information on nominated person approval.\nDefine also their responsibilities or give the reference of OM item 10.\nSee document L-TRA/0152-71 for the minimum applicable responsibilities of each nominated persons.', 'Ref. OM Part 1, Chapter 2.1.1', NULL, 'Yes', NULL, NULL),
(130, 'OMM', 'OMM4.0|P1|12|4', 'OMM REV 4.0', 'BCAA', 'ORA.ATO.210; ORA.GEN.210', 'Organization Management Manual (OMM)', 'PART 1', '12', '4', 'Management Staff.\nORA.GEN.210\nORA.ATO.210', 'Chief theoretical knowledge Instructor. Provide the following information for each ATO nominated persons:\nContact information (Name, phone, mobile, email, full time/part time);\nRequired qualifications and/or training;\nResponsibilities. \nSee the BCAA procedure “Accept a nominated person of an ATO – LA/L-TRA/0152” for further information on nominated person approval.\nDefine also their responsibilities or give the reference of OM item 10.\nSee document L-TRA/0152-71 for the minimum applicable responsibilities of each nominated persons.', 'Ref. OM Part 1, Chapter 2.1.1', NULL, 'Yes', NULL, NULL),
(131, 'OMM', 'OMM4.0|P1|12|5', 'OMM REV 4.0', 'BCAA', 'ORA.ATO.210; ORA.GEN.210', 'Organization Management Manual (OMM)', 'PART 1', '12', '5', 'Management Staff.\nORA.GEN.210\nORA.ATO.210', 'Safety manager. Provide the following information for each ATO nominated persons:\nContact information (Name, phone, mobile, email, full time/part time);\nRequired qualifications and/or training;\nResponsibilities. \nSee the BCAA procedure “Accept a nominated person of an ATO – LA/L-TRA/0152” for further information on nominated person approval.\nDefine also their responsibilities or give the reference of OM item 10.\nSee document L-TRA/0152-71 for the minimum applicable responsibilities of each nominated persons.', 'Ref. OM Part 1, Chapter 2.1.1', NULL, 'Yes', NULL, NULL),
(132, 'OMM', 'OMM4.0|P1|12|6', 'OMM REV 4.0', 'BCAA', 'ORA.ATO.210; ORA.GEN.210', 'Organization Management Manual (OMM)', 'PART 1', '12', '6', 'Management Staff.\nORA.GEN.210\nORA.ATO.210', 'Compliance monitoring manager. Provide the following information for each ATO nominated persons:\nContact information (Name, phone, mobile, email, full time/part time);\nRequired qualifications and/or training;\nResponsibilities. \nSee the BCAA procedure “Accept a nominated person of an ATO – LA/L-TRA/0152” for further information on nominated person approval.\nDefine also their responsibilities or give the reference of OM item 10.\nSee document L-TRA/0152-71 for the minimum applicable responsibilities of each nominated persons.', 'Ref. OM Part 1, Chapter 2.1.1', NULL, 'Yes', NULL, NULL),
(133, 'OMM', 'OMM4.0|P1|13|1', 'OMM REV 4.0', 'BCAA', 'ORA.ATO.210; ORA.GEN.210', 'Organization Management Manual (OMM)', 'PART 1', '13', '1', 'Instruction staff.\nORA.GEN.210\nORA.ATO.210', 'Theoretical knowledge instructors:\nName, surname;\nAssigned ground training courses;\nAssigned branches;\nFull time/part time.\nRefer to the BCAA procedure “Modify a FI/TKI list – LA/L-TRA/0153” for further information. The theoretical knowledge instructors list should ideally be presented as a table and put in annex of the OMM (i.e. Annex A: TKI list) so it can be modified without affecting the manual revision. The table should be based on the official BCAA document “ATO FI List – DOC/L-TRA-0153-52E”.', 'Part 1, Chapter 6 with references to OMM Annex 15 – TKI’s.\nAlso includes reference to OMM Chapter 16, changes not requiring prior approval procedure.', NULL, 'Yes', 'Annex 15 – TKI’s has been updated.\n\nAlso the procedure under Part 1, Chapter 16 has been updated in accordance with the actual regulations.', NULL),
(134, 'OMM', 'OMM4.0|P1|13|2', 'OMM REV 4.0', 'BCAA', 'ORA.ATO.210; ORA.GEN.210', 'Organization Management Manual (OMM)', 'PART 1', '13', '2', 'Instruction staff.\nORA.GEN.210\nORA.ATO.210', 'Flight instructors:\nName, Surname;\nLicence number;\nRatings / Authorisations;\nAssigned flight training courses;\nFull time/part time.\nRefer to the BCAA procedure “Modify a FI/TKI list  – LA/L-TRA/0153” for further information. The flight instructors list should ideally be presented as a table and put in annex of the OMM (i.e. Annex B: FI list) so it can be modified without affecting the manual revision. The table should be based on the official BCAA document “ATO TKI List – DOC/L-TRA-0153-51E”.', 'Part 1, Chapter 6 with references to OMM Annex 16, Flight Instructors.\nAlso includes reference to OMM Chapter 16, changes not requiring prior approval procedure.', NULL, 'Yes', 'Annex 16 – Flight Instructors has been updated.\n\nAlso the procedure under Part 1, Chapter 16 has been updated in accordance with the actual regulations.', NULL),
(135, 'OMM', 'OMM4.0|P1|14|1', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.210', 'Organization Management Manual (OMM)', 'PART 1', '14', '1', 'Administrative staff.\nORA.GEN.210', 'Name, Surname\nFunction and function description.\nFull time/part time', 'Part 1, Chapter 7 with reference to OMM Annex 17, Administrative Staff', NULL, 'Yes', 'Annex updated, no admin staff, however, based on workload analysis, in the process of hiring a Chief Operations Officer.', NULL),
(136, 'OMM', 'OMM4.0|P1|15|1', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.ATO.140; ORA.ATO.140', 'Organization Management Manual (OMM)', 'PART 1', '15', '1', 'Aerodrome(s)/Operating site(s) to be used.\nORA.ATO.140\n', 'List all the aerodromes that will be used for the training and for which type of training (Airwork, stalls and spins, T/G, night T/G, SID, ILS, holdings, hovering, slope landing, confined area, …) and how it complies with requirements laid down in AMC1 ORA.ATO.140.', 'Part 1, Chapter 8, Reference made to the OM Part 3, Training Areas and the Applicable TN for that particular Course. ', NULL, 'Yes', NULL, NULL),
(137, 'OMM', 'OMM4.0|P1|15|2', 'OMM REV 4.0', 'BCAA', 'ORA.ATO.140', 'Organization Management Manual (OMM)', 'PART 1', '15', '2', 'Aerodrome(s)/Operating site(s) to be used.\nORA.ATO.140\n', 'ATC or any other acceptable means of air to ground communication available.', 'Part 1, Chapter 8, Reference made to the OM Part 3, Training Areas and the Applicable TN for that particular Course. ', NULL, 'Yes', NULL, NULL),
(138, 'OMM', 'OMM4.0|P1|15|3', 'OMM REV 4.0', 'BCAA', 'ORA.ATO.140', 'Organization Management Manual (OMM)', 'PART 1', '15', '3', 'Aerodrome(s)/Operating site(s) to be used.\nORA.ATO.140\n', 'Describe facilities of each aerodrome (VOR, DME, ILS, ATC, Night flying) or refer to the concerned AIP.', 'Part 1, Chapter 8, Reference made to the OM Part 3, Training Areas and the Applicable TN for that particular Course. ', NULL, 'Yes', NULL, NULL),
(139, 'OMM', 'OMM4.0|P1|16|1', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.GEN.215; AMC2 ORA.GEN.215); ORA.GEN.215; ORA.GEN.215)', 'Organization Management Manual (OMM)', 'PART 1', '16', '1', 'Flight operations accommodation.\nORA.GEN.215', 'Per training site, provide a plan of the premises and describe the means to fulfil the following requirements (See AMC1 ORA.GEN.215 and AMC2 ORA.GEN.215):Operations room with facilities to control flying operations.', '', NULL, 'Yes', NULL, NULL),
(140, 'OMM', 'OMM4.0|P1|16|2', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.GEN.215; AMC2 ORA.GEN.215); ORA.GEN.215; ORA.GEN.215)', 'Organization Management Manual (OMM)', 'PART 1', '16', '2', 'Flight operations accommodation.\nORA.GEN.215', 'Per training site, provide a plan of the premises and describe the means to fulfil the following requirements (See AMC1 ORA.GEN.215 and AMC2 ORA.GEN.215): Flight planning room with the following facilities:\nAppropriate current maps and charts;', 'Part 1, Chapter 9, Annexes 18 and 19', NULL, 'Yes', 'Updated OMM Annex 18 and 19', NULL),
(141, 'OMM', 'OMM4.0|P1|16|3', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.GEN.215; AMC2 ORA.GEN.215); ORA.GEN.215; ORA.GEN.215)', 'Organization Management Manual (OMM)', 'PART 1', '16', '3', 'Flight operations accommodation.\nORA.GEN.215', 'Per training site, provide a plan of the premises and describe the means to fulfil the following requirements (See AMC1 ORA.GEN.215 and AMC2 ORA.GEN.215):Current aeronautical information service (AIS) information ;', 'Part 1, Chapter 9, Annexes 18 and 19', NULL, 'Yes', 'Updated OMM Annex 18 and 19', NULL),
(142, 'OMM', 'OMM4.0|P1|16|4', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.GEN.215; AMC2 ORA.GEN.215); ORA.GEN.215; ORA.GEN.215)', 'Organization Management Manual (OMM)', 'PART 1', '16', '4', 'Flight operations accommodation.\nORA.GEN.215', 'Per training site, provide a plan of the premises and describe the means to fulfil the following requirements (See AMC1 ORA.GEN.215 and AMC2 ORA.GEN.215):Current meteorological information;', 'Part 1, Chapter 9, Annexes 18 and 19', NULL, 'Yes', 'Updated OMM Annex 18 and 19', NULL),
(143, 'OMM', 'OMM4.0|P1|16|5', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.GEN.215; AMC2 ORA.GEN.215); ORA.GEN.215; ORA.GEN.215)', 'Organization Management Manual (OMM)', 'PART 1', '16', '5', 'Flight operations accommodation.\nORA.GEN.215', 'Per training site, provide a plan of the premises and describe the means to fulfil the following requirements (See AMC1 ORA.GEN.215 and AMC2 ORA.GEN.215):Communications to ATC and the operations room;', 'Part 1, Chapter 9, Annexes 18 and 19', NULL, 'Yes', NULL, NULL),
(144, 'OMM', 'OMM4.0|P1|16|6', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.GEN.215; AMC2 ORA.GEN.215); ORA.GEN.215; ORA.GEN.215)', 'Organization Management Manual (OMM)', 'PART 1', '16', '6', 'Flight operations accommodation.\nORA.GEN.215', 'Per training site, provide a plan of the premises and describe the means to fulfil the following requirements (See AMC1 ORA.GEN.215 and AMC2 ORA.GEN.215):Any other flight safety related material.', 'Part 1, Chapter 9, Annexes 18 and 19', NULL, 'Yes', 'Updated OMM Annex 18 and 19', NULL),
(145, 'OMM', 'OMM4.0|P1|16|7', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.GEN.215; AMC2 ORA.GEN.215); ORA.GEN.215; ORA.GEN.215)', 'Organization Management Manual (OMM)', 'PART 1', '16', '7', 'Flight operations accommodation.\nORA.GEN.215', 'Per training site, provide a plan of the premises and describe the means to fulfil the following requirements (See AMC1 ORA.GEN.215 and AMC2 ORA.GEN.215):Adequate briefing rooms/cubicles of sufficient size and number.', 'Part 1, Chapter 9, Annexes 18 and 19', NULL, 'Yes', 'Updated OMM Annex 18 and 19', NULL),
(146, 'OMM', 'OMM4.0|P1|16|8', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.GEN.215; AMC2 ORA.GEN.215); ORA.GEN.215; ORA.GEN.215)', 'Organization Management Manual (OMM)', 'PART 1', '16', '8', 'Flight operations accommodation.\nORA.GEN.215', 'Per training site, provide a plan of the premises and describe the means to fulfil the following requirements (See AMC1 ORA.GEN.215 and AMC2 ORA.GEN.215):Suitable offices for the supervisory staff and rooms to allow flying instructors  to write reports on student, complete records and other related documentation', 'Part 1, Chapter 9, Annexes 18 and 19', NULL, 'Yes', 'Updated OMM Annex 18 and 19', NULL),
(147, 'OMM', 'OMM4.0|P1|16|9', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.GEN.215; AMC2 ORA.GEN.215); ORA.GEN.215; ORA.GEN.215)', 'Organization Management Manual (OMM)', 'PART 1', '16', '9', 'Flight operations accommodation.\nORA.GEN.215', 'Per training site, provide a plan of the premises and describe the means to fulfil the following requirements (See AMC1 ORA.GEN.215 and AMC2 ORA.GEN.215):Furnished crew rooms for instructors and students.', 'Part 1, Chapter 9, Annexes 18 and 19', NULL, 'Yes', 'Updated OMM Annex 18 and 19', NULL),
(148, 'OMM', 'OMM4.0|P1|17|1', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.215', 'Organization Management Manual (OMM)', 'PART 1', '17', '1', 'Theoretical instruction facilities.\nORA.GEN.215', 'Per training site, provide a plan of the premises and describe the means to fulfil the following requirements:Adequate classroom accommodation for the current student population.', 'Part 1, Chapter 10, Annexes 18 and 19', NULL, 'Yes', 'Updated OMM Annex 18 and 19', NULL),
(149, 'OMM', 'OMM4.0|P1|17|2', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.215', 'Organization Management Manual (OMM)', 'PART 1', '17', '2', 'Theoretical instruction facilities.\nORA.GEN.215', 'Per training site, provide a plan of the premises and describe the means to fulfil the following requirements:Suitable demonstration equipment to support the theoretical knowledge instruction.', 'Part 1, Chapter 10, Annexes 18 and 19', NULL, 'Yes', 'Updated OMM Annex 18 and 19', NULL),
(150, 'OMM', 'OMM4.0|P1|17|3', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.215', 'Organization Management Manual (OMM)', 'PART 1', '17', '3', 'Theoretical instruction facilities.\nORA.GEN.215', 'Per training site, provide a plan of the premises and describe the means to fulfil the following requirements:An R/T training and testing facility.', 'Part 1, Chapter 10, Annexes 18 and 19 (use of FSTD/AATD)', NULL, 'Yes', 'Updated OMM Annex 18 and 19', NULL),
(151, 'OMM', 'OMM4.0|P1|17|4', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.215', 'Organization Management Manual (OMM)', 'PART 1', '17', '4', 'Theoretical instruction facilities.\nORA.GEN.215', 'Per training site, provide a plan of the premises and describe the means to fulfil the following requirements:A reference library containing publication giving coverage of the syllabus.', 'Part 1, Chapter 10, Annexes 18 and 19', NULL, 'Yes', 'Updated OMM Annex 18 and 19', NULL),
(152, 'OMM', 'OMM4.0|P1|17|5', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.215', 'Organization Management Manual (OMM)', 'PART 1', '17', '5', 'Theoretical instruction facilities.\nORA.GEN.215', 'Per training site, provide a plan of the premises and describe the means to fulfil the following requirements: Offices for the instructional staff.', 'Part 1, Chapter 10, Annexes 18 and 19', NULL, 'Yes', 'Updated OMM Annex 18 and 19', NULL),
(153, 'OMM', 'OMM4.0|P1|18|1', 'OMM REV 4.0', 'BCAA', 'ORA.ATO.135', 'Organization Management Manual (OMM)', 'PART 1', '18', '1', 'Description of training devices (as applicable).\nORA.ATO.135', 'List all FSTD that will be used by the ATO and for which courses.\nType of FSTD (FFS, FNPT I/II, BITD, etc…);\nFSTD identification;\nAircraft simulated including engine fits;\nLocation;\nOperator.\nRefer to the BCAA procedure “Modify ATO FSTD List – LA/L-TRA/0155” for further information. \nThe FSTD list should ideally be presented as a table and put in annex of the OMM (i.e. Annex C: FSTD list) so it can be modified without affecting the manual revision. The table should be based on the official BCAA document “ATO FSTD List – DOC/L-TRA-0155-51E”.', 'Part 1, Chapter 11, Annex 20 – EPC FSTD’s\n\nReference made to the procedure.', NULL, 'Yes', 'Updated Annex 20, showing all FSTD’s in use at EPC, Antwerp.\n\n', NULL),
(154, 'OMM', 'OMM4.0|P1|18|2', 'OMM REV 4.0', 'BCAA', 'ORA.ATO.135', 'Organization Management Manual (OMM)', 'PART 1', '18', '2', 'Description of training devices (as applicable).\nORA.ATO.135', 'Difference list between the FSTDs and aircrafts used in the ATO or the reference of the document providing that information.\nThe aircraft list should ideally be presented as a table and put in annex of the OMM (i.e. Annex D: A/C list) so it can be modified without affecting the manual revision. The table should be based on the official BCAA document “ATO Aircraft List – DOC/L-TRA-0154-51E”.', 'Reference is made to OMM Annex 24a (Difference List BE FNPT-014), OMM Annex 24b (Difference List BE FNPT-024) and OMM Annex  24c (Difference List BE FNPT-028)', NULL, 'Yes', 'Annex 24a, b and c updated and signed.', NULL),
(155, 'OMM', 'OMM4.0|P1|19|1', 'OMM REV 4.0', 'BCAA', 'ORA.ATO.135', 'Organization Management Manual (OMM)', 'PART 1', '19', '1', 'Description of aircraft.\nORA.ATO.135', 'List all the aircrafts that will be used by the ATO and for which courses.\nClass/type(s) of aircraft;\nRegistration of aircraft;\nIFR equipped;\nNight flying equipped.\nRefer to the BCAA procedure “Modify ATO Aircraft List – LA/L-TRA/0154” for further information. ', 'Part 1, Chapter 12, reference is made to OMM Annex 21 and the procedure OMM Chapter 16, changes not requiring prior approval of the BCAA.', NULL, 'Yes', 'OMM Annex 21 – Updated with the N641TH as per finding.\n\nAlso the procedure under Part 1, Chapter 16 has been updated in accordance with the actual regulations. ', NULL),
(156, 'OMM', 'OMM4.0|P1|20|1', 'OMM REV 4.0', 'BCAA', 'ORA.ATO.100; ORA.ATO.105; ORA.ATO.110; ORA.ATO.125; ORA.ATO.130; ORA.ATO.230', 'Organization Management Manual (OMM)', 'PART 1', '20', '1', 'Didactical material.', 'List of the reference manuals used for the training or provide a reference of the document mentioning that information. That information could be specified in each training manual. ', 'Part 1, Chapter 13, reference is made to each applicable Training Course.', NULL, 'Yes', NULL, NULL),
(157, 'OMM', 'OMM4.0|P1|20|2', 'OMM REV 4.0', 'BCAA', 'ORA.ATO.100; ORA.ATO.105; ORA.ATO.110; ORA.ATO.125; ORA.ATO.130; ORA.ATO.230', 'Organization Management Manual (OMM)', 'PART 1', '20', '2', 'Didactical material.', 'List and describe the computerized theoretical knowledge tools or provide a reference of the document mentioning that information. That information could be specified in each training manual.', 'Part 1, Chapter 13, reference is made to each applicable Training Course.', NULL, 'Yes', NULL, NULL),
(158, 'OMM', 'OMM4.0|P1|21|1', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.GEN.205; GM1 ORA.GEN.205); ORA.GEN.205; ORA.GEN.205)', 'Organization Management Manual (OMM)', 'PART 1', '21', '1', 'Contracted training.\nORA.GEN.205', 'Provide a list of the training or activity done by a third party. The contract/agreement between the ATO and the third party should be made available to the BCAA.\nSpecify if the third party is certified to do such training or if it will work under the approval of the ATO.  (See AMC1 ORA.GEN.205 and GM1 ORA.GEN.205).', 'Part 1, Chapter 14 describes the procedure in depth on how contracted activities should be handled.', NULL, 'Yes', 'A detailed procedure, as a result of the Audit Finding has been described on how a Management of Change Procedure should be triggered when considering a “change request for subcontracted activities”. Reference is also made in the notes on how subcontracted activities (if any) in the USA should be handled by the AM and CMM.', NULL),
(159, 'OMM', 'OMM4.0|P1|22|1', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.140', 'Organization Management Manual (OMM)', 'PART 1', '22', '1', 'Access.\nORA.GEN.140', 'Define who has access to the ATO premises and to which part of the building.', 'Part 1, Chapter 15.', NULL, 'Yes', NULL, NULL),
(160, 'OMM', 'OMM4.0|P1|22|2', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.140', 'Organization Management Manual (OMM)', 'PART 1', '22', '2', 'Access.\nORA.GEN.140', 'What are the means to prevent unwanted violation of critical part of the ATO (i.e. aircraft hangar, maintenance, student folders, etc).', 'Part 1, Chapter 15.', NULL, 'Yes', NULL, NULL),
(161, 'OMM', 'OMM4.0|P2A|23|1', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.200(a)(6); ORA.GEN.210', 'Organization Management Manual (OMM)', 'PART 2A', '23', '1', 'Compliance monitoring manager.\nORA.GEN.200(a)(6)\nORA.GEN.210', 'Who is the compliance monitoring manager.', 'Part 2, Chapter 3, reference is made to the OM Part 1, Chapter 2.1.2', NULL, 'Yes', 'OM Annex 35 – Organogram, UPDATED\n\nNote: CMM Training Certificates provided to the BCAA on 5/1/23.', NULL),
(162, 'OMM', 'OMM4.0|P2A|23|2', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.200(a)(6); ORA.GEN.210', 'Organization Management Manual (OMM)', 'PART 2A', '23', '2', 'Compliance monitoring manager.\nORA.GEN.200(a)(6)\nORA.GEN.210', 'What are his/her responsibilities. CMM must verify that standards are met and ensure that the compliance monitoring programme is established, implemented and maintained.\nIf the posts of CMM and AM are combined, provide the proof on how the independence of compliance audits will be assured.', 'Part 2, Chapter 3, reference is made to the OM Part 1, Chapter 2.1.2', NULL, 'Yes', NULL, NULL),
(163, 'OMM', 'OMM4.0|P2A|23|3', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.200(a)(6); ORA.GEN.210', 'Organization Management Manual (OMM)', 'PART 2A', '23', '3', 'Compliance monitoring manager.\nORA.GEN.200(a)(6)\nORA.GEN.210', 'Compliance policy statement. The compliance policy statement shall be signed by the accountable manager.', 'Part 2, Chapter 1', NULL, 'Yes', 'Policy updated and signed by the new AM.', NULL),
(164, 'OMM', 'OMM4.0|P2A|24|1', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.210', 'Organization Management Manual (OMM)', 'PART 2A', '24', '1', 'Compliance monitoring auditors (internal, external).\nORA.GEN.210', 'Define a list of the necessary internal or external auditors that have the privileges to perform compliance monitoring audits within the ATO.', 'Part 2, Chapter 3, reference is made to the OM Part 1, Chapter 2.1.2', NULL, 'Yes', 'OM Annex 35 – Organogram, UPDATED\n\nIn addition, OMM Annex 23 has been updated.\n', NULL),
(165, 'OMM', 'OMM4.0|P2A|24|2', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.210', 'Organization Management Manual (OMM)', 'PART 2A', '24', '2', 'Compliance monitoring auditors (internal, external).\nORA.GEN.210', 'How will the ATO assess their independence towards the areas they will be appointed to.', 'Part 2, Chapter 3.2 (bullet point item 3) and\nPart 2, Chapter 5.2, subchapter 5.2.1 + 5.2.2', NULL, 'Yes', NULL, NULL),
(166, 'OMM', 'OMM4.0|P2A|25|1', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.FSTD.100; AMC1 ORA.GEN.125; AMC1 ORA.GEN.200(a)(6); AMC1 ORA.GEN.215; ORA.ATO.100; ORA.ATO.105; ORA.ATO.110; ORA.ATO.125; ORA.ATO.130; ORA.ATO.230; ORA.FSTD.100; ORA.GEN.125; ORA.GEN.200(a)(6); ORA.GEN.215', 'Organization Management Manual (OMM)', 'PART 2A', '25', '1', 'Compliance monitoring programme.', 'Define the compliance monitoring programme for at least the following domains and their support documents:\nFacilities;\nFlight training;\nTheoretical knowledge training;\nCompliance with OSD, if applicable\nTechnical standards;\nTraining procedures;\nFlight safety;\nFlight and duty time limitations, rest requirements and scheduling;\nAircraft maintenance/operations interface;\nSubcontracted activities;\nFSTD specifications adequacy to the related programmes;\nFSTD compliance towards CS-FSTD;\nFSTD changes monitoring.\nThe compliance monitoring programme must check the scope of the ATO in full.', 'Part 2, Chapter 4.2 Inspection Scopes', NULL, 'Yes', 'Updated scope, added an additional item: Regulatory Changes (based on the Audit Finding), including a new column outlining which scope is applicable to which location (e.g US Satellite) and the frequency: e.g Regulatory Changes are verified on a Monthly Basis through a very detailed procedure, described in two new OMM Annexes:\nOMM Annex 26 – Regulatory Changes Notification and;\nOMM Annex 27 – Regulatory Changes Checklist', NULL),
(167, 'OMM', 'OMM4.0|P2A|26|1', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.GEN.200(a)(6); ORA.GEN.200(a)(6)', 'Organization Management Manual (OMM)', 'PART 2A', '26', '1', 'Compliance monitoring planning.', 'Define the compliance monitoring planning on a specific time basis or give the reference to the document/software providing that information. The planning must show when each domain of the compliance monitoring programme will be audited.\nAll domains must be audited within a 12 months period.', 'Part 2, Chapter 4.2 Inspection Scopes and also refer to OMM Annex 01 – Audit Plan', NULL, 'Yes', 'Updated OMM Annex 1 – Audit Plan with:\nItem 11. Regulatory Changes.', NULL),
(168, 'OMM', 'OMM4.0|P2A|26|2', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.GEN.200(a)(6); ORA.GEN.200(a)(6)', 'Organization Management Manual (OMM)', 'PART 2A', '26', '2', 'Compliance monitoring planning.', 'Management evaluations/reviews:\nPlanning of those management evaluations;\nWho must attend those management evaluations;\nForms on which those management evaluations are reported.', 'Part 2, Chapter 9 – Management Evaluation', NULL, 'Yes', NULL, NULL),
(169, 'OMM', 'OMM4.0|P2A|27|1', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.GEN.200(a)(6); ORA.GEN.200(a)(6)', 'Organization Management Manual (OMM)', 'PART 2A', '27', '1', 'Audit procedures.', 'Define or give the reference of the audit procedure. The procedure must define how an auditor must perform an audit and the forms to be used to record the audit.\nDefine the different levels of findings and the actions that must be undertaken.', 'Part 2, Chapter 5 Compliance Monitoring Audits and 5.1 Audit Procedure', NULL, 'Yes', NULL, NULL),
(170, 'OMM', 'OMM4.0|P2A|28|1', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.GEN.160; AMC1 ORA.GEN.200(a)(6); ORA.GEN.160; ORA.GEN.200(a)(6)', 'Organization Management Manual (OMM)', 'PART 2A', '28', '1', 'Reporting procedures.', 'Define or give the reference of the reporting procedures. The procedure must define how the audit report must be made (i.e. review of the report by the CMM), who will communicate the audit result, on which form.\nIt must also specified the classification system  of non-conformities.', 'Part 2, Chapter 5, Subchapter 5.1.3 - Reporting', NULL, 'Yes', NULL, NULL),
(171, 'OMM', 'OMM4.0|P2A|29|1', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.150', 'Organization Management Manual (OMM)', 'PART 2A', '29', '1', 'Follow up and corrective action procedures – Findings.\nORA.GEN.150', 'Define or give the reference of the follow up and corrective action procedure.\nThis procedure must be able to handle internal (ATO CMS findings) and external findings (any findings made by a third party).\nThis procedure must address the following:\nIdentification of corrective action;\nPerson responsible for rectification;\nFeedback system to the accountable manager providing an independent assessment of corrective action, implementation and completion;\nMonitoring of corrective action programme;\nEnsuring that the corrective action contain the necessary elements;\nEvaluation of the effectiveness of the corrective action programme;\nReporting of significant non-compliances to the competent authority.\nThis process must answer to at least the following questions:\nHow corrective action plan are decided, by who;\nWho is in charge to implement the corrective action;\nWho will assess the effective implementation of the corrective action;\nWho will evaluate if the corrective action has solved the non-conformity.', 'Part 2, Chapter 5:\nSubchapter 5.1.3 Reporting and 5.1.4 Follow Up of Corrective Actions', NULL, 'Yes', NULL, NULL),
(172, 'OMM', 'OMM4.0|P2A|30|1', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.220', 'Organization Management Manual (OMM)', 'PART 2A', '30', '1', 'Recording system.\nORA.GEN.220', 'How and on which form the compliance monitoring process will be recorded and stored.\nWho has access to it.\nThis can be any audit software or a simple Excel sheet providing the necessary information.\nThe records of the compliance monitoring programme shall be:\nAccurate;\nComplete;\nReadily accessible.', 'Part 2, Chapter 11.', NULL, 'Yes', NULL, NULL),
(173, 'OMM', 'OMM4.0|P2A|31|1', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.200(a)(4); ORA.GEN.210', 'Organization Management Manual (OMM)', 'PART 2A', '31', '1', 'Training on compliance monitoring system\nORA.GEN.210\nORA.GEN.200(a)(4)', 'Compliance auditors\nDefine the training that the compliance auditors must perform before being allowed to audit part of the scope of the ATO.\nWhen such training must be performed (initial training, recurrent training, refresher training).\nThe training of compliance auditor must cover at least the following topics:\nCompliance monitoring system procedures;\nATO manuals and document control procedures;\nATO OMM and OM procedures;\nAudit techniques, code of conduct of the compliance auditor (if needed);\nAudit reporting and recording;\nAny specific item related to a particular activity of the ATO.', 'Part 2, Chapter 7', NULL, 'Yes', NULL, NULL),
(174, 'OMM', 'OMM4.0|P2A|31|2', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.200(a)(4); ORA.GEN.210', 'Organization Management Manual (OMM)', 'PART 2A', '31', '2', 'Training on compliance monitoring system\nORA.GEN.210\nORA.GEN.200(a)(4)', 'Organisation personnel \nDefine the training that the organisation personnel must perform.\nWhen such training must be performed (initial training, recurrent training, refresher training).\nThe training of organisation personnel must cover at least the following topics:\nIntroduction to the concept of the CMS;\nOMM and OM procedures;\nAny specific item related to a particular activity of the ATO', 'Part 2, Chapter 10', NULL, 'Yes', NULL, NULL),
(175, 'OMM', 'OMM4.0|P2A|32|1', 'OMM REV 4.0', 'BCAA', 'GM1 ORA.GEN.130(a); GM2 ORA.GEN.130; ORA.GEN.130; ORA.GEN.130(a); ORA.GEN.130(a)(b)', 'Organization Management Manual (OMM)', 'PART 2A', '32', '1', 'Changes to organisations.\nORA.GEN.130(a)(b)', 'Define or give the reference to the procedure managing changes requiring prior approval.\nSee AMC1.ORA.GEN.130, GM1 ORA.GEN.130(a) and GM2 ORA.GEN.130 for further information.', 'Part 2, Chapter 2.4 ', NULL, 'Yes', 'Updated. Note has been added whereby the AM is required to send out a “Change Request” to the SM and CMM. We refer to the updated Management of Change Procedure in the OMM Part 3, Chapter 5.9.', NULL),
(176, 'OMM', 'OMM4.0|P2A|33|1', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.130(c)', 'Organization Management Manual (OMM)', 'PART 2A', '33', '1', 'Changes not requiring prior approval.\nORA.GEN.130(c)', 'Define or give the reference of all procedures managing changes not requiring prior approval from the BCAA.\nThe BCAA promote the following changes not requiring approval:\nFI/TKI ;\nFSTD;\nAircraft.\nAny other item might be proposed by the ATO.', 'Part 1, Chapter 16', NULL, 'Yes', 'Updated Chapter 16:\n16.1 Hiring new TKI’s\n16.2 Hiring new FI’s\n16.3 Adding/Removing Aircraft', NULL),
(177, 'OMM', 'OMM4.0|P2A|34|1', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.120', 'Organization Management Manual (OMM)', 'PART 2A', '34', '1', 'Alternative means of compliance (AltMOC).\nORA.GEN.120', 'Describe here if the ATO will use Alternative AMC (AltMOC).\nIf yes, describe or give the reference of the procedure that the ATO will use to assess the risk, demonstrate the equivalent level of safety, and propose the AMC to the BCAA.', 'Not Applicable', NULL, 'No', NULL, NULL),
(178, 'OMM', 'OMM4.0|P2A|34|2', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.120', 'Organization Management Manual (OMM)', 'PART 2A', '34', '2', 'Alternative means of compliance (AltMOC).\nORA.GEN.120', 'Give the reference of any AltMOC in use within the ATO.', 'Not Applicable', NULL, 'No', NULL, NULL),
(179, 'OMM', 'OMM4.0|P2A|35|1', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.GEN.220(b); ORA.ATO.120; ORA.GEN.220; ORA.GEN.220(b)', 'Organization Management Manual (OMM)', 'PART 2A', '35', '1', 'Record-keeping.\nORA.GEN.220\nORA.ATO.120', 'Define the record keeping means and procedures for any ATO documents. See AMC1 ORA.GEN.220(b) for further information.\nThis item is also covered by item 18 of the operations manual checklist. The manner how the ATO will comply with ORA.GEN.220/ORA.ATO.120 must be described in one of those two items.', 'Part 2, Chapter 11', NULL, 'Yes', NULL, NULL),
(180, 'OMM', 'OMM4.0|P2A|36|1', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.200(a)(5)', 'Organization Management Manual (OMM)', 'PART 2A', '36', '1', 'Documentation control procedure.\nORA.GEN.200(a)(5)', 'Define how ATO manuals and theoretical training courses manuals will be controlled throughout the organisation.', 'Described for each Manual under Chapter 0.2 Revisions System and OMM Part 2, Chapter 11.3', NULL, 'Yes', NULL, NULL),
(181, 'OMM', 'OMM4.0|P2A|36|2', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.200(a)(5)', 'Organization Management Manual (OMM)', 'PART 2A', '36', '2', 'Documentation control procedure.\nORA.GEN.200(a)(5)', 'Where are the ATO manuals stored and accessible to everyone involved in the organisation.', 'Described for each Manual under Chapter 0.2 Revisions System and OMM Part 2, Chapter 11.3', NULL, 'Yes', NULL, NULL),
(182, 'OMM', 'OMM4.0|P2B|11 B|2', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.FSTD.100; ORA.FSTD.100', 'Organization Management Manual (OMM)', 'PART 2B', '11 B', '2', 'FSTD Organisation chart.\nORA.GEN', 'An organisation chart providing the relationships between the personnel responsible to maintain the compliance of the FSTD.\nThe organisation chart can be the one of item 10 completed with relevant FSTD personnel.', 'OMM Part 2, Chapter 3, reference is made to the OM Part 1, Chapter 2.1.2', NULL, 'Yes', NULL, NULL),
(183, 'OMM', 'OMM4.0|P2B|12 B|7', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.210', 'Organization Management Manual (OMM)', 'PART 2B', '12 B', '7', 'FSTD Management Staff ORA.GEN.210', 'FSTD Manager \nProvide the following information for each FSTD nominated persons\nContact information (name, phone, mobile, email, full time/part time);\nRequired qualifications and/or training;\nResponsibilities.\nDefine also their responsibilities or give the reference of OM item 10.', 'OMM Part 2, Chapter 6 and reference to OM Part 1, Chapter 2.1.1 Management and Staffing.', NULL, 'Yes', 'Reference made to OMM Annex 14 – Nominated Person Contact Details.\n', NULL),
(184, 'OMM', 'OMM4.0|P2B|12 B|8', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.210', 'Organization Management Manual (OMM)', 'PART 2B', '12 B', '8', 'FSTD Management Staff ORA.GEN.210', 'FSTD maintenance technician.\nProvide the following information for each FSTD nominated persons\nContact information (name, phone, mobile, email, full time/part time);\nRequired qualifications and/or training;\nResponsibilities.\nDefine also their responsibilities or give the reference of OM item 10.\n', 'OMM Part 2, Chapter 3, reference is made to the OM Part 1, Chapter 2.1.2', NULL, 'Yes', NULL, NULL),
(185, 'OMM', 'OMM4.0|P2B|12 B|9', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.210', 'Organization Management Manual (OMM)', 'PART 2B', '12 B', '9', 'FSTD Management Staff ORA.GEN.210', 'Responsible for the daily release of the FSTD, periodic maintenance, unscheduled maintenance, recurrent QTGs.\nProvide the following information for each FSTD nominated persons\nContact information (name, phone, mobile, email, full time/part time);\nRequired qualifications and/or training;\nResponsibilities.\nDefine also their responsibilities or give the reference of OM item 10.', 'OMM Part 2, Chapter 3, reference is made to the OM Part 1, Chapter 2.1.2', NULL, 'Yes', NULL, NULL),
(186, 'OMM', 'OMM4.0|P2B|12 B|10', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.210', 'Organization Management Manual (OMM)', 'PART 2B', '12 B', '10', 'FSTD Management Staff ORA.GEN.210', 'Responsible for the fly-outs (function and subjective testing).\nProvide the following information for each FSTD nominated persons\nContact information (name, phone, mobile, email, full time/part time);\nRequired qualifications and/or training;\nResponsibilities.\nDefine also their responsibilities or give the reference of OM item 10.', 'OMM Part 2, Chapter 3, reference is made to the OM Part 1, Chapter 2.1.2', NULL, 'Yes', NULL, NULL),
(187, 'OMM', 'OMM4.0|P2B|17 B|6', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.FSTD.115; GM1 ORA.FSTD.115; ORA.FSTD.115', 'Organization Management Manual (OMM)', 'PART 2B', '17 B', '6', 'FSTD facilities\nORA.FSTD.115\nAMC1 ORA.FSTD.115\nGM1 ORA.FSTD.115', 'Provide information or the reference to the document containing that information, which assess full compliance towards AMC1 ORA.FSTD.115 and local Health and Safety regulations.', 'We refer to OM Annex 2', NULL, 'Yes', NULL, NULL),
(188, 'OMM', 'OMM4.0|P2B|17 B|7', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.FSTD.115; GM1 ORA.FSTD.115; ORA.FSTD.115', 'Organization Management Manual (OMM)', 'PART 2B', '17 B', '7', 'FSTD facilities\nORA.FSTD.115\nAMC1 ORA.FSTD.115\nGM1 ORA.FSTD.115', 'Provide the reference of the document regarding the safety briefings on the FSTD provided to users and instructors.', 'We refer to OM Annex 2', NULL, 'Yes', NULL, NULL),
(189, 'OMM', 'OMM4.0|P2B|21 B|2', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.205', 'Organization Management Manual (OMM)', 'PART 2B', '21 B', '2', 'FSTD contracted activities.\nORA.GEN.205', 'Provide a list of the FSTD maintenance or engineering activities done by a third party.\nThe contract/agreement between the FSTD operator and the third party should be made available to the BCAA.\nThe written agreement shall at least contain the following:\nServices and standards to be provided;\nThe necessary authorisations/approvals;\nProof of the technical competence of the third party.', '', NULL, 'Yes', NULL, NULL),
(190, 'OMM', 'OMM4.0|P2B|22 B|3', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.140', 'Organization Management Manual (OMM)', 'PART 2B', '22 B', '3', 'FSTD Access.\nORA.GEN.140', 'Define who has access to the FSTD premises and the means to prevent unexpected visit which can disrupt a FSTD training session.', 'Part 1, Chapter 15', NULL, 'Yes', NULL, NULL),
(191, 'OMM', 'OMM4.0|P2B|24 B|3', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.210', 'Organization Management Manual (OMM)', 'PART 2B', '24 B', '3', 'FSTD Compliance monitoring auditors (internal, external).\nORA.GEN.210', 'Define a list of the necessary internal or external auditors that have the privileges to perform compliance monitoring audits for FSTD.', 'OMM Annex 14', NULL, 'Yes', NULL, NULL),
(192, 'OMM', 'OMM4.0|P2B|24 B|4', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.210', 'Organization Management Manual (OMM)', 'PART 2B', '24 B', '4', 'FSTD Compliance monitoring auditors (internal, external).\nORA.GEN.210', 'How will the ATO assess their independence towards the areas they will be appointed to.', 'OMM Part 2, Chapter 6.2', NULL, 'Yes', NULL, NULL),
(193, 'OMM', 'OMM4.0|P2B|25 B|2', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.FSTD.100; AMC2 ORA.FSTD.100; GM2 ORA.FSTD.100; ORA.FSTD.100', 'Organization Management Manual (OMM)', 'PART 2B', '25 B', '2', 'FSTD Compliance monitoring programme.\nAMC1 ORA.FSTD.100\nAMC2 ORA.FSTD.100\nGM2 ORA.FSTD.100', 'Define the compliance monitoring programme for at least the following domains and their support documents:\nOrganisation;\nPlans and Objectives;\nMaintenance procedures;\nFSTD qualification level;\nSupervision;\nFSTD technical status;\nManuals, logs and records;\nMQTG;\nDefect deferral;\nPersonnel training;\nAircraft and simulator configuration management, including Airworthiness Directives;\nFSTD configuration management;\nFSTD safety features (including emergency stops and emergency lighting);\nQTGs re-runs;\nFunctional and subjective tests (fly-outs).', 'OMM Part 2, Chapter 6\nChapter 6.1 and \nSubchapters:\n6.1.1\n6.1.2\n6.1.3\n6.1.4', NULL, 'Yes', NULL, NULL),
(194, 'OMM', 'OMM4.0|P2B|26 B|2', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.FSTD.100; AMC1 ORA.GEN.200(a)(6); ORA.FSTD.100; ORA.GEN.200(a)(6)', 'Organization Management Manual (OMM)', 'PART 2B', '26 B', '2', 'FSTD Compliance monitoring planning.', 'Define the FSTD compliance monitoring planning or give the reference to the document/software providing that information.\nThe FSTD compliance monitoring planning shall ensure that all items of the compliance monitoring programme are covered each 12 months period.', 'Part 2, Chapter 6.1 and 6.1.1 Audit Planning plus\nOMM Annex 1 and 4', NULL, 'Yes', NULL, NULL),
(195, 'OMM', 'OMM4.0|P2B|26B|3', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.FSTD.100; AMC1 ORA.GEN.200(a)(6); ORA.FSTD.100; ORA.GEN.200(a)(6)', 'Organization Management Manual (OMM)', 'PART 2B', '26B', '3', 'FSTD Compliance monitoring planning.', 'Management evaluations/reviews:\nPlanning of those management evaluations (at least quarterly);\nWho must attend those management evaluations;\nForms on which those management evaluations are reported.\n', 'Part 2, Chapter 9 – Management Evaluation', NULL, 'Yes', NULL, NULL),
(196, 'OMM', 'OMM4.0|P2B|27 B|2', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.FSTD.100; AMC1 ORA.GEN.200(a)(6); ORA.FSTD.100; ORA.GEN.200(a)(6)', 'Organization Management Manual (OMM)', 'PART 2B', '27 B', '2', 'FSTD Audit procedures', 'Define or give the reference of the audit procedure regarding FSTDs.', 'Part 2, Chapter 6.1.2\nAlso refer to Annex OMM Annex 1', NULL, 'Yes', NULL, NULL),
(197, 'OMM', 'OMM4.0|P2B|28 B|2', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.FSTD.100; AMC1 ORA.GEN.160; ORA.FSTD.100; ORA.GEN.160', 'Organization Management Manual (OMM)', 'PART 2B', '28 B', '2', 'FSTD Reporting procedures.', 'Define or give the reference of the reporting procedures.', 'Part 2, Chapter 6.1.3\nRefer to OMM Annex 2 NCR and Annex 3 CMAR', NULL, 'Yes', NULL, NULL),
(198, 'OMM', 'OMM4.0|P2B|29 B|2', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.FSTD.100; AMC1 ORA.GEN.150(b); AMC1 ORA.GEN.160; GM1 ORA.GEN.150; ORA.ATO.100; ORA.ATO.105; ORA.ATO.110; ORA.ATO.125; ORA.ATO.130; ORA.ATO.230; ORA.FSTD.100; ORA.GEN.150; ORA.GEN.160; ORA.GEN.210', 'Organization Management Manual (OMM)', 'PART 2B', '29 B', '2', 'FSTD Follow up and corrective action procedures – Findings.', 'Define or give the reference of the follow up and corrective action procedure.\nThis procedure must be able to handle internal (ATO CMS findings) and external findings (any findings made by a third party).\nThis procedure must address the following:\nIdentification of corrective action;\nPerson responsible for rectification;\nFeedback system to the accountable manager providing an independent assessment of corrective action, implementation and completion;\nMonitoring of corrective action programme;\nEnsuring that the corrective action contain the necessary elements;\nEvaluation of the effectiveness of the corrective action programme;\nReporting of significant non-compliances to the competent authority.', 'Part 2, Chapter 6.1.4\nIncluding 6.4 (Classiifcation of FSTD Audit Findings).\nIn addition, Part 2, Subchapter 7.2.3', NULL, 'Yes', 'Subchapter 7.2.3 Updated with the BE FNPT-028 procedure.', NULL),
(199, 'OMM', 'OMM4.0|P2B|30 B|2', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.220', 'Organization Management Manual (OMM)', 'PART 2B', '30 B', '2', 'Recording system.\nORA.GEN.220', 'How and on which form the FSTD compliance monitoring process will be recorded and stored.\nWho has access to it.\nThe records of the compliance monitoring programme shall be:\nAccurate;\nComplete;\nReadily accessible.', 'Part 2, Chapter 11, including 11.1 and 11.2\nPart 2, Chapter 7.2.3', NULL, 'Yes', NULL, NULL),
(200, 'OMM', 'OMM4.0|P2B|31 B|2', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.FSTD.100; AMC1 ORA.GEN.125; AMC1 ORA.GEN.200(a)(6); ORA.FSTD.100; ORA.GEN.125; ORA.GEN.200(a)(6)', 'Organization Management Manual (OMM)', 'PART 2B', '31 B', '2', 'Training of FSTD compliance auditors.', 'Define the training that the FSTD compliance auditors must perform before being allowed to audit part of the scope of the FSTD.\nWhen such training must be performed (initial training, recurrent training, refresher training).', 'Part 2, Chapter 10', NULL, 'Yes', NULL, NULL),
(201, 'OMM', 'OMM4.0|P2B|32 B|2', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.FSTD.110; GM1 ORA.FSTD.110; ORA.FSTD.105; ORA.FSTD.110', 'Organization Management Manual (OMM)', 'PART 2B', '32 B', '2', 'FSTD specific procedures\nORA.FSTD.105\nORA.FSTD.110\nAMC1 ORA.FSTD.110\nGM1 ORA.FSTD.110\n\n', 'Define or give the reference of the manual or procedures providing the following information and their support documents: Defect reporting system.', 'Part 2, Chapter 7.2.3', NULL, 'Yes', NULL, NULL),
(202, 'OMM', 'OMM4.0|P2B|32 B|3', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.FSTD.110; GM1 ORA.FSTD.110; ORA.FSTD.105; ORA.FSTD.110', 'Organization Management Manual (OMM)', 'PART 2B', '32 B', '3', 'FSTD specific procedures\nORA.FSTD.105\nORA.FSTD.110\nAMC1 ORA.FSTD.110\nGM1 ORA.FSTD.110\n\n', 'Define or give the reference of the manual or procedures providing the following information and their support documents: Defect rectification process.', 'Part 2, Chapter 7.2.3', NULL, 'Yes', NULL, NULL),
(203, 'OMM', 'OMM4.0|P2B|32 B|4', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.FSTD.110; GM1 ORA.FSTD.110; ORA.FSTD.105; ORA.FSTD.110', 'Organization Management Manual (OMM)', 'PART 2B', '32 B', '4', 'FSTD specific procedures\nORA.FSTD.105\nORA.FSTD.110\nAMC1 ORA.FSTD.110\nGM1 ORA.FSTD.110\n\n', 'Define or give the reference of the manual or procedures providing the following information and their support documents: Defect tracking mechanism.', 'Part 2, Chapter 7.2.3', NULL, 'Yes', NULL, NULL),
(204, 'OMM', 'OMM4.0|P2B|32 B|5', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.FSTD.110; GM1 ORA.FSTD.110; ORA.FSTD.105; ORA.FSTD.110', 'Organization Management Manual (OMM)', 'PART 2B', '32 B', '5', 'FSTD specific procedures\nORA.FSTD.105\nORA.FSTD.110\nAMC1 ORA.FSTD.110\nGM1 ORA.FSTD.110\n\n', 'Define or give the reference of the manual or procedures providing the following information and their support documents: Preventive maintenance programmes.', '', NULL, 'Yes', NULL, NULL),
(205, 'OMM', 'OMM4.0|P2B|32 B|6', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.FSTD.110; GM1 ORA.FSTD.110; ORA.FSTD.105; ORA.FSTD.110', 'Organization Management Manual (OMM)', 'PART 2B', '32 B', '6', 'FSTD specific procedures\nORA.FSTD.105\nORA.FSTD.110\nAMC1 ORA.FSTD.110\nGM1 ORA.FSTD.110\n\n', 'Define or give the reference of the manual or procedures providing the following information and their support documents: Spares handling.', 'Refer to Service Contract for each individual FSTD', NULL, 'Yes', NULL, NULL),
(206, 'OMM', 'OMM4.0|P2B|32 B|7', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.FSTD.110; GM1 ORA.FSTD.110; ORA.FSTD.105; ORA.FSTD.110', 'Organization Management Manual (OMM)', 'PART 2B', '32 B', '7', 'FSTD specific procedures\nORA.FSTD.105\nORA.FSTD.110\nAMC1 ORA.FSTD.110\nGM1 ORA.FSTD.110\n\n', 'Define or give the reference of the manual or procedures providing the following information and their support documents: Equipment calibration.', 'Refer to the Operating Manual of each individual FSTD (MQTG)', NULL, 'Yes', NULL, NULL),
(207, 'OMM', 'OMM4.0|P2B|32 B|8', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.FSTD.110; GM1 ORA.FSTD.110; ORA.FSTD.105; ORA.FSTD.110', 'Organization Management Manual (OMM)', 'PART 2B', '32 B', '8', 'FSTD specific procedures\nORA.FSTD.105\nORA.FSTD.110\nAMC1 ORA.FSTD.110\nGM1 ORA.FSTD.110\n\n', 'Define or give the reference of the manual or procedures providing the following information and their support documents: QTG running and checking.', 'Refer to the MQTG of each individual FSTD and OMM Part 2, Chapter 6', NULL, 'Yes', NULL, NULL),
(208, 'OMM', 'OMM4.0|P2B|32 B|9', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.FSTD.110; GM1 ORA.FSTD.110; ORA.FSTD.105; ORA.FSTD.110', 'Organization Management Manual (OMM)', 'PART 2B', '32 B', '9', 'FSTD specific procedures\nORA.FSTD.105\nORA.FSTD.110\nAMC1 ORA.FSTD.110\nGM1 ORA.FSTD.110\n\n', 'Define or give the reference of the manual or procedures providing the following information and their support documents: Software and hardware control procedures.', 'Refer to each MQTG of each individual FSTD + Dropbox Shared with FSTD BCAA Audit Team', NULL, 'Yes', NULL, NULL),
(209, 'OMM', 'OMM4.0|P2B|32 B|10', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.FSTD.110; GM1 ORA.FSTD.110; ORA.FSTD.105; ORA.FSTD.110', 'Organization Management Manual (OMM)', 'PART 2B', '32 B', '10', 'FSTD specific procedures\nORA.FSTD.105\nORA.FSTD.110\nAMC1 ORA.FSTD.110\nGM1 ORA.FSTD.110\n\n', 'Define or give the reference of the manual or procedures providing the following information and their support documents: Configuration control procedures for:\nControl of training loads;\nUpdates to visual models;\nUpdates to navigation and instructor operation station (IOS) databases;\nQTG running and checking procedures;\nMaintenance procedures for defect rectification;\nMaintenance procedures for preventing maintenance.\nThe configuration control procedures shall also include an internal acceptance process for any modifications.\nAll modifications must be documented.\nA revision of the MQTG may be triggered following a FSTD modification.', 'Refer to each MQTG of each individual FSTD + Dropbox shared with FSTD BCAA Audit Team\n\nIn addition, refer to Management of Change Procedures', NULL, 'Yes', NULL, NULL),
(210, 'OMM', 'OMM4.0|P2B|32 B|11', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.FSTD.110; GM1 ORA.FSTD.110; ORA.FSTD.105; ORA.FSTD.110', 'Organization Management Manual (OMM)', 'PART 2B', '32 B', '11', 'FSTD specific procedures\nORA.FSTD.105\nORA.FSTD.110\nAMC1 ORA.FSTD.110\nGM1 ORA.FSTD.110\n\n', 'Control of the FSTD configuration Vs aircraft being simulated.', 'OMM Annex 24a\nOMM Annex 24b\nOMM Annex 24c', NULL, 'Yes', 'Updated', NULL),
(211, 'OMM', 'OMM4.0|P2B|32 B|12', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.FSTD.110; GM1 ORA.FSTD.110; ORA.FSTD.105; ORA.FSTD.110', 'Organization Management Manual (OMM)', 'PART 2B', '32 B', '12', 'FSTD specific procedures\nORA.FSTD.105\nORA.FSTD.110\nAMC1 ORA.FSTD.110\nGM1 ORA.FSTD.110\n\n', 'System that ensures that all relevant Airworthiness Directives are introduced where applicable on affected FSTDs.', '', NULL, 'Yes', NULL, NULL),
(212, 'OMM', 'OMM4.0|P2B|32 B|13', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.FSTD.110; GM1 ORA.FSTD.110; ORA.FSTD.105; ORA.FSTD.110', 'Organization Management Manual (OMM)', 'PART 2B', '32 B', '13', 'FSTD specific procedures\nORA.FSTD.105\nORA.FSTD.110\nAMC1 ORA.FSTD.110\nGM1 ORA.FSTD.110\n\n', 'Procedure to notify the authority in case of:\nMajor change;\nRelocation;\nDeactivation;\nMajor failure of a qualified device;\nMajor safety issue associated with the installation.', 'Part 2, Chapter 12 – FSTD Compliance Monitoring Measures', NULL, 'Yes', NULL, NULL),
(213, 'OMM', 'OMM4.0|P2B|32 B|14', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.FSTD.110; AMC1 ORA.FSTD.115; GM1 ORA.FSTD.110; ORA.FSTD.105; ORA.FSTD.110; ORA.FSTD.115', 'Organization Management Manual (OMM)', 'PART 2B', '32 B', '14', 'FSTD specific procedures\nORA.FSTD.105\nORA.FSTD.110\nAMC1 ORA.FSTD.110\nGM1 ORA.FSTD.110\n\n', 'Procedure that ensure compliance with applicable health and safety regulations, including:\nSafety briefings;\nFire/Smoke detection and suppression;\nProtection against electrical, mechanical, hydraulic and pneumatic hazards;\nOther items as defined in AMC1 ORA.FSTD.115.', 'We refer to OM Annex 2', NULL, 'Yes', NULL, NULL),
(214, 'OMM', 'OMM4.0|P2B|32 B|15', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.FSTD.110; GM1 ORA.FSTD.110; ORA.FSTD.105; ORA.FSTD.110', 'Organization Management Manual (OMM)', 'PART 2B', '32 B', '15', 'FSTD specific procedures\nORA.FSTD.105\nORA.FSTD.110\nAMC1 ORA.FSTD.110\nGM1 ORA.FSTD.110\n\n', 'Process to produce, review and track the following:\nFSTD availability;\nNumbers of defect by ATA chapter;\nOpen defects;\nDefect closure rates;\nTraining session interrupt rates;\nTraining session compliance rating.', 'Part 2, Chapter 12 – FSTD Compliance Monitoring Measures', NULL, 'Yes', NULL, NULL),
(215, 'OMM', 'OMM4.0|P2B|35 B|2', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.FSTD.240; ORA.ATO.120; ORA.FSTD.240; ORA.GEN.220', 'Organization Management Manual (OMM)', 'PART 2B', '35 B', '2', 'FSTD Record-keeping.\nORA.GEN.220\nORA.FSTD.240', 'Define the record keeping means and procedures for any FSTD documents. See AMC1 ORA.FSTD.240 for further information.\nThis item is also covered by item 18 of the operations manual checklist. The manner how the ATO will comply with ORA.GEN.220/ORA.ATO.120 must be described in one of those two items.\nAll training records of the FSTD personal shall be maintained.', 'Part 2, Chapter 11', NULL, 'Yes', NULL, NULL),
(216, 'OMM', 'OMM4.0|P2B|35 B|3', 'OMM REV 4.0', 'BCAA', 'GM3 ORA.FSTD.100; ORA.FSTD.100; ORA.FSTD.240; ORA.GEN.220', 'Organization Management Manual (OMM)', 'PART 2B', '35 B', '3', 'FSTD Record-keeping.\nORA.GEN.220\nORA.FSTD.240', 'Define the content of the dossier for an authority recurrent evaluation or give the reference of the document providing that information.\nSee GM3 ORA.FSTD.100 (d) for further information on the content of the dossier.', 'Part 2, Chapter 6.1.5 ', NULL, 'Yes', NULL, NULL),
(217, 'OMM', 'OMM4.0|P3|37|1', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.FSTD.100; AMC1 ORA.GEN.125; AMC1 ORA.GEN.200; ORA.ATO.100; ORA.ATO.105; ORA.ATO.110; ORA.ATO.125; ORA.ATO.130; ORA.ATO.230; ORA.FSTD.100; ORA.GEN.125; ORA.GEN.200', 'Organization Management Manual (OMM)', 'PART 3', '37', '1', 'Scope of the safety management system.', 'Define here what will be the scope of the ATO safety management system.\nIn which area of activities of the ATO it will be active (Administrative, training, FSTD, maintenance,…).\nIt can be the case that parts of the scope are already covered by an SMS of a third party (i.e. maintenance). It is therefore suitable to define how deep the ATO SMS will go.', 'Part 3, Chapter 1', NULL, 'Yes', NULL, NULL),
(218, 'OMM', 'OMM4.0|P3|38|1', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.200(a)(2)', 'Organization Management Manual (OMM)', 'PART 3', '38', '1', 'Safety policy and objectives.\nORA.GEN.200(a)(2)', 'The overall philosophies and principles of the organisation with regard to safety endorsed by the accountable manager.\nThis safety policy should explain how the senior management will promote the safety policy throughout the organisation, provide necessary human and financial resources for its implementation and establish safety objectives and performance standards.', 'Part 3, Chapter 2', NULL, 'Yes', NULL, NULL),
(219, 'OMM', 'OMM4.0|P3|38|2', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.GEN.200(a)(2); GM1 ORA.GEN.200(a)(2); ORA.GEN.200(a)(2)', 'Organization Management Manual (OMM)', 'PART 3', '38', '2', 'Safety policy and objectives.\nORA.GEN.200(a)(2)', 'Define the organisation’s safety objectives and performance standards. See AMC1 ORA.GEN.200(a)(2) and GM1 ORA.GEN.200(a)(2).', 'Part 3, Chapter 2', NULL, 'Yes', NULL, NULL),
(220, 'OMM', 'OMM4.0|P3|38|3', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.200(a)(2)', 'Organization Management Manual (OMM)', 'PART 3', '38', '3', 'Safety policy and objectives.\nORA.GEN.200(a)(2)', 'Commitment from the management that a “no blame” culture is in place.', 'Part 3, Chapter 2 and OMM Annex 07', NULL, 'Yes', NULL, NULL),
(221, 'OMM', 'OMM4.0|P3|38|4', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.200(a)(2)', 'Organization Management Manual (OMM)', 'PART 3', '38', '4', 'Safety policy and objectives.\nORA.GEN.200(a)(2)', 'Define the “just culture” approach.\nExplain how the ATO will assess if an incident/accident was a sabotage, intentional violation, reckless conduct or human error/no blame error (decision tree).', 'Part 3, Chapter 2 and OMM Annex 07', NULL, 'Yes', NULL, NULL),
(222, 'OMM', 'OMM4.0|P3|38|5', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.200(a)(2)', 'Organization Management Manual (OMM)', 'PART 3', '38', '5', 'Safety policy and objectives.\nORA.GEN.200(a)(2)', 'Define the means to promote the safety policy to all personnel.', 'Part 3, Chapter 2', NULL, 'Yes', NULL, NULL),
(223, 'OMM', 'OMM4.0|P3|39|1', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.200(a)(1)', 'Organization Management Manual (OMM)', 'PART 3', '39', '1', 'Lines of responsibility and accountability regarding safety.\nORA.GEN.200(a)(1)', 'Define lines of responsibility and accountability throughout the organisation, including a direct safety accountability of the accountable manager.\nAttest the safety accountability of the accountable manager or give the reference to the OM item 10.', 'Part 3, Chapter 3', NULL, 'Yes', NULL, NULL),
(224, 'OMM', 'OMM4.0|P3|40|1', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.200(a)(1)', 'Organization Management Manual (OMM)', 'PART 3', '40', '1', 'Safety manager (SM).\nORA.GEN.200(a)(1)', 'Who is the safety manager.', 'Part 3, Chapter 3.3', NULL, 'Yes', NULL, NULL),
(225, 'OMM', 'OMM4.0|P3|40|2', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.200(a)(1)', 'Organization Management Manual (OMM)', 'PART 3', '40', '2', 'Safety manager (SM).\nORA.GEN.200(a)(1)', 'Define his/her responsibilities and functions.', 'Part 3, Chapter 3.3', NULL, 'Yes', NULL, NULL),
(226, 'OMM', 'OMM4.0|P3|40|3', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.GEN.200(a)(1); ORA.GEN.200(a)(1)', 'Organization Management Manual (OMM)', 'PART 3', '40', '3', 'Safety manager (SM).\nORA.GEN.200(a)(1)', 'Define how he/she will comply with the requirements of such responsibilities/functions. See AMC1 ORA.GEN.200(a)(1).', 'Part 3, Chapter 3.3', NULL, 'Yes', NULL, NULL),
(227, 'OMM', 'OMM4.0|P3|41|1', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.200(a)(1)', 'Organization Management Manual (OMM)', 'PART 3', '41', '1', 'Safety review board (SRB).\nORA.GEN.200(a)(1)', 'Define the SRB members.', 'Part 3, Chapter 3.4', NULL, 'Yes', 'Updated', NULL),
(228, 'OMM', 'OMM4.0|P3|41|2', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.200(a)(1)', 'Organization Management Manual (OMM)', 'PART 3', '41', '2', 'Safety review board (SRB).\nORA.GEN.200(a)(1)', 'Define the responsibilities and functions within the SRB of each member.', 'Part 3, Chapter 3.4 and further detailed in Subchapter 3.4.1 ', NULL, 'Yes', 'Updated in accordance with the finding.', NULL),
(229, 'OMM', 'OMM4.0|P3|41|3', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.GEN.200(a)(1); ORA.GEN.200(a)(1)', 'Organization Management Manual (OMM)', 'PART 3', '41', '3', 'Safety review board (SRB).\nORA.GEN.200(a)(1)', 'Explain how the SRB will comply with its mission. See AMC1 ORA.GEN.200(a)(1)-(b)(3) and (c).', 'Part 3, Chapter 3.4.1', NULL, 'Yes', 'Updated procedure, with detailed explanation of the roles and responsibilities, the steps and the phases + Action planning and Closing.', NULL),
(230, 'OMM', 'OMM4.0|P3|41|4', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.200(a)(1)', 'Organization Management Manual (OMM)', 'PART 3', '41', '4', 'Safety review board (SRB).\nORA.GEN.200(a)(1)', 'Define the planning of the SRB meetings.', 'Part 3, Chapter 3.4.1', NULL, 'Yes', 'Updated procedure, with detailed explanation of the roles and responsibilities, the steps and the phases + Action planning and Closing.', NULL),
(231, 'OMM', 'OMM4.0|P3|42|1', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.200(a)(1)', 'Organization Management Manual (OMM)', 'PART 3', '42', '1', 'Safety action group (SAG).\nORA.GEN.200(a)(1)', 'Define any needed SAGs  members. Depending on the scope of the organisation, several SAGs might be needed (i.e. Operations, maintenance, training)', 'Part 3, Chapter 3.5', NULL, 'Yes', NULL, NULL),
(232, 'OMM', 'OMM4.0|P3|42|2', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.200(a)(1)', 'Organization Management Manual (OMM)', 'PART 3', '42', '2', 'Safety action group (SAG).\nORA.GEN.200(a)(1)', 'Define SAGs  members.', 'Part 3, Chapter 3.5', NULL, 'Yes', NULL, NULL),
(233, 'OMM', 'OMM4.0|P3|42|3', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.200(a)(1)', 'Organization Management Manual (OMM)', 'PART 3', '42', '3', 'Safety action group (SAG).\nORA.GEN.200(a)(1)', 'Define the responsibilities and functions within SAGs of each member.', 'Part 3, Chapter 3.5', NULL, 'Yes', NULL, NULL),
(234, 'OMM', 'OMM4.0|P3|42|4', 'OMM REV 4.0', 'BCAA', 'GM2 ORA.GEN.200(a)(1); ORA.GEN.200(a)(1)', 'Organization Management Manual (OMM)', 'PART 3', '42', '4', 'Safety action group (SAG).\nORA.GEN.200(a)(1)', 'Explain how the SAG will comply with its mission. See GM2 ORA.GEN.200(a)(1)-(c),(d) and (e).', 'Part 3, Chapter 3.5', NULL, 'Yes', NULL, NULL),
(235, 'OMM', 'OMM4.0|P3|42|5', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.200(a)(1)', 'Organization Management Manual (OMM)', 'PART 3', '42', '5', 'Safety action group (SAG).\nORA.GEN.200(a)(1)', 'Define the planning of the SAGs meetings.', 'Part 3, Chapter 3.5', NULL, 'Yes', NULL, NULL),
(236, 'OMM', 'OMM4.0|P3|43|1', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.GEN.200(a)(3); ORA.GEN.200(a)(3)', 'Organization Management Manual (OMM)', 'PART 3', '43', '1', 'Identification of safety hazards.\nORA.GEN.200(a)(3)', 'Define or give the reference of the identification of safety hazards procedure. See AMC1 ORA.GEN.200(a)(3)-(a).\nThis procedure should include at least the following:\nDefine who may identify any safety hazard.\nExplain how those persons may report any identified safety hazard.\nDefine who is in charge to collect identified safety hazards reports.\nDefine how it is reported to the safety manager.\nDefine how identified safety hazards are recorded (form to be used)', 'Part 3, Chapter 5', NULL, 'Yes', NULL, NULL),
(237, 'OMM', 'OMM4.0|P3|44|1', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.GEN.200(a)(3); ORA.GEN.200(a)(3)', 'Organization Management Manual (OMM)', 'PART 3', '44', '1', 'Risk assessment process.\nORA.GEN.200(a)(3)', 'Define or give the reference of the process in place within the organisation to analyse and assess the identified risks.\nSee AMC1 ORA.GEN.200(a)(3)-(b).\nThis procedure should include at least the following:\nDefine who may assess a safety hazard.\nDefine which method will be used to assess a safety hazard in terms of likelihood, severity and tolerability.\nDefine how a feedback will be provided (i.e. to the reporter).\nDefine how the assessment is recorded (Form to be used).', 'Part 3, Chapter 5.2.4', NULL, 'Yes', NULL, NULL),
(238, 'OMM', 'OMM4.0|P3|45|1', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.GEN.200(a)(3); ORA.GEN.200(a)(3)', 'Organization Management Manual (OMM)', 'PART 3', '45', '1', 'Risk mitigation process.\nORA.GEN.200(a)(3)', 'Define or give the reference of the process in place within the organisation to mitigate the identified risks. See AMC1 ORA.GEN.200(a)(3)-(b).\nThis procedure should include at least the following:\nDefine who can elaborate a mitigation measure\nExplain how the mitigation measure will be implemented in the safety action planning\nExplain how the mitigation measure will be communicated.\nDefine how a risk mitigation measure is recorded (form to be used).', 'Part 3, Chapter 5.3', NULL, 'Yes', NULL, NULL),
(239, 'OMM', 'OMM4.0|P3|46|1', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.200(a)(3)', 'Organization Management Manual (OMM)', 'PART 3', '46', '1', 'Safety action planning.\nORA.GEN.200(a)(3)', 'Define the planning of all safety actions that the ATO management chooses to perform or give the reference to the document/software providing that information.', 'Part 3, Chapter 5.2', NULL, 'Yes', NULL, NULL),
(240, 'OMM', 'OMM4.0|P3|47|1', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.GEN.200(a)(3); ORA.GEN.200(a)(3)', 'Organization Management Manual (OMM)', 'PART 3', '47', '1', 'Safety performance monitoring and measurement.\nORA.GEN.200(a)(3)', 'Define or give the reference of the process in place within the organisation to verify the safety performance and measurement in comparison to the safety policy and objectives. See AMC1 ORA.GEN.200(a)(3)-(d).', 'Part 3, Chapter 5.7', NULL, 'Yes', NULL, NULL),
(241, 'OMM', 'OMM4.0|P3|47|2', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.200(a)(3)', 'Organization Management Manual (OMM)', 'PART 3', '47', '2', 'Safety performance monitoring and measurement.\nORA.GEN.200(a)(3)', 'Define when this process will be performed and by who.', 'Part 3, Chapter 5.7', NULL, 'Yes', NULL, NULL),
(242, 'OMM', 'OMM4.0|P3|47|3', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.200(a)(3)', 'Organization Management Manual (OMM)', 'PART 3', '47', '3', 'Safety performance monitoring and measurement.\nORA.GEN.200(a)(3)', 'Define how it will be reported and by who.', 'Part 3, Chapter 5.7', NULL, 'Yes', NULL, NULL),
(243, 'OMM', 'OMM4.0|P3|48|1', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.GEN.200(a)(3); ORA.GEN.200(a)(3)', 'Organization Management Manual (OMM)', 'PART 3', '48', '1', 'Continuous improvement.\nORA.GEN.200(a)(3)', 'Define how the organisation will achieve continuous improvement of its safety performance. See AMC1 ORA.GEN.200(a)(3)-(f).', 'Part 3, Chapter 5.10', NULL, 'Yes', NULL, NULL),
(244, 'OMM', 'OMM4.0|P3|49|1', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.GEN.200(a)(3); ORA.GEN.200(a)(3)', 'Organization Management Manual (OMM)', 'PART 3', '49', '1', 'Incident investigation and reporting - Internal safety investigation.\nORA.GEN.200(a)(3)', 'Define or give the reference of the process managing internal safety investigations. See AMC1 ORA.GEN.200(a)(3)-(c).\nThis procedure should include at least the following:\nDefine who can perform internal safety investigations.\nDefine when such investigations shall take place.\nDefine the scope of those investigations.\nDefine how such investigations must be reported.', 'Part 3, Chapter 5.6', NULL, 'Yes', NULL, NULL),
(245, 'OMM', 'OMM4.0|P3|50|1', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.GEN.200(a)(3); ORA.GEN.200(a)(3)', 'Organization Management Manual (OMM)', 'PART 3', '50', '1', 'The Emergency Response Plan (ERP).\nORA.GEN.200(a)(3)', 'Define the organisation ERP. See AMC1 ORA.GEN.200(a)(3)-(g).', 'Part 3, Chapter 5.8', NULL, 'Yes', NULL, NULL),
(246, 'OMM', 'OMM4.0|P3|51|1', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.GEN.200(a)(3); ORA.GEN.200(a)(3)', 'Organization Management Manual (OMM)', 'PART 3', '51', '1', 'Management of change (MOC).\nORA.GEN.200(a)(3)', 'Define or give the reference of the process in place within the organization to cope with safety risks related to an external or internal change. See AMC1 ORA.GEN.200(a)(3)-(e).\nThis procedure should include at least the following:\nDefine the type of changes that should be assessed (i.e. new training location, new type of aircraft and change of a nominated person).\nDefine who can take part of that assessment.\nDefine how the assessment will be performed.\nDefine how the result will be communicated and to who.', 'Part 3, Chapter 5.9', NULL, 'Yes', 'Updated Procedure MOC, including the Phases, Analysis, Reporting, Actions and Closing.\nThis should cover the audit finding.', NULL),
(247, 'OMM', 'OMM4.0|P3|52|1', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.200(a)(4)', 'Organization Management Manual (OMM)', 'PART 3', '52', '1', 'Training on safety.\nORA.GEN.200(a)(4)', 'Define the training over safety for every category of personnel and for the candidates.', 'Part 3, Chapter 8', NULL, 'Yes', NULL, NULL),
(248, 'OMM', 'OMM4.0|P3|52|2', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.200(a)(4)', 'Organization Management Manual (OMM)', 'PART 3', '52', '2', 'Training on safety.\nORA.GEN.200(a)(4)', 'Define how the safety training will be performed (self-instruction via media, classroom training, e-learning, etc…)recorded and stored.', 'Part 3, Chapter 8', NULL, 'Yes', NULL, NULL),
(249, 'OMM', 'OMM4.0|P3|52|3', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.200(a)(4)', 'Organization Management Manual (OMM)', 'PART 3', '52', '3', 'Training on safety.\nORA.GEN.200(a)(4)', 'Define how the safety training will be recorded.', 'Part 3, Chapter 8', NULL, 'Yes', NULL, NULL),
(250, 'OMM', 'OMM4.0|P3|53|1', 'OMM REV 4.0', 'BCAA', 'AMC1 ORA.GEN.200(a)(4); ORA.GEN.200(a)(4)', 'Organization Management Manual (OMM)', 'PART 3', '53', '1', 'Safety promotion – Communication on safety.\nORA.GEN.200(a)(4)', 'Define the means that the ATO will use to promote safety in order to :\nEnsure that everyone involved in the ATO is aware of the safety management activities;\nInform about the outcome of any assessed risks and analysed hazard;\nExplain the mitigation measures undertaken;\nThat relevant persons receives a feedback from a voluntary report.\nSee AMC1 ORA.GEN.200(a)(4).\nA safety system must also be an “open” system. The ATO should also promote any safety items coming from aerodromes, maintenance facilities, the BCAA or the EASA.', 'Part 3, Chapter 6\nPart 3, Chapter 8.2', NULL, 'Yes', 'Updated Chapter 8.2 with the inclusion of Annex 30, Visible Mandatory Documents. This should cover the audit finding.\n\nIncluded as well: New Chapter 8.3 regarding Safety Committee Meetings (procedure)', NULL),
(251, 'OMM', 'OMM4.0|P3|54|1', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.155', 'Organization Management Manual (OMM)', 'PART 3', '54', '1', 'Immediate reaction to a safety problem.\nORA.GEN.155', 'Describe how the organisation will remain vigilant towards any safety problems raised either by the industry, the EASA or the BCAA and who is responsible for this task.', 'Part 3, Chapter 5.6.3', NULL, 'Yes', NULL, NULL),
(252, 'OMM', 'OMM4.0|P3|55|1', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.160', 'Organization Management Manual (OMM)', 'PART 3', '55', '1', 'Occurrence reporting.\nORA.GEN.160', 'Describe how the organisation and who will report any accident, serious incident and occurrences as defined in Regulation (EU) No 996/2010 and Directive 2003/42/EC.\nThe reports shall be made available as soon as practicable, but in any case within 72 hours.', 'Part 3, Chapter 5.6 – Subchapter 5.6.1', NULL, 'Yes', NULL, NULL),
(253, 'OMM', 'OMM4.0|P3|55|2', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.160', 'Organization Management Manual (OMM)', 'PART 3', '55', '2', 'Occurrence reporting.\nORA.GEN.160', 'Describe how the organisation will report to the competent authority and to the organisation responsible for the design of the aircraft any incident, malfunction, technical defect, exceeding of technical limitations, occurrence that would highlight inaccurate, incomplete or ambiguous information contained in data established in accordance with Part-21 or other irregular circumstance that has or may have endangered the safe operation of the aircraft and that has not resulted in an accident or serious incident.', 'Part 3, Chapter 5.6 – Subchapter 5.6.1', NULL, 'Yes', NULL, NULL),
(254, 'OMM', 'OMM4.0|P3|55|3', 'OMM REV 4.0', 'BCAA', 'ORA.GEN.160', 'Organization Management Manual (OMM)', 'PART 3', '55', '3', 'Occurrence reporting.\nORA.GEN.160', 'Describe also how the organisation will produce a follow up report to provide details of actions it intends to take to prevent similar occurrences in the future, as soon as these actions have been identified.\nThis should be linked with the safety management system.', 'Part 3, Chapter 5.6 – Subchapter 5.6.4 and 5.6.5', NULL, 'Yes', NULL, NULL);

Ref. to Part 0 – 0.7 Highlights of changes'),
