(14, 14, 'OM6.0|P0|7|1', 'OM REV 6.0', 'BCAA', 'ORA.GEN.210', 'Operations Manual (OM)', 'PART 0', 7, 1, 'Record of temporary revisions', 'Gives all the temporary revisions issued for this manual, their issue date and an abstract of the changes implemented by the temporary revision.\nThis page must be signed by the compliance monitoring manager.', 'No procedure', 'No', NULL),
(15, 15, 'OM6.0|P1|8|1', 'OM REV 6.0', 'BCAA', 'AMC1 ORA.ATO.230(b)(a)(1)', 'Operations Manual (OM)', 'PART 1', 8, 1, 'A list and description of all volumes in the operations manual.', 'A summary which clearly defines the content and the purpose of each part of the manual.', 'Part 1 – Ch. 1', 'Yes', NULL),
(16, 16, 'OM6.0|P1|9|1', 'OM REV 6.0', 'BCAA', 'ORA.GEN.210', 'Operations Manual (OM)', 'PART 1', 9, 1, 'Administration (function and management).', 'An organization chart providing the relationships between the post holders (AM, HT, CFI, CTKI, CMM and SM) their assistants/deputies and the rest of the staff.', 'Part 1 – Ch. 2', 'Yes', NULL),
