(18, 18, 'OM6.0|P1|10|1', 'OM REV 6.0', 'BCAA', 'AMC1 ORA.ATO.230(b)(a)(3)', 'Operations Manual (OM)', 'PART 1', 10, 1, 'Responsibilities (all management and administrative staff).', 'The responsibilities of each nominated persons /assistants/deputies and administrative staff must be described.', 'Part 1 – Ch. 2.2', 'Yes', NULL),
