(20, 20, 'OM6.0|P1|11|2', 'OM REV 6.0', 'BCAA', 'AMC1 ORA.ATO.230(b)(a)(4)', 'Operations Manual (OM)', 'PART 1', 11, 2, 'Student discipline and disciplinary action.', 'The consequences and procedure in case of failing to comply with those rules.', 'Part 1 – Ch. 3.1', 'Yes', NULL),
(21, 21, 'OM6.0|P1|12|1', 'OM REV 6.0', 'BCAA', 'AMC1 ORA.ATO.230(b)(a)(5)', 'Operations Manual (OM)', 'PART 1', 12, 1, 'Approval/authorisation of flights.', 'The procedure to authorise a flight (Dual, solo, solo x-country).', 'Part 1 – Ch. 4.1', 'Yes', NULL),
(22, 22, 'OM6.0|P1|12|2', 'OM REV 6.0', 'BCAA', 'AMC1 ORA.ATO.230(b)(a)(5)', 'Operations Manual (OM)', 'PART 1', 12, 2, 'Approval/authorisation of flights.', 'What are the requirements to authorise a flight?', 'Part 1 – Ch. 4.1', 'Yes', NULL),
