(37, 37, 'OM6.0|P1|17|1', 'OM REV 6.0', 'BCAA', 'AMC1 ORA.ATO.230(b)(a)(10)', 'Operations Manual (OM)', 'PART 1', 17, 1, 'Aircraft documentation.', 'Which documents must be aboard an aircraft?\nA separation must be made between legal documents and ATO’s specific documents.', 'Part 1 – Ch. 8.9', 'Yes', NULL),
(38, 38, 'OM6.0|P1|18|1', 'OM REV 6.0', 'BCAA', 'ORA.ATO.120', 'Operations Manual (OM)', 'PART 1', 18, 1, 'Retention of documents.', 'Define retention procedures for each type of document (ATO manuals, student folder, instructor folders, POH, document of reference, archives…). This item is also covered by item 35 of the organization management manual checklist. The manner how the ATO will comply with ORA.GEN.220/ORA.ATO.120 must be described in one of those two items.', 'Part 1 – Ch. 8.9.2', 'Yes', NULL),
(39, 39, 'OM6.0|P1|18|2', 'OM REV 6.0', 'BCAA', 'ORA.GEN.220', 'Operations Manual (OM)', 'PART 1', 18, 2, 'Retention of documents.', 'Where they will be contained?', 'Part 1 – Ch. 8.9.2', 'Yes', NULL),
(40, 40, 'OM6.0|P1|18|3', 'OM REV 6.0', 'BCAA', 'ORA.GEN.220', 'Operations Manual (OM)', 'PART 1', 18, 3, 'Retention of documents.', 'Who has access to those documents?', 'Part 1 – Ch. 8.9.2', 'Yes', NULL),
