(89, 89, 'OM6.0|P4|39|1', 'OM REV 6.0', 'BCAA', 'AMC1 ORA.ATO.230(b)(d)(1)', 'Operations Manual (OM)', 'PART 4', 39, 1, 'Appointments of persons responsible for standards/competence of flight personnel.', 'Define the persons designated for the selection, initial evaluation, continuous evaluation and standardisation of the FIs.', 'Part 4 – Ch. 1', 'Yes', NULL),
(90, 90, 'OM6.0|P4|40|1', 'OM REV 6.0', 'BCAA', 'AMC1 ORA.ATO.230(b)(d)(2)', 'Operations Manual (OM)', 'PART 4', 40, 1, 'Initial training.', 'Provide the training plan of the initial training that the new hired FIs and TKIs must performed before being scheduled for a training activity.\nA certificate, signed by the applicant and countersigned by the HT, must be delivered at the end of the initial training course.\nTopics to be covered : SMS of the ATO, Manuals, forms, software in use within the ATO, FSTD instructor guide, etc...', 'Part 4 – Ch. 2', 'Yes', 'Updated with Chapter 1.4.8 - KSA.100 Training (Initial and Recurrent)\nAnnex 16 Updated'),
(91, 91, 'OM6.0|P4|40|2', 'OM REV 6.0', 'BCAA', 'AMC1 ORA.ATO.230(b)(d)(2)', 'Operations Manual (OM)', 'PART 4', 40, 2, 'Initial training.', 'Forms to be used to report the initial training.', 'Part 4 – Ch. 2', 'Yes', NULL),
(92, 92, 'OM6.0|P4|41|1', 'OM REV 6.0', 'BCAA', 'AMC1 ORA.ATO.230(b)(d)(3)', 'Operations Manual (OM)', 'PART 4', 41, 1, 'Refresher training.', 'Describe the training plan and content of the refresher training for the FIs and TKIs depending of their field of activity within the ATO.', 'Part 4 – Ch. 3', 'Yes', 'Updated with Chapter 1.4.8 - KSA.100 Training (Initial and Recurrent)'),
(93, 93, 'OM6.0|P4|41|2', 'OM REV 6.0', 'BCAA', 'AMC1 ORA.ATO.230(b)(d)(3)', 'Operations Manual (OM)', 'PART 4', 41, 2, 'Refresher training.', 'When will the refresher trainings be organised?\ni.e.: A refresher training must be performed after a long absence, an update of training programmes and/or ATO SOPs, introduction of a new/updated regulation, introduction of a new type of A/C, update of any operational procedures.', 'Part 4 – Ch. 3', 'Yes', 'Annex 16 Updated'),
(94, 94, 'OM6.0|P4|41|3', 'OM REV 6.0', 'BCAA', 'AMC1 ORA.ATO.230(b)(d)(3)', 'Operations Manual (OM)', 'PART 4', 41, 3, 'Refresher training.', 'Forms to be used to report the refresher training.', 'Part 4 – Ch. 3.1.1', 'Yes', NULL),
(95, 95, 'OM6.0|P4|42|1', 'OM REV 6.0', 'BCAA', 'AMC1 ORA.ATO.230(b)(d)(4)', 'Operations Manual (OM)', 'PART 4', 42, 1, 'Standardisation training.', 'Describe the training plan and content to standardise the FIs and TKIs for each type of training.\nStandardisation training is to prevent deviation from ATO SOPs or ATO training manuals.', 'Part 4 – Ch. 4', 'Yes', NULL),
(96, 96, 'OM6.0|P4|42|2', 'OM REV 6.0', 'BCAA', 'AMC1 ORA.ATO.230(b)(d)(4)', 'Operations Manual (OM)', 'PART 4', 42, 2, 'Standardisation training.', 'When will the standardisation training be organised?', 'Part 4 – Ch. 4.1', 'Yes', NULL),
(97, 97, 'OM6.0|P4|42|3', 'OM REV 6.0', 'BCAA', 'AMC1 ORA.ATO.230(b)(d)(4)', 'Operations Manual (OM)', 'PART 4', 42, 3, 'Standardisation training.', 'Forms to be used to report the standardisation training. The forms assessing the standardisation training can be based on the BCAA documents “FI Standardisation Certificate – DOC/L-TRA-0153-53E” and “TKI Standardisation Certificate – DOC/L-TRA-0153-54E”.\nStandardisation training is to prevent deviation from ATO SOPs or ATO training manuals.', 'Part 4 – Ch. 4.1', 'Yes', NULL),
(98, 98, 'OM6.0|P4|43|1', 'OM REV 6.0', 'BCAA', 'AMC1 ORA.ATO.230(b)(d)(5)', 'Operations Manual (OM)', 'PART 4', 43, 1, 'Proficiency checks.', 'Describe for each type of training the content of a proficiency check that a FI or a TKI must perform.\nThis proficiency check is not about the ratings of the FIs but the proficiency towards the ATO standards. This check must be developed in order to remain certain of the standardisation among the training staff.', 'Part 4 – Ch. 5', 'Yes', NULL),
(99, 99, 'OM6.0|P4|43|2', 'OM REV 6.0', 'BCAA', 'AMC1 ORA.ATO.230(b)(d)(5)', 'Operations Manual (OM)', 'PART 4', 43, 2, 'Proficiency checks.', 'Define the criteria for this evaluation, define the key elements that must be evaluated (skill, behaviour, pedagogy,…).', 'Part 4 – Ch. 5', 'Yes', NULL),
(100, 100, 'OM6.0|P4|43|3', 'OM REV 6.0', 'BCAA', 'AMC1 ORA.ATO.230(b)(d)(5)', 'Operations Manual (OM)', 'PART 4', 43, 3, 'Proficiency checks.', 'When will the proficiency checks be organised?', 'Part 4 – Ch. 5', 'Yes', NULL),
(101, 101, 'OM6.0|P4|43|4', 'OM REV 6.0', 'BCAA', 'AMC1 ORA.ATO.230(b)(d)(5)', 'Operations Manual (OM)', 'PART 4', 43, 4, 'Proficiency checks.', 'Forms to be used to report the proficiency check.', 'Part 4 – Ch. 5', 'Yes', NULL),
(102, 102, 'OM6.0|P4|44|1', 'OM REV 6.0', 'BCAA', 'AMC1 ORA.ATO.230(b)(d)(6)', 'Operations Manual (OM)', 'PART 4', 44, 1, 'Upgrading training.', 'Define the training plan and content for a FI or TKI that is promoted to give instruction in a higher phase of the training or in another branch of the theoretical knowledge instruction/long briefing.\nA certificate, signed by the applicant and countersigned by the HT, must be delivered at the end of the upgrading training course.', 'Part 4 – Ch. 6', 'Yes', NULL),
(103, 103, 'OM6.0|P4|45|1', 'OM REV 6.0', 'BCAA', 'AMC1 ORA.ATO.230(b)(d)(7)', 'Operations Manual (OM)', 'PART 4', 45, 1, 'ATO personnel standards evaluation.', 'Define the procedure to evaluate ATO personnel standards.\nThis evaluation should be composed of proficiency checks and standardisation trainings.', 'Part 4 – Ch. 7', 'Yes', NULL);






